/* roomObj.items parentGroup helpers (flat-array shape; legacy bucketed
 * shape auto-migrated by window.VRC.migrateLegacyItemsShape).
 * PERF RULE: any function reading 2+ categories MUST call
 * bucketItemsByParentGroup() once instead of N filter() calls. */
function getItemsByParentGroup(parentGroup, obj) {
    const room = obj || roomObj;
    if (!room || !Array.isArray(room.items)) return [];
    return room.items.filter(it =>
        allDeviceTypes[it.data_deviceid] &&
        allDeviceTypes[it.data_deviceid].parentGroup === parentGroup
    );
}

function firstItemOfParentGroup(parentGroup, obj) {
    const room = obj || roomObj;
    if (!room || !Array.isArray(room.items)) return undefined;
    return room.items.find(it =>
        allDeviceTypes[it.data_deviceid] &&
        allDeviceTypes[it.data_deviceid].parentGroup === parentGroup
    );
}

function countItemsByParentGroup(parentGroup, obj) {
    const room = obj || roomObj;
    if (!room || !Array.isArray(room.items)) return 0;
    let n = 0;
    for (let i = 0; i < room.items.length; i++) {
        const it = room.items[i];
        const dt = allDeviceTypes[it.data_deviceid];
        if (dt && dt.parentGroup === parentGroup) n++;
    }
    return n;
}

function bucketItemsByParentGroup(obj) {
    const room = obj || roomObj;
    const buckets = Object.create(null);
    if (!room || !Array.isArray(room.items)) return buckets;
    for (let i = 0; i < room.items.length; i++) {
        const it = room.items[i];
        const dt = allDeviceTypes[it.data_deviceid];
        if (!dt || !dt.parentGroup) continue;
        const pg = dt.parentGroup;
        if (!buckets[pg]) buckets[pg] = [];
        buckets[pg].push(it);
    }
    return buckets;
}

/* Snapshot of sibling + rect start positions for member-direct drag follow. */
let _groupDragSnapshot = null;

/* CustomItem rects whose members ALL belong to groupId — these ride
 * along on Group drags/rotates. Split-membership CustomItems stay put. */
function getCustomItemRectsAllInGroup(groupId) {
    if (!groupId || typeof groupCustomItemRects === 'undefined' || !groupCustomItemRects) return [];
    const result = [];
    groupCustomItemRects.getChildren().forEach(rect => {
        const ciId = rect.data_customItemId;
        if (!ciId) return;
        const members = getCustomItemMemberNodes(ciId);
        if (members.length === 0) return;
        if (members.every(m => m.data_groupId === groupId)) result.push(rect);
    });
    return result;
}

/* Per-handler dragend/transformend intentionally do NOT call canvasToJson().
 * Single source-of-truth call is in stage.on('mouseup touchend'). */

/* Snapshot sibling + Group rect positions. MUST be called from dragstart
 * — by the first dragmove, target.x() has already advanced. */
function beginGroupDragFollow(target) {
    if (!target || !target.data_groupId) return;
    if (tr.isDragging()) { _groupDragSnapshot = null; return; }
    _groupDragSnapshot = {
        groupId:  target.data_groupId,
        target:   target,
        startPos: { x: target.x(), y: target.y() },
        others:   new Map(),
    };
    getGroupMemberNodes(target.data_groupId).forEach(member => {
        if (member === target) return;
        _groupDragSnapshot.others.set(member, { x: member.x(), y: member.y() });
    });
    if (groupGroupRects) {
        const rectNode = groupGroupRects.find(n => n.data_groupId === target.data_groupId)[0];
        if (rectNode && rectNode !== target) {
            _groupDragSnapshot.others.set(rectNode, { x: rectNode.x(), y: rectNode.y() });
        }
    }
    /* Pull in fully-contained CustomItem rects so they don't get left behind. */
    getCustomItemRectsAllInGroup(target.data_groupId).forEach(rect => {
        if (rect === target) return;
        if (_groupDragSnapshot.others.has(rect)) return;
        _groupDragSnapshot.others.set(rect, { x: rect.x(), y: rect.y() });
    });
}

/* Apply group drag-follow during a member-direct drag.
 * No-op during Transformer drag (Konva moves nodes natively). */
function followGroupDragFromMember(target) {
    if (!target || !target.data_groupId) return;
    if (tr.isDragging()) { _groupDragSnapshot = null; return; }

    if (!_groupDragSnapshot || _groupDragSnapshot.target !== target) {
        beginGroupDragFollow(target);
        if (!_groupDragSnapshot) return; /* tr.isDragging guard kicked in */
    }

    const dx = target.x() - _groupDragSnapshot.startPos.x;
    const dy = target.y() - _groupDragSnapshot.startPos.y;
    if (dx === 0 && dy === 0) return;
    _groupDragSnapshot.others.forEach((startPos, node) => {
        node.x(startPos.x + dx);
        node.y(startPos.y + dy);
        /* Sync coverage (#fov~/#audio~/#dispDist~/#speaker~/#label~).
         * Skip group/customItem rects — no coverage, and not in allDeviceTypes. */
        if (node.data_deviceid !== 'group' && node.data_deviceid !== 'customItem') {
            updateShading(node);
        }
    });
    refreshGroupDetailsFromCanvas();
}

function endGroupDragFollow() {
    _groupDragSnapshot = null;
}

/* CustomItem drag-follow state (parallels Group drag-follow above). */
let _customItemDragSnapshot = null;

function beginCustomItemDragFollow(target) {
    if (!target || !target.data_customItemId) return;
    if (tr.isDragging()) { _customItemDragSnapshot = null; return; }
    _customItemDragSnapshot = {
        customItemId: target.data_customItemId,
        target:       target,
        startPos:     { x: target.x(), y: target.y() },
        others:       new Map(),
    };
    getCustomItemMemberNodes(target.data_customItemId).forEach(member => {
        if (member === target) return;
        _customItemDragSnapshot.others.set(member, { x: member.x(), y: member.y() });
    });
    if (groupCustomItemRects) {
        const rectNode = groupCustomItemRects.find(n => n.data_customItemId === target.data_customItemId)[0];
        if (rectNode && rectNode !== target) {
            _customItemDragSnapshot.others.set(rectNode, { x: rectNode.x(), y: rectNode.y() });
        }
    }
}

/* Apply customItem drag-follow during a member-direct drag. Skips items
 * already moved by the Group follower (would otherwise double-shift). */
function followCustomItemDragFromMember(target) {
    if (!target || !target.data_customItemId) return;
    if (tr.isDragging()) { _customItemDragSnapshot = null; return; }

    if (!_customItemDragSnapshot || _customItemDragSnapshot.target !== target) {
        beginCustomItemDragFollow(target);
        if (!_customItemDragSnapshot) return;
    }

    const dx = target.x() - _customItemDragSnapshot.startPos.x;
    const dy = target.y() - _customItemDragSnapshot.startPos.y;
    if (dx === 0 && dy === 0) return;

    const dragGroupId = target.data_groupId || null;

    _customItemDragSnapshot.others.forEach((startPos, node) => {
        /* Skip siblings already moved by the Group follower (avoid double-shift). */
        if (dragGroupId && node.data_groupId === dragGroupId && node.data_deviceid !== 'customItem') {
            return;
        }
        node.x(startPos.x + dx);
        node.y(startPos.y + dy);
        if (node.data_deviceid !== 'customItem' && node.data_deviceid !== 'group') {
            updateShading(node);
        }
    });
    refreshCustomItemDetailsFromCanvas();
}

function endCustomItemDragFollow() {
    _customItemDragSnapshot = null;
}

/* Drift detection (opt-in diagnostic). Enable via window.VRC.debugDriftDetection = true.
 * Reports pushed to window.VRC._driftReports[]. Tolerances: 0.5px x/y, 0.01° rotation.
 * Rotation branch checks dRot only (per-member position deltas differ legitimately). */
let _driftCheckSnapshot = null;

function _driftCheckEnabled() {
    return !!(typeof window !== 'undefined' && window.VRC && window.VRC.debugDriftDetection);
}

/* Returns Set<Konva.Node> of bundle members for current drag/transform. */
function _collectBundleMemberSet(target) {
    const set = new Set();
    const addByGroupId = (gid) => {
        if (!gid || typeof getGroupMemberNodes !== 'function') return;
        getGroupMemberNodes(gid).forEach(n => set.add(n));
        if (typeof groupGroupRects !== 'undefined' && groupGroupRects) {
            const r = groupGroupRects.find(n => n.data_groupId === gid)[0];
            if (r) set.add(r);
        }
    };
    const addByCustomItemId = (cid) => {
        if (!cid || typeof getCustomItemMemberNodes !== 'function') return;
        getCustomItemMemberNodes(cid).forEach(n => set.add(n));
        if (typeof groupCustomItemRects !== 'undefined' && groupCustomItemRects) {
            const r = groupCustomItemRects.find(n => n.data_customItemId === cid)[0];
            if (r) set.add(r);
        }
    };
    if (target) {
        addByGroupId(target.data_groupId);
        addByCustomItemId(target.data_customItemId);
        set.add(target);
    }
    /* Only walk tr.nodes() if no target (Transformer-handle drag) OR target IS in tr.nodes()
     * (multi-bundle marquee). Otherwise it's a click-then-drag of an unselected item and
     * the OLD tr.nodes() is a stale leftover that produces false drift positives. */
    const targetInTrNodes = target && typeof tr !== 'undefined' && tr && tr.nodes
        ? tr.nodes().includes(target)
        : false;
    if ((!target || targetInTrNodes) && typeof tr !== 'undefined' && tr && tr.nodes) {
        tr.nodes().forEach(n => {
            addByGroupId(n.data_groupId);
            addByCustomItemId(n.data_customItemId);
            if (n.data_deviceid === 'group') addByGroupId(n.data_groupId);
            if (n.data_deviceid === 'customItem') addByCustomItemId(n.data_customItemId);
        });
    }
    return set;
}

function beginDriftCheck(source, target) {
    if (!_driftCheckEnabled()) { _driftCheckSnapshot = null; return; }
    /* Snapshot once on the FIRST dragstart only — Konva's _proxyDrag fires
     * dragstart per-node after shifting each, so overwriting later would
     * capture post-shift positions and produce phantom drift. */
    if (_driftCheckSnapshot) return;
    const members = _collectBundleMemberSet(target);
    if (members.size < 2) { _driftCheckSnapshot = null; return; }
    const positions = new Map();
    members.forEach(n => {
        positions.set(n, {
            x: n.x(),
            y: n.y(),
            rotation: n.rotation(),
            id: n.id ? n.id() : null,
            data_deviceid: n.data_deviceid || null,
            data_groupId: n.data_groupId || null,
            data_customItemId: n.data_customItemId || null,
        });
    });
    _driftCheckSnapshot = {
        source: source,
        target: target || null,
        targetId: (target && target.id) ? target.id() : null,
        startedAt: Date.now(),
        positions: positions,
        kind: (source && source.indexOf('transform') >= 0) ? 'rotation' : 'translation',
    };
}

function endDriftCheck(source) {
    if (!_driftCheckEnabled() || !_driftCheckSnapshot) {
        _driftCheckSnapshot = null;
        return;
    }
    const snap = _driftCheckSnapshot;
    _driftCheckSnapshot = null;

    const POS_TOL = 0.5;   /* px */
    const ROT_TOL = 0.01;  /* degrees */

    /* Normalize angle delta to [-180, 180) — absorbs ±180 wrap when one
     * member's rotation crosses the boundary mid-rotation but others don't. */
    const _norm180 = (a) => ((((a + 180) % 360) + 360) % 360) - 180;

    const deltas = [];
    snap.positions.forEach((startPos, node) => {
        if (!node || typeof node.x !== 'function') return; /* destroyed mid-drag */
        deltas.push({
            id: startPos.id,
            data_deviceid: startPos.data_deviceid,
            data_groupId: startPos.data_groupId,
            data_customItemId: startPos.data_customItemId,
            startX: startPos.x, startY: startPos.y, startRot: startPos.rotation,
            endX: node.x(), endY: node.y(), endRot: node.rotation(),
            dx: node.x() - startPos.x,
            dy: node.y() - startPos.y,
            dRot: node.rotation() - startPos.rotation,
        });
    });

    if (deltas.length < 2) return;

    /* Pick dragged target's deltas as reference; fall back to first snapshot entry. */
    let referenceDelta = null;
    if (snap.targetId) {
        referenceDelta = deltas.find(d => d.id === snap.targetId) || null;
    }
    if (!referenceDelta) referenceDelta = deltas[0];

    const drifted = deltas.filter(d => {
        if (d === referenceDelta) return false;
        if (snap.kind === 'rotation') {
            /* Compare normalized angle delta to absorb ±180 wrap. */
            return Math.abs(_norm180(d.dRot - referenceDelta.dRot)) > ROT_TOL;
        }
        return (
            Math.abs(d.dx - referenceDelta.dx) > POS_TOL ||
            Math.abs(d.dy - referenceDelta.dy) > POS_TOL
        );
    });

    if (!drifted.length) return;

    const report = {
        source: source,
        beganAt: snap.source,
        kind: snap.kind,
        durationMs: Date.now() - snap.startedAt,
        targetId: snap.targetId,
        targetDeviceId: snap.target ? snap.target.data_deviceid : null,
        reference: {
            id: referenceDelta.id,
            data_deviceid: referenceDelta.data_deviceid,
            dx: referenceDelta.dx, dy: referenceDelta.dy, dRot: referenceDelta.dRot,
        },
        drifted: drifted.map(d => ({
            id: d.id,
            data_deviceid: d.data_deviceid,
            data_groupId: d.data_groupId,
            data_customItemId: d.data_customItemId,
            dx: d.dx, dy: d.dy, dRot: d.dRot,
            expectedDx: referenceDelta.dx,
            expectedDy: referenceDelta.dy,
            expectedDRot: referenceDelta.dRot,
            errorDx: d.dx - referenceDelta.dx,
            errorDy: d.dy - referenceDelta.dy,
            errorDRot: d.dRot - referenceDelta.dRot,
        })),
        allDeltas: deltas,
    };

    console.warn('[VRC drift detected]', report);
    if (typeof window !== 'undefined') {
        window.VRC = window.VRC || {};
        window.VRC._driftReports = window.VRC._driftReports || [];
        window.VRC._driftReports.push(report);
    }
}

/* ---- Group helper functions ---- */

function getGroupById(groupId) {
    if (!roomObj.groups) return null;
    return roomObj.groups.find(g => g.groupid === groupId) || null;
}

function ensureGroups(obj) {
    const target = obj || roomObj;
    if (!target.groups) target.groups = [];
}

/* Backward-compat: rename legacy `layersVisible` + `gr*` keys to new schema on load. */
function migrateLegacyOverlayKeys(obj) {
    if (!obj || typeof obj !== 'object') return;
    const src = obj.layersVisible;
    if (!src || obj.overlaysVisible) return; /* already migrated */
    const dst = {};
    if ('grShadingCamera' in src) dst.cameraCoverage = src.grShadingCamera;
    if ('grShadingMicrophone' in src) dst.microphoneCoverage = src.grShadingMicrophone;
    if ('grShadingSpeaker' in src) dst.speakerCoverage = src.grShadingSpeaker;
    if ('grDisplayDistance' in src) dst.displayDistanceCoverage = src.grDisplayDistance;
    if ('grLabels' in src) dst.overlayLabels = src.grLabels;
    if ('gridLines' in src) dst.gridLines = src.gridLines;
    obj.overlaysVisible = dst;
    delete obj.layersVisible;
}

/* Ensures obj.overlaysVisible exists with every required key. Migrates
 * legacy `layersVisible` and fills missing keys with defaults. */
function ensureOverlaysVisibleDefaulted(obj) {
    if (!obj || typeof obj !== 'object') return;
    migrateLegacyOverlayKeys(obj);
    const defaults = {
        cameraCoverage: true,
        displayDistanceCoverage: false,
        microphoneCoverage: false,
        gridLines: true,
        speakerCoverage: false,
        overlayLabels: false
    };
    if (!obj.overlaysVisible || typeof obj.overlaysVisible !== 'object') {
        obj.overlaysVisible = Object.assign({}, defaults);
        return;
    }
    for (const k in defaults) {
        if (!Object.prototype.hasOwnProperty.call(obj.overlaysVisible, k)) {
            obj.overlaysVisible[k] = defaults[k];
        }
    }
}

/* Bounding box in layerTransform-local coords (same getClientRect the Transformer uses). */
function getMemberBoundingRect(node) {
    return node.getClientRect({
        skipShadow: true,
        relativeTo: layerTransform,
    });
}

/* Return all Konva nodes (across all item groups) whose data_groupId matches groupId */
function getGroupMemberNodes(groupId) {
    const members = [];
    allNodeShapeGroups.forEach(kg => {
        kg.getChildren().forEach(node => {
            if (node.data_groupId === groupId) members.push(node);
        });
    });
    return members;
}

/* Recalculate the Group rect's x, y, width, height from current member positions
 * and update both the Konva node and the roomObj.groups entry. */
function updateGroupBounds(groupId) {
    if (!groupGroupRects) return;
    const members = getGroupMemberNodes(groupId);
    if (!members.length) return;

    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    members.forEach(node => {
        const r = getMemberBoundingRect(node);
        if (r.x < minX) minX = r.x;
        if (r.y < minY) minY = r.y;
        if (r.x + r.width  > maxX) maxX = r.x + r.width;
        if (r.y + r.height > maxY) maxY = r.y + r.height;
    });

    /* No padding — match the Transformer's tight blue box exactly. */
    const newX = minX;
    const newY = minY;
    const newW = maxX - minX;
    const newH = maxY - minY;

    /* Update Konva node */
    const groupRectNode = groupGroupRects.find(n => n.data_groupId === groupId)[0];
    if (groupRectNode) {
        groupRectNode.x(newX);
        groupRectNode.y(newY);
        groupRectNode.width(newW);
        groupRectNode.height(newH);
    }

    /* Update roomObj.groups entry (in unit space) */
    const g = getGroupById(groupId);
    if (g) {
        g.x = ((newX - pxOffset) / scale) + activeRoomX;
        g.y = ((newY - pyOffset) / scale) + activeRoomY;
        g.width  = newW / scale;
        g.height = newH / scale;
        const zPositions = members
            .map(n => parseFloat(n.data_zPosition) || 0)
            .filter(z => !isNaN(z));
        if (zPositions.length) g.data_zPosition = Math.min(...zPositions);
    }
}

/* Returns { rectNode, group, groupId } when tr.nodes() is exactly one
 * Group bundle (rect + only its members); null otherwise. */
function getActiveGroupSelection(nodes) {
    nodes = nodes || tr.nodes();
    if (!nodes || !nodes.length) return null;
    const groupRects = nodes.filter(n => n.data_deviceid === 'group');
    if (groupRects.length !== 1) return null;
    const rectNode = groupRects[0];
    const groupId = rectNode.data_groupId;
    if (!groupId) return null;
    /* Allow fellow-traveler CustomItem rects (members are in this group). */
    const allBelong = nodes.every(n =>
        n === rectNode ||
        n.data_deviceid === 'customItem' ||
        n.data_groupId === groupId
    );
    if (!allBelong) return null;
    const group = getGroupById(groupId);
    if (!group) return null;
    return { rectNode: rectNode, group: group, groupId: groupId };
}

/* Visual centre of a (possibly rotated) Konva.Rect in parent coords. */
function getRotatedRectCenter(rectNode) {
    const r = rectNode.rotation();
    const rad = Math.PI / 180 * r;
    const cosR = Math.cos(rad);
    const sinR = Math.sin(rad);
    const halfW = rectNode.width() / 2;
    const halfH = rectNode.height() / 2;
    return {
        x: rectNode.x() + halfW * cosR - halfH * sinR,
        y: rectNode.y() + halfW * sinR + halfH * cosR,
    };
}

/* Rigid-body rotation of a Konva node around parent-space (cx, cy). */
function rotateNodeAroundPoint(node, cx, cy, deltaR) {
    if (!deltaR) return;
    const newPos = rotatePointAroundOrigin(node.x(), node.y(), cx, cy, deltaR);
    node.x(newPos.x);
    node.y(newPos.y);
    node.rotation(node.rotation() + deltaR);
}

/* Live-refresh Group Details-panel X/Y/Rotation/W/L during drag/rotate. */
function refreshGroupDetailsFromCanvas() {
    const sel = getActiveGroupSelection();
    if (!sel) return;
    const r = sel.rectNode;
    const itemX   = document.getElementById('itemX');
    const itemY   = document.getElementById('itemY');
    const itemRot = document.getElementById('itemRotation');
    const itemW   = document.getElementById('itemWidth');
    const itemL   = document.getElementById('itemLength');
    if (itemX)   itemX.value   = round(((r.x() - pxOffset) / scale) + activeRoomX);
    if (itemY)   itemY.value   = round(((r.y() - pyOffset) / scale) + activeRoomY);
    if (itemRot) itemRot.value = round(r.rotation(), -1);
    if (itemW)   itemW.value   = round(r.width()  / scale);
    if (itemL)   itemL.value   = round(r.height() / scale);
}

/* Populate Details panel with Group fields. Width/Length are read-only
 * (set by members + Transformer); X/Y/Z/Rotation/Label/Layer are
 * editable via updateItem() → updateGroupItem(). */
function populateGroupDetails(rectNode) {
    const group = getGroupById(rectNode.data_groupId);
    if (!group) return;

    /* Hide everything that doesn't apply to a Group.
     * (The non-group branch of updateFormatDetails re-shows itemNameDiv.) */
    const hideIds = [
        'itemNameDiv', 'labelPathId', 'itemTopElevationDiv', 'itemDiagonalTvDiv',
        'itemVheightDiv', 'trapNarrowWidthDiv', 'tblRectRadiusRow', 'tblRectRadiusDiv', 'tblRectRadiusRightDiv',
        'itemTiltSlantDiv', 'itemTiltDiv', 'itemSlantDiv',
        'itemOffsetDiv', 'roleDiv', 'mountDiv', 'colorDiv', 'fillDiv',
    ];
    hideIds.forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = 'none';
    });

    /* Show the divs we use */
    const showIds = [
        'labelFieldDiv', 'itemLayerDiv', 'itemWidthLengthDiv',
        'itemWidthDiv', 'itemLengthDiv', 'itemRotationDiv',
    ];
    showIds.forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = '';
    });

    document.getElementById('itemLabeldiv').textContent = 'Group Name:';
    document.getElementById('labelField').value = group.name || '';

    /* X/Y track the rect's top-left, same convention as tables/walls. */
    document.getElementById('itemX').value = round(((rectNode.x() - pxOffset) / scale) + activeRoomX);
    document.getElementById('itemY').value = round(((rectNode.y() - pyOffset) / scale) + activeRoomY);
    document.getElementById('itemZposition').value = (group.data_zPosition != null) ? group.data_zPosition : 0;

    /* Width/Length are display-only — set by updateGroupBounds() / Transformer. */
    document.getElementById('itemWidth').value  = round(rectNode.width()  / scale);
    document.getElementById('itemLength').value = round(rectNode.height() / scale);
    document.getElementById('itemWidth').disabled  = true;
    document.getElementById('itemLength').disabled = true;

    document.getElementById('itemRotation').value = round(rectNode.rotation(), -1);

    document.getElementById('itemId').innerText    = group.groupid;
    document.getElementById('itemType').innerText  = 'Group';
    document.getElementById('itemGroup').innerText = '';

    populateLayerDropdown('drpItemLayer', group.data_layerId || '0');
}

/* Apply a Group-level edit from the Details panel: X/Y/Z translate
 * every member + rect; rotation rotates them around the rect's centre;
 * label/layer cascade to all members; updateShading() re-aligns coverage. */
function updateGroupItem(group) {
    if (!group || !groupGroupRects) return;
    const rectNode = groupGroupRects.find(n => n.data_groupId === group.groupid)[0];
    if (!rectNode) return;

    const newName = (DOMPurify.sanitize(document.getElementById('labelField').value) || '').trim() || group.name;
    const newX = Number(document.getElementById('itemX').value) || 0;
    const newY = Number(document.getElementById('itemY').value) || 0;
    /* Z field: empty / null / non-numeric all collapse to 0, matching the
     * "treat missing data_zPosition as 0" rule applied to members below. */
    const newZ = Number(document.getElementById('itemZposition').value) || 0;
    const newRot = normalizeDegree(Number(document.getElementById('itemRotation').value) || 0);
    const newLayerId = (document.getElementById('drpItemLayer') && document.getElementById('drpItemLayer').value) || '0';

    /* Compute deltas in the same units the form uses */
    const currentX_user = ((rectNode.x() - pxOffset) / scale) + activeRoomX;
    const currentY_user = ((rectNode.y() - pyOffset) / scale) + activeRoomY;
    /* group.data_zPosition is the group's current baseline (the lowest
     * member z at create time, kept in sync by every updateGroupItem
     * call). Missing / NaN -> 0. */
    const currentZ      = Number(group.data_zPosition) || 0;
    const currentRot    = rectNode.rotation();

    const deltaX_px = (newX - currentX_user) * scale;
    const deltaY_px = (newY - currentY_user) * scale;
    const deltaZ    = newZ - currentZ;
    const deltaR    = newRot - currentRot;

    const members = getGroupMemberNodes(group.groupid);
    /* CustomItem rects whose every member belongs to this Group ride along
     * with the Group during translate / rotate (same rule the drag-follow
     * uses — see beginGroupDragFollow for the rationale). Without this, a
     * Details-panel X / Y / Rotation edit on a Group would leave any
     * fully-contained CustomItem rect floating where it was. */
    const customItemRects = getCustomItemRectsAllInGroup(group.groupid);

    /* 1) Translate first so the rotation pivot we compute next is the
     *    visual centre at the new location. */
    if (deltaX_px !== 0 || deltaY_px !== 0) {
        members.forEach(m => { m.x(m.x() + deltaX_px); m.y(m.y() + deltaY_px); });
        rectNode.x(rectNode.x() + deltaX_px);
        rectNode.y(rectNode.y() + deltaY_px);
        customItemRects.forEach(r => { r.x(r.x() + deltaX_px); r.y(r.y() + deltaY_px); });
    }

    /* 2) Rigid rotation around the (post-translation) rect centre. */
    if (deltaR !== 0) {
        const centre = getRotatedRectCenter(rectNode);
        members.forEach(m => rotateNodeAroundPoint(m, centre.x, centre.y, deltaR));
        rotateNodeAroundPoint(rectNode, centre.x, centre.y, deltaR);
        customItemRects.forEach(r => rotateNodeAroundPoint(r, centre.x, centre.y, deltaR));
    }

    /* 3) Z elevation: deltaZ adds to every member's data_zPosition.
     *    A member with no existing data_zPosition (or NaN/non-numeric) is
     *    treated as 0, so the new value lands at exactly deltaZ. The group
     *    object then holds the new baseline (which equals newZ since every
     *    member was shifted by the same amount, preserving the relative
     *    stack). The early-return on `deltaZ === 0` avoids polluting nodes
     *    that previously had no data_zPosition with an explicit `0`. */
    if (deltaZ !== 0) {
        members.forEach(m => {
            const existingZ = Number(m.data_zPosition) || 0;
            m.data_zPosition = existingZ + deltaZ;
            /* Mirror to roomObj.items directly — canvasToJson() only writes
             * data_zPosition when `in` the node, missing fresh assignments. */
            if (roomObj && Array.isArray(roomObj.items)) {
                const entry = roomObj.items.find(it => it.id === m.id());
                if (entry) entry.data_zPosition = m.data_zPosition;
            }
        });
    }
    group.data_zPosition = newZ;
    rectNode.data_zPosition = newZ;

    /* 4) Group name */
    group.name = newName;
    rectNode.data_labelField = newName;

    /* 5) Layer cascade — share-a-layer invariant matches createGroup(). */
    if (newLayerId !== (group.data_layerId || '0')) {
        group.data_layerId = newLayerId;
        rectNode.data_layerId = newLayerId;
        applyLayerStateToNode(rectNode, newLayerId);
        members.forEach(m => {
            m.data_layerId = newLayerId;
            applyLayerStateToNode(m, newLayerId);
        });
        renderLayersList();
    }

    /* 6) Re-align FOV / audio / display-distance / labels for moved members. */
    members.forEach(m => updateShading(m));

    canvasToJson();

    /* Match the existing single-item updateItem button-debounce. */
    const btn = document.getElementById("btnUpdateItemId");
    if (btn) {
        btn.disabled = true;
        setTimeout(() => { btn.disabled = false; }, 700);
    }
}

/* ---- CustomItem helper functions ----
 * Parallel to Groups; weaker selection precedence (Group wins on overlap). */

function getCustomItemById(customItemId) {
    if (!roomObj.customItems) return null;
    return roomObj.customItems.find(c => c.customitemid === customItemId) || null;
}

function ensureCustomItems(obj) {
    const target = obj || roomObj;
    if (!target.customItems) target.customItems = [];
}

/* Backfill customItemBaseId on any customItem lacking one. Idempotent. */
function ensureCustomItemBaseIds(obj) {
    const target = obj || roomObj;
    if (!target || !Array.isArray(target.customItems)) return 0;
    let assigned = 0;
    target.customItems.forEach(c => {
        if (!c) return;
        if (!c.customItemBaseId) {
            c.customItemBaseId = createUuid();
            assigned++;
        }
    });
    return assigned;
}

/* Populate customItemLibraryIds Set from IndexedDB at page load. Never rejects. */
function hydrateCustomItemLibraryIds() {
    if (!window.idbStore || typeof window.idbStore.customItemGetAllIds !== 'function') {
        return Promise.resolve();
    }
    return window.idbStore.customItemGetAllIds()
        .then(ids => {
            customItemLibraryIds = new Set(ids || []);
            console.info('[customItemLibrary] hydrated', customItemLibraryIds.size, 'template id(s) from IDB');
            /* Initial state for the Export Custom Items button. */
            if (typeof updateExportCustomItemsButtonState === 'function') {
                updateExportCustomItemsButtonState();
            }
        })
        .catch(e => {
            console.warn('[customItemLibrary] hydrate failed:', e && e.message);
        });
}

/* Synchronous predicate. Falsy/unknown baseIds always return false. */
function isCustomItemInLibrary(customItemBaseId) {
    if (!customItemBaseId) return false;
    return customItemLibraryIds.has(customItemBaseId);
}

/* Record baseId in cache. Call after every successful idbStore.customItemPut(). */
function markCustomItemInLibrary(customItemBaseId) {
    if (!customItemBaseId) return;
    const before = customItemLibraryIds.size;
    customItemLibraryIds.add(customItemBaseId);
    if (customItemLibraryIds.size !== before &&
        typeof updateExportCustomItemsButtonState === 'function') {
        updateExportCustomItemsButtonState();
    }
}

/* Inverse of markCustomItemInLibrary. Also removes sidebar tile and
 * surfaces empty-state banner if the grid is now empty. */
function unmarkCustomItemInLibrary(customItemBaseId) {
    if (!customItemBaseId) return;
    const before = customItemLibraryIds.size;
    customItemLibraryIds.delete(customItemBaseId);
    if (customItemLibraryIds.size !== before &&
        typeof updateExportCustomItemsButtonState === 'function') {
        updateExportCustomItemsButtonState();
    }

    const sidebarTile = document.getElementById('customItem-' + customItemBaseId + '-div');
    if (sidebarTile && sidebarTile.parentNode) {
        sidebarTile.parentNode.removeChild(sidebarTile);
    }
    const container = document.getElementById('customItemsMenuContainer');
    const empty = document.getElementById('customItemsEmptyState');
    if (container && empty && container.children.length === 0) {
        empty.style.display = 'block';
    }
}

/* Compute a customItem member's geometry in the customItem's normalized
 * local frame (UL at 0,0, rotation removed). Returns null on invalid.
 * Math (θ = ci.rotation, dx = part.x - ci.x, dy = part.y - ci.y):
 *   localX =  cos(θ)*dx + sin(θ)*dy, localY = -sin(θ)*dx + cos(θ)*dy
 *   localRotation = part.rotation - θ */
function getPartRenderRect(item, customItem) {
    if (!item || !customItem) return null;
    if (!item.data_deviceid) return null;

    /* Resolve w/h. Fixed-size devices pull from device library (mm).
     * Device .height is 3D vHeight; use .depth for floor-plan height. */
    let w = Number(item.width);
    let h = Number(item.height);
    if (!w || !h) {
        const dt = allDeviceTypes && allDeviceTypes[item.data_deviceid];
        if (dt) {
            if (!w && typeof dt.width === 'number') w = dt.width / 1000;
            if (!h && typeof dt.depth === 'number') h = dt.depth / 1000;
        }
        /* Feet rooms: re-scale mm→meters output to feet for parity with item.x/y. */
        if (roomObj && roomObj.unit === 'feet') {
            if (!Number(item.width) && w) w = w * 3.28084;
            if (!Number(item.height) && h) h = h * 3.28084;
        }
    }
    w = w || 0;
    h = h || 0;

    const partX = Number(item.x) || 0;
    const partY = Number(item.y) || 0;
    const partRotation = Number(item.rotation) || 0;
    const ciX = Number(customItem.x) || 0;
    const ciY = Number(customItem.y) || 0;
    const ciRotation = Number(customItem.rotation) || 0;

    const dx = partX - ciX;
    const dy = partY - ciY;

    const theta = ciRotation * Math.PI / 180;
    const cosT = Math.cos(theta);
    const sinT = Math.sin(theta);
    const localX = cosT * dx + sinT * dy;
    const localY = -sinT * dx + cosT * dy;

    let localRotation = partRotation - ciRotation;
    /* Wrap into (-180, 180] — stable across export/import round-trips. */
    while (localRotation > 180) localRotation -= 360;
    while (localRotation <= -180) localRotation += 360;

    return {
        data_deviceid: item.data_deviceid,
        localX: localX,
        localY: localY,
        width: w,
        height: h,
        localRotation: localRotation,
    };
}

/* Look up a roomObj item entry by uuid (O(n) flat-array scan).
 * For Konva nodes, use roomObjItemsMap (O(1)) instead. */
function findRoomItemByUuid(uuid) {
    if (!uuid || !roomObj || !Array.isArray(roomObj.items)) return null;
    return roomObj.items.find(i => i && i.id === uuid) || null;
}

/* Per-part data_* fields that round-trip through .vrcCustomItems export.
 * Fields not listed are dropped intentionally. */
const CUSTOM_ITEM_PART_VERBATIM_FIELDS = [
    'data_color',
    'data_fill',
    'data_opacity',
    'data_labelField',
    'data_role',
    'data_mount',
    'data_tilt',
    'data_slant',
    'data_diagonalInches',
    'data_fovHidden',
    'data_audioHidden',
];

/* Per-part fields stored in roomObj.unit; scaled to meters on export. */
const CUSTOM_ITEM_UNIT_SCALED_PART_FIELDS = [
    'data_zPosition',
    'data_vHeight',
    'data_trapNarrowWidth',
    'tblRectRadius',
    'tblRectRadiusRight',
];

/* Read top-level customItem name; falls back to legacy data_labelField. */
function getCustomItemRecordName(rec) {
    if (!rec) return '';
    return String(rec.customItemName || rec.data_labelField || '');
}

/* Build serializable export record for a customItem (METERS, menuImage empty).
 * Returns null on missing baseId or empty members. */
function buildCustomItemExportRecord(customItem) {
    if (!customItem || !customItem.customItemBaseId) return null;
    if (!Array.isArray(customItem.customItemMembers) || !customItem.customItemMembers.length) return null;

    const unitToMeters = (roomObj && roomObj.unit === 'feet') ? (1 / 3.28084) : 1;

    const parts = [];
    customItem.customItemMembers.forEach(uuid => {
        const item = findRoomItemByUuid(uuid);
        if (!item) return;
        const rect = getPartRenderRect(item, customItem);
        if (!rect) return;

        const part = {
            data_deviceid: rect.data_deviceid,
            x: rect.localX * unitToMeters,
            y: rect.localY * unitToMeters,
            width: rect.width * unitToMeters,
            height: rect.height * unitToMeters,
            rotation: rect.localRotation,
        };

        CUSTOM_ITEM_PART_VERBATIM_FIELDS.forEach(field => {
            if (item[field] !== undefined && item[field] !== null) {
                /* Deep-clone objects so canvas edits don't mutate IDB record. */
                if (typeof item[field] === 'object') {
                    try { part[field] = JSON.parse(JSON.stringify(item[field])); }
                    catch (e) { part[field] = item[field]; }
                } else {
                    part[field] = item[field];
                }
            }
        });

        CUSTOM_ITEM_UNIT_SCALED_PART_FIELDS.forEach(field => {
            const v = item[field];
            if (typeof v === 'number') part[field] = v * unitToMeters;
        });

        /* cornerRadius is number or 4-element array (Konva per-corner). */
        if (typeof item.cornerRadius === 'number') {
            part.cornerRadius = item.cornerRadius * unitToMeters;
        } else if (Array.isArray(item.cornerRadius)) {
            part.cornerRadius = item.cornerRadius.map(v => (typeof v === 'number' ? v * unitToMeters : v));
        }

        /* `points` is flat [x0, y0, x1, y1, ...] — uniformly scale. */
        if (Array.isArray(item.points)) {
            part.points = item.points.map(v => (typeof v === 'number' ? v * unitToMeters : v));
        }

        parts.push(part);
    });

    if (!parts.length) return null;

    /* `version` is a string (forward-compat); UI writes "1" currently. */
    return {
        customItemBaseId: customItem.customItemBaseId,
        customItemName: String(customItem.name || ''),
        author: String(customItem.author || ''),
        description: String(customItem.description || ''),
        version: String(customItem.version || '1'),
        width: (Number(customItem.width) || 0) * unitToMeters,
        height: (Number(customItem.height) || 0) * unitToMeters,
        customItemParts: parts,
        menuImage: '', /* populated by createCustomItemMenuImage() */
    };
}

/* Render a 100×100 PNG thumbnail in normalized pose (rotation=0, UL origin).
 * Parts fit in a centered 90×90 box. Returns Promise<dataURL|''>. */
function createCustomItemMenuImage(record) {
    const FULL = 100;          /* total thumbnail size, px */
    const INNER = 90;          /* drawable region inside the padding, px */

    if (!record || !Array.isArray(record.customItemParts) || !record.customItemParts.length) {
        return Promise.resolve('');
    }

    /* Per-part anchor: tables/stageFloors/boxes/rooms use UL; everything
     * else uses CENTER (offsetX=w/2 idiom). pathShape is in 'tables' but
     * (x,y) is the path's local origin. getPartRenderRect() preserves
     * the source convention, so branch per-device when placing nodes. */
    function partAnchorIsUL(part) {
        const dt = (typeof allDeviceTypes !== 'undefined' && allDeviceTypes)
            ? allDeviceTypes[part.data_deviceid] : null;
        if (!dt) return false;
        const pg = dt.parentGroup;
        return pg === 'tables' || pg === 'stageFloors' || pg === 'boxes' || pg === 'rooms';
    }

    /* Off-DOM Konva stage; unique id per call avoids concurrent collisions. */
    const divContainerId = 'containerCustomItemMenuImageCreate-' + createUuid();
    const existing = document.getElementById(divContainerId);
    if (existing) existing.remove();
    const container = document.createElement('div');
    container.id = divContainerId;
    container.style.display = 'none';
    document.body.appendChild(container);

    let stage, layer;
    try {
        stage = new Konva.Stage({ container: divContainerId, width: FULL, height: FULL });
        layer = new Konva.Layer();
        stage.add(layer);
    } catch (e) {
        console.warn('[customItemLibrary] menuImage stage create failed:', e && e.message);
        if (container.parentNode) container.parentNode.removeChild(container);
        return Promise.resolve('');
    }

    /* pathShape stores its presentation (path data, scale, fill, opacity)
     * inside data_labelField as a JSON object. The canvas renderer at
     * insertDevice.id === 'pathShape' applies the same parsing — we
     * mirror it here so the thumbnail matches what the user sees. Regex
     * (not JSON.parse) is used because the labelField historically also
     * carries free-text comments alongside the JSON object. */
    function parsePathShapeLabel(labelField) {
        const out = { path: 'M-0.5-0.5 h1.2 l0.1 1 l-0.5 -0.4 L-0.5 0.5z',
                      scaleX: 1, scaleY: 1, fill: '#D3D3D3', opacity: 0.4 };
        if (typeof labelField !== 'string') return out;
        const pm = labelField.match(/"path"\s*:\s*"\s*([Mm][^"]*)"/);
        if (pm && pm[1]) out.path = pm[1];
        const sm = labelField.match(/"scale"\s*:\s*\[\s*([\-0-9.]+)\s*,\s*[\-0-9.]+\s*,\s*([\-0-9.]+)\s*\]/);
        if (sm) { out.scaleX = Number(sm[1]) || 1; out.scaleY = Number(sm[2]) || 1; }
        const cm = labelField.match(/"color"\s*:\s*"([^"]+)"/);
        if (cm && cm[1]) out.fill = cm[1];
        const om = labelField.match(/"opacity"\s*:\s*"?([\d.]+)"?/);
        if (om) out.opacity = parseFloat(om[1]);
        return out;
    }

    /* Build the Konva node for one part at METER scale (i.e. no
     * thumbnail-fit scaling yet). Position is in part-frame METERS, so
     * we can read layer.getClientRect() afterwards to compute the union
     * bbox in the same units. The fit-to-INNER scale + center
     * translation is then applied to the whole LAYER below, which keeps
     * per-part math simple and unaffected by stacking order or
     * rotation interactions. Resolves once the node is fully rendered:
     * for Konva.Image that means the underlying Image() has loaded (so
     * toDataURL captures pixels, not an empty bitmap); for Rect/Path
     * it's synchronous so resolves immediately. */
    function addPartNodeAtMeterScale(part) {
        return new Promise(function (resolveOne) {
            const dt = (typeof allDeviceTypes !== 'undefined' && allDeviceTypes)
                ? allDeviceTypes[part.data_deviceid] : null;
            const cx = Number(part.x) || 0;
            const cy = Number(part.y) || 0;
            const rotation = Number(part.rotation) || 0;
            const w = Number(part.width)  || 0;
            const h = Number(part.height) || 0;

            /* pathShape — Konva.Path. (x, y) is where path-(0,0) lands;
             * rotation pivots around that point (Konva default offset).
             * Scale from labelField JSON "scale". strokeScaleEnabled:false
             * keeps stroke at fixed pixel width despite layer.scale(). */
            if (part.data_deviceid === 'pathShape') {
                const lf = parsePathShapeLabel(part.data_labelField);
                /* Precedence: Details picker > label-JSON > device default. */
                const pathFill = part.data_fill || lf.fill;
                const pathOpacity = (part.data_opacity != null)
                    ? Number(part.data_opacity)
                    : (typeof lf.opacity === 'number' ? lf.opacity : 0.4);
                layer.add(new Konva.Path({
                    x: cx, y: cy,
                    data: lf.path,
                    fill: pathFill,
                    stroke: (dt && dt.stroke) || 'black',
                    strokeWidth: 1,
                    strokeScaleEnabled: false,
                    opacity: pathOpacity,
                    scale: { x: lf.scaleX, y: lf.scaleY },
                    rotation: rotation,
                }));
                resolveOne();
                return;
            }

            const isUl = partAnchorIsUL(part);
            /* Style mapping replicates the canvas insertItem() branch per device-id
             * so the thumbnail matches what the user dragged onto the canvas. */
            let nodeAttrs = {
                x: cx, y: cy,
                width: w, height: h,
                rotation: rotation,
                offsetX: isUl ? 0 : w / 2,
                offsetY: isUl ? 0 : h / 2,
            };

            if (part.data_deviceid === 'box' ||
                part.data_deviceid === 'carpet' ||
                part.data_deviceid === 'stageFloor') {
                nodeAttrs.fill = part.data_fill || '#FFFFFF99';
                if (part.data_opacity != null) {
                    nodeAttrs.opacity = Number(part.data_opacity);
                }
                nodeAttrs.stroke = (dt && dt.stroke) || 'black';
                nodeAttrs.strokeWidth = 1;
                nodeAttrs.strokeScaleEnabled = false; /* see pathShape */
                if (dt && Array.isArray(dt.dash)) {
                    nodeAttrs.dash = dt.dash.slice();
                }
                if (typeof part.cornerRadius === 'number') {
                    nodeAttrs.cornerRadius = part.cornerRadius;
                } else if (Array.isArray(part.cornerRadius)) {
                    nodeAttrs.cornerRadius = part.cornerRadius;
                }
                layer.add(new Konva.Rect(nodeAttrs));
                resolveOne();
                return;
            }

            if (dt && dt.topImage) {
                /* Create Image node FIRST so it participates in getClientRect();
                 * bitmap attaches later inside onload. */
                const imageNode = new Konva.Image(Object.assign({ image: null }, nodeAttrs));
                layer.add(imageNode);
                const imgObj = new Image();
                imgObj.onload = function () {
                    imageNode.image(imgObj);
                    layer.batchDraw();
                    resolveOne();
                };
                imgObj.onerror = function () {
                    /* Asset missing — leave empty outline so thumbnail still completes. */
                    imageNode.stroke('#888888');
                    imageNode.strokeWidth(1);
                    imageNode.strokeScaleEnabled(false);
                    imageNode.fill('#dddddd');
                    layer.batchDraw();
                    resolveOne();
                };
                imgObj.src = './assets/images/' + dt.topImage;
                return;
            }

            /* Fallback: rect with best-effort fill (honors data_fill/data_opacity). */
            nodeAttrs.fill = part.data_fill || '#cccccc';
            if (part.data_opacity != null) {
                nodeAttrs.opacity = Number(part.data_opacity);
            }
            nodeAttrs.stroke = (dt && dt.stroke) || '#666666';
            nodeAttrs.strokeWidth = 1;
            nodeAttrs.strokeScaleEnabled = false;
            layer.add(new Konva.Rect(nodeAttrs));
            resolveOne();
        });
    }

    /* Sort parts to match drawRoom()'s z-stacking (rooms → boxes →
     * touchPanels → speakers → displays → stageFloors → tables → chairs
     * → microphones → videoDevices). Reads from `allNodeShapeGroups` so
     * any future canvas reorder stays in lockstep. Unknown parentGroups
     * sort to the end so they paint on top and remain visible. */
    const groupZOrder = (typeof allNodeShapeGroups !== 'undefined' && Array.isArray(allNodeShapeGroups))
        ? allNodeShapeGroups.map(g => g.name())
        : [];
    function partZIndex(part) {
        const dt = (typeof allDeviceTypes !== 'undefined' && allDeviceTypes)
            ? allDeviceTypes[part.data_deviceid] : null;
        if (!dt || !dt.parentGroup) return groupZOrder.length;
        const idx = groupZOrder.indexOf(dt.parentGroup);
        return idx >= 0 ? idx : groupZOrder.length;
    }
    const orderedParts = record.customItemParts
        .map((part, originalIdx) => ({ part: part, idx: originalIdx, z: partZIndex(part) }))
        .sort((a, b) => (a.z - b.z) || (a.idx - b.idx))
        .map(entry => entry.part);

    /* Pass 1: synchronously create every node at meter scale (image loads continue in background). */
    const partPromises = orderedParts.map(addPartNodeAtMeterScale);

    /* Pass 2: measure layer bbox in meters and apply layer-wide fit-and-center transform.
     * skipStroke:true so placeholder strokeWidth doesn't poison the bbox. */
    let bbox = layer.getClientRect({ skipTransform: false, skipStroke: true });
    if (!bbox || !isFinite(bbox.width) || !isFinite(bbox.height) ||
        bbox.width <= 0 || bbox.height <= 0) {
        bbox = { x: 0, y: 0,
                 width: Number(record.width)  || 1,
                 height: Number(record.height) || 1 };
    }
    const scaleFactor = INNER / Math.max(bbox.width, bbox.height);
    const drawW = bbox.width  * scaleFactor;
    const drawH = bbox.height * scaleFactor;
    const offsetX = (FULL - drawW) / 2;
    const offsetY = (FULL - drawH) / 2;
    layer.scale({ x: scaleFactor, y: scaleFactor });
    layer.position({
        x: offsetX - bbox.x * scaleFactor,
        y: offsetY - bbox.y * scaleFactor,
    });

    return Promise.all(partPromises).then(function () {
        layer.draw();
        /* PNG (alpha) + pixelRatio:1 (avoid devicePixelRatio inflation on Retina). */
        let dataUrl;
        try {
            dataUrl = stage.toDataURL({ mimeType: 'image/png', pixelRatio: 1 });
        } catch (e) {
            console.warn('[customItemLibrary] toDataURL failed:', e && e.message);
            dataUrl = '';
        }
        try { stage.destroy(); } catch (_) { /* best-effort */ }
        if (container.parentNode) container.parentNode.removeChild(container);
        return dataUrl;
    }).catch(function (e) {
        console.warn('[customItemLibrary] menuImage render failed:', e && e.message);
        try { stage.destroy(); } catch (_) { /* best-effort */ }
        if (container.parentNode) container.parentNode.removeChild(container);
        return '';
    });
}

/* Build + persist customItem to IDB Library. Resolves to baseId or null. */
function persistCustomItemToLibrary(customItem) {
    if (!customItem || !customItem.customItemBaseId) return Promise.resolve(null);
    if (!window.idbStore || typeof window.idbStore.customItemPut !== 'function') {
        return Promise.resolve(null);
    }

    /* Unnamed customItems are CANVAS-ONLY (skip persist silently). */
    const cleanName = (customItem.name == null) ? '' : String(customItem.name).trim();
    if (!cleanName) return Promise.resolve(null);

    const record = buildCustomItemExportRecord(customItem);
    if (!record) return Promise.resolve(null);

    return createCustomItemMenuImage(record).then(function (dataUrl) {
        record.menuImage = dataUrl || '';
        return window.idbStore.customItemPut(record);
    }).then(function (savedBaseId) {
        if (savedBaseId) {
            markCustomItemInLibrary(savedBaseId);
            return savedBaseId;
        }
        return null;
    }).catch(function (e) {
        console.warn('[customItemLibrary] persistCustomItemToLibrary failed:', e && e.message);
        return null;
    });
}

/* Quick Add palette library cache. Loaded on dialog open, cleared on close. */
let _customItemQuickAddRecordsCache = [];
let _customItemQuickAddRecordsLoading = null; /* in-flight fetch Promise */

function loadCustomItemLibraryRecordsForQuickAdd() {
    if (_customItemQuickAddRecordsLoading) return _customItemQuickAddRecordsLoading;
    if (!window.idbStore || typeof window.idbStore.customItemGetAll !== 'function') {
        _customItemQuickAddRecordsCache = [];
        return Promise.resolve([]);
    }
    _customItemQuickAddRecordsLoading = window.idbStore.customItemGetAll()
        .then(function (records) {
            _customItemQuickAddRecordsCache = Array.isArray(records) ? records : [];
            _customItemQuickAddRecordsLoading = null;
            return _customItemQuickAddRecordsCache;
        })
        .catch(function (e) {
            console.warn('[customItemLibrary] Quick Add fetch failed:', e && e.message);
            _customItemQuickAddRecordsCache = [];
            _customItemQuickAddRecordsLoading = null;
            return [];
        });
    return _customItemQuickAddRecordsLoading;
}

/* Per-baseId debounce timers for maybeAutoSaveCustomItemEdit.
 * 750ms coalesces drag-frame storms into one IDB upsert. */
const _customItemAutoSaveTimers = new Map();
const _CUSTOM_ITEM_AUTO_SAVE_DEBOUNCE_MS = 750;

/* Debounced auto-save. Only fires for templates already in the library. */
function maybeAutoSaveCustomItemEdit(customItem) {
    if (!customItem || !customItem.customItemBaseId) return;
    if (!isCustomItemInLibrary(customItem.customItemBaseId)) return;

    const baseId = customItem.customItemBaseId;
    const customitemid = customItem.customitemid;

    const existing = _customItemAutoSaveTimers.get(baseId);
    if (existing) clearTimeout(existing);

    const timer = setTimeout(function () {
        _customItemAutoSaveTimers.delete(baseId);
        /* Re-resolve by id — may have been ungrouped/deleted mid-debounce. */
        const current = (typeof getCustomItemById === 'function')
            ? getCustomItemById(customitemid)
            : null;
        if (!current) return;
        if (!isCustomItemInLibrary(current.customItemBaseId)) return;
        persistCustomItemToLibrary(current).then(function (saved) {
            if (saved) console.info('[customItemLibrary] auto-saved edit to', saved);
        });
    }, _CUSTOM_ITEM_AUTO_SAVE_DEBOUNCE_MS);

    _customItemAutoSaveTimers.set(baseId, timer);
}

/* Explicit "Add to Library" opt-in; upserts by baseId. */
function addCustomItemToLibrary(customItem) {
    if (!customItem) return;
    persistCustomItemToLibrary(customItem).then(function (savedBaseId) {
        if (savedBaseId) showToast('Custom Item saved to library');
    });
}

/* Explicit "Remove from Library" — deletes IDB record only; canvas untouched. */
function removeCustomItemFromLibrary(customItem) {
    if (!customItem || !customItem.customItemBaseId) return;
    if (!window.idbStore || typeof window.idbStore.customItemDelete !== 'function') return;
    const baseId = customItem.customItemBaseId;
    window.idbStore.customItemDelete(baseId).then(function (ok) {
        if (ok) {
            unmarkCustomItemInLibrary(baseId);
            showToast('Custom Item removed from library');
        }
    });
}

/* "Delete Custom Item" confirmation modal from the Quick Add tile trash button.
 * Deletes IDB record + syncs caches; canvas instances are left in place. */
function openDeleteCustomItemFromLibraryDialog(baseId, name) {
    if (!baseId) return;
    const dialog = document.getElementById('dialogCustomItemDelete');
    if (!dialog) return;

    const displayName = (name && String(name).trim().length) ? String(name).trim() : '(unnamed)';
    const safeName = (typeof DOMPurify !== 'undefined') ? DOMPurify.sanitize(displayName) : displayName;
    let html = `<div>Delete <b>"${safeName}"</b> from your local Custom Item Library?</div>`;
    html += `<div style="margin-top: 8px; color: #555;">This only removes the saved template. Existing instances of this Custom Item already on the room canvas are unaffected.</div>`;

    const main = document.getElementById('dialogCustomItemDeleteMain');
    if (main) main.innerHTML = html;

    const btn = document.getElementById('dialogCustomItemDeleteConfirmBtn');
    if (btn) {
        btn.onclick = function () {
            dialog.close();
            if (!window.idbStore || typeof window.idbStore.customItemDelete !== 'function') {
                showToast('Library unavailable — delete failed');
                return;
            }
            window.idbStore.customItemDelete(baseId).then(function (ok) {
                if (!ok) {
                    showToast('Delete failed for "' + displayName + '"');
                    return;
                }
                unmarkCustomItemInLibrary(baseId);
                _customItemQuickAddRecordsCache = (_customItemQuickAddRecordsCache || [])
                    .filter(r => r && r.customItemBaseId !== baseId);
                showToast('Deleted "' + displayName + '" from library');
                const input = document.querySelector('.quick-dialog input');
                if (input) onQuickAddChange({ target: input });
            });
        };
    }
    dialog.showModal();
}

/* Edit Custom Item dialog (Quick Add ellipsis). Cascades Name/Author/Description
 * to every canvas instance with matching baseId on save. */
let _customItemEditDialogBaseId = null;

function openEditCustomItemDialog(baseId) {
    if (!baseId) return;
    const dialog = document.getElementById('dialogCustomItemEdit');
    const nameInput = document.getElementById('customItemEditNameInput');
    if (!dialog || !nameInput) {
        /* Older HTML: fall back to delete dialog. */
        const cached = (_customItemQuickAddRecordsCache || [])
            .find(r => r && r.customItemBaseId === baseId);
        const fallbackName = getCustomItemRecordName(cached);
        openDeleteCustomItemFromLibraryDialog(baseId, fallbackName);
        return;
    }

    /* Prefer Quick Add cache; fall through to IDB read defensively. */
    const cached = (_customItemQuickAddRecordsCache || [])
        .find(r => r && r.customItemBaseId === baseId);

    const fillFromRecord = (rec) => {
        _customItemEditDialogBaseId = baseId;
        nameInput.value = getCustomItemRecordName(rec);
        const authorInput = document.getElementById('customItemEditAuthorInput');
        const descInput = document.getElementById('customItemEditDescriptionInput');
        if (authorInput) authorInput.value = rec ? String(rec.author || '') : '';
        if (descInput) descInput.value = rec ? String(rec.description || '') : '';

        /* Rewire action buttons each open so captured baseId tracks the clicked tile. */
        const exportBtn = document.getElementById('customItemEditExportBtn');
        const removeBtn = document.getElementById('customItemEditRemoveBtn');
        const deleteBtn = document.getElementById('customItemEditDeleteBtn');
        const displayNameRaw = getCustomItemRecordName(rec).trim();
        const displayName = displayNameRaw || '(unnamed)';

        if (exportBtn) {
            exportBtn.onclick = function () {
                exportCustomItemRecordFromLibrary(baseId);
            };
        }
        /* Delete and Remove-From-Library both route through the same confirmation. */
        const destructive = function () {
            dialog.close();
            openDeleteCustomItemFromLibraryDialog(baseId, displayName);
        };
        if (removeBtn) removeBtn.onclick = destructive;
        if (deleteBtn) deleteBtn.onclick = destructive;

        dialog.showModal();
        setTimeout(() => { nameInput.focus(); nameInput.select(); }, 0);
    };

    if (cached) {
        fillFromRecord(cached);
        return;
    }
    if (window.idbStore && typeof window.idbStore.customItemGet === 'function') {
        window.idbStore.customItemGet(baseId).then(fillFromRecord);
    } else {
        fillFromRecord(null);
    }
}

/* Save handler — descriptive metadata only; geometry/parts/menuImage preserved verbatim. */
function confirmEditCustomItemFromDialog() {
    const baseId = _customItemEditDialogBaseId;
    if (!baseId) return;

    const nameInput = document.getElementById('customItemEditNameInput');
    if (!nameInput) return;

    const cleanField = (val) => {
        const trimmed = (val || '').trim();
        if (!trimmed) return '';
        return (typeof DOMPurify !== 'undefined' && DOMPurify && typeof DOMPurify.sanitize === 'function')
            ? (DOMPurify.sanitize(trimmed) || '').trim()
            : trimmed;
    };

    const newName = cleanField(nameInput.value);
    if (!newName) {
        alertDialog('Custom Item Name Required',
            'Please enter a name for the Custom Item.');
        return;
    }
    const newAuthor = cleanField((document.getElementById('customItemEditAuthorInput') || {}).value);
    const newDesc = cleanField((document.getElementById('customItemEditDescriptionInput') || {}).value);

    if (!window.idbStore || typeof window.idbStore.customItemGet !== 'function' ||
        typeof window.idbStore.customItemPut !== 'function') {
        showToast('Library unavailable — save failed');
        return;
    }

    window.idbStore.customItemGet(baseId).then(function (rec) {
        if (!rec) {
            showToast('Custom Item no longer in library');
            const dlg = document.getElementById('dialogCustomItemEdit');
            if (dlg) dlg.close();
            return null;
        }
        /* Merge edits into the existing record. menuImage,
         * customItemParts, width, height, customItemBaseId, and addedAt
         * are all preserved verbatim by the customItemPut path (which
         * reads them off `record` and passes them through). Writes the
         * new canonical name key + drops the legacy `data_labelField`
         * so the next customItemPut atomically migrates the row. */
        rec.customItemName = newName;
        if ('data_labelField' in rec) delete rec.data_labelField;
        rec.author = newAuthor;
        rec.description = newDesc;
        if (!rec.version) rec.version = '1';
        return window.idbStore.customItemPut(rec).then(function (savedBaseId) {
            if (!savedBaseId) {
                showToast('Save failed');
                return null;
            }
            /* Cascade to any live canvas instance(s) of this template
             * so the Details panel and the customItem rect label
             * reflect the new name immediately. The strict-family
             * model says all instances share metadata derived from
             * the library — see CLAUDE.md "Strict-family model". */
            if (Array.isArray(roomObj.customItems)) {
                roomObj.customItems.forEach(ci => {
                    if (!ci || ci.customItemBaseId !== baseId) return;
                    ci.name = newName;
                    ci.author = newAuthor;
                    ci.description = newDesc;
                    if (!ci.version) ci.version = rec.version || '1';
                    /* Mirror name onto the rect's data_labelField so
                     * the canvas label and Details-panel "Custom Item
                     * Name" both pick it up on next refresh. */
                    if (typeof groupCustomItemRects !== 'undefined' && groupCustomItemRects) {
                        const rectNode = groupCustomItemRects
                            .find(n => n.data_customItemId === ci.customitemid)[0];
                        if (rectNode) rectNode.data_labelField = newName;
                    }
                });
            }

            /* Refresh the Quick Add cache so the tile label / search
             * match the new name on the next keystroke without a
             * round-trip. The cache is the source of truth for the
             * palette renderer while the dialog is open. */
            if (Array.isArray(_customItemQuickAddRecordsCache)) {
                const idx = _customItemQuickAddRecordsCache.findIndex(
                    r => r && r.customItemBaseId === baseId);
                if (idx >= 0) {
                    const merged = Object.assign(
                        {}, _customItemQuickAddRecordsCache[idx], {
                            customItemName: newName,
                            author: newAuthor,
                            description: newDesc,
                            version: rec.version || '1',
                        });
                    /* Drop the legacy key from the cache entry so
                     * helper-based reads always land on the new key
                     * and the migrated shape is what the palette sees
                     * on the next keystroke (no Object.assign carry-over). */
                    if ('data_labelField' in merged) delete merged.data_labelField;
                    _customItemQuickAddRecordsCache[idx] = merged;
                }
            }

            showToast('Custom Item updated');
            const dlg = document.getElementById('dialogCustomItemEdit');
            if (dlg) dlg.close();
            const input = document.querySelector('.quick-dialog input');
            if (input) onQuickAddChange({ target: input });

            /* Persist roomObj so the rename survives undo history /
             * page refresh from a saved URL. canvasToJson() walks
             * tr.nodes() and merges into roomObj — the customItems
             * array we just mutated is untouched by that walker, so
             * the rename is preserved as long as canvasToJson runs
             * after our mutation. */
            if (typeof canvasToJson === 'function') canvasToJson();
            return savedBaseId;
        });
    }).catch(function (e) {
        console.warn('[customItemLibrary] save edit failed:', e && e.message);
        showToast('Save failed');
    });
}

/* ============================================================================
 * Storage and Local Data dialog
 *
 * Opened from Details -> Settings -> "Storage and Local Data..." button.
 * Shows per-bucket counts plus a navigator.storage.estimate() total when
 * available, and offers two destructive actions:
 *
 *   - Clear Undo/Redo History (recommended) - safe; addresses "many tabs
 *     sluggish" complaints. Clears IDB undo/redo stores and resets in-memory
 *     undoArray/redoArray. No page reload.
 *
 *   - Clear All - wipes every IDB store this app manages (undo, redo,
 *     Custom Item Library, Background Image Library) plus localStorage
 *     (snap settings, default unit, wd overrides, copyItemsObj, etc.).
 *     Reloads the page so every in-memory cache (customItemLibraryIds,
 *     undoArray, etc.) restarts from a clean slate.
 *
 * Both buttons are no-ops with a tooltip when idbStore.isAvailable() is
 * false (Safari private mode quirks etc.); see "fallbacks" below.
 *
 * Numbers are point-in-time (fetched on dialog open). The Clear Undo/Redo
 * path refreshes them after running so the user sees the bucket drop to 0.
 * ============================================================================ */

/* Format a byte count as a human-friendly string (MB to one decimal,
 * or GB once we cross ~1 GB). Used for the navigator.storage.estimate()
 * total + quota lines. */
function _formatStorageBytes(bytes) {
    if (bytes == null || !isFinite(bytes) || bytes < 0) return '—';
    const KB = 1024;
    const MB = KB * 1024;
    const GB = MB * 1024;
    if (bytes >= GB) return (bytes / GB).toFixed(2) + ' GB';
    if (bytes >= MB) return (bytes / MB).toFixed(1) + ' MB';
    if (bytes >= KB) return (bytes / KB).toFixed(0) + ' KB';
    return String(bytes) + ' B';
}

/* Format "N / cap" for the per-bucket rows. If cap is null/undefined,
 * just shows the count. */
function _formatStorageCount(count, cap) {
    if (typeof count !== 'number' || !isFinite(count)) return '—';
    if (typeof cap === 'number' && isFinite(cap) && cap > 0) {
        return String(count) + ' / ' + String(cap);
    }
    return String(count);
}

/* Refresh the per-bucket count cells and the total/IDB lines. Called on
 * dialog open AND after a Clear Undo/Redo so the table updates without
 * closing the dialog. */
function _refreshStorageDialogCounts() {
    const totalLineEl = document.getElementById('storageDialogTotalLine');
    const idbLineEl = document.getElementById('storageDialogIdbLine');
    const undoCellEl = document.getElementById('storageCountUndo');
    const redoCellEl = document.getElementById('storageCountRedo');
    const customCellEl = document.getElementById('storageCountCustomItems');
    const bgCellEl = document.getElementById('storageCountBgImages');

    const idbAvailable = !!(window.idbStore && typeof window.idbStore.isAvailable === 'function' && window.idbStore.isAvailable());

    if (idbLineEl) {
        idbLineEl.textContent = idbAvailable
            ? 'IndexedDB: available'
            : 'IndexedDB: unavailable (undo/redo and library features disabled)';
    }

    /* Per-bucket caps — pulled from idbStore._constants when exposed,
     * otherwise hardcoded fallbacks that match the values in
     * js/idbStorage.js. */
    let caps = { undo: 100, redo: 100, customItems: 200, bgImages: 10 };
    if (window.idbStore && window.idbStore._constants) {
        const c = window.idbStore._constants;
        caps.undo = c.MAX_UNDO_ENTRIES || caps.undo;
        caps.redo = c.MAX_REDO_ENTRIES || caps.redo;
        caps.customItems = c.MAX_CUSTOM_ITEMS || caps.customItems;
        caps.bgImages = c.MAX_BG_IMAGES || caps.bgImages;
    }

    /* When IDB is unavailable every count is "—". Skip the IDB calls
     * entirely so we don't show "0 / 100" which would be misleading. */
    if (!idbAvailable) {
        if (undoCellEl) undoCellEl.textContent = '—';
        if (redoCellEl) redoCellEl.textContent = '—';
        if (customCellEl) customCellEl.textContent = '—';
        if (bgCellEl) bgCellEl.textContent = '—';
        if (totalLineEl) totalLineEl.textContent = 'Storage usage unavailable in this browser.';
        return;
    }

    /* Pull all four counts in parallel. Each helper resolves to 0 on
     * failure so the table never blocks on an error. */
    const idb = window.idbStore;
    Promise.all([
        (typeof idb.undoCount === 'function') ? idb.undoCount() : Promise.resolve(null),
        (typeof idb.redoCount === 'function') ? idb.redoCount() : Promise.resolve(null),
        (typeof idb.customItemCount === 'function') ? idb.customItemCount() : Promise.resolve(null),
        (typeof idb.bgImagesCount === 'function') ? idb.bgImagesCount() : Promise.resolve(null)
    ]).then(function (counts) {
        if (undoCellEl) undoCellEl.textContent = _formatStorageCount(counts[0], caps.undo);
        if (redoCellEl) redoCellEl.textContent = _formatStorageCount(counts[1], caps.redo);
        if (customCellEl) customCellEl.textContent = _formatStorageCount(counts[2], caps.customItems);
        if (bgCellEl) bgCellEl.textContent = _formatStorageCount(counts[3], caps.bgImages);
    }).catch(function (e) {
        console.warn('[storageDialog] count refresh failed:', e && e.message);
    });

    /* navigator.storage.estimate() is broadly supported (Chrome / Edge /
     * Firefox / Safari 15.4+) but we feature-detect anyway and fall back
     * to a generic message on older browsers. The total is per-origin so
     * it includes ANY other apps hosted at the same origin (see the
     * footnote in the modal text). */
    if (totalLineEl) {
        if (navigator && navigator.storage && typeof navigator.storage.estimate === 'function') {
            totalLineEl.textContent = 'Calculating storage usage...';
            navigator.storage.estimate().then(function (est) {
                const usage = (est && typeof est.usage === 'number') ? est.usage : null;
                const quota = (est && typeof est.quota === 'number') ? est.quota : null;
                if (usage != null && quota != null) {
                    totalLineEl.textContent = 'Browser storage used: ' + _formatStorageBytes(usage)
                        + ' (of ' + _formatStorageBytes(quota) + ' available)';
                } else if (usage != null) {
                    totalLineEl.textContent = 'Browser storage used: ' + _formatStorageBytes(usage);
                } else {
                    totalLineEl.textContent = 'Browser storage usage not reported by this browser.';
                }
            }).catch(function () {
                totalLineEl.textContent = 'Browser storage usage not reported by this browser.';
            });
        } else {
            totalLineEl.textContent = 'Browser storage usage not reported by this browser.';
        }
    }
}

/* Open the Storage and Local Data dialog. Refreshes the count table,
 * resets the inline-confirm row, and disables the action buttons when
 * IDB is unavailable. */
function openStorageDialog() {
    const dialog = document.getElementById('dialogStorage');
    if (!dialog) return;

    /* Always start with the inline confirm row hidden — a previous open
     * may have left it visible if the user closed the dialog mid-confirm. */
    const inlineConfirm = document.getElementById('storageInlineConfirmUndo');
    if (inlineConfirm) inlineConfirm.style.display = 'none';

    /* Toggle disabled state of action buttons based on IDB availability.
     * When IDB is down both clears are no-ops, so we grey them out and
     * surface the reason via the title tooltip. */
    const idbAvailable = !!(window.idbStore && typeof window.idbStore.isAvailable === 'function' && window.idbStore.isAvailable());
    const btnUndoRedo = document.getElementById('btnClearUndoRedoStorage');
    const btnAll = document.getElementById('btnClearAllStorage');
    if (btnUndoRedo) {
        btnUndoRedo.disabled = !idbAvailable;
        btnUndoRedo.title = idbAvailable ? '' : 'IndexedDB unavailable in this browser';
    }
    if (btnAll) {
        /* Clear All also wipes localStorage which is independent of IDB,
         * so we keep it enabled even when IDB is down — clearing prefs
         * may still help troubleshooting. */
        btnAll.title = idbAvailable ? '' : 'IndexedDB unavailable — only preferences will be cleared';
    }

    _refreshStorageDialogCounts();
    dialog.showModal();
}

/* "Clear Undo/Redo History (recommended)" button handler. Shows the
 * inline confirm row inside the same dialog (one fewer modal step than
 * a full nested dialog). The actual clear runs from
 * confirmClearUndoRedoInline(). */
function onClearUndoRedoClicked() {
    const idbAvailable = !!(window.idbStore && typeof window.idbStore.isAvailable === 'function' && window.idbStore.isAvailable());
    if (!idbAvailable) {
        showToast('IndexedDB unavailable — nothing to clear');
        return;
    }
    const inlineConfirm = document.getElementById('storageInlineConfirmUndo');
    if (inlineConfirm) inlineConfirm.style.display = '';
}

function cancelClearUndoRedoInline() {
    const inlineConfirm = document.getElementById('storageInlineConfirmUndo');
    if (inlineConfirm) inlineConfirm.style.display = 'none';
}

/* Actually clear undo/redo. Wipes both IDB stores, resets the in-memory
 * arrays, and re-syncs the toolbar undo/redo button states. No reload —
 * the user keeps their current canvas. */
function confirmClearUndoRedoInline() {
    const inlineConfirm = document.getElementById('storageInlineConfirmUndo');
    if (inlineConfirm) inlineConfirm.style.display = 'none';

    if (!window.idbStore || typeof window.idbStore.clearAllUndoRedo !== 'function') {
        showToast('IndexedDB unavailable — clear failed');
        return;
    }

    window.idbStore.clearAllUndoRedo().then(function () {
        /* Reset in-memory mirrors. saveToUndoArray() handles the
         * "length === 0" case (treats last item as empty string), so
         * the next real edit will push the current roomObj as the new
         * baseline. enableBtnUndoRedo() greys out the toolbar buttons
         * immediately because both arrays are now empty. */
        undoArray = [];
        redoArray = [];
        if (typeof enableBtnUndoRedo === 'function') enableBtnUndoRedo();

        _refreshStorageDialogCounts();
        showToast('Cleared undo and redo history');
    }).catch(function (e) {
        console.warn('[storageDialog] clear undo/redo failed:', e && e.message);
        showToast('Clear failed — see console');
    });
}

/* "Clear All" button handler. Opens the separate confirmation dialog
 * because the action is irreversible and reloads the page; an inline
 * confirm row would be too easy to brush past. */
function onClearAllClicked() {
    const dialogConfirm = document.getElementById('dialogStorageClearAllConfirm');
    const main = document.getElementById('dialogStorageClearAllMain');
    if (!dialogConfirm || !main) return;

    /* Fetch fresh counts so the warning text shows the user exactly
     * what they're about to lose. Resolves to 0 on any failure. */
    const idb = window.idbStore || {};
    const customCountP = (typeof idb.customItemCount === 'function') ? idb.customItemCount() : Promise.resolve(0);
    const bgCountP = (typeof idb.bgImagesCount === 'function') ? idb.bgImagesCount() : Promise.resolve(0);

    Promise.all([customCountP, bgCountP]).then(function (counts) {
        const customCount = counts[0] || 0;
        const bgCount = counts[1] || 0;
        /* Build the warning as DOM nodes (not innerHTML) — counts are
         * numbers and the strings are static, but keep the safe pattern
         * anyway so future edits can't accidentally introduce an XSS. */
        main.textContent = '';

        const intro = document.createElement('div');
        intro.style.marginBottom = '8px';
        intro.textContent = 'This will permanently delete:';
        main.appendChild(intro);

        const ul = document.createElement('ul');
        ul.style.margin = '0 0 12px 18px';
        ul.style.padding = '0';
        const items = [
            'All undo and redo history',
            'Your Custom Item Library (' + customCount + ' template' + (customCount === 1 ? '' : 's') + ')',
            'Your Background Image Library (' + bgCount + ' image' + (bgCount === 1 ? '' : 's') + ')',
            'All saved preferences (snap settings, default unit, Workspace Designer site, etc.)'
        ];
        items.forEach(function (label) {
            const li = document.createElement('li');
            li.textContent = label;
            ul.appendChild(li);
        });
        main.appendChild(ul);

        const note = document.createElement('div');
        note.style.marginBottom = '8px';
        note.textContent = 'Your current room is not affected, but if it uses a background image from the library, the image will be removed on reload.';
        main.appendChild(note);

        const reloadNote = document.createElement('div');
        reloadNote.style.fontWeight = '600';
        reloadNote.textContent = 'The page will reload.';
        main.appendChild(reloadNote);

        dialogConfirm.showModal();
    }).catch(function (e) {
        console.warn('[storageDialog] count fetch for Clear All failed:', e && e.message);
        /* Fall back to a generic warning if the count fetch failed. */
        main.textContent = 'This will permanently delete all local data (undo/redo history, libraries, and preferences) and reload the page. Your current room is not affected.';
        dialogConfirm.showModal();
    });
}

/* Confirm button on the Clear All dialog. Wipes IDB + localStorage, then
 * reloads. The reload is essential because in-memory caches
 * (customItemLibraryIds, undoArray, redoArray, _customItemQuickAddRecordsCache,
 * the rehydrated bgImage on canvas, etc.) all need to restart from a
 * clean slate. */
function confirmClearAllStorage() {
    /* Disable the button so the user can't double-click while the
     * async IDB clear is in flight. */
    const btn = document.getElementById('btnConfirmClearAllStorage');
    if (btn) btn.disabled = true;

    const idbClearP = (window.idbStore && typeof window.idbStore.clearAllStores === 'function')
        ? window.idbStore.clearAllStores()
        : Promise.resolve();

    idbClearP.then(function () {
        try {
            if (typeof localStorage !== 'undefined') localStorage.clear();
        } catch (e) {
            console.warn('[storageDialog] localStorage.clear failed:', e && e.message);
        }
        /* Reload from the current URL so any shareable-link params
         * survive (the user's current room is encoded in the URL).
         * location.reload() is fine here — it's a same-origin
         * synchronous trigger, not a navigation. */
        try {
            location.reload();
        } catch (e) {
            console.warn('[storageDialog] reload failed:', e && e.message);
            if (btn) btn.disabled = false;
        }
    }).catch(function (e) {
        console.warn('[storageDialog] clearAllStores failed:', e && e.message);
        showToast('Clear All failed — see console');
        if (btn) btn.disabled = false;
        closeAllDialogModals();
    });
}

/* Export-from-Library: verbatim IDB record → .vrcCustomItems.json (no menuImage rebuild). */
function exportCustomItemRecordFromLibrary(baseId) {
    if (!baseId) return;
    if (!window.idbStore || typeof window.idbStore.customItemGet !== 'function') {
        showToast('Library unavailable — export failed');
        return;
    }
    window.idbStore.customItemGet(baseId).then(function (rec) {
        if (!rec) {
            showToast('Custom Item no longer in library');
            return;
        }
        const name = getCustomItemRecordName(rec).trim();
        if (!name) {
            /* Defensive — canvas-only invariant should prevent this. */
            alertDialog('Custom Item Name Required',
                'This Custom Item has no name. Save a name before exporting.');
            return;
        }
        /* Export uses canonical customItemName; legacy data_labelField dropped from copy only. */
        rec.customItemName = name;
        if ('data_labelField' in rec) delete rec.data_labelField;
        const fileObj = { vrcCustomItems: [rec] };
        const json = JSON.stringify(fileObj, null, 2);
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        const safeName = name.replace(/[/\\?%*:|"<>]/g, '-').trim().slice(0, 60) || 'custom_item';
        link.download = safeName + '.vrcCustomItems.json';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
        showToast('Custom Item exported');
    }).catch(function (e) {
        console.warn('[customItemLibrary] export from library failed:', e && e.message);
        showToast('Export failed');
    });
}

/* Export Custom Item to .vrcCustomItems.json + IDB upsert; name required. */
function exportCustomItem(customItem) {
    if (!customItem) return;

    const name = (customItem.name || '').trim();
    if (!name) {
        alertDialog(
            'Custom Item Name Required',
            'Please add a Custom Item Name in the Details panel before exporting.'
        );
        return;
    }

    const record = buildCustomItemExportRecord(customItem);
    if (!record) {
        alertDialog(
            'Export Failed',
            'Unable to build an export record for this Custom Item. It may have no members.'
        );
        return;
    }

    createCustomItemMenuImage(record).then(function (dataUrl) {
        record.menuImage = dataUrl || '';

        /* Best-effort library upsert by baseId; never blocks the download. */
        if (window.idbStore && typeof window.idbStore.customItemPut === 'function') {
            window.idbStore.customItemPut(record).then(function (savedBaseId) {
                if (savedBaseId) markCustomItemInLibrary(savedBaseId);
            });
        }

        /* Single-entry array; format reserves shape for multi-record export. */
        const fileObj = { vrcCustomItems: [record] };
        const json = JSON.stringify(fileObj, null, 2);
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        const safeName = name.replace(/[/\\?%*:|"<>]/g, '-').trim().slice(0, 60) || 'custom_item';
        link.download = safeName + '.vrcCustomItems.json';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        showToast('Custom Item exported');
    });
}

/* Settings tab: export all IDB library records as one .vrcCustomItems.json. */
function exportAllCustomItemsFromLibrary() {
    if (!window.idbStore || typeof window.idbStore.customItemGetAll !== 'function') {
        alertDialog(
            'Export Failed',
            'Local storage (IndexedDB) is unavailable in this browser session.'
        );
        return;
    }
    window.idbStore.customItemGetAll().then(function (records) {
        if (!Array.isArray(records) || !records.length) {
            alertDialog(
                'No Custom Items',
                'There are no Custom Items in your local library to export.'
            );
            return;
        }
        const fileObj = { vrcCustomItems: records };
        const json = JSON.stringify(fileObj, null, 2);
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        /* ISO date stamp; OS adds -2/-3 suffix to same-day duplicates. */
        const stamp = new Date().toISOString().slice(0, 10); /* YYYY-MM-DD */
        link.download = 'customItemLibrary-' + stamp + '.vrcCustomItems.json';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        const n = records.length;
        alertDialog(
            'Custom Items Exported',
            n + ' Custom Item' + (n === 1 ? '' : 's') + ' exported to ' +
            '<code>' + (typeof DOMPurify !== 'undefined' ? DOMPurify.sanitize(link.download) : link.download) + '</code>.'
        );
    }).catch(function (e) {
        console.warn('[customItemLibrary] exportAllCustomItemsFromLibrary failed:', e && e.message);
        alertDialog(
            'Export Failed',
            'Reading the local Custom Item Library failed. See the browser console for details.'
        );
    });
}

/* Enable Export Custom Items button when customItemLibraryIds is non-empty. */
function updateExportCustomItemsButtonState() {
    const btn = document.getElementById('btnExportAllCustomItems');
    if (!btn) return;
    const count = customItemLibraryIds ? customItemLibraryIds.size : 0;
    btn.disabled = count === 0;
    btn.title = count === 0
        ? 'No Custom Items in the local library yet.'
        : 'Download all ' + count + ' Custom Item' + (count === 1 ? '' : 's') +
          ' as a single .vrcCustomItems.json file.';
}

/* Validate .vrcCustomItems record schema; returns { valid, error? }. */
function validateCustomItemRecord(rec) {
    if (!rec || typeof rec !== 'object') return { valid: false, error: 'Not an object' };
    if (typeof rec.customItemBaseId !== 'string' || !rec.customItemBaseId.trim()) {
        return { valid: false, error: 'Missing customItemBaseId' };
    }
    if (typeof rec.width !== 'number' || !isFinite(rec.width) || rec.width <= 0) {
        return { valid: false, error: 'Invalid width' };
    }
    if (typeof rec.height !== 'number' || !isFinite(rec.height) || rec.height <= 0) {
        return { valid: false, error: 'Invalid height' };
    }
    /* author/description/version are OPTIONAL but must be strings if present. */
    if (rec.author !== undefined && typeof rec.author !== 'string') {
        return { valid: false, error: 'Invalid author' };
    }
    if (rec.description !== undefined && typeof rec.description !== 'string') {
        return { valid: false, error: 'Invalid description' };
    }
    if (rec.version !== undefined && typeof rec.version !== 'string') {
        return { valid: false, error: 'Invalid version' };
    }
    if (!Array.isArray(rec.customItemParts) || !rec.customItemParts.length) {
        return { valid: false, error: 'No customItemParts' };
    }
    for (let i = 0; i < rec.customItemParts.length; i++) {
        const p = rec.customItemParts[i];
        if (!p || typeof p !== 'object') {
            return { valid: false, error: 'Part ' + i + ': not an object' };
        }
        if (typeof p.data_deviceid !== 'string' || !p.data_deviceid.trim()) {
            return { valid: false, error: 'Part ' + i + ': missing data_deviceid' };
        }
        if (typeof p.x !== 'number' || typeof p.y !== 'number' ||
            !isFinite(p.x) || !isFinite(p.y)) {
            return { valid: false, error: 'Part ' + i + ': invalid x/y' };
        }
        if (typeof p.width !== 'number' || typeof p.height !== 'number' ||
            !isFinite(p.width) || !isFinite(p.height)) {
            return { valid: false, error: 'Part ' + i + ': invalid width/height' };
        }
        /* Unknown device kinds are a hard error (no topImage / parentGroup). */
        if (typeof allDeviceTypes === 'undefined' || !allDeviceTypes[p.data_deviceid]) {
            return { valid: false, error: 'Part ' + i + ': unknown device "' + p.data_deviceid + '"' };
        }
    }
    return { valid: true };
}

/* Drop a validated customItem record at the center of the active room. */
function insertCustomItemAtRoomCenter(record) {
    /* activeRoomWidth/Length when inside a polyRoom part; activeRoomX/Y are 0 otherwise. */
    const roomW = Number(activeRoomWidth)  || (roomObj.room && Number(roomObj.room.roomWidth))  || 5;
    const roomL = Number(activeRoomLength) || (roomObj.room && Number(roomObj.room.roomLength)) || 5;
    const roomCenterX = (Number(activeRoomX) || 0) + roomW / 2;
    const roomCenterY = (Number(activeRoomY) || 0) + roomL / 2;
    return insertCustomItemAtPosition(record, roomCenterX, roomCenterY);
}

/* Insert customItem at world center (meters→unit); uses Add Items to: layer. */
function insertCustomItemAtPosition(record, worldX, worldY) {
    ensureCustomItems();

    /* Export records store meters; roomObj is in roomObj.unit. */
    const unitFromMeters = (roomObj && roomObj.unit === 'feet') ? 3.28084 : 1;

    const ciW = Number(record.width)  * unitFromMeters;
    const ciH = Number(record.height) * unitFromMeters;
    /* Center → upper-left (parts are normalized to UL-origin in record). */
    const ciX = Number(worldX) - ciW / 2;
    const ciY = Number(worldY) - ciH / 2;

    const layerSel = document.getElementById('drpAddItemLayer');
    const targetLayerId = (layerSel && layerSel.value) || '0';

    const customitemid = createUuid();
    const newMembers = [];

    const pendingInserts = [];

    /* Restore allow-list matches export field set. */
    const RESTORE_VERBATIM = CUSTOM_ITEM_PART_VERBATIM_FIELDS;
    const RESTORE_UNIT_SCALED = CUSTOM_ITEM_UNIT_SCALED_PART_FIELDS;

    record.customItemParts.forEach(part => {
        const dt = allDeviceTypes[part.data_deviceid];
        if (!dt) return; /* validator already rejected, defensive guard */

        const uuid = createUuid();
        const newItem = {
            id: uuid,
            data_deviceid: part.data_deviceid,
            name: dt.name || part.data_deviceid,
            /* CustomItem rotation = 0 on insert → simple translate. */
            x: ciX + Number(part.x) * unitFromMeters,
            y: ciY + Number(part.y) * unitFromMeters,
            width:  Number(part.width)  * unitFromMeters,
            height: Number(part.height) * unitFromMeters,
            rotation: Number(part.rotation) || 0,
            data_layerId: targetLayerId,
            data_customItemId: customitemid,
        };

        RESTORE_VERBATIM.forEach(f => {
            if (part[f] !== undefined && part[f] !== null) {
                /* Deep-clone objects so canvas item doesn't share refs with IDB. */
                if (typeof part[f] === 'object') {
                    try { newItem[f] = JSON.parse(JSON.stringify(part[f])); }
                    catch (_e) { newItem[f] = part[f]; }
                } else {
                    newItem[f] = part[f];
                }
            }
        });

        RESTORE_UNIT_SCALED.forEach(f => {
            if (typeof part[f] === 'number') newItem[f] = part[f] * unitFromMeters;
        });

        if (typeof part.cornerRadius === 'number') {
            newItem.cornerRadius = part.cornerRadius * unitFromMeters;
        } else if (Array.isArray(part.cornerRadius)) {
            newItem.cornerRadius = part.cornerRadius.map(v => (typeof v === 'number' ? v * unitFromMeters : v));
        }
        if (Array.isArray(part.points)) {
            newItem.points = part.points.map(v => (typeof v === 'number' ? v * unitFromMeters : v));
        }

        const parentGroup = dt.parentGroup;
        if (!parentGroup) return;
        roomObj.items.push(newItem);
        /* Must register in roomObjItemsMap before trNodesFromUuids → canvasToJson. */
        roomObjItemsMap.set(newItem.id, newItem);
        newMembers.push(uuid);
        pendingInserts.push({ deviceId: part.data_deviceid, parentGroup, attrs: newItem, uuid });
    });

    if (!newMembers.length) {
        console.warn('[customItemLibrary] insertCustomItemAtRoomCenter: no members materialized');
        return null;
    }

    /* Lowest member zPosition (same as createCustomItem). */
    let minZ = Infinity;
    newMembers.forEach(uuid => {
        const it = findRoomItemByUuid(uuid);
        if (it) {
            const z = Number(it.data_zPosition) || 0;
            if (z < minZ) minZ = z;
        }
    });
    if (!isFinite(minZ)) minZ = 0;

    const newCustomItem = {
        customitemid: customitemid,
        customItemBaseId: record.customItemBaseId,
        name: getCustomItemRecordName(record),
        author: String(record.author || ''),
        description: String(record.description || ''),
        version: String(record.version || '1'),
        data_layerId: targetLayerId,
        x: ciX,
        y: ciY,
        width: ciW,
        height: ciH,
        rotation: 0,
        data_zPosition: minZ,
        customItemMembers: newMembers,
    };

    roomObj.customItems.push(newCustomItem);

    /* Insert without full drawRoom rebuild (pasteItems pattern). */
    pendingInserts.forEach(({ deviceId, parentGroup, attrs, uuid }) => {
        insertShapeItem(deviceId, parentGroup, attrs, uuid, false);
    });
    insertCustomItemRect(newCustomItem);

    trNodesFromUuids([customitemid, ...newMembers], true);

    return customitemid;
}

/* HTML-escape user strings for import summary dialog (innerHTML). */
function _escapeHtmlForCustomItemDialog(s) {
    return String(s == null ? '' : s)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

/* Import summary: saved / alreadyHad / skippedNoName / failures buckets. */
function showCustomItemsImportSummaryDialog(saved, alreadyHad, skippedNoName, failures, insertedOnCanvas) {
    const esc = _escapeHtmlForCustomItemDialog;
    const totalAccepted = saved.length + alreadyHad.length + skippedNoName.length;
    const failureCount = failures.length;

    let header;
    if (totalAccepted > 0 && failureCount === 0) {
        header = 'Imported ' + totalAccepted + ' Custom Item' + (totalAccepted === 1 ? '' : 's');
    } else if (totalAccepted === 0 && failureCount > 0) {
        header = 'Custom Item Import Failed';
    } else if (totalAccepted > 0 && failureCount > 0) {
        header = 'Imported ' + totalAccepted + ' Custom Item' + (totalAccepted === 1 ? '' : 's') +
                 ' (' + failureCount + ' failed)';
    } else {
        header = 'No Custom Items in File';
    }

    let body = '';
    if (saved.length) {
        body += '<p><strong>Saved to Library:</strong></p><ul>';
        saved.forEach(s => {
            body += '<li>' + esc(s.name || '(unnamed)') + '</li>';
        });
        body += '</ul>';
    }
    if (alreadyHad.length) {
        body += '<p><strong>Already existed:</strong></p><ul>';
        alreadyHad.forEach(s => {
            body += '<li>' + esc(s.name || '(unnamed)') + '</li>';
        });
        body += '</ul>';
    }
    if (skippedNoName.length) {
        body += '<p><strong>Not saved to Library (no name):</strong></p><ul>';
        skippedNoName.forEach(s => {
            body += '<li>(unnamed)</li>';
        });
        body += '</ul>';
    }
    if (insertedOnCanvas) {
        body += '<p><em>Inserted at the center of the room canvas.</em></p>';
    }
    if (failureCount > 0) {
        body += '<p style="color: #c00;"><strong>Errors:</strong></p><ul style="color: #c00;">';
        failures.forEach(f => {
            body += '<li><strong>' + esc(f.name || '(unnamed)') + '</strong>: ' + esc(f.reason) + '</li>';
        });
        body += '</ul>';
    }

    alertDialog(header, body);
}

/* .vrcCustomItems file import entry point. */
function importCustomItemsFile(jsonFile) {
    if (!jsonFile || !Array.isArray(jsonFile.vrcCustomItems)) return;
    const incoming = jsonFile.vrcCustomItems;

    const valid = [];
    const failures = [];
    incoming.forEach((rec, idx) => {
        const v = validateCustomItemRecord(rec);
        if (v.valid) {
            valid.push(rec);
        } else {
            failures.push({
                name: getCustomItemRecordName(rec) || ('Entry ' + (idx + 1)),
                reason: v.error,
            });
        }
    });

    if (!valid.length) {
        showCustomItemsImportSummaryDialog([], [], [], failures, false);
        return;
    }

    /* Library save is best-effort; canvas-insert still works without it. */
    const idbAvailable = !!(window.idbStore && typeof window.idbStore.customItemPut === 'function');

    /* Unnamed/duplicate baseId bucketing for library import. */
    const willSaveBaseIds = new Set();
    const toSave = [];
    const alreadyHad = [];
    const skippedNoName = [];

    valid.forEach(rec => {
        const cleanName = getCustomItemRecordName(rec).trim();
        const baseId = rec.customItemBaseId;
        const alreadyExists = isCustomItemInLibrary(baseId) || willSaveBaseIds.has(baseId);

        if (alreadyExists) {
            alreadyHad.push({ rec: rec, name: cleanName });
            return;
        }
        if (!cleanName) {
            skippedNoName.push({ rec: rec, name: '' });
            return;
        }
        willSaveBaseIds.add(baseId);
        toSave.push({ rec: rec, name: cleanName });
    });

    if (!idbAvailable || !toSave.length) {
        const saved = []; /* nothing persisted */
        if (!idbAvailable) {
            /* IDB down: still list toSave in dialog (canvas-only this session). */
            toSave.forEach(t => saved.push({ customItemBaseId: t.rec.customItemBaseId, name: t.name }));
        }
        let insertedOnCanvas = false;
        if (valid.length === 1) {
            const inserted = insertCustomItemAtRoomCenter(valid[0]);
            insertedOnCanvas = !!inserted;
        }
        showCustomItemsImportSummaryDialog(saved, alreadyHad, skippedNoName, failures, insertedOnCanvas);
        return;
    }

    const persistPromises = toSave.map(entry => {
        return window.idbStore.customItemPut(entry.rec)
            .then(savedBaseId => ({ entry: entry, savedBaseId: savedBaseId }))
            .catch(_e => ({ entry: entry, savedBaseId: null }));
    });

    Promise.all(persistPromises).then(results => {
        const saved = [];
        results.forEach(r => {
            if (r.savedBaseId) {
                markCustomItemInLibrary(r.savedBaseId);
                saved.push({
                    customItemBaseId: r.savedBaseId,
                    name: r.entry.name,
                });
            } else {
                failures.push({
                    name: r.entry.name || '(unnamed)',
                    reason: 'IDB save failed',
                });
            }
        });

        let insertedOnCanvas = false;
        if (valid.length === 1) {
            const inserted = insertCustomItemAtRoomCenter(valid[0]);
            insertedOnCanvas = !!inserted;
        }

        showCustomItemsImportSummaryDialog(saved, alreadyHad, skippedNoName, failures, insertedOnCanvas);

        if (saved.length === 1 && insertedOnCanvas) {
            showToast('Imported 1 Custom Item — saved to library');
        } else if (saved.length > 1) {
            showToast('Imported ' + saved.length + ' Custom Items — saved to library');
        }
    });
}

/* Return all Konva nodes (across all item groups) whose data_customItemId matches customItemId */
function getCustomItemMemberNodes(customItemId) {
    const members = [];
    allNodeShapeGroups.forEach(kg => {
        kg.getChildren().forEach(node => {
            if (node.data_customItemId === customItemId) members.push(node);
        });
    });
    return members;
}

/* Recalculate CustomItem rect bounds from members (getMemberBoundingRect). */
function updateCustomItemBounds(customItemId) {
    if (!groupCustomItemRects) return;
    const members = getCustomItemMemberNodes(customItemId);
    if (!members.length) return;

    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    members.forEach(node => {
        const r = getMemberBoundingRect(node);
        if (r.x < minX) minX = r.x;
        if (r.y < minY) minY = r.y;
        if (r.x + r.width  > maxX) maxX = r.x + r.width;
        if (r.y + r.height > maxY) maxY = r.y + r.height;
    });

    const newX = minX;
    const newY = minY;
    const newW = maxX - minX;
    const newH = maxY - minY;

    const customItemRectNode = groupCustomItemRects.find(n => n.data_customItemId === customItemId)[0];
    if (customItemRectNode) {
        customItemRectNode.x(newX);
        customItemRectNode.y(newY);
        customItemRectNode.width(newW);
        customItemRectNode.height(newH);
    }

    const c = getCustomItemById(customItemId);
    if (c) {
        c.x = ((newX - pxOffset) / scale) + activeRoomX;
        c.y = ((newY - pyOffset) / scale) + activeRoomY;
        c.width  = newW / scale;
        c.height = newH / scale;
        const zPositions = members
            .map(n => parseFloat(n.data_zPosition) || 0)
            .filter(z => !isNaN(z));
        if (zPositions.length) c.data_zPosition = Math.min(...zPositions);

        /* Not called per drag frame today — drag-only library sync is a known gap. */
        maybeAutoSaveCustomItemEdit(c);
    }
}

/* Single CustomItem bundle selected (Group precedence). Mirrors getActiveGroupSelection(). */
function getActiveCustomItemSelection(nodes) {
    nodes = nodes || tr.nodes();
    if (!nodes || !nodes.length) return null;
    if (nodes.some(n => n.data_deviceid === 'group')) return null;
    const customItemRects = nodes.filter(n => n.data_deviceid === 'customItem');
    if (customItemRects.length !== 1) return null;
    const rectNode = customItemRects[0];
    const customItemId = rectNode.data_customItemId;
    if (!customItemId) return null;
    const allBelong = nodes.every(n => n === rectNode || n.data_customItemId === customItemId);
    if (!allBelong) return null;
    const customItem = getCustomItemById(customItemId);
    if (!customItem) return null;
    return { rectNode: rectNode, customItem: customItem, customItemId: customItemId };
}

/* Live-refresh CustomItem Details panel during drag/rotate. */
function refreshCustomItemDetailsFromCanvas() {
    const sel = getActiveCustomItemSelection();
    if (!sel) return;
    const r = sel.rectNode;
    const itemX   = document.getElementById('itemX');
    const itemY   = document.getElementById('itemY');
    const itemRot = document.getElementById('itemRotation');
    const itemW   = document.getElementById('itemWidth');
    const itemL   = document.getElementById('itemLength');
    if (itemX)   itemX.value   = round(((r.x() - pxOffset) / scale) + activeRoomX);
    if (itemY)   itemY.value   = round(((r.y() - pyOffset) / scale) + activeRoomY);
    if (itemRot) itemRot.value = round(r.rotation(), -1);
    if (itemW)   itemW.value   = round(r.width()  / scale);
    if (itemL)   itemL.value   = round(r.height() / scale);
}

/* Populate Details panel for a selected CustomItem. */
function populateCustomItemDetails(rectNode) {
    const customItem = getCustomItemById(rectNode.data_customItemId);
    if (!customItem) return;

    const hideIds = [
        'itemNameDiv', 'labelPathId', 'itemTopElevationDiv', 'itemDiagonalTvDiv',
        'itemVheightDiv', 'trapNarrowWidthDiv', 'tblRectRadiusRow', 'tblRectRadiusDiv', 'tblRectRadiusRightDiv',
        'itemTiltSlantDiv', 'itemTiltDiv', 'itemSlantDiv',
        'itemOffsetDiv', 'roleDiv', 'mountDiv', 'colorDiv', 'fillDiv',
    ];
    hideIds.forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = 'none';
    });

    const showIds = [
        'labelFieldDiv', 'itemLayerDiv', 'itemWidthLengthDiv',
        'itemWidthDiv', 'itemLengthDiv', 'itemRotationDiv',
    ];
    showIds.forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = '';
    });

    document.getElementById('itemLabeldiv').textContent = 'Custom Item Name:';
    document.getElementById('labelField').value = customItem.name || '';

    document.getElementById('itemX').value = round(((rectNode.x() - pxOffset) / scale) + activeRoomX);
    document.getElementById('itemY').value = round(((rectNode.y() - pyOffset) / scale) + activeRoomY);
    document.getElementById('itemZposition').value = (customItem.data_zPosition != null) ? customItem.data_zPosition : 0;

    document.getElementById('itemWidth').value  = round(rectNode.width()  / scale);
    document.getElementById('itemLength').value = round(rectNode.height() / scale);
    document.getElementById('itemWidth').disabled  = true;
    document.getElementById('itemLength').disabled = true;

    document.getElementById('itemRotation').value = round(rectNode.rotation(), -1);

    document.getElementById('itemId').innerText    = customItem.customitemid;
    document.getElementById('itemType').innerText  = 'Custom Item';
    document.getElementById('itemGroup').innerText = '';

    populateLayerDropdown('drpItemLayer', customItem.data_layerId || '0');
}

/* Apply CustomItem Details-panel edits (translate/rotate members). Mirrors updateGroupItem(). */
function updateCustomItemItem(customItem) {
    if (!customItem || !groupCustomItemRects) return;
    const rectNode = groupCustomItemRects.find(n => n.data_customItemId === customItem.customitemid)[0];
    if (!rectNode) return;

    const newName = (DOMPurify.sanitize(document.getElementById('labelField').value) || '').trim() || customItem.name;
    const newX = Number(document.getElementById('itemX').value) || 0;
    const newY = Number(document.getElementById('itemY').value) || 0;
    const newZ = Number(document.getElementById('itemZposition').value) || 0;
    const newRot = normalizeDegree(Number(document.getElementById('itemRotation').value) || 0);
    const newLayerId = (document.getElementById('drpItemLayer') && document.getElementById('drpItemLayer').value) || '0';

    const currentX_user = ((rectNode.x() - pxOffset) / scale) + activeRoomX;
    const currentY_user = ((rectNode.y() - pyOffset) / scale) + activeRoomY;
    const currentZ      = Number(customItem.data_zPosition) || 0;
    const currentRot    = rectNode.rotation();

    const deltaX_px = (newX - currentX_user) * scale;
    const deltaY_px = (newY - currentY_user) * scale;
    const deltaZ    = newZ - currentZ;
    const deltaR    = newRot - currentRot;

    const members = getCustomItemMemberNodes(customItem.customitemid);

    if (deltaX_px !== 0 || deltaY_px !== 0) {
        members.forEach(m => { m.x(m.x() + deltaX_px); m.y(m.y() + deltaY_px); });
        rectNode.x(rectNode.x() + deltaX_px);
        rectNode.y(rectNode.y() + deltaY_px);
        /* v1: skip shifting a Group rect when membership is only partial. */
    }

    if (deltaR !== 0) {
        const centre = getRotatedRectCenter(rectNode);
        members.forEach(m => rotateNodeAroundPoint(m, centre.x, centre.y, deltaR));
        rotateNodeAroundPoint(rectNode, centre.x, centre.y, deltaR);
    }

    if (deltaZ !== 0) {
        members.forEach(m => {
            const existingZ = Number(m.data_zPosition) || 0;
            m.data_zPosition = existingZ + deltaZ;
            if (roomObj && Array.isArray(roomObj.items)) {
                const entry = roomObj.items.find(it => it.id === m.id());
                if (entry) entry.data_zPosition = m.data_zPosition;
            }
        });
    }
    customItem.data_zPosition = newZ;
    rectNode.data_zPosition = newZ;

    customItem.name = newName;
    rectNode.data_labelField = newName;

    /* Layer cascade — same share-a-layer invariant Groups enforce. */
    if (newLayerId !== (customItem.data_layerId || '0')) {
        customItem.data_layerId = newLayerId;
        rectNode.data_layerId = newLayerId;
        applyLayerStateToNode(rectNode, newLayerId);
        members.forEach(m => {
            m.data_layerId = newLayerId;
            applyLayerStateToNode(m, newLayerId);
        });
        renderLayersList();
    }

    members.forEach(m => updateShading(m));

    canvasToJson();

    /* Debounced library auto-save after roomObj is reconciled. */
    maybeAutoSaveCustomItemEdit(customItem);

    const btn = document.getElementById("btnUpdateItemId");
    if (btn) {
        btn.disabled = true;
        setTimeout(() => { btn.disabled = false; }, 700);
    }
}

function getDefaultLayers() {
    return [
        { name: 'Default', visible: true, locked: false, layerid: '0' },
        { name: 'Ceiling', visible: true, locked: false, layerid: '1' }
    ];
}

/* Ensure reserved layers '0' and '1' are always present in a layers array */
function ensureDefaultLayers(layers) {
    if (!layers.find(l => l.layerid === '0')) {
        layers.unshift({ name: 'Default', visible: true, locked: false, layerid: '0' });
    }
    if (!layers.find(l => l.layerid === '1')) {
        const idx = layers.findIndex(l => l.layerid === '0');
        layers.splice(idx + 1, 0, { name: 'Ceiling', visible: true, locked: false, layerid: '1' });
    }
}

function getLayerById(layerId) {
    if (!roomObj.layers) return null;
    return roomObj.layers.find(l => l.layerid === layerId) || null;
}

/* Returns true if the given item (or Konva node) is assigned to a hidden VRC layer. */
function isItemInHiddenLayer(itemOrNode) {
    if (!itemOrNode) return false;
    const layerId = itemOrNode.data_layerId || '0';
    const layer = getLayerById(layerId);
    return !!(layer && layer.visible === false);
}

/* Drop hidden-layer items from a WD export clone (mutates roomObj2). */
function removeHiddenLayerItemsForExport(roomObj2) {
    if (!roomObj2 || !Array.isArray(roomObj2.items) || !roomObj.layers) return;
    const hiddenLayerIds = new Set(
        roomObj.layers.filter(l => l.visible === false).map(l => l.layerid)
    );
    if (hiddenLayerIds.size === 0) return;
    roomObj2.items = roomObj2.items.filter(item => {
        const lid = item.data_layerId || '0';
        return !hiddenLayerIds.has(lid);
    });
    /* Also drop customItems on hidden layers (export consistency). */
    if (Array.isArray(roomObj2.customItems)) {
        roomObj2.customItems = roomObj2.customItems.filter(c => {
            const lid = c.data_layerId || '0';
            return !hiddenLayerIds.has(lid);
        });
    }
}

/* Returns the next available URL layer number (20, 21, ...) for custom layers */
function nextLayerUrlNumber() {
    let used = roomObj.layers
        .filter(l => l.layerid !== '0' && l.layerid !== '1' && l._urlNum != null)
        .map(l => l._urlNum);
    for (let n = 20; ; n++) {
        if (!used.includes(n)) return n;
    }
}

/* Apply layer visible/locked to node + coverage children. Hidden layer hides all coverage. */
function applyLayerStateToNode(node, layerId) {
    if (!layerId || layerId === '') layerId = '0';
    const layer = getLayerById(layerId);
    if (!layer) return;
    if (layer.visible) {
        node.show();
    } else {
        node.hide();
    }
    node.listening(!layer.locked);
    applyLayerLockOpacity(node, layer.locked);
    applyLayerStateToCoverageNodes(node, layer.visible);
}

/* Dim locked-layer nodes to 0.7× original opacity (idempotent via data_lockOpacityApplied). */
function applyLayerLockOpacity(node, locked) {
    if (!node || typeof node.opacity !== 'function') return;
    if (locked) {
        if (node.data_lockOpacityApplied !== true) {
            node.data_originalOpacity = node.opacity();
            node.opacity(node.data_originalOpacity * 0.7);
            node.data_lockOpacityApplied = true;
        }
    } else {
        if (node.data_lockOpacityApplied === true) {
            const original = (typeof node.data_originalOpacity === 'number')
                ? node.data_originalOpacity
                : 1;
            node.opacity(original);
            node.data_lockOpacityApplied = false;
            delete node.data_originalOpacity;
        }
    }
}

/* Coverage/label visibility = layer visible AND per-item hidden flags. */
function applyLayerStateToCoverageNodes(node, layerVisible) {
    const id = node.id();
    if (!id) return;

    const audioNode = stage.findOne('#audio~' + id);
    if (audioNode) {
        audioNode.visible(layerVisible && node.data_audioHidden !== true);
    }

    const speakerNode = stage.findOne('#speaker~' + id);
    if (speakerNode) {
        speakerNode.visible(layerVisible && node.data_speakerHidden !== true);
    }

    const fovNode = stage.findOne('#fov~' + id);
    if (fovNode) {
        fovNode.visible(layerVisible && node.data_fovHidden !== true);
    }

    const dispDistNode = stage.findOne('#dispDist~' + id);
    if (dispDistNode) {
        dispDistNode.visible(layerVisible && node.data_dispDistHidden !== true);
    }

    const labelNode = stage.findOne('#label~' + id);
    if (labelNode) {
        /* Labels have no per-item hidden flag; just respect layer visibility */
        labelNode.visible(layerVisible);
    }
}

/* Re-apply layer visible/locked to all canvas nodes + coverage. */
function applyAllLayerStates() {
    const allNodes = layerTransform.find('Image, Rect, Circle, Shape, Line, Text, RegularPolygon');
    allNodes.forEach(node => {
        if (node.data_layerId) {
            applyLayerStateToNode(node, node.data_layerId);
        }
    });
    updateModeStatusBadge();
}

/* Status badge beside #controlButtons: active mode or hidden/locked layer counts. */
function updateModeStatusBadge() {
    const el = document.getElementById('modeStatusBadge');
    if (!el) return;
    let html = '';
    /* isMode: blue for active tool; yellow for layer hide/lock counts. */
    let isMode = true;
    if (isWallBuilderOn || isWallWriterOn2) {
        html = 'Wall Builder';
    } else if (isPolyBuilderOn) {
        html = polyBuilderMode === 'customPathEditor' ? 'Path Editor' : 'Irregular Room';
    } else if (movingBackgroundImage) {
        html = 'Move Floor Plan';
    } else if (isMeasuringToolOn) {
        html = 'Measuring Tool';
    } else if (isSelectingTwoPointsOn) {
        html = 'Select 2 Points';
    } else if (roomObj && Array.isArray(roomObj.layers)) {
        const hidden = roomObj.layers.filter(l => !l.visible).length;
        const locked = roomObj.layers.filter(l => l.locked).length;
        if (hidden || locked) {
            const parts = ['Layer:'];
            if (hidden) parts.push(`<i class="icon icon-hide-bold"></i> ${hidden}`);
            if (locked) parts.push(`<i class="icon icon-secure-lock-bold"></i> ${locked}`);
            html = parts.join(' ');
            isMode = false;
        } else {
            isMode = false;
        }
    } else {
        isMode = false;
    }
    el.innerHTML = html;
    el.classList.toggle('mode-status-badge--mode', !!html && isMode);
    /* visibility (not display) keeps the badge slot reserved so toolbar buttons don't jump. */
    el.style.visibility = html ? 'visible' : 'hidden';
    if (html) fitBadgeTextSize(el);
}

/* Shrink badge font until content fits 120px frame (floor 9px). */
function fitBadgeTextSize(el) {
    if (!el) return;
    el.style.fontSize = '';
    let size = parseFloat(getComputedStyle(el).fontSize) || 13;
    const minSize = 9;
    let guard = 30;
    while (el.scrollWidth > el.clientWidth && size > minSize && guard-- > 0) {
        size -= 0.5;
        el.style.fontSize = size + 'px';
    }
}

/* ---- Layer CRUD ---- */

function addLayer(name) {
    if (!name || name.trim() === '') name = 'New Layer';
    name = DOMPurify.sanitize(name.trim());

    if (isLayerNameDuplicate(name)) {
        name = makeUniqueLayerName(name);
    }
    const urlNum = nextLayerUrlNumber();
    const newLayer = { name: name, visible: true, locked: false, layerid: createUuid(), _urlNum: urlNum };
    roomObj.layers.push(newLayer);
    renderLayersList();
    canvasToJson();
    return newLayer;
}

function deleteLayer(layerId) {
    if (layerId === '0' || layerId === '1') return; /* reserved layers cannot be deleted */

    /* Items move to currentAddLayerId, or Default if that layer is being deleted. */
    let targetLayerId = currentAddLayerId;
    if (targetLayerId === layerId || !getLayerById(targetLayerId)) {
        currentAddLayerId = '0';
        targetLayerId = '0';
    }

    getAllCanvasNodes().forEach(node => {
        if (node.data_layerId === layerId) {
            node.data_layerId = targetLayerId;
            applyLayerStateToNode(node, targetLayerId);
        }
    });
    /* update roomObj items */
    roomObj.items.forEach(item => {
        if (item.data_layerId === layerId) {
            if (targetLayerId === '0') {
                /* Default layer is implicit — omit data_layerId */
                delete item.data_layerId;
            } else {
                item.data_layerId = targetLayerId;
            }
        }
    });
    roomObj.layers = roomObj.layers.filter(l => l.layerid !== layerId);
    renderLayersList();
    canvasToJson();
}

function renameLayer(layerId, newName) {
    if (layerId === '0' || layerId === '1') return;
    newName = DOMPurify.sanitize(newName.trim());
    if (!newName) return;
    if (isLayerNameDuplicate(newName, layerId)) {
        alertDialog('Duplicate Layer Name', 'A layer with that name already exists. Please choose a unique name.');
        return false;
    }
    const layer = getLayerById(layerId);
    if (layer) {
        layer.name = newName;
        renderLayersList();
        canvasToJson();
    }
    return true;
}

/* ---- Layer dialog modals ---- */

/* Count canvas items on a layer (implicit Default when data_layerId absent). */
function countItemsInLayer(layerId) {
    if (typeof layerTransform === 'undefined' || !layerTransform.find) return 0;
    return getAllCanvasNodes().filter(node => {
        const id = node.data_layerId || '0';
        return id === layerId;
    }).length;
}

/* Add Layer modal — unique default name, focused on open. */
function openAddLayerDialog() {
    const dlg = document.getElementById('dialogLayerAdd');
    const input = document.getElementById('layerAddNameInput');
    if (!dlg || !input) return;
    let defaultName = 'New Layer';
    if (typeof isLayerNameDuplicate === 'function' && isLayerNameDuplicate(defaultName)) {
        defaultName = makeUniqueLayerName(defaultName);
    }
    input.value = defaultName;
    dlg.showModal();
    setTimeout(() => { input.focus(); input.select(); }, 0);
}

/* dialogLayerAdd "Add" handler — duplicate-name check, then addLayer(). */
function confirmAddLayerFromDialog() {
    const input = document.getElementById('layerAddNameInput');
    if (!input) return;
    const name = (input.value || '').trim();
    if (!name) {
        alertDialog('Invalid Layer Name', 'Please enter a name for the new layer.');
        return;
    }
    if (typeof isLayerNameDuplicate === 'function' && isLayerNameDuplicate(name)) {
        alertDialog('Duplicate Layer Name', 'A layer with that name already exists. Please choose a unique name.');
        return;
    }
    document.getElementById('dialogLayerAdd').close();
    addLayer(name);
}

/* "Create Custom Item" dialog — name required for user-created bundles. */
function openCreateCustomItemDialog() {
    const dlg = document.getElementById('dialogCustomItemAdd');
    const input = document.getElementById('customItemAddNameInput');
    if (!dlg || !input) {
        /* Defensive: older RoomCalculator.html without dialog markup. */
        alertDialog('Cannot Create Custom Item',
            'The "Create Custom Item" dialog is unavailable in this build. Please refresh the page.');
        return;
    }

    /* Same selection rules as createCustomItem() / canCustomItem. */
    const candidates = (typeof tr !== 'undefined' && tr && tr.nodes) ? tr.nodes() : [];
    const itemNodes = candidates.filter(n =>
        n.data_deviceid && n.data_deviceid !== 'group' && n.data_deviceid !== 'customItem' && n.isVisible()
    );
    const isSinglePathShape =
        itemNodes.length === 1 && itemNodes[0].data_deviceid === 'pathShape';
    if (itemNodes.length < 2 && !isSinglePathShape) {
        alertDialog('Cannot Create Custom Item',
            'Select at least two items, or a single Custom Path Shape, to create a Custom Item.');
        return;
    }

    input.value = '';
    /* Author/Description are optional; older HTML may lack the inputs. */
    const authorInput = document.getElementById('customItemAddAuthorInput');
    const descInput = document.getElementById('customItemAddDescriptionInput');
    if (authorInput) authorInput.value = '';
    if (descInput) descInput.value = '';
    dlg.showModal();
    /* setTimeout(0) lets <dialog>.showModal finish opening before focus. */
    setTimeout(() => { input.focus(); input.select(); }, 0);
}

/* dialogCustomItemAdd "Create" handler — empty name → alertDialog. */
function confirmCreateCustomItemFromDialog() {
    const input = document.getElementById('customItemAddNameInput');
    if (!input) return;
    const raw = (input.value || '').trim();
    if (!raw) {
        alertDialog('Custom Item Name Required',
            'Please enter a name for the new Custom Item.');
        return;
    }
    const cleaned = (typeof DOMPurify !== 'undefined' && DOMPurify && typeof DOMPurify.sanitize === 'function')
        ? (DOMPurify.sanitize(raw) || '').trim()
        : raw;
    /* DOMPurify can strip to '' (all-script input) — treat as blank. */
    if (!cleaned) {
        alertDialog('Custom Item Name Required',
            'Please enter a name for the new Custom Item.');
        return;
    }

    /* Optional author/description — same DOMPurify path as name; empty after strip is OK. */
    const authorInput = document.getElementById('customItemAddAuthorInput');
    const descInput = document.getElementById('customItemAddDescriptionInput');
    const cleanField = (val) => {
        const trimmed = (val || '').trim();
        if (!trimmed) return '';
        return (typeof DOMPurify !== 'undefined' && DOMPurify && typeof DOMPurify.sanitize === 'function')
            ? (DOMPurify.sanitize(trimmed) || '').trim()
            : trimmed;
    };
    const cleanedAuthor = cleanField(authorInput ? authorInput.value : '');
    const cleanedDesc = cleanField(descInput ? descInput.value : '');

    const dlg = document.getElementById('dialogCustomItemAdd');
    if (dlg) dlg.close();
    createCustomItem(undefined, cleaned, cleanedAuthor, cleanedDesc);
}

/* Delete Layer confirmation modal. */
function openDeleteLayerDialog(layerId) {
    if (layerId === '0' || layerId === '1') return; /* reserved layers cannot be deleted */
    const layer = getLayerById(layerId);
    if (!layer) return;

    /* Mirror deleteLayer() destination logic. */
    let destName = 'Default';
    if (currentAddLayerId !== '0' && currentAddLayerId !== layerId) {
        const dest = getLayerById(currentAddLayerId);
        if (dest) destName = dest.name;
    }

    const itemCount = countItemsInLayer(layerId);
    const itemWord = itemCount === 1 ? 'item' : 'items';

    const layerNameSafe = DOMPurify.sanitize(layer.name);
    const destNameSafe = DOMPurify.sanitize(destName);

    let html = `<div>Delete layer <b>"${layerNameSafe}"</b>?</div>`;
    html += `<div style="margin-top: 8px;">${itemCount} ${itemWord} will move to <b>${destNameSafe}</b>.</div>`;
    if (!layer.visible) {
        html += `<div style="margin-top: 8px; color: #b35900;"><i class="icon icon-hide-bold" style="vertical-align: middle;"></i> Note: this layer is currently <b>hidden</b>.</div>`;
    }

    const main = document.getElementById('dialogLayerDeleteMain');
    if (main) main.innerHTML = html;

    const btn = document.getElementById('dialogLayerDeleteConfirmBtn');
    if (btn) {
        btn.onclick = () => {
            document.getElementById('dialogLayerDelete').close();
            deleteLayer(layerId);
        };
    }
    document.getElementById('dialogLayerDelete').showModal();
}

function toggleLayerVisible(layerId) {
    const layer = getLayerById(layerId);
    if (!layer) return;
    layer.visible = !layer.visible;
    applyAllLayerStates();
    if (!layer.visible || layer.locked) {
        removeLayerNodesFromSelection(layerId);
    }
    renderLayersList();
    canvasToJson();
}

function toggleLayerLocked(layerId) {
    const layer = getLayerById(layerId);
    if (!layer) return;
    layer.locked = !layer.locked;
    applyAllLayerStates();
    if (layer.locked || !layer.visible) {
        removeLayerNodesFromSelection(layerId);
    }
    renderLayersList();
    canvasToJson();
}

/* Remove layer's nodes from tr selection (Layers tab hide/lock). */
function removeLayerNodesFromSelection(layerId) {
    const remaining = tr.nodes().filter(n => (n.data_layerId || '0') !== layerId);
    tr.nodes(remaining);
    refreshCopyDelBtnState();
}

/* Global hide/show: any hidden layer → show all, else hide all. */
function toggleAllLayersVisible() {
    if (!roomObj.layers) return;
    const anyHidden = roomObj.layers.some(l => !l.visible);
    const newVisible = anyHidden; /* if any hidden → show all; else hide all */
    roomObj.layers.forEach(l => { l.visible = newVisible; });
    applyAllLayerStates();
    if (!newVisible) {
        tr.nodes([]);
        refreshCopyDelBtnState();
    }
    renderLayersList();
    canvasToJson();
}

/* Global lock/unlock: any locked layer → unlock all, else lock all. */
function toggleAllLayersLocked() {
    if (!roomObj.layers) return;
    const anyLocked = roomObj.layers.some(l => l.locked);
    const newLocked = !anyLocked; /* if any locked → unlock all; else lock all */
    roomObj.layers.forEach(l => { l.locked = newLocked; });
    applyAllLayerStates();
    if (newLocked) {
        tr.nodes([]);
        refreshCopyDelBtnState();
    }
    renderLayersList();
    canvasToJson();
}

function isLayerNameDuplicate(name, excludeLayerId) {
    if (!name) return false;
    const lower = String(name).trim().toLowerCase();
    if (!lower) return false;

    /* Block renaming custom layers to reserved names Default/Ceiling. */
    if (lower === 'default' && excludeLayerId !== '0') return true;
    if (lower === 'ceiling' && excludeLayerId !== '1') return true;

    return roomObj.layers.some(l => l.name.toLowerCase() === lower && l.layerid !== excludeLayerId);
}

function makeUniqueLayerName(baseName) {
    let n = 2;
    let candidate = baseName + ' ' + n;
    while (isLayerNameDuplicate(candidate)) {
        n++;
        candidate = baseName + ' ' + n;
    }
    return candidate;
}

/* Return every draggable/data-carrying Konva node from layerTransform */
function getAllCanvasNodes() {
    return layerTransform.find('Image, Rect, Circle, Shape, Line, RegularPolygon');
}

/* Change one item's layer; Group/CustomItem rects cascade to all members. */
function updateItemLayer(nodeId, newLayerId) {
    if (!newLayerId) newLayerId = '0';
    const node = stage.find('#' + nodeId)[0];
    if (!node) return;

    if (node.data_deviceid === 'group') {
        const groupId = node.data_groupId;
        const group = getGroupById(groupId);
        if (group) group.data_layerId = newLayerId;
        node.data_layerId = newLayerId;
        applyLayerStateToNode(node, newLayerId);
        getGroupMemberNodes(groupId).forEach(m => {
            m.data_layerId = newLayerId;
            applyLayerStateToNode(m, newLayerId);
        });
    } else if (node.data_deviceid === 'customItem') {
        const customItemId = node.data_customItemId;
        const customItem = getCustomItemById(customItemId);
        if (customItem) customItem.data_layerId = newLayerId;
        node.data_layerId = newLayerId;
        applyLayerStateToNode(node, newLayerId);
        getCustomItemMemberNodes(customItemId).forEach(m => {
            m.data_layerId = newLayerId;
            applyLayerStateToNode(m, newLayerId);
        });
    } else {
        node.data_layerId = newLayerId;
        applyLayerStateToNode(node, newLayerId);
    }
    canvasToJson();
    renderLayersList();
}

/* Multi-select layer change; "none"/empty is a no-op. */
function updateMultipleItemsLayer(newLayerId) {
    if (!newLayerId || newLayerId === 'none') return;
    tr.nodes().forEach(node => {
        node.data_layerId = newLayerId;
        applyLayerStateToNode(node, newLayerId);
    });
    canvasToJson();
    renderLayersList();
}

/* Layer item count via selectAllNodes() (excludes bundle rects). */
function getLayerItemCount(layerId) {
    if (typeof groupVideoDevices === 'undefined' || !groupVideoDevices) return 0;
    return selectAllNodes().filter(n => {
        if (n.data_deviceid === 'group' || n.data_deviceid === 'customItem') return false;
        return (n.data_layerId || '0') === layerId;
    }).length;
}

/* Select layer items via selectAllNodes() — NOT getAllCanvasNodes() (nested children overflow Konva stack). */
function selectLayerItems(layerId) {
    const nodes = selectAllNodes().filter(node => {
        if (!node.listening() || !node.isVisible()) return false;
        const nLayerId = node.data_layerId || '0';
        return nLayerId === layerId;
    });
    tr.nodes(nodes);
    if (nodes.length > 0) {
        expandSelectionForGroups();
    }
    refreshCopyDelBtnState();
}

/* Reset fill/opacity overrides via updateItem() pipeline. */
function resetFillToDefault() {
    if (!tr || tr.nodes().length !== 1) return;
    const node = tr.nodes()[0];
    if (!node || !node.data_deviceid) return;
    const def = allDeviceTypes[node.data_deviceid];
    if (!def || (!def.configurableColor && !def.wdOpacity)) return;

    const fillEl = document.getElementById('itemFill');
    const opEl = document.getElementById('itemOpacity');
    if (fillEl) fillEl.value = '#FFFFFF';
    if (opEl) opEl.value = '';

    if (!multiUpdateMode) {
        updateItem();
    }
}

/* Session-only target layer for new items (Add Items to: dropdown); not persisted in roomObj/URL. */
let currentAddLayerId = '0';

/* Setter wired to the "Add Items to:" dropdown's onchange handler. */
function setCurrentAddLayerId(layerId) {
    currentAddLayerId = (layerId && getLayerById(layerId)) ? layerId : '0';
}

/* New-item layer id; reset currentAddLayerId to Default if selection was deleted. */
function getDefaultLayerForNewItems() {
    if (currentAddLayerId && getLayerById(currentAddLayerId)) {
        return currentAddLayerId;
    }
    currentAddLayerId = '0';
    return '0';
}

/* Populate Add Items to: dropdown; reset to Default if selected layer gone. */
function populateAddItemLayerDropdown() {
    const sel = document.getElementById('drpAddItemLayer');
    if (!sel) return;
    if (!getLayerById(currentAddLayerId)) currentAddLayerId = '0';
    populateLayerDropdown('drpAddItemLayer', currentAddLayerId);
}

/* Layer <select>; includeNoneOption adds blank "none" (multi-select no-op on update). */
function populateLayerDropdown(selectId, selectedLayerId, includeNoneOption) {
    const sel = document.getElementById(selectId);
    if (!sel) return;
    sel.innerHTML = '';

    if (includeNoneOption) {
        const none = document.createElement('option');
        none.value = 'none';
        none.textContent = '';
        if (selectedLayerId === 'none' || selectedLayerId == null) none.selected = true;
        sel.appendChild(none);
    }

    roomObj.layers.forEach(layer => {
        const opt = document.createElement('option');
        opt.value = layer.layerid;
        opt.textContent = layer.name;
        if (layer.layerid === selectedLayerId) opt.selected = true;
        sel.appendChild(opt);
    });
}

/* Render / refresh the Layers tab list and refresh open layer dropdowns */
function renderLayersList() {
    const container = document.getElementById('layersListContainer');
    if (container) {
        container.innerHTML = '';

        const anyHidden = roomObj.layers.some(l => !l.visible);
        const anyLocked = roomObj.layers.some(l => l.locked);

        const headerRow = document.createElement('div');
        headerRow.className = 'layer-row layer-header-row';
        headerRow.dataset.layerid = '__header__';

        const globalVisBtn = document.createElement('button');
        globalVisBtn.className = 'layer-icon-btn' + (!anyHidden ? ' layer-btn-active' : '');
        globalVisBtn.title = anyHidden ? 'Show all layers' : 'Hide all layers';
        globalVisBtn.innerHTML = `<i class="icon ${anyHidden ? 'icon-hide-bold' : 'icon-show-bold'}"></i>`;
        globalVisBtn.onclick = () => toggleAllLayersVisible();

        const globalLockBtn = document.createElement('button');
        globalLockBtn.className = 'layer-icon-btn' + (anyLocked ? ' layer-btn-active layer-btn-locked' : '');
        globalLockBtn.title = anyLocked ? 'Unlock all layers' : 'Lock all layers';
        globalLockBtn.innerHTML = `<i class="icon ${anyLocked ? 'icon-secure-lock-bold' : 'icon-unsecure-unlocked-bold'}"></i>`;
        globalLockBtn.onclick = () => toggleAllLayersLocked();

        const headerLabel = document.createElement('span');
        headerLabel.className = 'layer-name layer-header-label';
        headerLabel.textContent = 'All Layers';

        /* Spacers align header hide/lock with per-row columns. */
        const headerSpacerSelect = document.createElement('span');
        headerSpacerSelect.className = 'layer-header-spacer';
        const headerSpacerDel = document.createElement('span');
        headerSpacerDel.className = 'layer-header-spacer';

        headerRow.appendChild(globalVisBtn);
        headerRow.appendChild(globalLockBtn);
        headerRow.appendChild(headerLabel);
        headerRow.appendChild(headerSpacerSelect);
        headerRow.appendChild(headerSpacerDel);
        container.appendChild(headerRow);

        roomObj.layers.forEach(layer => {
            const isReserved = (layer.layerid === '0' || layer.layerid === '1');

            const row = document.createElement('div');
            row.className = 'layer-row';
            row.dataset.layerid = layer.layerid;

            const visBtn = document.createElement('button');
            visBtn.className = 'layer-icon-btn' + (layer.visible ? ' layer-btn-active' : '');
            visBtn.title = layer.visible ? 'Hide layer' : 'Show layer';
            visBtn.innerHTML = `<i class="icon ${layer.visible ? 'icon-show-bold' : 'icon-hide-bold'}"></i>`;
            visBtn.onclick = () => toggleLayerVisible(layer.layerid);

            const lockBtn = document.createElement('button');
            lockBtn.className = 'layer-icon-btn' + (layer.locked ? ' layer-btn-active layer-btn-locked' : '');
            lockBtn.title = layer.locked ? 'Unlock layer' : 'Lock layer';
            lockBtn.innerHTML = `<i class="icon ${layer.locked ? 'icon-secure-lock-bold' : 'icon-unsecure-unlocked-bold'}"></i>`;
            lockBtn.onclick = () => toggleLayerLocked(layer.layerid);

            const nameSpan = document.createElement('span');
            nameSpan.className = 'layer-name' + (!layer.visible ? ' layer-name-hidden' : '');
            nameSpan.textContent = layer.name;
            if (isReserved) {
                nameSpan.title = 'Reserved layer (cannot be renamed)';
                nameSpan.classList.add('layer-name-reserved');
            } else {
                nameSpan.title = 'Click to rename';
                nameSpan.onclick = (e) => startInlineRename(e, layer.layerid, nameSpan);
            }

            /* Select all layer items; disabled when hidden, locked, or empty. */
            const layerItemCount = getLayerItemCount(layer.layerid);
            const canSelectLayerItems =
                layer.visible && !layer.locked && layerItemCount > 0;
            const selBtn = document.createElement('button');
            selBtn.className = 'layer-icon-btn layer-select-btn'
                + (canSelectLayerItems ? ' layer-btn-active' : '');
            if (!layer.visible) {
                selBtn.title = 'Layer is hidden — cannot select items';
            } else if (layer.locked) {
                selBtn.title = 'Layer is locked — cannot select items';
            } else if (layerItemCount === 0) {
                selBtn.title = 'Layer is empty — no items to select';
            } else {
                selBtn.title = `Select ${layerItemCount} item${layerItemCount === 1 ? '' : 's'} in this layer`;
            }
            selBtn.disabled = !canSelectLayerItems;
            selBtn.innerHTML = `<i class="icon icon-selection-bold"></i>`;
            selBtn.onclick = () => selectLayerItems(layer.layerid);

            const delBtn = document.createElement('button');
            delBtn.className = 'layer-icon-btn layer-delete-btn';
            delBtn.title = isReserved ? 'Reserved layer cannot be deleted' : 'Delete layer';
            delBtn.disabled = isReserved;
            delBtn.innerHTML = `<i class="icon icon-delete-bold"></i>`;
            delBtn.onclick = () => {
                let destName = 'Default';
                if (currentAddLayerId !== '0' && currentAddLayerId !== layer.layerid) {
                    const dest = getLayerById(currentAddLayerId);
                    if (dest) destName = dest.name;
                }
                if (confirm(`Delete layer "${layer.name}"? Items will move to ${destName}.`)) {
                    deleteLayer(layer.layerid);
                }
            };

            row.appendChild(visBtn);
            row.appendChild(lockBtn);
            row.appendChild(nameSpan);
            row.appendChild(selBtn);
            row.appendChild(delBtn);
            container.appendChild(row);
        });
    } /* end if (container) */

    const singleSel = document.getElementById('drpItemLayer');
    if (singleSel) {
        const cur = singleSel.value;
        populateLayerDropdown('drpItemLayer', cur);
    }
    const multiSel = document.getElementById('drpItemLayer2');
    if (multiSel) {
        const cur2 = multiSel.value;
        populateLayerDropdown('drpItemLayer2', cur2, true);
    }

    populateAddItemLayerDropdown();

    /* Sync layer hide/lock badge on load/undo paths (toggle path already calls this). */
    updateModeStatusBadge();
}

/* Inline rename via single-click on a custom layer's name span (reserved layers are not editable) */
function startInlineRename(e, layerId, nameSpan) {
    e.stopPropagation();
    const currentName = nameSpan.textContent;
    const input = document.createElement('input');
    input.type = 'text';
    input.value = currentName;
    input.className = 'layer-name-input';
    nameSpan.replaceWith(input);
    input.focus();
    input.select();

    function commit() {
        const newName = input.value.trim();
        if (newName && newName !== currentName) {
            const ok = renameLayer(layerId, newName);
            if (!ok) {
                input.replaceWith(nameSpan);
            }
        } else {
            input.replaceWith(nameSpan);
        }
    }

    input.onblur = commit;
    input.onkeydown = (ev) => {
        if (ev.key === 'Enter') { commit(); ev.preventDefault(); }
        if (ev.key === 'Escape') { input.replaceWith(nameSpan); ev.preventDefault(); }
    };
}

