function isTouchEnabled() {
    return ('ontouchstart' in window) || (navigator.maxTouchPoints > 0) || (navigator.msMaxTouchPoints > 0);
}

function addOnBlurUnitInputListener() {


    let inputs = document.querySelectorAll(".unitInput");

    for (var i = 0; i < inputs.length; i++) {

        inputs[i].addEventListener("input", (event) => {
            event.target.value = event.target.value.replace(/[^0-9.inmcft"'-\s\u2018\u2019\u201C\u201D]/i, '');  /* allow the characters in the Regex */
        })

        inputs[i].addEventListener("blur", (event) => {

            /* allow for blank inputs for class allowBlank by not applying convertToUnit */
            if (!(event.target.classList.contains('allowBlank') && event.target.value === '')) {
                event.target.value = convertToUnit(event.target.value);
            }

            if (event.target.classList.contains('updateDrawRoom')) {
                if (event.target.id === 'roomWidth') {
                    roomObj.room.roomWidth = event.target.value;
                }

                if (event.target.id === 'roomLength') {
                    roomObj.room.roomLength = event.target.value;
                }

            }

            if (!multiUpdateMode) {
                updateItem();
            }

        })
    }
}

addOnBlurUnitInputListener();

/* #itemFill: debounce input (500ms) so picker scrub doesn't spam updateItem(). */
function addOnFillInputListeners() {
    const fillEl = document.getElementById('itemFill');
    const opEl = document.getElementById('itemOpacity');

    let fillInputDebounce = null;
    const FILL_INPUT_DEBOUNCE_MS = 500;

    function flushFillUpdate() {
        if (fillInputDebounce) {
            clearTimeout(fillInputDebounce);
            fillInputDebounce = null;
        }
        if (!multiUpdateMode) {
            updateItem();
        }
    }

    if (fillEl) {
        fillEl.addEventListener('input', () => {
            if (fillInputDebounce) clearTimeout(fillInputDebounce);
            fillInputDebounce = setTimeout(flushFillUpdate, FILL_INPUT_DEBOUNCE_MS);
        });
        fillEl.addEventListener('change', flushFillUpdate);
        fillEl.addEventListener('blur', flushFillUpdate);
    }

    if (opEl) {
        opEl.addEventListener('blur', () => {
            if (!multiUpdateMode) {
                updateItem();
            }
        });
    }
}

