function convertItemUnitBasedOnRatio(item, ratio) {


    if ('x' in item) {
        item.x = item.x * ratio;
    }

    if ('y' in item) {
        item.y = item.y * ratio;
    }

    if ('width' in item) {
        item.width = item.width * ratio;
    }

    if ('height' in item) {
        item.height = item.height * ratio;
    }

    if ('radius' in item) {
        item.radius = item.radius * ratio;
    }

    if ('data_zPosition' in item) {
        item.data_zPosition = round(item.data_zPosition * ratio);
    }

    if ('data_vHeight' in item) {
        item.data_vHeight = round(item.data_vHeight * ratio);
    }

    if ('data_trapNarrowWidth' in item && !isNaN(item.data_trapNarrowWidth)) {
        item.data_trapNarrowWidth = round(item.data_trapNarrowWidth * ratio);
    }

    if ('tblRectRadiusRight' in item) {
        item.tblRectRadiusRight = round(item.tblRectRadiusRight * ratio);
    }

    if ('tblRectRadius' in item) {
        item.tblRectRadius = round(item.tblRectRadius * ratio);
    }

    if ('points' in item && item.points) {
        item.points.forEach((point, index) => {
            item.points[index] = round(point * ratio);
        });
    }

    return item;

}

function getQueryString() {

    const queryString = window.location.search;
    const urlParams = new URLSearchParams(queryString);
    roomName = urlParams.get('roomName');
    roomName = DOMPurify.sanitize(roomName);
    roomObj.name = roomName;

    if (urlParams.has('x')) {
        let x = urlParams.get('x');
        parseShortenedXYUrl(x);

        keepDefaultUnit();

        drawRoom(true, true, false);

        roomLoadedFromXQuery = true;
    }

    else if (urlParams.has('ver')) {
        if (urlParams.has('ver')) versionQueryString = DOMPurify.sanitize(urlParams.get('ver'));

        lastAction = 'load from querystring';

        if (!(versionQueryString == version)) {
            versionQueryString = DOMPurify.sanitize(versionQueryString);
            lastAction = "redirect to " + versionQueryString;
        }
    } else {
        loadTemplate('A1v0b2600c2000B100100'); /* create a default */
        openNewRoomDialog();
    }

    /* Legacy Google URL redirect — block auto-redirect but still support older formats. */
    let googleWrongUrl = "https://collabexperience.com/?drpMetersFeet=feet&roomWidth=12&roomLength=20&tableWidth=4&tableLength=10&distDisplayToTable=5&frntWallToTv=0.5&tvDiag=65&drpTvNum=1&drpVideoDevice=roomBarPro&wideFOV=112&teleFOV=70&zoom=5&fieldOfViewDist=5&roomName=";

    if ((urlParams.has('roomWidth')) && window.location.href != googleWrongUrl) {
        responseRedirect('rc/v0.1.599/RoomCalculator.html'); /* redirect version v0.1.599 is just to update querystring values and then redirect back to the current version */
    }

    function responseRedirect(newPath) {
        let redirectLink = location.origin + '/' + newPath + '?' + queryString.replace(/^\?/, '');
        window.location.href = redirectLink;
    }

    if (urlParams.has('qr')) {
        qrCodeButtonsVisible = true;
        qrCodeAlwaysOn = true;
        makeButtonsVisible();
    }

    if (urlParams.has('test')) {
        let testValue = urlParams.get('test');
        if (testValue === '' || testValue == 1 || testValue == 'on') {
            console.info('test in querystring. Test fields shown.  Test fields are highly experimental and unstable.');
            if (document.getElementById('test')) {
                document.getElementById('test').setAttribute('style', 'visibility: visible;');
            }

            setItemForLocalStorage('test', 'true');
        }
        else if (testValue == '0' || testValue === 'off') {
            console.info('"test" fields are turned off and the setting is removed from local storage');
            localStorage.removeItem('test');
        }

    } else if (localStorage.getItem('test') === 'true') {

        if (document.getElementById('test')) {
            document.getElementById('test').setAttribute('style', 'visibility: visible;');
        }

    }

    /* ?debug=1: fps/item/node overlay; persisted in localStorage. */
    const QS_DEBUG = (window.VRC && VRC.constants && VRC.constants.QS_DEBUG) || 'debug';
    if (urlParams.has(QS_DEBUG)) {
        const debugValue = urlParams.get(QS_DEBUG);
        if (debugValue === '' || debugValue == 1 || debugValue == 'on') {
            setItemForLocalStorage('debug', 'true');
            debugOverlayEnable();
        } else if (debugValue == '0' || debugValue === 'off') {
            localStorage.removeItem('debug');
            debugOverlayDisable();
        }
    } else if (localStorage.getItem('debug') === 'true') {
        debugOverlayEnable();
    }

    /* simulate RoomOS for testing only */
    if (urlParams.has('RoomOS') || urlParams.has('roomos')) {
        mobileDevice = 'RoomOS';
    }

    if (urlParams.has('tesla') || urlParams.has('Tesla')) {
        mobileDevice = 'Tesla';
    }

    /* RoomOS does not support the Workspace Designer cross-launch */

    if ((mobileDevice === 'RoomOS')) {
        loadDrpDownOverrideScript();
        testiFrame = true;
        newWorkspaceTab = defaultWorkspaceTestSite;
        testNew = true;
    }
    else if ((mobileDevice === 'Tesla')) {
        loadDrpDownOverrideScript();
        document.getElementById('testA').setAttribute('style', 'visibility: visible;');
        document.getElementById('testB').style.display = '';
    } else {
        document.getElementById('testA').setAttribute('style', 'visibility: visible;');
        document.getElementById('testB').style.display = '';
    }


    if (urlParams.has('testProduction')) {
        testProduction = true;
    }

    if (urlParams.has('offset')) {
        testOffset = true;
    }

    if (urlParams.has('testNew')) {
        let testNewQueryString = urlParams.get('testNew');
        if (testNewQueryString == '0') {
            console.info('urlParams testNew=0, new feature test is off');
            testNew = false;
            localStorage.removeItem('testNew');
        }
        else {

            setItemForLocalStorage('testNew', 'true');
            testNew = true;
        }
    } else {
        if (localStorage.getItem('testNew') === 'true') {
            testNew = true;
        } else {
            testNew = false;
            localStorage.removeItem('testNew');
        }
    }




    if (urlParams.has('testiFrame')) {
        let testiFrameQueryString = urlParams.get('testiFrame');
        if (testiFrameQueryString == '0') {
            console.info('urlParams testiFramee=0, new feature test is off');
            testiFrame = false;
            localStorage.removeItem('testiFrame');
        }
        else {

            setItemForLocalStorage('testiFrame', 'true');
            testiFrame = true;
        }
    } else {
        if (localStorage.getItem('testiFrame') === 'true') {
            testiFrame = true;
        } else {
            testiFrame = false;
        }
    }

    if (testiFrame) {
        console.info('Testing iFrame is turned On. To turn off use ?testiFrame=0');

    }

    /* WD site: ?wd= > drpWdSite dropdown > localStorage.wd — all via applyWdSiteSelection(). */
    if (urlParams.has('wd')) {
        const wd = urlParams.get('wd');
        if (wd == '0') {
            console.info('urlParams wd=0, custom Workspace Designer tab is turned off');
            applyWdSiteSelection('default');
        } else if (wd === '1') {
            applyWdSiteSelection('default');
            testNew = false;
            setItemForLocalStorage('testNew', testNew);
            console.info('urlParams wd=1, Workspace Designer reset to default site.');
        } else {
            const base = decodeURIComponent(wd);                /* ?wd=https%3A%2F%2Flocalhost%3A3000 */
            const mode = detectWdSiteMode(base);
            if (mode === 'default') {
                applyWdSiteSelection('default');
            } else if (mode === 'beta') {
                applyWdSiteSelection('beta');
            } else {
                applyWdSiteSelection('custom', base);
            }
            setItemForLocalStorage('testNew', testNew);
            console.info('urlParams wd=', workspaceDesignerTestUrl, 'custom Workspace Designer tab is set.');
        }
    } else {
        const stored = localStorage.getItem('wd');
        const mode = detectWdSiteMode(stored);
        if (mode === 'beta') {
            applyWdSiteSelection('beta');
        } else if (mode === 'custom') {
            const display = String(stored).replace(/\/?#\/room\/custom$/, '');
            applyWdSiteSelection('custom', display);
        } else {
            applyWdSiteSelection('default');
        }
    }

    preloadWdCustomFromStorage();

    if (urlParams.has('test2')) {
        console.info('test2 in querystring. Test & test2 fields shown.  Try fields are works in progress, highly experimental and unstable.');
    }


    setTimeout(() => {
        canvasToJson();
    }, 1000)

}

function parseShortenedXYUrl(parameters) {

    let output = []; /* parameter object - an intermedidate step to create a param */

    function isUpperCaseLetter(character) {
        return /[A-Z_]/.test(character);
    }

    function isLowerCaseLetter(character) {
        return /[a-z]/.test(character);
    }

    function isNumberLike(character) {   /* includes numbers and version numbers.  For example: 2, 0.05, -2, 0.1.1.2 or a series of numbers separarted by a space*/
        return /[\-.0-9+ ]/.test(character);
    }

    let i = 0;

    let objCount = 0;

    const charType = {
        Start: 0,
        CapLetter: "CapLetter",
        CapNum: "CapNum",
        LowLetter: "LowLetter",
        LowNum: "LowNum",
        OpenTilde: "OpenTilde",
        BetweenTilde: "BetweenTilde",
        EndTilde: "EndTilde",
        OpenLowLetterTilde: "OpenLowLetterTilde",
        BetweenLowLetterTilde: "BetweenLowLetterTilde",
        EndLowLetterTilde: "EndLowLetterTilde"
    }

    let lastCharType = charType.Start;

    let strBldrLowerCase = '';

    let lowerCaseLetters = '';

    while (i < parameters.length) {
        let char = parameters[i];
        if (char === '_' && (lastCharType != charType.BetweenTilde)) {  /* represents a repeat of the last Capital Letter used. */
            deleteBlankDotKeys(output[objCount]);
            repeateStringItem = true;
            output.push(structuredClone(output[objCount]));
            objCount += 1;
            lastCharType = charType.CapLetter;
        }
        else if (lastCharType === charType.Start) {
            if (isUpperCaseLetter(char)) {
                output.push({ "sid": char });
                lastCharType = charType.CapLetter;
            } else {
                console.error('Error parsing Short XY Parameter.  lastChar === chartType.Start but next character is not UpperCase.  Current character: ', char);
            }
        }
        else if (isUpperCaseLetter(char) && lastCharType === charType.CapLetter) {
            output[objCount].sid += char;
            lastCharType = charType.CapLetter;
        }
        else if (isNumberLike(char) && lastCharType === charType.CapLetter) {
            output[objCount].value = char;
            lastCharType = charType.CapNum;
        }
        else if (isNumberLike(char) && lastCharType === charType.CapNum) {
            output[objCount].value += char;
            lastCharType = charType.CapNum;
        }
        else if (isLowerCaseLetter(char) && lastCharType != charType.LowLetter && lastCharType != charType.BetweenTilde && lastCharType != charType.OpenTilde && lastCharType != charType.OpenLowLetterTilde && lastCharType != charType.BetweenLowLetterTilde) {

            strBldrLowerCase = char;
            lastCharType = charType.LowLetter;
        }
        else if (isLowerCaseLetter(char) && lastCharType === charType.LowLetter) {

            strBldrLowerCase += char;
            lastCharType = charType.LowLetter;
        }
        else if (isNumberLike(char) && lastCharType === charType.LowLetter) {
            lowerCaseLetters = strBldrLowerCase;
            strBldrLowerCase = '';
            output[objCount][lowerCaseLetters] = char;
            lastCharType = charType.LowNum;
        }
        else if (isNumberLike(char) && lastCharType === charType.LowNum) {
            output[objCount][lowerCaseLetters] += char;
            lastCharType = charType.LowNum;
        }
        else if (char === '~' && lastCharType === charType.LowLetter) {
            lastCharType = charType.OpenLowLetterTilde;

        }
        else if (char === '~' && lastCharType != charType.BetweenTilde && lastCharType != charType.BetweenLowLetterTilde && lastCharType != charType.OpenTilde && lastCharType != charType.OpenLowLetterTilde) {
            lastCharType = charType.OpenTilde;

        }
        else if (lastCharType === charType.OpenLowLetterTilde && char != '~') {
            lowerCaseLetters = strBldrLowerCase;
            strBldrLowerCase = '';
            output[objCount][lowerCaseLetters] = char;
            lastCharType = charType.BetweenLowLetterTilde;

        }
        else if (lastCharType === charType.OpenTilde && char != '~') {
            output[objCount].text = char;
            lastCharType = charType.BetweenTilde;

        }
        else if (lastCharType === charType.BetweenLowLetterTilde && char != '~') {
            output[objCount][lowerCaseLetters] += char;
            lastCharType = charType.BetweenLowLetterTilde;

        }
        else if (lastCharType === charType.BetweenTilde && char != '~') {
            output[objCount].text += char;
            lastCharType = charType.BetweenTilde;

        }
        else if ((lastCharType === charType.OpenLowLetterTilde || lastCharType === charType.OpenTilde) && char === '~') {
            output[objCount].text = "";
            lastCharType = charType.EndTilde;

        }
        else if ((lastCharType === charType.BetweenTilde || lastCharType === charType.BetweenLowLetterTilde) && char === '~') {
            lastCharType = charType.EndTilde;

        }
        else if (isUpperCaseLetter(char) && lastCharType != charType.CapLetter && lastCharType != charType.BetweenTilde && lastCharType != charType.BetweenLowLetterTilde) {

            if (Object.keys(output[objCount]).length === 1) {
                output[objCount].value = strBldrLowerCase;
                strBldrLowerCase = '';
            }
            output.push({ "sid": char });
            objCount += 1;
            lastCharType = charType.CapLetter;
        }
        if ((parameters.length - 1) === i && Object.keys(output[objCount]).length === 1) {
            output[objCount].value = strBldrLowerCase;
        }

        i += 1;


    }

    deleteBlankDotKeys(output[objCount]);

    /* deleteBlankDotKeys: t==='.' sentinel (was assignment bug). */
    function deleteBlankDotKeys(outputObj) {

        if (outputObj.t === '.') {
            delete outputObj.t;
            delete outputObj.text;
        }

        for (const [key, value] of Object.entries(outputObj)) {
            if (value === '.') {
                delete outputObj[key];

            }
        }
    }

    output.forEach((item) => {

        if (item.sid === "A") {
            if ('text' in item) {
                roomObj.name = DOMPurify.sanitize(item.text);
            }

            if ('value' in item) {
                if ((item.value === '1')) {
                    roomObj.unit = 'feet';
                }
                else if (item.value === '0') {
                    roomObj.unit = 'meters'
                }
            }

            if ('b' in item) {
                roomObj.room.roomWidth = item.b / 100;
            }

            if ('c' in item) {
                roomObj.room.roomLength = item.c / 100;
            }

            if ('f' in item) {
                roomObj.room.roomHeight = round(item.f / 100);
            }

            if ('e' in item) {
                if (item.e == "0") {
                    roomObj.software = 'webex';
                } else if (item.e == '1') {
                    roomObj.software = 'mtr'
                }
            }

        }
        else if (item.sid === "B") {
            if ('value' in item) {
                let value = item.value;
                let shadeArray = value.split('');


                if (shadeArray[0] == '1') {
                    roomObj.overlaysVisible.cameraCoverage = true;
                } else {
                    roomObj.overlaysVisible.cameraCoverage = false;
                }

                if (shadeArray[1] == '1') {
                    roomObj.overlaysVisible.displayDistanceCoverage = true;
                } else {
                    roomObj.overlaysVisible.displayDistanceCoverage = false;
                }

                if (shadeArray[2] == '1') {
                    roomObj.overlaysVisible.microphoneCoverage = true;
                } else {
                    roomObj.overlaysVisible.microphoneCoverage = false;
                }

                if (shadeArray[3] == '1') {
                    roomObj.overlaysVisible.gridLines = true;
                } else {
                    roomObj.overlaysVisible.gridLines = false;
                }

                if (shadeArray[4] == '1') {
                    roomObj.workspace.addCeiling = true;
                } else {
                    roomObj.workspace.addCeiling = false;
                }

                if (shadeArray[5] == '1') {
                    roomObj.workspace.removeDefaultWalls = true;
                } else {
                    roomObj.workspace.removeDefaultWalls = false;
                }

                if (shadeArray[6] == '1') {
                    roomObj.overlaysVisible.overlayLabels = true;
                } else {
                    roomObj.overlaysVisible.overlayLabels = false;
                }

                if (shadeArray[7] == '1') {
                    roomObj.overlaysVisible.speakerCoverage = true;
                } else {
                    roomObj.overlaysVisible.speakerCoverage = false;
                }

                if (shadeArray[8] === '1') {
                    /* roomObj.workspace.theme = 'christmas'; */
                    roomObj.workspace.theme = 'regular';
                } else {
                    roomObj.workspace.theme = 'regular';
                }


            }

        } else if (item.sid === "C") { /* authorVersion */
            if ('text' in item) {
                roomObj.authorVersion = DOMPurify.sanitize(item.text);
            }
        }
        else if (item.sid === "L" && 'value' in item) {
            const urlNum = parseInt(item.value, 10);
            if (!isNaN(urlNum)) {
                const visible = !('v' in item && item.v === '0');
                const locked = ('k' in item && item.k === '1');
                if (!roomObj.layers) roomObj.layers = getDefaultLayers();

                if (urlNum === 0 || urlNum === 1) {
                    const reservedId = String(urlNum);
                    const reserved = roomObj.layers.find(l => l.layerid === reservedId);
                    if (reserved) {
                        reserved.visible = visible;
                        reserved.locked = locked;
                    }
                } else if (urlNum >= 20) {
                    const layerName = DOMPurify.sanitize('text' in item ? decodeURIComponent(item.text.replaceAll('+', ' ')) : 'Layer ' + urlNum);
                    let existing = roomObj.layers.find(l => l._urlNum === urlNum);
                    if (existing) {
                        existing.name = layerName;
                        existing.visible = visible;
                        existing.locked = locked;
                    } else {
                        roomObj.layers.push({ name: layerName, visible: visible, locked: locked, layerid: createUuid(), _urlNum: urlNum });
                    }
                }
            }
        }
        else if (item.sid === "H" && 'value' in item) {
            /* H{n}: group geometry; members from item s{n}. */
            const grpUrlNum = parseInt(item.value, 10);
            if (!isNaN(grpUrlNum) && grpUrlNum > 0) {
                ensureGroups(roomObj);

                const grpName = DOMPurify.sanitize(
                    'text' in item
                        ? decodeURIComponent(item.text.replaceAll('+', ' ')) 
                        : ''
                );

                let grpLayerId = '0';
                if ('ll' in item) {
                    const layerUrlNum = parseInt(item.ll, 10);
                    if (layerUrlNum === 1) {
                        grpLayerId = '1';
                    } else if (layerUrlNum >= 20) {
                        if (!roomObj.layers) roomObj.layers = getDefaultLayers();
                        let matchedLayer = roomObj.layers.find(l => l._urlNum === layerUrlNum);
                        if (!matchedLayer) {
                            matchedLayer = { name: 'Layer ' + layerUrlNum, visible: true, locked: false, layerid: createUuid(), _urlNum: layerUrlNum };
                            roomObj.layers.push(matchedLayer);
                        }
                        grpLayerId = matchedLayer.layerid;
                    }
                }

                const grpRotation = ('f' in item) ? (parseInt(item.f, 10) / 10) : 0;
                const grpX        = ('x' in item) ? (parseInt(item.x, 10) / 100) : 0;
                const grpY        = ('y' in item) ? (parseInt(item.y, 10) / 100) : 0;
                const grpZ        = ('z' in item) ? (parseInt(item.z, 10) / 100) : 0;
                const grpW        = ('w' in item) ? (parseInt(item.w, 10) / 100) : 0;
                const grpH        = ('h' in item) ? (parseInt(item.h, 10) / 100) : 0;

                let existingGroup = roomObj.groups.find(g => g._urlNum === grpUrlNum);
                if (existingGroup) {
                    existingGroup.name = grpName;
                    existingGroup.data_layerId = grpLayerId;
                    existingGroup.rotation = grpRotation;
                    existingGroup.x = grpX;
                    existingGroup.y = grpY;
                    existingGroup.data_zPosition = grpZ;
                    existingGroup.width = grpW;
                    existingGroup.height = grpH;
                } else {
                    roomObj.groups.push({
                        groupid: createUuid(),
                        name: grpName,
                        data_layerId: grpLayerId,
                        x: grpX,
                        y: grpY,
                        width: grpW,
                        height: grpH,
                        rotation: grpRotation,
                        data_zPosition: grpZ,
                        groupMembers: [],
                        _urlNum: grpUrlNum,
                    });
                }
            }
        }
        else if (item.sid === "J" && 'value' in item) {
            const cUrlNum = parseInt(item.value, 10);
            if (!isNaN(cUrlNum) && cUrlNum > 0) {
                ensureCustomItems(roomObj);

                const cName = DOMPurify.sanitize(
                    'text' in item
                        ? decodeURIComponent(item.text.replaceAll('+', ' '))
                        : ''
                );

                let cLayerId = '0';
                if ('ll' in item) {
                    const layerUrlNum = parseInt(item.ll, 10);
                    if (layerUrlNum === 1) {
                        cLayerId = '1';
                    } else if (layerUrlNum >= 20) {
                        if (!roomObj.layers) roomObj.layers = getDefaultLayers();
                        let matchedLayer = roomObj.layers.find(l => l._urlNum === layerUrlNum);
                        if (!matchedLayer) {
                            matchedLayer = { name: 'Layer ' + layerUrlNum, visible: true, locked: false, layerid: createUuid(), _urlNum: layerUrlNum };
                            roomObj.layers.push(matchedLayer);
                        }
                        cLayerId = matchedLayer.layerid;
                    }
                }

                const cRotation = ('f' in item) ? (parseInt(item.f, 10) / 10) : 0;
                const cX        = ('x' in item) ? (parseInt(item.x, 10) / 100) : 0;
                const cY        = ('y' in item) ? (parseInt(item.y, 10) / 100) : 0;
                const cZ        = ('z' in item) ? (parseInt(item.z, 10) / 100) : 0;
                const cW        = ('w' in item) ? (parseInt(item.w, 10) / 100) : 0;
                const cH        = ('h' in item) ? (parseInt(item.h, 10) / 100) : 0;

                let existingCustomItem = roomObj.customItems.find(c => c._urlNum === cUrlNum);
                if (existingCustomItem) {
                    existingCustomItem.name = cName;
                    existingCustomItem.data_layerId = cLayerId;
                    existingCustomItem.rotation = cRotation;
                    existingCustomItem.x = cX;
                    existingCustomItem.y = cY;
                    existingCustomItem.data_zPosition = cZ;
                    existingCustomItem.width = cW;
                    existingCustomItem.height = cH;
                } else {
                    roomObj.customItems.push({
                        customitemid: createUuid(),
                        name: cName,
                        data_layerId: cLayerId,
                        x: cX,
                        y: cY,
                        width: cW,
                        height: cH,
                        rotation: cRotation,
                        data_zPosition: cZ,
                        customItemMembers: [],
                        _urlNum: cUrlNum,
                    });
                }
            }
        }
        else if (item.sid === "D" || item.sid === "E" || item.sid === "F" || item.sid === "G") {
            let roomSurface = {};
            let wall;

            if ('value' in item) {
                if (item.value === '0') {
                    roomSurface.type = 'regular';
                }
                else if (item.value === '1') {
                    roomSurface.type = 'glass';
                }
                else if (item.value === '2') {
                    roomSurface.type = 'window';
                }
            }

            if ('a' in item) {
                if (item.a === '0') {
                    roomSurface.acousticTreatment = false;
                }
                else if (item.a === '1') {
                    roomSurface.acousticTreatment = true;
                }
            }

            if ('b' in item) {
                if (item.b === '0') {
                    roomSurface.door = 'left';
                }
                else if (item.b === '1') {
                    roomSurface.door = 'center';
                }
                else if (item.b === '2') {
                    roomSurface.door = 'right';
                }
            }

            if (item.sid === "D") {
                wall = 'leftwall';
            } else if (item.sid === 'E') {
                wall = 'rightwall';
            } else if (item.sid === 'F') {
                wall = 'videowall';
            } else if (item.sid === 'G') {
                wall = 'backwall';
            }

            roomObj.roomSurfaces[wall] = roomSurface;
        }

        if (item.sid in keyIdObj) {

            let newItem = {};

            newItem.data_deviceid = keyIdObj[item.sid].data_deviceid;

            newItem.name = keyIdObj[item.sid].name;

            newItem.width = keyIdObj[item.sid].width / 1000;
            newItem.height = keyIdObj[item.sid].height / 1000;


            roomObj.items.push(newItem);

            if (roomObj.unit === 'feet') {
                newItem.width = newItem.width * 3.28084;
                newItem.height = newItem.height * 3.28084;
            }

            if ('value' in item) {
                newItem.x = item.value / 100;

            }

            if ('a' in item) {
                newItem.y = item.a / 100;
            }

            if ('b' in item) {
                newItem.data_zPosition = item.b / 100;
            }

            if ('c' in item) {
                newItem.width = item.c / 100;
            }

            if ('d' in item) {
                newItem.length = item.d / 100;
            }

            if ('e' in item) {
                newItem.height = item.e / 100;
            }

            if ('f' in item) {
                newItem.rotation = item.f / 10;
            } else {
                newItem.rotation = 0;
            }

            if ('g' in item) {
                newItem.data_diagonalInches = item.g;
            }

            if ('h' in item) {
                newItem.tblRectRadius = item.h / 100;
            }

            if ('i' in item) {
                newItem.tblRectRadiusRight = item.i / 100;
            }

            if ('j' in item) {
                newItem.data_vHeight = item.j / 100;
            } else {
                newItem.data_vHeight = "";
            }

            if ('k' in item) {
                newItem.data_trapNarrowWidth = item.k / 100;
            }

            if ('l' in item) {
                populateRoleFromUrl(newItem, item.l);
            } else {
                populateRoleFromUrl(newItem);
            }

            if ('m' in item) {
                populateColorFromUrl(newItem, item.m);
            } else {
                populateColorFromUrl(newItem);
            }

            if ('n' in item) {
                parseShadingDecimalToBinary(newItem, item.n);
            }

            if ('o' in item) {
                newItem.data_tilt = item.o / 10;
            }

            if ('p' in item) {
                newItem.data_slant = item.p / 10;
            }

            if ('q' in item) {
                populateMountFromUrl(newItem, item.q);
            } else {
                populateMountFromUrl(newItem);
            }

            if ('r' in item) {
                newItem.points = parseUrlPoints(item.r)
            }

            if ('ll' in item) {
                const urlNum = parseInt(item.ll, 10);
                if (urlNum === 1) {
                    newItem.data_layerId = '1';
                } else {
                    const matchedLayer = roomObj.layers ? roomObj.layers.find(l => l._urlNum === urlNum) : null;
                    if (matchedLayer) {
                        newItem.data_layerId = matchedLayer.layerid;
                    } else {
                        const fallbackLayer = { name: 'Layer ' + urlNum, visible: true, locked: false, layerid: createUuid(), _urlNum: urlNum };
                        if (!roomObj.layers) roomObj.layers = getDefaultLayers();
                        roomObj.layers.push(fallbackLayer);
                        newItem.data_layerId = fallbackLayer.layerid;
                    }
                }
            }

            if ('s' in item) {
                const grpUrlNum = parseInt(item.s, 10);
                if (!isNaN(grpUrlNum) && grpUrlNum > 0) {
                    ensureGroups(roomObj);
                    let matchedGroup = roomObj.groups.find(g => g._urlNum === grpUrlNum);
                    if (!matchedGroup) {
                        matchedGroup = {
                            groupid: createUuid(),
                            data_layerId: '0',
                            x: 0, y: 0, width: 0, height: 0,
                            rotation: 0,
                            data_zPosition: 0,
                            groupMembers: [],
                            _urlNum: grpUrlNum,
                        };
                        roomObj.groups.push(matchedGroup);
                    }
                    newItem.data_groupId = matchedGroup.groupid;
                    if (!('ll' in item)) {
                        newItem.data_layerId = matchedGroup.data_layerId;
                    }
                }
            }

            if ('t' in item) {
                const cUrlNum = parseInt(item.t, 10);
                if (!isNaN(cUrlNum) && cUrlNum > 0) {
                    ensureCustomItems(roomObj);
                    let matchedCustomItem = roomObj.customItems.find(c => c._urlNum === cUrlNum);
                    if (!matchedCustomItem) {
                        matchedCustomItem = {
                            customitemid: createUuid(),
                            data_layerId: '0',
                            x: 0, y: 0, width: 0, height: 0,
                            rotation: 0,
                            data_zPosition: 0,
                            customItemMembers: [],
                            _urlNum: cUrlNum,
                        };
                        roomObj.customItems.push(matchedCustomItem);
                    }
                    newItem.data_customItemId = matchedCustomItem.customitemid;
                    if (!('ll' in item) && !('s' in item)) {
                        newItem.data_layerId = matchedCustomItem.data_layerId;
                    }
                }
            }

            if ('u' in item) {
                newItem.data_fill = urlRgbToHex(String(item.u));
            }
            if ('v' in item) {
                const opNum = parseInt(item.v, 10);
                if (!isNaN(opNum) && opNum >= 0 && opNum < 100) {
                    newItem.data_opacity = opNum / 100;
                }
            }

            if ('text' in item) {
                newItem.data_labelField = DOMPurify.sanitize(item.text);
            }

            newItem.id = createUuid();


        }


    })

    if (roomObj.groups && roomObj.groups.length) {
        roomObj.groups.forEach(g => { g.groupMembers = []; });

        roomObj.items.forEach(it => {
            if (!it.data_groupId) return;
            const g = roomObj.groups.find(grp => grp.groupid === it.data_groupId);
            if (g) g.groupMembers.push(it.id);
        });

        roomObj.groups = roomObj.groups.filter(g => g.groupMembers && g.groupMembers.length);
    }

    if (roomObj.customItems && roomObj.customItems.length) {
        roomObj.customItems.forEach(c => { c.customItemMembers = []; });

        roomObj.items.forEach(it => {
            if (!it.data_customItemId) return;
            const c = roomObj.customItems.find(cit => cit.customitemid === it.data_customItemId);
            if (c) c.customItemMembers.push(it.id);
        });

        roomObj.customItems = roomObj.customItems.filter(c => c.customItemMembers && c.customItemMembers.length);

        ensureCustomItemBaseIds();
    }

    return output;

}

function parseUrlPoints(itemPoints) {
    const points = itemPoints.split(' ');

    const newPoints = points.map(point => {
        return point / 100;
    });

    return newPoints;
}

