/* converts lowerCase letters (base26) to discrete binary number */
function base26ToBinaryString(characters) {
    let letterArray = characters.split('');
    letterArray.reverse();
    let decimalNumber = 0;
    let base = 26;
    letterArray.forEach((char, index) => {
        decimalNumber = ((char.charCodeAt(0) - 97) * base ** index) + decimalNumber;
    })
    let binary = decimalNumber.toString(2);
    let binaryString = binary.toString();

    while (binaryString.length < 8) {
        binaryString = '0' + binaryString;
    }
    return binaryString;
}

function binaryToBase26(binary) {
    let array = createTable();

    let letters;
    array.forEach(entry => {
        if (Number(entry[1]) == Number(binary)) {
            letters = entry[0];
        }
    });

    return letters;

    function createTable() {

        alphabet = 'abcdefghijklmnopqrstuvwxyz';
        let alphaArray = alphabet.split('');
        let array = [];
        let i = 0;

        alphaArray.forEach(outerLetter => {
            alphaArray.forEach((letter) => {
                let fullLetter = outerLetter + letter;
                let txtBinary = base26ToBinaryString(fullLetter);
                array[i] = [fullLetter, txtBinary];
                i++;
            })
        });
        return array;
    }
};



/* Boot: hydrate undo/redo from IDB, then onLoad(). Empty stack if IDB unavailable. */
(function bootHydrateThenOnLoad() {
    const idbReady = (typeof window !== 'undefined' && window.idbStore && typeof window.idbStore.hydrateUndoRedoFromIdb === 'function')
        ? window.idbStore.hydrateUndoRedoFromIdb()
        : Promise.resolve({ undo: [], redo: [], priorHadData: false });

    if (typeof hydrateCustomItemLibraryIds === 'function') {
        hydrateCustomItemLibraryIds();
    }

    idbReady.then(function (state) {
        undoArray = Array.isArray(state.undo) ? state.undo : [];
        redoArray = Array.isArray(state.redo) ? state.redo : [];
        priorUndoArrayHasData = !!state.priorHadData;

        const hasLegacy = (arr) => arr.some(e => e && e.items
            && !Array.isArray(e.items)
            && typeof e.items === 'object');
        const migrateAll = () => {
            undoArray.forEach(e => window.VRC.migrateLegacyItemsShape(e));
            redoArray.forEach(e => window.VRC.migrateLegacyItemsShape(e));
        };
        const needsMigration = hasLegacy(undoArray) || hasLegacy(redoArray);

        /* Recompute priorUndoArrayHasData from item content (IDB priorHadData is over-broad on empty boot snapshots). */
        const refinePriorHadData = () => {
            priorUndoArrayHasData = undoArray.some(e => e && roomObjHasAnyItems(e));
        };

        /* Normalize overlaysVisible on hydrated undo/redo snapshots. */
        const normalizeAllOverlays = () => {
            undoArray.forEach(ensureOverlaysVisibleDefaulted);
            redoArray.forEach(ensureOverlaysVisibleDefaulted);
        };

        const finishBoot = () => {
            normalizeAllOverlays();
            refinePriorHadData();
            onLoad();
            if (typeof rehydrateBackgroundImageFromIdb === 'function') {
                setTimeout(function () { rehydrateBackgroundImageFromIdb(); }, 250);
            }
        };

        if (needsMigration) {
            if (typeof window.VRC?.migrateLegacyItemsShape === 'function') {
                migrateAll();
                finishBoot();
            } else {
                loadScriptOnce(VRC.constants.SCRIPT_MIGRATE_LEGACY_ITEMS).then(() => {
                    migrateAll();
                    finishBoot();
                }).catch(() => {
                    finishBoot();
                });
            }
        } else {
            finishBoot();
        }
    }).catch(function (err) {
        console.warn('IDB hydrate failed; starting with empty undo/redo:', err && err.message);
        undoArray = [];
        redoArray = [];
        priorUndoArrayHasData = false;
        onLoad();
    });
})();


