function createShareableLink() {

    if (itemCount > 750) {
        fullShareLink = 'https://collabexperience.com/'
        fullShareLink = location.origin + location.pathname;
        document.getElementById('shareLink').style.display = 'none'
        return;
    }

    listItemsOffStage();
    let strUrlQuery2;
    strUrlQuery2 = `A${roomObj.unit == 'feet' ? '1' : '0'}`;
    strUrlQuery2 += `${roomObj.version || version}`;
    strUrlQuery2 += `b${expand(roomObj.room.roomWidth)}c${expand(roomObj.room.roomLength)}`;

    if (roomObj.software === 'webex') {
        strUrlQuery2 += `e0`;
    }
    else if (roomObj.software === 'mtr') {
        strUrlQuery2 += 'e1';
    }


    if (!(roomObj.room.roomHeight == 0 || roomObj.room.roomHeight == '')) {
        strUrlQuery2 += 'f' + Math.round(roomObj.room.roomHeight * 100);
    }

    strUrlQuery2 += `${roomObj.name == '' ? '' : '~' + encodeURIComponent(roomObj.name.replace(/^[\s_]+|[\s_]+$/g, '')).replaceAll('%20', '+') + '~'}`;


    strUrlQuery2 += createShareableLinkItemShading();

    strUrlQuery2 += `${roomObj.authorVersion == '' ? '' : 'C~' + encodeURIComponent(roomObj.authorVersion).replaceAll('%20', '+') + '~'}`;

    if ('roomSurfaces' in roomObj) {

        ['leftwall', 'rightwall', 'videowall', 'backwall'].forEach(wall => {
            let strWall = '';
            if (wall in roomObj.roomSurfaces) {
                if ('type' in roomObj.roomSurfaces[wall]) {
                    if (roomObj.roomSurfaces[wall].type === 'regular') {
                        strWall += '0';
                    }
                    else if (roomObj.roomSurfaces[wall].type === 'glass') {
                        strWall += '1';
                    }
                    else if (roomObj.roomSurfaces[wall].type === 'window') {
                        strWall += '2';
                    } else {
                        strWall += '0';
                    }
                }

                if ('acousticTreatment' in roomObj.roomSurfaces[wall]) {
                    if (roomObj.roomSurfaces[wall].acousticTreatment === true) {
                        strWall += 'a1';
                    }
                }

                if ('door' in roomObj.roomSurfaces[wall] && roomObj.roomSurfaces[wall] != 'none') {
                    strWall += 'b';
                    if (roomObj.roomSurfaces[wall].door === 'left') {
                        strWall += '0';
                    }
                    else if (roomObj.roomSurfaces[wall].door === 'center') {
                        strWall += '1';
                    }
                    else if (roomObj.roomSurfaces[wall].door === 'right') {
                        strWall += '2';
                    }
                    else {
                        strWall += '1'; /* default to center of wall for door */
                    }

                }

                if (strWall != '0') {  /* if it is just a regular wall, don't save anything to the URL */
                    if (wall === 'leftwall') {
                        strWall = 'D' + strWall;
                    }
                    else if (wall === 'rightwall') {
                        strWall = 'E' + strWall;
                    }
                    else if (wall === 'videowall') {
                        strWall = 'F' + strWall;
                    }
                    else if (wall === 'backwall') {
                        strWall = 'G' + strWall;
                    }

                    strUrlQuery2 += strWall;
                }

            }
        })
    }

    /* L0/L1 reserved layers: omit from URL when visible+unlocked (parser assumes defaults). */
    if (roomObj.layers) {
        roomObj.layers.forEach(layer => {
            if (layer.layerid === '0' || layer.layerid === '1') {
                if (!layer.visible || layer.locked) {
                    let layerStr = 'L' + layer.layerid;
                    if (!layer.visible) layerStr += 'v0';
                    if (layer.locked) layerStr += 'k1';
                    strUrlQuery2 += layerStr;
                }
            }
        });
    }

    /* build layerId → URL number map for custom layers (skip '0'=Default and '1'=Ceiling) */
    _layerUrlEncodeMap = {};
    let urlLayerNum = 20;
    if (roomObj.layers && roomObj.layers.length > 2) {
        roomObj.layers.forEach(layer => {
            if (layer.layerid !== '0' && layer.layerid !== '1') {
                _layerUrlEncodeMap[layer.layerid] = urlLayerNum;
                /* encode: L{num}[v0][k1]~name~ */
                let layerStr = 'L' + urlLayerNum;
                if (!layer.visible) layerStr += 'v0';
                if (layer.locked) layerStr += 'k1';
                layerStr += '~' + encodeURIComponent(layer.name).replaceAll('%20', '+') + '~';
                strUrlQuery2 += layerStr;
                urlLayerNum++;
            }
        });
    }

    /* H{n} group blocks: explicit bounds (async image load breaks member-derived bounds on first frame). Emit after L{n}, before items. */
    _groupUrlEncodeMap = {};
    _customItemUrlEncodeMap = {};
    if (roomObj.groups && roomObj.groups.length) {
        const groupsWithMembers = new Set();
        roomObj.items.forEach(it => {
            if (it.data_groupId) groupsWithMembers.add(it.data_groupId);
        });
        let urlGroupNum = 1;
        roomObj.groups.forEach(group => {
            if (!groupsWithMembers.has(group.groupid)) return;
            _groupUrlEncodeMap[group.groupid] = urlGroupNum;
            let grpStr = 'H' + urlGroupNum;
            grpStr += 'x' + Math.round((group.x || 0) * 100);
            if (group.y) grpStr += 'y' + Math.round(group.y * 100);
            if (group.data_zPosition) grpStr += 'z' + Math.round(group.data_zPosition * 100);
            grpStr += 'w' + Math.round((group.width || 0) * 100);
            if (group.height) grpStr += 'h' + Math.round(group.height * 100);
            if (group.data_layerId && group.data_layerId !== '0') {
                if (group.data_layerId === '1') {
                    grpStr += 'll1';
                } else if (_layerUrlEncodeMap[group.data_layerId] != null) {
                    grpStr += 'll' + _layerUrlEncodeMap[group.data_layerId];
                }
            }
            if (group.rotation) {
                grpStr += 'f' + Math.round(group.rotation * 10);
            }
            const safeName = group.name && group.name.trim() ? group.name : ('');
            grpStr += '~' + encodeURIComponent(safeName).replaceAll('%20', '+') + '~';
            strUrlQuery2 += grpStr;
            urlGroupNum++;
        });
    }

    /* J{n} customItem blocks — mirror H{n}; per-item ref is t{n}. */
    if (roomObj.customItems && roomObj.customItems.length) {
        const customItemsWithMembers = new Set();
        roomObj.items.forEach(it => {
            if (it.data_customItemId) customItemsWithMembers.add(it.data_customItemId);
        });
        let urlCustomItemNum = 1;
        roomObj.customItems.forEach(customItem => {
            if (!customItemsWithMembers.has(customItem.customitemid)) return;
            _customItemUrlEncodeMap[customItem.customitemid] = urlCustomItemNum;
            let cStr = 'J' + urlCustomItemNum;
            cStr += 'x' + Math.round((customItem.x || 0) * 100);
            if (customItem.y) cStr += 'y' + Math.round(customItem.y * 100);
            if (customItem.data_zPosition) cStr += 'z' + Math.round(customItem.data_zPosition * 100);
            cStr += 'w' + Math.round((customItem.width || 0) * 100);
            if (customItem.height) cStr += 'h' + Math.round(customItem.height * 100);
            if (customItem.data_layerId && customItem.data_layerId !== '0') {
                if (customItem.data_layerId === '1') {
                    cStr += 'll1';
                } else if (_layerUrlEncodeMap[customItem.data_layerId] != null) {
                    cStr += 'll' + _layerUrlEncodeMap[customItem.data_layerId];
                }
            }
            if (customItem.rotation) {
                cStr += 'f' + Math.round(customItem.rotation * 10);
            }
            const safeCName = customItem.name && customItem.name.trim() ? customItem.name : ('');
            cStr += '~' + encodeURIComponent(safeCName).replaceAll('%20', '+') + '~';
            strUrlQuery2 += cStr;
            urlCustomItemNum++;
        });
    }

    let i = 0;
    roomObj.items.forEach((item) => {
        strUrlQuery2 += createShareableLinkItem(item);
        i += 1;
        previousItem = item;
    });

    fullShareLink = location.origin + location.pathname + '?x=' + strUrlQuery2;
    fullShareLink = fullShareLink.replaceAll(' ', '+');
    fullShareLinkCollabExpBase = 'https://collabexperience.com/' + fullShareLink.match(/\?x=.*/);

    document.getElementById('shareLink').setAttribute('href', fullShareLink);

    document.getElementById('qrCodeLinkText').value = 'QR Code Character Length: ' + fullShareLink.length + ' / 2950 max';

    if (fullShareLink.length > 8189 && !firstLoad) {

        if (characterLimitWarningShow) {
            document.getElementById('characterLimitWarning').show();
            characterLimitWarningShow = false;
        }

        fullShareLink = 'https://collabexperience.com/'
        fullShareLink = location.origin + location.pathname;
        document.getElementById('shareLink').style.display = 'none'

    } else {
        document.getElementById('characterLimitWarning').close();
        document.getElementById('shareLink').style.display = ''
    }

    if (fullShareLink.length > 2500) {
        document.getElementById('qrCodeLinkText').style.backgroundColor = '#ffffc5';
    } else {
        document.getElementById('qrCodeLinkText').style.backgroundColor = '#ffffff';
    }

    if (fullShareLink.length > 2950) {
        document.getElementById('qrCodeLinkText').style.backgroundColor = '#f9bfbf';
    }

    let regex = /^A[01]v[0-9\.]+b(2[56][09]|79)\dc(200|61)\dB[01]{4,10}(D0a1)?$/;
    let queryParams = new URLSearchParams(window.location.search);



    if (regex.test(strUrlQuery2) || fullShareLink.length > 8189) {
        queryParams.delete("x", strUrlQuery2);
        history.replaceState(null, null, location.origin + location.pathname);
    } else {
        queryParams.set("x", strUrlQuery2);
        history.replaceState(null, null, fullShareLink);
    }



    /* resend workspace postmessage with the updated URL */
    postMessageToWorkspace();

    /* only create QR Code if RoomOS and only every 2 seconds for performance */
    if (qrCodeAlwaysOn && document.getElementById('dialogSave').open) {
        let qrImage = document.getElementById('qrCode').firstChild;
        clearTimeout(timerQRcodeOn);

        /* blur the QR code until it is recreated */
        if (qrImage) {
            qrImage.style.filter = 'blur(5px)';
        }

        timerQRcodeOn = setTimeout(() => {
            createQrCode();
        }, 500);

    }

}

function expand(num) {
    return Math.round(num * 100);
}

/* u-letter RGB triple (hexToUrlRgb cached; urlRgbToHex uncached). */
let _hexToUrlRgbCache = new Map();
function hexToUrlRgb(hex) {
    if (!hex || typeof hex !== 'string') return '255255255';
    const cached = _hexToUrlRgbCache.get(hex);
    if (cached) return cached;
    let h = hex.trim().replace(/^#/, '');
    if (h.length === 3) {
        h = h[0] + h[0] + h[1] + h[1] + h[2] + h[2];
    }
    if (!/^[0-9a-fA-F]{6}$/.test(h)) return '255255255';
    const r = parseInt(h.substring(0, 2), 16);
    const g = parseInt(h.substring(2, 4), 16);
    const b = parseInt(h.substring(4, 6), 16);
    const result = String(r).padStart(3, '0') + String(g).padStart(3, '0') + String(b).padStart(3, '0');
    _hexToUrlRgbCache.set(hex, result);
    return result;
}
function urlRgbToHex(rgb9) {
    if (!rgb9 || rgb9.length !== 9 || !/^\d{9}$/.test(rgb9)) return '#FFFFFF';
    const r = Math.min(255, Math.max(0, parseInt(rgb9.substring(0, 3), 10)));
    const g = Math.min(255, Math.max(0, parseInt(rgb9.substring(3, 6), 10)));
    const b = Math.min(255, Math.max(0, parseInt(rgb9.substring(6, 9), 10)));
    return '#' + r.toString(16).padStart(2, '0').toUpperCase()
               + g.toString(16).padStart(2, '0').toUpperCase()
               + b.toString(16).padStart(2, '0').toUpperCase();
}

/* WD color → #RRGGBB (hex or CSS name via getComputedStyle); cached. */
let _namedColorToHexCache = new Map();
function normalizeColorToHex(input) {
    if (input == null) return null;
    const key = String(input).trim();
    if (!key) return null;
    if (_namedColorToHexCache.has(key)) return _namedColorToHexCache.get(key);

    let h = key.replace(/^#/, '');
    if (/^[0-9a-fA-F]{3}$/.test(h)) {
        h = h[0] + h[0] + h[1] + h[1] + h[2] + h[2];
    }
    if (/^[0-9a-fA-F]{6}$/.test(h)) {
        const hex = '#' + h.toUpperCase();
        _namedColorToHexCache.set(key, hex);
        return hex;
    }

    let result = null;
    try {
        const probe = document.createElement('div');
        probe.style.color = '';
        probe.style.color = key;
        if (probe.style.color !== '') {
            document.body.appendChild(probe);
            const rgb = getComputedStyle(probe).color;
            document.body.removeChild(probe);
            const m = rgb && rgb.match(/^rgba?\((\d+)\s*,\s*(\d+)\s*,\s*(\d+)/);
            if (m) {
                const r = Math.min(255, parseInt(m[1], 10));
                const g = Math.min(255, parseInt(m[2], 10));
                const b = Math.min(255, parseInt(m[3], 10));
                result = '#' + r.toString(16).padStart(2, '0').toUpperCase()
                             + g.toString(16).padStart(2, '0').toUpperCase()
                             + b.toString(16).padStart(2, '0').toUpperCase();
            }
        }
    } catch (e) {
        result = null;
    }
    _namedColorToHexCache.set(key, result);
    return result;
}

function createShareableLinkItem(item) {
    let strItem = '';

    if (itemsOffStageId.includes(item.id)) {
        return '';
    }

    strItem += idKeyObj[item.data_deviceid];

    if ('x' in item) {
        strItem += Math.round(item.x * 100);
    }

    if ('y' in item) {
        strItem += 'a' + Math.round(round(item.y) * 100);
    }

    if ('data_zPosition' in item) {
        if (item.data_zPosition != "") {
            strItem += 'b' + Math.round(round(item.data_zPosition) * 100);
        }
    }

    if ('width' in item && item.width && item.data_deviceid != 'pathShape' && item.data_deviceid != 'polyRoom') {
        strItem += 'c' + Math.round(round(item.width) * 100);
    }

    if ('length' in item && item.length && item.data_deviceid != 'pathShape' && item.data_deviceid != 'polyRoom') {
        strItem += 'd' + Math.round(round(item.length) * 100);
    }

    if ('height' in item && item.data_deviceid != 'tblSchoolDesk' && item.height) { /* tblSchoolDesk has a set length of 0.59m and does not need to be saved in the URL */
        strItem += 'e' + Math.round(round(item.height) * 100);
    }

    if ('rotation' in item) {
        let rotation = Math.round(item.rotation);
        if (rotation != 0) {
            strItem += 'f' + Math.round(round(item.rotation) * 10);
        }
    }

    if ('data_diagonalInches' in item) {
        strItem += 'g' + item.data_diagonalInches;
    }

    if ('tblRectRadius' in item && item.data_deviceid != 'tblSchoolDesk') { /* tblSchoolDesk tblRectRadius and tblRectRadiusRight are set and don't need to be in the URL */
        strItem += 'h' + Math.round(round(item.tblRectRadius) * 100);
    }

    if ('tblRectRadiusRight' in item && item.data_deviceid != 'tblSchoolDesk') {
        strItem += 'i' + Math.round(round(item.tblRectRadiusRight) * 100);
    }

    if ('data_vHeight' in item) {
        if (item.data_vHeight) {
            strItem += 'j' + Math.round(round(item.data_vHeight) * 100);
        }
    }

    if ('data_trapNarrowWidth' in item) {
        if (item.data_trapNarrowWidth && !isNaN(item.data_trapNarrowWidth)) {
            strItem += 'k' + Math.round(round(item.data_trapNarrowWidth) * 100);
        }
    }

    /* don't store non-default data_role index */
    if ('data_role' in item && item.data_role) {
        let place = item.data_role.index - 1;
        if (place > -1) {
            strItem += 'l' + place;
        }
    }

    if ('data_color' in item && item.data_color) {
        let place = item.data_color.index - 1;
        if (place > -1) {
            strItem += 'm' + place;
        }
    }

    let hiddenShading = createLinkSingleItemShadingDecimal(item);
    if (hiddenShading != 0) {
        strItem += 'n' + hiddenShading;
    }

    if ('data_tilt' in item) {
        let tilt = Math.round(item.data_tilt);
        if (tilt != 0) {
            strItem += 'o' + Math.round(round(item.data_tilt) * 10);
        }
    }

    if ('data_slant' in item) {
        let slant = Math.round(item.data_slant);
        if (slant != 0) {
            strItem += 'p' + Math.round(round(item.data_slant) * 10);
        }
    }

    if ('data_mount' in item && item.data_mount) {
        let place = item.data_mount.index - 1;
        if (place > -1) {
            strItem += 'q' + place;
        }
    }

    if (item.points && item.points.length > 0) {

        const points = item.points.map(point => {
            return Math.round(round(point) * 100)
        });

        strItem += 'r' + points.join(' ');
    }

    /* Group/CustomItem members inherit bundle layer — skip per-item ll. */
    const itemHasGroupRef = item.data_groupId && _groupUrlEncodeMap[item.data_groupId] != null;
    const itemHasCustomItemRef = item.data_customItemId && _customItemUrlEncodeMap[item.data_customItemId] != null;

    /* encode layer reference: ll1 for Ceiling, ll20+ for custom layers; skip Default (ll0 not needed) */
    if (!itemHasGroupRef && !itemHasCustomItemRef && 'data_layerId' in item && item.data_layerId && item.data_layerId !== '0') {
        if (item.data_layerId === '1') {
            strItem += 'll1';
        } else if (_layerUrlEncodeMap[item.data_layerId] != null) {
            strItem += 'll' + _layerUrlEncodeMap[item.data_layerId];
        }
    }

    if (itemHasGroupRef) {
        strItem += 's' + _groupUrlEncodeMap[item.data_groupId];
    }

    if (itemHasCustomItemRef) {
        strItem += 't' + _customItemUrlEncodeMap[item.data_customItemId];
    }

    /* u=RGB triple (9 digits); v=opacity×100 (omit at 1.0). */
    if (item.data_fill) {
        strItem += 'u' + hexToUrlRgb(item.data_fill);
    }
    if (item.data_opacity != null && Number(item.data_opacity) !== 1) {
        const opacityNum = Number(item.data_opacity);
        if (!isNaN(opacityNum) && opacityNum >= 0 && opacityNum < 1) {
            strItem += 'v' + Math.round(opacityNum * 100);
        }
    }

    if ('data_labelField' in item) {
        if (item.data_labelField && item.data_labelField.trim() !== '{}') {
            strItem += '~' + encodeURIComponent(item.data_labelField.replace(/^[\s_]+|[\s_]+$/g, '')).replaceAll('%20', '+') + '~';
        }
    }



    return strItem;
}

/* Per-item shading flags as decimal (decoded to binary). */
function createLinkSingleItemShadingDecimal(item) {
    let totalDecimal = 0;
    if (item.data_fovHidden) totalDecimal += 1;
    if (item.data_audioHidden) totalDecimal += 2;
    if (item.data_dispDistHidden) totalDecimal += 4;

    return totalDecimal;
}

function createShareableLinkItemShading() {
    let shadeArray = [];
    if (roomObj.overlaysVisible.cameraCoverage) {
        shadeArray[0] = 1;
    } else {
        shadeArray[0] = 0;
    }

    if (roomObj.overlaysVisible.displayDistanceCoverage) {
        shadeArray[1] = 1;
    } else {
        shadeArray[1] = 0;
    }

    if (roomObj.overlaysVisible.microphoneCoverage) {
        shadeArray[2] = 1;
    } else {
        shadeArray[2] = 0;
    }

    if (roomObj.overlaysVisible.gridLines) {
        shadeArray[3] = 1;
    } else {
        shadeArray[3] = 0;
    }

    if (roomObj.workspace.addCeiling) {
        shadeArray[4] = 1;
    } else {
        shadeArray[4] = 0;
    }


    if (roomObj.workspace.removeDefaultWalls) {
        shadeArray[5] = 1;
    } else {
        shadeArray[5] = 0;
    }

    if (roomObj.overlaysVisible.overlayLabels) {
        shadeArray[6] = 1;
    } else {
        shadeArray[6] = 0;
    }

    if (roomObj.overlaysVisible.speakerCoverage) {
        shadeArray[7] = 1;
    } else {
        shadeArray[7] = 0;
    }

    if (roomObj.workspace.theme === 'christmas') {
        shadeArray[8] = 1;

    } else {
        shadeArray[8] = 0;
    }

    return 'B' + shadeArray.join('');

}

/* download a transparent image */
function downloadCanvasTransPNG() {
    zoomInOut('reset');
    /* allow time to reset */

    setTimeout(() => { downloadCanvasPNG2(false); }, 100);
}

function downloadCanvasPNG() {
    zoomInOut('reset');
    /* allow time to reset */
    setTimeout(() => { downloadCanvasPNG2(true); }, 100);
}

function downloadCanvasPNG2(isSolidBackground = true) {

    txtAttribution.visible(true);

    if (!isSolidBackground) groupBackground.visible(false);
    tr.nodes([]);
    enableCopyDelBtn(false);
    try {

        let roomName = DOMPurify.sanitize(document.getElementById('roomName').value);

        let downloadRoomName;

        if (roomName == null || roomName == '') {
            downloadRoomName = 'VideoRoomCalc.png';
        } else {
            downloadRoomName = roomName.replace(/[/\\?%*:|"<>]/g, '-');
            downloadRoomName = downloadRoomName.trim() + '.png'
        }

        function downloadURI(uri, name) {
            let link = document.createElement('a');
            link.download = name;
            link.href = uri;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            delete link;
        }

        let stageDataUrl = stage.toDataURL({ pixelRatio: 5 });
        downloadURI(stageDataUrl, downloadRoomName);

        lastAction = 'download png';
        postHeartbeat();

    } catch (err) {
        console.error(`Error: ${err}`);
    }
    if (!isSolidBackground) groupBackground.visible(true)

    txtAttribution.visible(false);
}

const downloadPNG = document.querySelector('#downloadPNG');
downloadPNG.addEventListener('click', downloadCanvasPNG);

const downloadTransPNG = document.querySelector('#downloadTransPNG');

downloadTransPNG.addEventListener('click', downloadCanvasTransPNG);

function shareableLinkClicked() {
    lastAction = "shareable link";
    postHeartbeat();
}

async function postHeartbeat() {
    if (location.hostname === 'localhost') return
    setTimeout(() => {

        let path = location.origin + "/heartbeat";
        let primaryDevice = 'none';
        const firstVideoDevice = firstItemOfParentGroup('videoDevices');
        if (firstVideoDevice) {
            primaryDevice = firstVideoDevice.data_deviceid;
        }
        let data = {
            sessionId: roomObj.version + '_' + sessionId,
            clientTimeStamp: clientTimeStamp,
            videoDevice: primaryDevice,
            lastAction: lastAction,
            mobileDevice: mobileDevice,
            unit: unit
        }

        fetch(path, {
            method: "POST",
            body: JSON.stringify(data),
            headers: {
                "Content-type": "application/json; charset=UTF-8"
            }
        })
            .then((response) => response.json())
            .catch(() => console.info('heart beat failed'))

    }, 1000);
}

function openTab(evt, tabName) {
    let i, tabcontent, tablinks;
    tabcontent = document.getElementsByClassName("tabcontent");
    for (i = 0; i < tabcontent.length; i++) {
        tabcontent[i].style.display = "none";
    }

    tablinks = document.getElementsByClassName("tablinks");
    for (i = 0; i < tablinks.length; i++) {
        tablinks[i].className = tablinks[i].className.replace(" active", "");
    }

    /* Show tab (display:flex keeps sub-tab layout per CSS .tabcontent). */
    document.getElementById(tabName).style.display = "flex";

    evt.currentTarget.className += " active";

    resetBackgroundImageFloorSettings();
    updateAllScrollHints();

    if (tabName === 'Insert') {
        const scrollArea = document.getElementById('equipmentScrollArea');
        if (scrollArea) scrollArea.dispatchEvent(new Event('scroll'));
    }
}

/* Equipment tab: pill row + inline search (replaces legacy subtabs / floating search). */
let _activeEquipmentCategory = 'Cameras';
let _equipmentScrollProgrammatic = false;
let _equipmentScrollProgrammaticTimer = null;

/* Scroll to category panel; re-populate Custom Items on each visit. */
function selectEquipmentCategory(tabName) {
    const panel = document.getElementById(tabName);
    const scrollArea = document.getElementById('equipmentScrollArea');

    if (panel && scrollArea) {
        const top = panel.getBoundingClientRect().top
            - scrollArea.getBoundingClientRect().top
            + scrollArea.scrollTop;

        _equipmentScrollProgrammatic = true;
        if (_equipmentScrollProgrammaticTimer) clearTimeout(_equipmentScrollProgrammaticTimer);
        _equipmentScrollProgrammaticTimer = setTimeout(function () {
            _equipmentScrollProgrammatic = false;
        }, 600);

        scrollArea.scrollTo({ top: Math.max(0, top - 4), behavior: 'smooth' });
    }

    _setActivePillSilent(tabName);

    if (tabName === 'CustomItems') {
        populateCustomItemsMenuContainer();
    }
}

function _setActivePillSilent(tabName) {
    if (_activeEquipmentCategory === tabName) return;

    const pills = document.getElementsByClassName('equipmentCategoryPill');
    for (let i = 0; i < pills.length; i++) {
        pills[i].classList.remove('active');
    }
    const pill = document.querySelector('.equipmentCategoryPill[data-target="' + tabName + '"]');
    if (pill) {
        pill.classList.add('active');
        if (typeof pill.scrollIntoView === 'function') {
            pill.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'nearest' });
        }
    }

    _activeEquipmentCategory = tabName;

    if (tabName === 'CustomItems'
        && typeof populateCustomItemsMenuContainer === 'function') {
        populateCustomItemsMenuContainer();
    }
}

/* Scroll-spy: active pill = last panel with top ≤ 80px; at scroll max → last panel. */
function initEquipmentScrollSpy() {
    const scrollArea = document.getElementById('equipmentScrollArea');
    if (!scrollArea) return;
    /* Skip searchOnlyPanel (no matching pill). */
    const panels = Array.from(scrollArea.querySelectorAll(
        ':scope > .subtabcontent:not(.searchOnlyPanel)'));
    if (!panels.length) return;

    let ticking = false;

    function onScroll() {
        if (ticking) return;
        ticking = true;
        requestAnimationFrame(function () {
            ticking = false;
            if (_equipmentScrollProgrammatic) return;

            const scrollerRect = scrollArea.getBoundingClientRect();
            const threshold = 80;
            let active = null;
            for (let i = 0; i < panels.length; i++) {
                const p = panels[i];
                if (p.classList.contains('searchHidden')) continue;
                const top = p.getBoundingClientRect().top - scrollerRect.top;
                if (top <= threshold) {
                    active = p;
                } else {
                    break;
                }
            }
            if (!active) {
                active = panels.find(function (p) { return !p.classList.contains('searchHidden'); });
            }
            const atMax = scrollArea.scrollTop + scrollArea.clientHeight
                >= scrollArea.scrollHeight - 2;
            if (atMax) {
                for (let i = panels.length - 1; i >= 0; i--) {
                    if (!panels[i].classList.contains('searchHidden')) {
                        active = panels[i];
                        break;
                    }
                }
            }
            if (active) _setActivePillSilent(active.id);
        });
    }

    scrollArea.addEventListener('scroll', onScroll, { passive: true });
    onScroll();

    /* IntersectionObserver: re-populate Custom Items when panel enters scroller. */
    const customItemsPanel = document.getElementById('CustomItems');
    if (customItemsPanel && typeof IntersectionObserver !== 'undefined') {
        const io = new IntersectionObserver(function (entries) {
            entries.forEach(function (entry) {
                if (entry.isIntersecting
                    && typeof populateCustomItemsMenuContainer === 'function') {
                    populateCustomItemsMenuContainer();
                }
            });
        }, { root: scrollArea, threshold: 0 });
        io.observe(customItemsPanel);
    }
}

/* Legacy openSubTab shim → selectEquipmentCategory. */
function openSubTab(evt, tabName) {
    selectEquipmentCategory(tabName);
}

function initEquipmentCategoryPills() {
    const pillRow = document.getElementById('equipmentCategoryPills');
    const wrap = document.getElementById('equipmentCategoryPillsWrap');
    if (!pillRow || !wrap) return;

    const chevLeft = wrap.querySelector('.pillScrollChevronLeft');
    const chevRight = wrap.querySelector('.pillScrollChevronRight');

    pillRow.querySelectorAll('.equipmentCategoryPill').forEach((pill) => {
        pill.addEventListener('click', () => {
            const target = pill.dataset.target;
            if (target) selectEquipmentCategory(target);
        });
    });

    /* Chevron visibility: shown only when there is content to scroll
     * to in that direction. 4px slop avoids visual flicker right at
     * the extremes due to sub-pixel scroll values. */
    function updateChevrons() {
        if (!chevLeft || !chevRight) return;
        const canLeft = pillRow.scrollLeft > 4;
        const canRight = pillRow.scrollLeft < pillRow.scrollWidth - pillRow.clientWidth - 4;
        chevLeft.classList.toggle('visible', canLeft);
        chevRight.classList.toggle('visible', canRight);
    }
    pillRow.addEventListener('scroll', updateChevrons, { passive: true });
    window.addEventListener('resize', updateChevrons);

    if (chevLeft) chevLeft.addEventListener('click', () =>
        pillRow.scrollBy({ left: -120, behavior: 'smooth' }));
    if (chevRight) chevRight.addEventListener('click', () =>
        pillRow.scrollBy({ left: 120, behavior: 'smooth' }));

    /* First paint: defer one frame so the row has its final layout
     * width before we measure scrollWidth / clientWidth. */
    requestAnimationFrame(updateChevrons);

    /* ResizeObserver catches the case where the Equipment tab starts
     * out hidden (display:none) — the pill row has clientWidth=0 at
     * boot, so the initial rAF probe wrongly concludes "nothing to
     * scroll" and leaves the right chevron hidden. When the user
     * later clicks Equipment, `openTab` flips display:none → flex
     * and the row's width jumps to its real value; this observer
     * fires and re-evaluates the chevrons. Without it the right
     * chevron stayed hidden until the user manually wiggled the
     * pill-row scroll (the only other trigger). */
    if (typeof ResizeObserver !== 'undefined') {
        new ResizeObserver(updateChevrons).observe(pillRow);
    }
}

initEquipmentCategoryPills();
initEquipmentScrollSpy();

/* Eagerly populate the Custom Items panel at boot so it has content
 * when the user scrolls down to it in the long-scroll view — without
 * this, the panel would render empty until the user explicitly
 * clicked the Custom Items pill. Fire-and-forget; the IDB query is
 * async and the `.then()` callback inside populateCustomItemsMenuContainer
 * re-fires onEquipmentSearchChange when it lands, so any keystrokes
 * the user typed during the race window get applied to the late-
 * arriving Custom Item tiles too. */
if (typeof populateCustomItemsMenuContainer === 'function') {
    populateCustomItemsMenuContainer();
}

/* Defense-in-depth against the boot race: re-fire the Custom Items
 * load when the user focuses the search box. If the boot-time call
 * somehow failed (browser threw, idbStore wasn't ready, etc.) or the
 * library has been mutated in another tab, this guarantees Custom
 * Items are available before the very first keystroke is filtered.
 * Idempotent — re-running just re-renders the same tile DOM. */
(function () {
    const searchInput = document.getElementById('equipmentSearch');
    if (searchInput) {
        searchInput.addEventListener('focus', function () {
            if (typeof populateCustomItemsMenuContainer === 'function') {
                populateCustomItemsMenuContainer();
            }
        });
    }
})();

/* Equipment search: filter tiles/panels; extras go to Other panel. */
function onEquipmentSearchChange(e) {
    const bar = document.getElementById('equipmentSearchBar');
    const insertTab = document.getElementById('Insert');
    const scrollArea = document.getElementById('equipmentScrollArea');
    const query = (e && e.target && e.target.value || '').trim();
    if (bar) bar.classList.toggle('hasValue', query.length > 0);

    /* Curated panels only; Other panel uses `.hasMatches` (excludes `.searchOnlyPanel`). */
    const allPanels = scrollArea
        ? Array.from(scrollArea.querySelectorAll(
            ':scope > .subtabcontent:not(.searchOnlyPanel)'))
        : [];

    const otherPanel = document.getElementById('OtherSearch');
    const otherContainer = document.getElementById('otherSearchMenuContainer');

    if (query.length < 2) {
        if (insertTab) insertTab.classList.remove('searching');
        document.querySelectorAll('#Insert .equipmentItemOnMenu')
            .forEach(t => { t.style.display = ''; });
        document.querySelectorAll('#Insert .menuDivider.searchHidden, '
            + '#Insert .containerItems.searchHidden, '
            + '#Insert .subtabcontent.searchHidden')
            .forEach(el => el.classList.remove('searchHidden'));
        document.querySelectorAll('.equipmentCategoryPill.disabled')
            .forEach(p => p.classList.remove('disabled'));
        /* Other panel tiles exist only during search. */
        if (otherContainer) otherContainer.innerHTML = '';
        if (otherPanel) otherPanel.classList.remove('hasMatches');
        setEquipmentSearchNoResults(false);
        return;
    }

    if (insertTab) insertTab.classList.add('searching');

    /* Same regex/stripping as searchQuickItem. */
    const { regex, stripped } = (typeof getEquipmentSearchRegex === 'function')
        ? getEquipmentSearchRegex(query)
        : { regex: /(^_.*)|(.*\*$)/, stripped: query };

    const needle = stripped.toLowerCase().replace(/\s/g, '');

    if (otherContainer) {
        otherContainer.innerHTML = '';
        const fullDeviceList = [].concat(
            tables, videoDevices, microphones, chairs, displays, boxes, stageFloors, rooms);
        const matchedDevices = fullDeviceList.filter(function (d) {
            if (!d || !d.name || !d.id) return false;
            if (regex.test(d.name)) return false;
            const hay = String(d.name).toLowerCase().replace(/\s/g, '');
            return hay.length > 0 && hay.includes(needle);
        });
        /* Devices matching search but not already in a curated panel tile. */
        const extraIds = [];
        const seen = new Set();
        matchedDevices.forEach(function (d) {
            if (seen.has(d.id)) return;
            seen.add(d.id);
            const existingTileId = (d.parentGroup ? d.parentGroup + '-' : '') + d.id + '-div';
            if (d.parentGroup && document.getElementById(existingTileId)) return;
            extraIds.push(d.id);
        });
        if (extraIds.length && typeof createItemsOnMenu === 'function') {
            createItemsOnMenu('otherSearchMenuContainer', extraIds);
        }
        if (otherPanel) otherPanel.classList.toggle('hasMatches', extraIds.length > 0);
    }

    const panelMatchCounts = {};

    /* Tile-level: show only label substring matches. */
    document.querySelectorAll('#Insert .equipmentItemOnMenu').forEach((tile) => {
        const labelEl = tile.querySelector('.flexSubItemLabel') || tile.querySelector('label');
        const labelText = (labelEl ? labelEl.textContent : '').toLowerCase().replace(/\s/g, '');
        const match = labelText.length > 0 && labelText.includes(needle);
        tile.style.display = match ? '' : 'none';
        if (match) {
            const panel = tile.closest('.subtabcontent');
            if (panel && panel.id) {
                panelMatchCounts[panel.id] = (panelMatchCounts[panel.id] || 0) + 1;
            }
        }
    });

    /* Section-level: hide empty divider/container chains. */
    document.querySelectorAll('#Insert .subtabcontent .menuDivider').forEach((divider) => {
        const containers = [];
        let sib = divider.nextElementSibling;
        while (sib && !sib.classList.contains('menuDivider')) {
            if (sib.classList.contains('containerItems')) containers.push(sib);
            sib = sib.nextElementSibling;
        }
        const visibleCount = containers.reduce(function (acc, c) {
            const tiles = c.querySelectorAll('.equipmentItemOnMenu');
            let n = 0;
            for (let i = 0; i < tiles.length; i++) {
                if (tiles[i].style.display !== 'none') n++;
            }
            return acc + n;
        }, 0);

        divider.classList.toggle('searchHidden', visibleCount === 0);
        containers.forEach(c => c.classList.toggle('searchHidden', visibleCount === 0));
    });

    /* Panel-level: hide empty panels and mute pills. */
    allPanels.forEach((panel) => {
        const matched = panelMatchCounts[panel.id] > 0;
        panel.classList.toggle('searchHidden', !matched);
        const pill = document.querySelector(
            '.equipmentCategoryPill[data-target="' + panel.id + '"]');
        if (pill) pill.classList.toggle('disabled', !matched);
    });

    /* Auto-scroll to first matching panel (or Other if only match). */
    const firstMatchPanel = allPanels.find(p => panelMatchCounts[p.id] > 0);
    if (firstMatchPanel && _activeEquipmentCategory !== firstMatchPanel.id) {
        selectEquipmentCategory(firstMatchPanel.id);
    } else if (!firstMatchPanel && otherPanel
        && otherPanel.classList.contains('hasMatches')
        && typeof otherPanel.scrollIntoView === 'function') {
        otherPanel.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }

    const curatedMatches = Object.values(panelMatchCounts).reduce((a, b) => a + b, 0);
    const otherMatches = (otherPanel && otherPanel.classList.contains('hasMatches')) ? 1 : 0;
    setEquipmentSearchNoResults((curatedMatches + otherMatches) === 0);
}

function clearEquipmentSearch() {
    const input = document.getElementById('equipmentSearch');
    if (input) input.value = '';
    onEquipmentSearchChange({ target: { value: '' } });
    if (input) input.focus();
}

/* Empty-state banner when equipment search has no matches. */
function setEquipmentSearchNoResults(show) {
    let el = document.getElementById('equipmentSearchNoResults');
    if (!show) {
        if (el) el.style.display = 'none';
        return;
    }
    if (!el) {
        el = document.createElement('div');
        el.id = 'equipmentSearchNoResults';
        el.className = 'customItemsEmpty';
        /* Fixed markup only — no caller data. */
        el.innerHTML = '<b>No matches.</b><br />Press <code>Space</code> to open the full Quick Add palette.';
        const insertTab = document.getElementById('Insert');
        if (insertTab) insertTab.appendChild(el);
    }
    el.style.display = 'block';
}

/* Shared customItem tile builder for sidebar drag and Quick Add modal. */
function buildCustomItemTile(record, opts) {
    opts = opts || {};
    const name = (typeof getCustomItemRecordName === 'function'
        ? getCustomItemRecordName(record)
        : (record.customItemName || record.data_labelField || '')) || '';
    const baseId = record.customItemBaseId;

    const btnItem = document.createElement('button');
    btnItem.type = 'button';

    if (record.menuImage) {
        const i = document.createElement('img');
        i.src = record.menuImage;
        i.draggable = false;
        i.id = `customItem-${baseId}-img`;
        /* Match regular device-tile image sizing. */
        i.className = 'flexSubItemImage';
        btnItem.appendChild(i);
    }

    const label = document.createElement('label');
    label.innerText = name.slice(0, 30);
    btnItem.title = `${name} — Custom Item`;
    label.className = 'flexSubItemLabel';
    btnItem.appendChild(label);

    btnItem.classList.add('flexItems');
    btnItem.classList.add('equipmentItemOnMenu');
    btnItem.classList.add('customItemTile');
    btnItem.id = `customItem-${baseId}-div`;

    /* Must be <span role="button"> — nested <button> breaks DOM/layout. */
    const moreBtn = document.createElement('span');
    moreBtn.className = 'customItemTileDeleteBtn';
    moreBtn.setAttribute('role', 'button');
    moreBtn.setAttribute('tabindex', '0');
    moreBtn.setAttribute('aria-label', 'More actions for ' + (name || 'Custom Item'));
    moreBtn.title = 'More actions (rename, export, remove)';
    moreBtn.innerHTML = '<i class="icon icon-more-bold"></i>';
    moreBtn.addEventListener('click', function (ev) {
        ev.stopPropagation();
        ev.preventDefault();
        openEditCustomItemDialog(baseId);
    });
    moreBtn.addEventListener('keydown', function (ev) {
        if (ev.key === 'Enter' || ev.key === ' ') {
            ev.stopPropagation();
            ev.preventDefault();
            openEditCustomItemDialog(baseId);
        }
    });
    btnItem.appendChild(moreBtn);

    if (opts.onClick === 'insertCenter') {
        /* Quick Add modal mode — click-to-insert, no drag. */
        btnItem.draggable = false;
        btnItem.onclick = function () {
            const { roomWidth, roomLength } = roomObj.room;
            let dropX, dropY;
            const b = roomObj.unit === 'feet' ? 0.6 : 0.2;
            if (quickAddMouse.x > -b && quickAddMouse.x < (roomWidth + b) &&
                quickAddMouse.y > -b && quickAddMouse.y < (roomLength + b)) {
                dropX = quickAddMouse.x;
                dropY = quickAddMouse.y;
            } else {
                dropX = roomWidth / 2;
                dropY = roomLength / 2;
            }
            const newCustomitemid = insertCustomItemAtPosition(record, dropX, dropY);
            if (newCustomitemid) showToast('Custom Item added: ' + name);
            toggleQuickAdd(false);
        };
    } else {
        /* Sidebar mode — draggable; click is a no-op (matches device-
         * tile behaviour, which is drag-only in the sidebar). */
        btnItem.draggable = true;
        btnItem.addEventListener('dragstart', dragStart);
        btnItem.addEventListener('drag', drag);
        /* Custom dragEnd — insertItemFromMenu doesn't know library baseIds. */
        btnItem.addEventListener('dragend', function (event) {
            dragEndCustomItemTile(event, record, name);
        });

        /* Touch drag; gated on _touchDragArmed to ignore quick taps. */
        btnItem.addEventListener('touchstart', touchStart);
        btnItem.addEventListener('touchmove', touchMove);
        btnItem.addEventListener('touchend', function (event) {
            if (!_touchDragArmed) {
                _clearTouchDragArmTimer();
                _touchDragStart = null;
                return;
            }
            dragEndCustomItemTile(event, record, name);
            if (typeof newInsertItem !== 'undefined' && newInsertItem && newInsertItem.parentNode) {
                document.body.removeChild(newInsertItem);
            }
            if (_touchDragStart && _touchDragStart.target && _touchDragStart.target.classList) {
                _touchDragStart.target.classList.remove('flexItems--dragArmed');
            }
            _touchDragArmed = false;
            _touchDragStart = null;
        });
        btnItem.addEventListener('touchcancel', touchCancel);
    }

    return btnItem;
}

/* Drop handler; coordinate math mirrors dragEnd(). */
function dragEndCustomItemTile(event, record, displayName) {
    if (!event.target || event.target.id === '') return;

    const canvas = document.getElementById('canvasDiv');
    if (!canvas) return;
    const canvasBound = canvas.getBoundingClientRect();

    const dx = scrollContainer.scrollLeft;
    const dy = scrollContainer.scrollTop;

    let cx, cy;
    if ('clientX' in event && !isSafari) {
        cx = event.clientX;
        cy = event.clientY;
    } else if (event.changedTouches && event.changedTouches.length) {
        cx = event.changedTouches[0].clientX;
        cy = event.changedTouches[0].clientY;
    } else {
        cx = dragClientX;
        cy = dragClientY;
    }

    const canvasPixelX = (cx - canvasBound.x + dx) / zoomScaleX;
    const canvasPixelY = (cy - canvasBound.y + dy) / zoomScaleY;
    const unitX = (canvasPixelX - pxOffset) / scale + activeRoomX;
    const unitY = (canvasPixelY - pxOffset) / scale + activeRoomY;

    /* Same buffer as dragEnd: abort if the drop is outside the canvas
     * area (negative or extremely small canvas coords). */
    if (canvasPixelX < 10 || canvasPixelY < 10) return;

    const newCustomitemid = insertCustomItemAtPosition(record, unitX, unitY);
    if (newCustomitemid && displayName) {
        showToast('Custom Item added: ' + displayName);
    }

    dragClientX = 0;
    dragClientY = 0;
}

/* Refresh Custom Items pill from IDB on each open. */
function populateCustomItemsMenuContainer() {
    const container = document.getElementById('customItemsMenuContainer');
    const empty = document.getElementById('customItemsEmptyState');
    if (!container) return;

    if (!window.idbStore || typeof window.idbStore.customItemGetAll !== 'function') {
        container.innerHTML = '';
        if (empty) empty.style.display = 'block';
        return;
    }

    window.idbStore.customItemGetAll().then(function (records) {
        const list = Array.isArray(records) ? records : [];
        /* Canvas-only unnamed bundles — skip library grid. */
        const named = list.filter(function (rec) {
            const n = (typeof getCustomItemRecordName === 'function'
                ? getCustomItemRecordName(rec)
                : (rec && (rec.customItemName || rec.data_labelField) || ''));
            return rec && String(n).trim().length > 0;
        });
        /* Newest-first by updatedAt (ISO 8601). */
        named.sort(function (a, b) {
            const ka = String(a.updatedAt || a.addedAt || '');
            const kb = String(b.updatedAt || b.addedAt || '');
            return kb.localeCompare(ka);
        });

        container.innerHTML = '';
        named.forEach(function (rec) {
            container.appendChild(buildCustomItemTile(rec, { onClick: 'drag' }));
        });

        if (empty) empty.style.display = named.length ? 'none' : 'block';

        /* Re-apply search filter if user typed before async IDB returned. */
        const searchInput = document.getElementById('equipmentSearch');
        if (searchInput && searchInput.value && searchInput.value.trim().length >= 2) {
            onEquipmentSearchChange({ target: searchInput });
        }
    }).catch(function (e) {
        console.warn('[customItemLibrary] sidebar fetch failed:', e && e.message);
    });
}

