/* Undo/redo restore: incremental patch when safe, else full drawRoom(). */
function restoreSnapshotToCanvas(prev, next) {
    const undoApply = window.VRC && window.VRC.undoApply;
    const fallback = !undoApply || undoApply.requiresFullRedraw(prev, next);

    roomObj = next;
    /* Backfill missing overlaysVisible before any reader touches it. */
    ensureOverlaysVisibleDefaulted(roomObj);
    unit = roomObj.unit;

    if (fallback) {
        /* Full redraw can lose items while zoomed — reset zoom first. */
        zoomInOut('reset');
        drawRoom(true, true, true);
    } else {
        applyRoomObjDelta(prev, next);
    }
}

function btnUndoClicked() {

    if (!(polyBuilderMode === 'none' || polyBuilderMode === '')) {
        closeAllDialogModals();
        polyBuilderOn(false);
        updateItem();
        return;
    };


    showUndoRedoRoomOs();

    clearTimeout(undoArrayTimer);

    if (undoArray.length > 0) {
        const movedEntry = undoArray.pop();
        redoArray.push(movedEntry);
        const prev = roomObj;
        const next = structuredClone(undoArray[undoArray.length - 1]);
        restoreSnapshotToCanvas(prev, next);
        enableBtnUndoRedo();
        setTimeout(() => {
            createShareableLink();
        }, 750);

        /* Mirror in-memory pop onto IDB. */
        if (typeof window !== 'undefined' && window.idbStore) {
            window.idbStore.undoPopLast();
            window.idbStore.redoAdd(structuredClone(movedEntry));
        }

        if (typeof rehydrateBackgroundImageFromIdb === 'function') {
            rehydrateBackgroundImageFromIdb();
        }
    }
}

function btnRedoClicked() {

    if (!(polyBuilderMode === 'none' || polyBuilderMode === '')) {
        closeAllDialogModals();
        polyBuilderOn(false);
        updateItem();
        return;
    };

    showUndoRedoRoomOs()

    if (redoArray.length > 0) {
        const movedEntry = redoArray.pop();
        undoArray.push(movedEntry);
        const prev = roomObj;
        const next = structuredClone(undoArray[undoArray.length - 1]);
        restoreSnapshotToCanvas(prev, next);
        setTimeout(() => {
            createShareableLink();

        }, 500);

        /* Mirror onto IDB. */
        if (typeof window !== 'undefined' && window.idbStore) {
            window.idbStore.redoPopLast();
            window.idbStore.undoAdd(structuredClone(movedEntry));
        }

        if (typeof rehydrateBackgroundImageFromIdb === 'function') {
            rehydrateBackgroundImageFromIdb();
        }
    }
    enableBtnUndoRedo();
}

function enableBtnUndoRedo() {
    if (undoArray.length > 1) {
        document.getElementById('btnUndo').disabled = false;
    } else {
        document.getElementById('btnUndo').disabled = true;
    }
    if (redoArray.length > 0) {
        document.getElementById('btnRedo').disabled = false;
    } else {
        document.getElementById('btnRedo').disabled = true;
    }
}

let canvasClipBoard = {};

function copyToCanvasClipBoard(nodes) {
    let itemsObj = { unit: roomObj.unit }

    if (!nodes) nodes = tr.nodes();

    let uuids = [];

    let clipBoardArray = [];

    /* Complete bundle only: rect + all members round-trip; else paste ungrouped. */
    const selectedRectGroupIds = new Set();
    const selectedMemberIdsByGroup = {};
    const selectedRectCustomItemIds = new Set();
    const selectedMemberIdsByCustomItem = {};
    nodes.forEach(n => {
        if (n.data_deviceid === 'group' && n.data_groupId) {
            selectedRectGroupIds.add(n.data_groupId);
        } else if (n.data_deviceid === 'customItem' && n.data_customItemId) {
            selectedRectCustomItemIds.add(n.data_customItemId);
            /* Legacy: customItem rect may also carry data_groupId. */
            if (n.data_groupId) {
                (selectedMemberIdsByGroup[n.data_groupId] = selectedMemberIdsByGroup[n.data_groupId] || new Set()).add(n.id());
            }
        } else {
            if (n.data_groupId) {
                (selectedMemberIdsByGroup[n.data_groupId] = selectedMemberIdsByGroup[n.data_groupId] || new Set()).add(n.id());
            }
            if (n.data_customItemId) {
                (selectedMemberIdsByCustomItem[n.data_customItemId] = selectedMemberIdsByCustomItem[n.data_customItemId] || new Set()).add(n.id());
            }
        }
    });
    const completeGroupIds = new Set();
    selectedRectGroupIds.forEach(gid => {
        const group = getGroupById(gid);
        if (!group) return;
        const present = selectedMemberIdsByGroup[gid] || new Set();
        const allHere = (group.groupMembers || []).every(id => present.has(id));
        if (allHere) completeGroupIds.add(gid);
    });
    const completeCustomItemIds = new Set();
    selectedRectCustomItemIds.forEach(cid => {
        const customItem = getCustomItemById(cid);
        if (!customItem) return;
        const present = selectedMemberIdsByCustomItem[cid] || new Set();
        const allHere = (customItem.customItemMembers || []).every(id => present.has(id));
        if (allHere) completeCustomItemIds.add(cid);
    });

    nodes.forEach(node => {
        /* Group rect: special clipboard entry (geometry lives in roomObj.groups). */
        if (node.data_deviceid === 'group') {
            const oldGroupId = node.data_groupId;
            if (!completeGroupIds.has(oldGroupId)) return;
            const group = getGroupById(oldGroupId);
            if (!group) return;
            clipBoardArray.push({
                isGroupRect: true,
                oldGroupId: oldGroupId,
                groupAttrs: {
                    name: group.name,
                    data_layerId: group.data_layerId || '0',
                    data_zPosition: parseFloat(group.data_zPosition) || 0,
                    x: group.x || 0,
                    y: group.y || 0,
                    width: group.width || 0,
                    height: group.height || 0,
                    rotation: group.rotation || 0,
                },
            });
            return;
        }

        /* CustomItem rect: preserve customItemBaseId (strict-family). */
        if (node.data_deviceid === 'customItem') {
            const oldCustomItemId = node.data_customItemId;
            if (!completeCustomItemIds.has(oldCustomItemId)) return;
            const customItem = getCustomItemById(oldCustomItemId);
            if (!customItem) return;
            clipBoardArray.push({
                isCustomItemRect: true,
                oldCustomItemId: oldCustomItemId,
                customItemAttrs: {
                    name: customItem.name,
                    author: customItem.author || '',
                    description: customItem.description || '',
                    version: customItem.version || '1',
                    customItemBaseId: customItem.customItemBaseId || null,
                    data_layerId: customItem.data_layerId || '0',
                    data_zPosition: parseFloat(customItem.data_zPosition) || 0,
                    x: customItem.x || 0,
                    y: customItem.y || 0,
                    width: customItem.width || 0,
                    height: customItem.height || 0,
                    rotation: customItem.rotation || 0,
                },
            });
            return;
        }

        let x2Offset, y2Offset, x2, y2; /* new x and new y */
        let attrs = node.attrs;

        let uuid = createUuid();

        uuids.push(uuid);

        if (!('rotation' in attrs)) {
            node.rotation(0);
        }

        let rotation = attrs.rotation;
        let center = {};

        if (node.getParent().name() === 'tables' || node.getParent().name() === 'stageFloors' || node.getParent().name() === 'boxes' || node.getParent().name() === 'rooms') {
            center.x = node.x();
            center.y = node.y();
        } else {
            center = getNodeCenter(node);
        }

        x2Offset = 0;
        y2Offset = 0;

        x2 = ((center.x - pxOffset) / scale) + x2Offset / scale;
        y2 = ((center.y - pyOffset) / scale) + y2Offset / scale;


        let width = attrs.width / scale;
        let height = attrs.height / scale;
        let deviceId = node.data_deviceid;
        let newAttr = { x: x2, y: y2, width: width, height: height, rotation: rotation };

        if ('points' in attrs) {
            let newPoints = [];
            attrs.points.forEach((point, index) => {
                newPoints[index] = point / scale;
            });

            newAttr.points = newPoints;
        }

        if ('data_diagonalInches' in node) {
            newAttr.data_diagonalInches = node.data_diagonalInches;
        }

        if ('data_zPosition' in node) {
            newAttr.data_zPosition = node.data_zPosition;
        }

        if ('data_vHeight' in node) {
            newAttr.data_vHeight = node.data_vHeight;
        }

        if ('cornerRadius' in node.attrs) {
            if (node.attrs.cornerRadius.length > 1) {
                newAttr.tblRectRadius = node.attrs.cornerRadius[2] / scale;
            }

            if (node.attrs.cornerRadius[0] != node.attrs.cornerRadius[2]) {
                newAttr.tblRectRadiusRight = node.attrs.cornerRadius[0] / scale;
            }
        }

        if ('data_labelField' in node) {
            newAttr.data_labelField = node.data_labelField;
        }

        if ('data_fovHidden' in node) {
            newAttr.data_fovHidden = node.data_fovHidden;
        }

        if ('item.data_audioHidden' in node) {
            newAttr.data_audioHidden = node.data_audioHidden
        }

        if ('data_role' in node) {
            newAttr.data_role = node.data_role;
        }

        if ('data_color' in node) {
            newAttr.data_color = node.data_color;
        }

        if ('data_mount' in node) {
            newAttr.data_mount = node.data_mount;
        }

        if ('data_tilt' in node) {
            newAttr.data_tilt = node.data_tilt;
        }

        if ('data_slant' in node) {
            newAttr.data_slant = node.data_slant;
        }

        if ('data_trapNarrowWidth' in node && !isNaN(node.data_trapNarrowWidth)) {
            newAttr.data_trapNarrowWidth = node.data_trapNarrowWidth;
        }

        if ('data_layerId' in node && node.data_layerId) {
            newAttr.data_layerId = node.data_layerId;
        }

        /* Complete-group members only; pasteItems remaps groupid. */
        if (node.data_groupId && completeGroupIds.has(node.data_groupId)) {
            newAttr.data_groupId = node.data_groupId;
        }

        /* CustomItem membership — same rule as Group above. */
        if (node.data_customItemId && completeCustomItemIds.has(node.data_customItemId)) {
            newAttr.data_customItemId = node.data_customItemId;
        }

        /* Configurable fill/opacity — no UUID remapping needed. */
        if (node.data_fill) {
            newAttr.data_fill = node.data_fill;
        }
        if (node.data_opacity != null && Number(node.data_opacity) !== 1) {
            newAttr.data_opacity = Number(node.data_opacity);
        }

        clipBoardArray.push({ deviceId: deviceId, parent: node.getParent().name(), newAttr: newAttr, uuid: createUuid() });

    });

    itemsObj.items = clipBoardArray;
    canvasClipBoard.items = clipBoardArray;


    /* get transform (tr) upper left hand corner in pixels and adjust for zoom, pan and scale.  */
    let canvasPixelX = (tr.x() + dx) / zoomScaleX;
    let canvasPixelY = (tr.y() + dy) / zoomScaleY;

    let unitX = (canvasPixelX - pxOffset) / scale;
    let unitY = (canvasPixelY - pxOffset) / scale;

    canvasClipBoard.upperLeft = { x: unitX, y: unitY };

    canvasClipBoard.sessionId = sessionId;
    canvasClipBoard.unit = roomObj.unit;
    setItemForLocalStorage('copyItemsObj', JSON.stringify(canvasClipBoard));


}

/* allow copying items between tabs / windows of the same browsers */
