/* Makes an html element draggable. If the element has an ID of {element.id}-dragger, use the that -dragger element as the part to drag, otherwise make the whole element draggable. Works on touch devices too. */
function dragElement(element) {
    let pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;
    const dragger = document.getElementById(element.id + "-dragger");

    if (dragger) {
        dragger.onmousedown = dragMouseDown;
        dragger.ontouchstart = dragTouchStart;
    } else {
        element.onmousedown = dragMouseDown;
        element.ontouchstart = dragTouchStart;
    }

    function dragMouseDown(e) {
        e.preventDefault();
        pos3 = e.clientX;
        pos4 = e.clientY;
        document.onmouseup = closeDragElement;
        document.onmousemove = elementDrag;
        element.style.boxShadow = "10px 10px 20px rgba(0, 0, 0, 0.8)";
    }

    function dragTouchStart(e) {
        e.preventDefault();
        const touch = e.touches[0];
        pos3 = touch.clientX;
        pos4 = touch.clientY;
        document.ontouchend = closeDragElement;
        document.ontouchmove = elementTouchDrag;
        element.style.boxShadow = "10px 10px 20px rgba(0, 0, 0, 0.8)";
    }

    function elementDrag(e) {
        e.preventDefault();
        pos1 = pos3 - e.clientX;
        pos2 = pos4 - e.clientY;
        pos3 = e.clientX;
        pos4 = e.clientY;
        moveElement();
    }

    function elementTouchDrag(e) {
        e.preventDefault();
        const touch = e.touches[0];
        pos1 = pos3 - touch.clientX;
        pos2 = pos4 - touch.clientY;
        pos3 = touch.clientX;
        pos4 = touch.clientY;
        moveElement();
    }

    function moveElement() {
        let elementTop = (element.offsetTop - pos2);
        let elementLeft = (element.offsetLeft - pos1);

        let boundRect = element.getBoundingClientRect();

        if (elementTop < 0) {
            elementTop = 0;
        }

        if (elementTop > window.innerHeight - 40) {
            elementTop = window.innerHeight - 40;
        }

        if (elementLeft < (0 - boundRect.width + 50)) {
            elementLeft = (0 - boundRect.width + 50);
        }

        if (elementLeft > window.innerWidth - 150) {
            elementLeft = window.innerWidth - 150;
        }

        element.style.top = elementTop + 'px';
        element.style.left = elementLeft + 'px';
        element.style.boxShadow = "10px 10px 20px rgba(0, 0, 0, 0.8)";
    }

    function closeDragElement() {
        document.onmouseup = null;
        document.onmousemove = null;
        document.ontouchend = null;
        document.ontouchmove = null;
    }

}


/*
   Moves an object from one part of the array to another.
   Code from https://stackoverflow.com/questions/5306680/move-an-array-element-from-one-array-position-to-another
*/
function arrayMove(arr, old_index, new_index) {
    if (new_index >= arr.length) {
        let k = new_index - arr.length + 1;
        while (k--) {
            arr.push(undefined);
        }
    }
    arr.splice(new_index, 0, arr.splice(old_index, 1)[0]);
};



function changeZheightOfItem(dragItem, dragNode) {

    let overlapItemOutlines = layerTransform.find('#overlapItemOutline');
    let compareToGroups = [];

    overlapItemOutlines.forEach(node => {
        node.destroy();
    });



    if (!(dragNode.getParent().name() === 'videoDevices' || dragItem.data_deviceid.startsWith('webcam')) || ((dragNode.getParent().name() === 'videoDevices') && 'data_diagonalInches' in dragItem)) {

        return;
    }

    if (dragItem.data_deviceid.startsWith('ptz')) {
        compareToGroups = [groupVideoDevices, groupDisplays];
    } else {
        compareToGroups = [groupDisplays];
    }



    let dragNodeFourCorners = findFourCornersOfNode(dragNode);

    outerLoop: for (let i = 0; i < compareToGroups.length; i++) {
        let children = compareToGroups[i].getChildren();
        for (let j = 0; j < children.length; j++) {
            let node = children[j];
            if (!(node.data_deviceid === 'boxRoomPart' || node.data_deviceid === 'polyRoom' || node.id() === dragNode.id()) && 'data_deviceid' in node) {

                let fourCorners = findFourCornersOfNode(node);

                if (doPolygonsIntersect2(fourCorners, dragNodeFourCorners)) {

                    let newPoints = [];
                    fourCorners.forEach(corner => {
                        newPoints.push(corner.x);
                        newPoints.push(corner.y);
                    });

                    if (newPoints.length > 0) {

                        let overlapItemOutline = new Konva.Line({
                            points: newPoints, // A flat array of x, y coordinates
                            stroke: 'orange',
                            strokeWidth: 3,
                            closed: true,
                            id: 'overlapItemOutline',
                            opacity: 0.9,
                            listening: false,
                        });

                        node.getParent().add(overlapItemOutline);


                        let height = node.data_zPosition || 0;

                        height = height + (node.data_vHeight || 0);



                        if (node.getParent().name() === 'tables' && !node.data_vHeight) {
                            height = height + 0.71 * ((roomObj.unit === 'feet') ? 3.8084 : 1);

                        }
                        else if (!node.data_vHeight) {

                            let deviceVertHeight = (allDeviceTypes[node.data_deviceid].height || 0) / 1000; /* device height in meters */

                            if (roomObj.unit === 'feet') {
                                deviceVertHeight = deviceVertHeight * 3.28084;
                            }

                            height = height + deviceVertHeight;
                        }


                        if ('data_diagonalInches' in node && !node.data_deviceid?.match(/brdPro|boardPro|webexDesk/)) {

                            if (node.getParent().name() === 'displays') {
                                height = (fillInTopElevationDisplay(node, false) || 0);

                            }

                        }


                        if (dragNode.data_deviceid.startsWith('webcam')) {
                            height = height + 0.08 / ((roomObj.unit === 'feet') ? 1 : 3.28084);
                        }


                        height = round(height);

                        document.getElementById('itemZposition').value = height;
                        document.getElementById('itemTopElevation').value = '';
                        dragItem.data_zPosition = round(height);
                        document.getElementById('itemZposition').style.backgroundColor = '#ffcc5449';

                        overlapItemOutline.data_dragNode = dragNode;

                        overlapItemOutline.data_dragItem = dragItem;

                        overlapItemOutline.data_dragItem_zPosition = height;

                        break outerLoop;
                    }
                }

            }
        }

        document.getElementById('itemZposition').style.backgroundColor = '';
    }

}

/* shapes that have x: or y: less than 0 for all four corners will be deleted */
function deleteNegativeShapes() {

    let transformGroups = layerTransform.getChildren();

    transformGroups.forEach((group) => {
        let groupName = group.name();
        if (!(groupName === 'theTransformer' || groupName === 'microphoneCoverage' || groupName === 'cameraCoverage' || groupName === 'displayDistanceCoverage' || groupName === 'speakerCoverage')) {

            deleteNegShapeGroups(group);
        }
    })


    function deleteNegShapeGroups(parentGroup, xBound = 1, yBound = 1) {
        let theObjects = parentGroup.getChildren();

        theObjects.forEach(node => {

            let attrs = node.attrs;
            let height = 0;
            let width = 0;

            if ('height' in attrs) {
                height = attrs.height;
            }

            if ('width' in attrs) {
                width = attrs.width;
            }

            let corners = [];

            /* Now get the 4 corner points */
            corners[0] = { x: 0, y: 0 }; // top left
            corners[1] = { x: width, y: 0 }; // top right
            corners[2] = { x: width, y: height }; // bottom right
            corners[3] = { x: 0, y: height }; // bottom left

            /* Rotate the corners using the node's transform relative to
             * the stage (NOT absolute). Passing `stage` as the `top`
             * argument excludes the stage's own transform — which
             * matters at zoom > 100% because `repositionStage()` sets
             * stage.x(-dx) / stage.y(-dy) to follow the DOM scroll, and
             * stage.scaleX/Y = zoomValue/100. Including those would
             * make every node's absolute corners massively negative
             * whenever the user has scrolled while zoomed in, causing
             * `deleteNegativeShapes` to destroy legitimate items.
             * Stage-local coords keep the (xBound=1, yBound=1) check
             * meaningful: it really does mean "all corners are
             * upper-left of the room's pixel origin". */
            for (let i = 0; i < 4; i++) {
                corners[i] = node.getAbsoluteTransform(stage).point(corners[i]);
            }

            if ((corners[0].x < xBound && corners[1].x < xBound && corners[2].x < xBound && corners[3].x < xBound)
                || (corners[0].y < yBound && corners[1].y < yBound && corners[2].y < yBound && corners[3].y < yBound)) {

                let audioShading = stage.find('#audio~' + node.id())[0];
                let speakerShading = stage.find('#speaker~' + node.id())[0];
                let videoShading = stage.find('#fov~' + node.id())[0];

                node.destroy();
                if (audioShading) {
                    audioShading.destroy();
                }

                if (speakerShading) {
                    speakerShading.destroy();
                }

                if (videoShading) {
                    videoShading.destroy();
                }

            }

        });
    }
}


/**
 * Helper function to determine whether there is an intersection between the two polygons described
 * by the lists of vertices. Uses the   .
 *
 * @param {Array} a - An array of connected points [{x:, y:}, {x:, y:},...] that form a closed polygon
 * @param {Array} b - An array of connected points [{x:, y:}, {x:, y:},...] that form a closed polygon
 * @return {boolean} - True if there is any intersection between the 2 polygons, false otherwise
 */
function doPolygonsIntersect(a, b) {
    const polygons = [a, b];
    let minA, maxA, projected, minB, maxB;

    for (let i = 0; i < polygons.length; i++) {
        const polygon = polygons[i];

        for (let i1 = 0; i1 < polygon.length; i1++) {
            const i2 = (i1 + 1) % polygon.length;
            const p1 = polygon[i1];
            const p2 = polygon[i2];

            const normal = { x: p2.y - p1.y, y: p1.x - p2.x };

            minA = maxA = undefined;
            for (let j = 0; j < a.length; j++) {
                projected = normal.x * a[j].x + normal.y * a[j].y;
                if (typeof minA === 'undefined' || projected < minA) {
                    minA = projected;
                }
                if (typeof maxA === 'undefined' || projected > maxA) {
                    maxA = projected;
                }
            }

            minB = maxB = undefined;
            for (let j = 0; j < b.length; j++) {
                projected = normal.x * b[j].x + normal.y * b[j].y;
                if (typeof minB === 'undefined' || projected < minB) {
                    minB = projected;
                }
                if (typeof maxB === 'undefined' || projected > maxB) {
                    maxB = projected;
                }
            }

            if (maxA < minB || maxB < minA) {
                return false;
            }
        }
    }
    return true;
}

/* populates the arrary itemsOffStageId.  These are devices not on the stage and not passed to the Shareable Link or the Workspace Designer */
