/* ---- Group creation / destruction ---- */

/* Dissolve a group. keepItems=true → leave member nodes on canvas (Ungroup).
 * keepItems=false → destroy member nodes too (Delete path). */
function ungroupItems(groupId, keepItems) {
    if (!groupId) return;
    ensureGroups();

    const members = getGroupMemberNodes(groupId);

    members.forEach(node => {
        node.data_groupId = null;
        if (keepItems) {
            /* Members already had listening:true; nothing to restore.
             * Just clear the group attribute from the roomObj.items entry. */
            const entry = roomObj.items.find(i => i.id === node.id());
            if (entry) delete entry.data_groupId;
        } else {
            /* Hard-delete: destroy member and its coverage nodes */
            ['audio~', 'speaker~', 'fov~', 'dispDist~'].forEach(prefix => {
                const cov = stage.find('#' + prefix + node.id())[0];
                if (cov) cov.destroy();
            });
            stage.find('#label~' + node.id()).forEach(l => l.destroy());
            canvasNodesMap.delete(node.id());
            node.destroy();
        }
    });

    /* Remove the Konva group rect */
    if (groupGroupRects) {
        const rectNode = groupGroupRects.find(n => n.data_groupId === groupId)[0];
        if (rectNode) rectNode.destroy();
    }

    /* Remove from roomObj.groups */
    roomObj.groups = roomObj.groups.filter(g => g.groupid !== groupId);

    if (!keepItems) {
        /* Clean up roomObj.items entries for hard-deleted members */
        roomObj.items = roomObj.items.filter(i => i.data_groupId !== groupId);
    }

    /* No batchDraw() — Konva v8+ auto-redraws after node.destroy() / .remove() above. */
}

/* Group the current tr.nodes() selection (or the nodes passed in). */
function createGroup(nodesToGroup) {
    ensureGroups();

    const candidates = nodesToGroup || tr.nodes();
    /* Only group actual items — skip existing Group rects (data_deviceid='group')
     * AND existing CustomItem rects (data_deviceid='customItem'). CustomItem
     * rects are NOT items; they are a parallel bundle primitive. The
     * CustomItem's member items are already in `candidates` (pulled in by
     * expandSelectionForGroups() when the user clicks the CustomItem rect),
     * so they get added to the new Group individually with a shared
     * data_groupId. The CustomItem rect itself stays a CustomItem (its
     * own bundle), and `getCustomItemRectsAllInGroup()` makes it ride
     * along when the new Group is later dragged or rotated.
     *
     * Without the customItem exclusion, the CustomItem rect was getting
     * added to `group.groupMembers` and tagged with `data_groupId`. On
     * copy, `copyToCanvasClipBoard()`'s completeness check routed the
     * CustomItem rect into `selectedRectCustomItemIds` (because of its
     * data_deviceid) and never counted it as a Group member, so the
     * Group always failed the completeness gate and was silently dropped
     * from the clipboard. Mirror createCustomItem()'s filter to fix it. */
    const itemNodes = candidates.filter(n =>
        n.data_deviceid && n.data_deviceid !== 'group' && n.data_deviceid !== 'customItem' && n.isVisible()
    );

    if (itemNodes.length < 2) {
        alertDialog('Cannot Group', 'Select at least two items to create a group.');
        return;
    }

    /* Collect unique group IDs already on the selection — dissolve them first */
    const existingGroupIds = new Set(
        itemNodes.filter(n => n.data_groupId).map(n => n.data_groupId)
    );
    existingGroupIds.forEach(id => ungroupItems(id, true));

    /* Re-collect after dissolve (data_groupId is now null on all) */
    const finalNodes = itemNodes; /* same Konva node references, groupId cleared */

    /* Layer resolution */
    const layerIds = [...new Set(finalNodes.map(n => n.data_layerId || '0'))];
    let targetLayerId;
    if (layerIds.length === 1) {
        targetLayerId = layerIds[0];
    } else {
        const drp = document.getElementById('drpAddItemLayer');
        targetLayerId = (drp && drp.value) ? drp.value : '0';
        /* Move all members to the target layer */
        finalNodes.forEach(n => updateItemLayer(n.id(), targetLayerId));
    }

    /* Calculate bounding box in layerTransform-local pixel space using the
     * same getClientRect call the Transformer uses internally, so the
     * Group rect hugs the items exactly the way the blue Transformer box
     * does (no visible gap). No padding. */
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    finalNodes.forEach(node => {
        const r = getMemberBoundingRect(node);
        if (r.x < minX) minX = r.x;
        if (r.y < minY) minY = r.y;
        if (r.x + r.width  > maxX) maxX = r.x + r.width;
        if (r.y + r.height > maxY) maxY = r.y + r.height;
    });

    const pixelX = minX;
    const pixelY = minY;
    const pixelW = maxX - minX;
    const pixelH = maxY - minY;

    const lowestZ = Math.min(...finalNodes.map(n => parseFloat(n.data_zPosition) || 0));

    const newGroup = {
        groupid: createUuid(),
       // name: 'Group ' + (roomObj.groups.length + 1),
        name: '',
        data_layerId: targetLayerId,
        x: ((pixelX - pxOffset) / scale) + activeRoomX,
        y: ((pixelY - pyOffset) / scale) + activeRoomY,
        width:  pixelW / scale,
        height: pixelH / scale,
        rotation: 0,
        data_zPosition: lowestZ,
        groupMembers: finalNodes.map(n => n.id()),
    };

    roomObj.groups.push(newGroup);

    /* Tag member Konva nodes */
    finalNodes.forEach(node => {
        node.data_groupId = newGroup.groupid;
        /* Tag roomObj.items entry */
        const entry = roomObj.items.find(i => i.id === node.id());
        if (entry) entry.data_groupId = newGroup.groupid;
    });

    const groupRectNode = insertGroupRect(newGroup);

    /* Select the group rect + all members so Konva's Transformer can
     * move/rotate them as one bundle when the user grabs any of them. */
    if (groupRectNode) {
        tr.nodes([groupRectNode, ...finalNodes]);
    } else {
        tr.nodes(finalNodes);
    }
    /* Re-pull any CustomItem rects (and their members) whose member items
     * just landed in the new Group. Without this, Ctrl+G immediately
     * followed by Ctrl+C would copy the items + Group rect but leave the
     * CustomItem rect out of `tr.nodes()` (it was filtered out of
     * `finalNodes` above), and the CustomItem would be dropped from the
     * clipboard. expandSelectionForGroups() also re-clamps the
     * Transformer's anchors/resize state for the bundle. */
    expandSelectionForGroups();
    tr.enabledAnchors([]);
    tr.resizeEnabled(false);
    enableCopyDelBtn();
    canvasToJson();
    console.info('Group created:', newGroup.groupid, 'with', finalNodes.length, 'members');
}

/* Ungroup all groups referenced in the current tr.nodes() selection */
function ungroupSelectedItems() {
    const groupIds = new Set();
    tr.nodes().forEach(n => {
        if (n.data_deviceid === 'group') groupIds.add(n.data_groupId);
        else if (n.data_groupId) groupIds.add(n.data_groupId);
    });
    if (!groupIds.size) return;
    tr.nodes([]);
    groupIds.forEach(id => ungroupItems(id, true));
    canvasToJson();
}

/* CustomItem creation/destruction. Mirrors createGroup/ungroupItems
 * with data_customItemId / roomObj.customItems / groupCustomItemRects. */

function ungroupCustomItem(customItemId, keepItems) {
    if (!customItemId) return;
    ensureCustomItems();

    const members = getCustomItemMemberNodes(customItemId);

    members.forEach(node => {
        node.data_customItemId = null;
        if (keepItems) {
            const entry = roomObj.items.find(i => i.id === node.id());
            if (entry) delete entry.data_customItemId;
        } else {
            ['audio~', 'speaker~', 'fov~', 'dispDist~'].forEach(prefix => {
                const cov = stage.find('#' + prefix + node.id())[0];
                if (cov) cov.destroy();
            });
            stage.find('#label~' + node.id()).forEach(l => l.destroy());
            canvasNodesMap.delete(node.id());
            node.destroy();
        }
    });

    if (groupCustomItemRects) {
        const rectNode = groupCustomItemRects.find(n => n.data_customItemId === customItemId)[0];
        if (rectNode) rectNode.destroy();
    }

    roomObj.customItems = roomObj.customItems.filter(c => c.customitemid !== customItemId);

    if (!keepItems) {
        roomObj.items = roomObj.items.filter(i => i.data_customItemId !== customItemId);
    }

    /* No batchDraw() — Konva v8+ auto-redraws after node.destroy() / .remove() above. */
}

/* Create a CustomItem from tr.nodes() (or supplied nodes). Pre-cleanup:
 * dissolves any existing CustomItem memberships, then dissolves every
 * Group touched by the selection (CustomItem CANNOT contain Groups).
 * Group co-tenants outside the selection also lose Group membership —
 * see CLAUDE.md "Group / CustomItem nesting model".
 * `name` is optional at the signature level for programmatic callers;
 * the dialog forces a non-empty name. */
function createCustomItem(nodesToGroup, name, author, description) {
    ensureCustomItems();

    const candidates = nodesToGroup || tr.nodes();
    const itemNodes = candidates.filter(n =>
        n.data_deviceid && n.data_deviceid !== 'group' && n.data_deviceid !== 'customItem' && n.isVisible()
    );

    /* Selection floor: 2+ real items, with a single-item exception for
     * a lone `pathShape`. Custom Path Shapes are user-authored geometry
     * that the user often wants to save to the Custom Item Library as a
     * standalone reusable template, so the usual "redundant 1-item
     * bundle" objection (which justifies the 2+ rule for normal
     * devices) doesn't apply. All downstream code paths (membership
     * wiring, rect insertion, URL/WD/clipboard round-trip, library
     * export, menu-image generation) already work for any member count
     * >= 1.
     *
     * Note on the deletion path: `deleteTrNodes` still dissolves any
     * CustomItem that drops below 2 members on deletion. A 1-pathShape
     * CustomItem whose single member is deleted dissolves cleanly
     * (length 0). A 2-member CustomItem reduced to 1 by deletion also
     * still dissolves — even if the remaining member is a pathShape —
     * because that path is conservative and shared with the Group
     * dissolve logic. The user can re-create a 1-pathShape CustomItem
     * from the loose remainder if desired. */
    const isSinglePathShape =
        itemNodes.length === 1 && itemNodes[0].data_deviceid === 'pathShape';
    if (itemNodes.length < 2 && !isSinglePathShape) {
        alertDialog('Cannot Create Custom Item',
            'Select at least two items, or a single Custom Path Shape, to create a Custom Item.');
        return;
    }

    /* Dissolve any existing customItem memberships first so each item ends
     * up with exactly one data_customItemId (the new one). */
    const existingCustomItemIds = new Set(
        itemNodes.filter(n => n.data_customItemId).map(n => n.data_customItemId)
    );
    existingCustomItemIds.forEach(id => ungroupCustomItem(id, true));

    /* Strip ALL Group memberships touched by the selection. For every
     * distinct data_groupId carried by any selected item, dissolve the
     * whole Group via `ungroupItems(id, true)` — clears `data_groupId`
     * on every member node + roomObj.items entry, destroys the Group
     * rect, and removes the entry from `roomObj.groups`. After this
     * loop every selected item is guaranteed to have no `data_groupId`,
     * matching the rule "when a customItem is created, all group
     * information should be removed from each item and the group
     * removed".
     *
     * Side effect — Group "co-tenants" lose membership too: if a Group
     * G has members [A, B, C, D] and the user selects A, B for a new
     * CustomItem, dissolving G also clears `data_groupId` on C and D
     * (they are not in the new CustomItem; they simply become loose
     * items). This is the documented trade-off of keeping the dissolve
     * a single atomic operation with the existing helper. The
     * alternative (surgically removing only A, B from G's
     * `groupMembers` and recomputing the rect bounds) would leave a
     * Group of size <2 in many real workflows, which the rest of the
     * code does not gracefully tolerate.
     *
     * Items not in any Group are skipped by the `n.data_groupId` filter
     * — Set already de-duplicates so each Group is dissolved once even
     * if multiple selected items share it. */
    const groupIdsToDissolve = new Set(
        itemNodes.filter(n => n.data_groupId).map(n => n.data_groupId)
    );
    groupIdsToDissolve.forEach(id => ungroupItems(id, true));

    const finalNodes = itemNodes;

    /* Layer resolution: same convention as createGroup(). All members
     * adopt a single shared layer. If the selection spans multiple
     * layers, fall back to the "Add Items to:" dropdown. */
    const layerIds = [...new Set(finalNodes.map(n => n.data_layerId || '0'))];
    let targetLayerId;
    if (layerIds.length === 1) {
        targetLayerId = layerIds[0];
    } else {
        const drp = document.getElementById('drpAddItemLayer');
        targetLayerId = (drp && drp.value) ? drp.value : '0';
        finalNodes.forEach(n => updateItemLayer(n.id(), targetLayerId));
    }

    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    finalNodes.forEach(node => {
        const r = getMemberBoundingRect(node);
        if (r.x < minX) minX = r.x;
        if (r.y < minY) minY = r.y;
        if (r.x + r.width  > maxX) maxX = r.x + r.width;
        if (r.y + r.height > maxY) maxY = r.y + r.height;
    });

    const pixelX = minX;
    const pixelY = minY;
    const pixelW = maxX - minX;
    const pixelH = maxY - minY;

    const lowestZ = Math.min(...finalNodes.map(n => parseFloat(n.data_zPosition) || 0));

    const newCustomItem = {
        customitemid: createUuid(),
        /* Template / "family" id — stable across copies, pastes, exports,
         * and IDB library entries. Used as the primary key when saving
         * the customItem template to the VRC Custom Item Library
         * (IndexedDB) and when deciding whether an imported
         * vrcCustomItems file overwrites an existing library entry.
         * customitemid is the per-instance id (changes on paste);
         * customItemBaseId is the per-template id (persists). */
        customItemBaseId: createUuid(),
        /* Name supplied by the dialog (openCreateCustomItemDialog). Falls
         * back to '' if the function is called programmatically without
         * a name — matches the schema for import paths that may carry
         * an unnamed template through. */
        name: (name == null) ? '' : String(name),
        /* Optional descriptive metadata from the create dialog.
         * Author + description are free-form strings; version defaults
         * to '1' (UI doesn't surface this field — every template
         * created in v1 is implicitly version 1, with the wire format
         * reserving the string shape for future bumps). */
        author: (author == null) ? '' : String(author),
        description: (description == null) ? '' : String(description),
        version: '1',
        data_layerId: targetLayerId,
        x: ((pixelX - pxOffset) / scale) + activeRoomX,
        y: ((pixelY - pyOffset) / scale) + activeRoomY,
        width:  pixelW / scale,
        height: pixelH / scale,
        rotation: 0,
        data_zPosition: lowestZ,
        customItemMembers: finalNodes.map(n => n.id()),
    };

    roomObj.customItems.push(newCustomItem);

    finalNodes.forEach(node => {
        node.data_customItemId = newCustomItem.customitemid;
        const entry = roomObj.items.find(i => i.id === node.id());
        if (entry) entry.data_customItemId = newCustomItem.customitemid;
    });

    const customItemRectNode = insertCustomItemRect(newCustomItem);

    /* Select customItem rect + members so the Konva Transformer carries
     * the bundle as one unit. expandSelectionForGroups() will also pull in
     * any Group rect that contains some of these members (since
     * data_groupId is preserved). */
    if (customItemRectNode) {
        tr.nodes([customItemRectNode, ...finalNodes]);
    } else {
        tr.nodes(finalNodes);
    }
    expandSelectionForGroups();
    tr.enabledAnchors([]);
    tr.resizeEnabled(false);
    enableCopyDelBtn();
    canvasToJson();
    console.info('CustomItem created:', newCustomItem.customitemid, 'with', finalNodes.length, 'members');

    /* Fire-and-forget save to the VRC Custom Item Library (IDB). The
     * customItem already exists on the canvas; this background work
     * only affects future flows (Quick Add palette tile, "Add to /
     * Remove from Library" menu state). Toast is shown only on
     * successful save so a silent IDB failure isn't misrepresented to
     * the user — they'll still see the customItem on the canvas and
     * can re-trigger a save via "Add to Custom Library". */
    persistCustomItemToLibrary(newCustomItem).then(function (savedBaseId) {
        if (savedBaseId) {
            showToast('Custom Item saved to library');
        }
    });
}

/* Ungroup all customItems referenced in the current tr.nodes() selection */
function ungroupSelectedCustomItems() {
    const customItemIds = new Set();
    tr.nodes().forEach(n => {
        if (n.data_deviceid === 'customItem') customItemIds.add(n.data_customItemId);
        else if (n.data_customItemId) customItemIds.add(n.data_customItemId);
    });
    if (!customItemIds.size) return;
    tr.nodes([]);
    customItemIds.forEach(id => ungroupCustomItem(id, true));
    canvasToJson();
}

/* ---- Group rect visual ----
 * Creates (or recreates) the purple bounding-box rectangle for a VRC Group.
 * The rect is placed in groupGroupRects (behind all items).
 * groupObj: an entry from roomObj.groups.
 */
function insertGroupRect(groupObj) {
    if (!groupObj || !groupObj.groupid) return;

    /* Remove any stale rect for this group first */
    const existing = groupGroupRects.find(n => n.data_groupId === groupObj.groupid)[0];
    if (existing) existing.destroy();

    const pixelX = scale * groupObj.x + pxOffset - activeRoomX * scale;
    const pixelY = scale * groupObj.y + pyOffset - activeRoomY * scale;
    const pixelW = scale * (groupObj.width  || 1);
    const pixelH = scale * (groupObj.height || 1);

    /* listening: false — the rect is a passive visual anchor; the user
     *            initiates a selection by clicking any member item.
     *            `expandSelectionForGroups()` then adds this rect to
     *            tr.nodes() so it travels with the group.
     * draggable: true — needed so Konva's Transformer can carry the rect
     *            as part of tr.nodes() (the rect always moves with its
     *            members when the group is selected).
     * No manual drag/transform handlers on the rect; member-direct drags
     * are followed by `followGroupDragFromMember()` from each member's
     * own dragmove handler.
     */
    /* Default appearance: invisible (opacity 0) so the rect is just a
     * passive bounding-box anchor that doesn't add visual noise to the
     * canvas. When the group is selected (single-Group bundle OR part of a
     * multi-select), `updateTrNodesShading()` raises opacity to 0.2 so the
     * user can see the group bounds; `removeShadingTrNodes()` drops it
     * back to 0 on deselect. The fill/stroke colours are baked in here
     * (light blue + solid blue) so the highlight just toggles opacity. */
    const groupRect = new Konva.Rect({
        x: pixelX,
        y: pixelY,
        width: pixelW,
        height: pixelH,
        rotation: groupObj.rotation || 0,
        fill: '#8FD9FB',
        stroke: 'blue',
        strokeWidth: 1,
        dash: [6, 4],
        opacity: 0,
        name: 'Group Item',
        id: groupObj.groupid,
        draggable: true,
        listening: false,
    });

    groupRect.data_deviceid   = 'group';
    groupRect.data_groupId    = groupObj.groupid;
    groupRect.data_zPosition  = groupObj.data_zPosition || 0;
    groupRect.data_layerId    = groupObj.data_layerId || '0';
    groupRect.data_labelField = groupObj.name || 'Group Item';

    groupGroupRects.add(groupRect);
    /* No batchDraw() — Konva v8+ auto-redraws after .add() (Konva.autoDrawEnabled === true). */
    return groupRect;
}

/* ---- CustomItem rect visual ----
 * Mirrors insertGroupRect() — see that function for the design notes. The
 * only differences are the visual style (light green / green stroke) and
 * the parent Konva group (groupCustomItemRects). */
function insertCustomItemRect(customItemObj) {
    if (!customItemObj || !customItemObj.customitemid) return;

    const existing = groupCustomItemRects.find(n => n.data_customItemId === customItemObj.customitemid)[0];
    if (existing) existing.destroy();

    const pixelX = scale * customItemObj.x + pxOffset - activeRoomX * scale;
    const pixelY = scale * customItemObj.y + pyOffset - activeRoomY * scale;
    const pixelW = scale * (customItemObj.width  || 1);
    const pixelH = scale * (customItemObj.height || 1);

    const customItemRect = new Konva.Rect({
        x: pixelX,
        y: pixelY,
        width: pixelW,
        height: pixelH,
        rotation: customItemObj.rotation || 0,
        fill: '#B6EAB0',
        stroke: 'green',
        strokeWidth: 1,
        dash: [4, 4],
        opacity: 0,
        name: 'Custom Item',
        id: customItemObj.customitemid,
        draggable: true,
        listening: false,
    });

    customItemRect.data_deviceid     = 'customItem';
    customItemRect.data_customItemId = customItemObj.customitemid;
    customItemRect.data_zPosition    = customItemObj.data_zPosition || 0;
    customItemRect.data_layerId      = customItemObj.data_layerId || '0';
    customItemRect.data_labelField   = customItemObj.name || 'Custom Item';

    groupCustomItemRects.add(customItemRect);
    /* No batchDraw() — Konva v8+ auto-redraws after .add() (Konva.autoDrawEnabled === true). */
    return customItemRect;
}

function insertShapeItem(deviceId, groupName, attrs, uuid = '', selectTrNode = false) {

    let hitStrokeWidth = 0; /* px:  allows the user to be close within X pixels to click on shape */
    let updateNode;

    /* scale the attrs to fit grid */
    let pixelX = scale * attrs.x + pxOffset - activeRoomX * scale;
    let pixelY = scale * attrs.y + pyOffset - activeRoomY * scale;

    let insertDevice = {};
    let group;
    let width, height, rotation, data_zPosition, data_vHeight, data_slant, data_tilt;
    let abbrUnit = 'm';  /* abbreviated unit - will be m for meters, f for feet. Inserted in the shape rendering. */

    if (unit === 'feet') {
        abbrUnit = 'ft'
    }


    allNodeShapeGroups.forEach(shapeGroup => {
        if (shapeGroup.name() === allDeviceTypes[deviceId].parentGroup) {
            group = shapeGroup;
        }
    });

    insertDevice = allDeviceTypes[deviceId];
    groupName = group.name();

    /*
        Check if deviceId is in group tables or stageFloors - which includes the wall, column, box or stageFloors
        if in tables/stageFloors break out of this and go to insertTable.
    */
    if (groupName === 'tables' || groupName === 'stageFloors' || groupName === 'boxes' || groupName === 'rooms') {
        insertTable(insertDevice, groupName, attrs, uuid, selectTrNode)
        return;
    }

    /* each shape gets a unique uuid for tracking.  This UUID is also in the roomObj JSON and not recreated if it exists */
    if (uuid === '') {
        uuid = createUuid();
    }
    // else {
    //     updateNode = canvasNodesMap.get(uuid);
    // }

    tr.resizeEnabled(false);

    /* convert mm to meters * scale */
    width = insertDevice.width / 1000 * scale;
    height = insertDevice.depth / 1000 * scale;

    let addHighlight = false;

    /* add circular highlight to any device smaller than sizeToAddOutline. Added after image obj is created */
    if (smallItemsHighlight && insertDevice.width < sizeToAddOultine && insertDevice.depth < sizeToAddOultine) {
        width = sizeToAddOultine / 1000 * scale;
        height = sizeToAddOultine / 1000 * scale;
        addHighlight = true;
    }

    if (unit === 'feet') {
        width = width * 3.28084;
        height = height * 3.28084;
    }

    if ('rotation' in attrs) {
        rotation = attrs.rotation;
    } else {
        rotation = 0;
    }

    /* should move Display calculations here */
    let data_diagonalInches = 0;


    if ('data_diagonalInches' in attrs) {
        data_diagonalInches = attrs.data_diagonalInches;
    }
    else if ('diagonalInches' in insertDevice) {
        data_diagonalInches = insertDevice.diagonalInches;
        attrs.data_diagonalInches = data_diagonalInches;
    }

    if ('data_zPosition' in attrs) {
        data_zPosition = attrs.data_zPosition;
    } else {
        data_zPosition = "";
    }

    if ('data_vHeight' in attrs) {
        data_vHeight = attrs.data_vHeight;
    } else {
        data_vHeight = "";
    }

    if ('data_tilt' in attrs) {
        data_tilt = attrs.data_tilt;
    } else {
        data_tilt = "";
    }

    if ('data_slant' in attrs) {
        data_slant = attrs.data_slant;
    } else {
        data_slant = "";
    }

    /*
        Calculate width of displays based on Diagonal inches.
    */
    let displayNumber = 1;
    if (groupName === 'displays' || deviceId.startsWith('roomKitEqx')) {

        if (deviceId === 'displaySngl') {
            displayNumber = 1;
        }
        else if (deviceId.startsWith('displayDbl') || deviceId.startsWith('roomKitEqx')) {
            displayNumber = 2;
        }
        else if (deviceId.startsWith('displayTrpl')) {
            displayNumber = 3;
        }


        if (deviceId === 'display21_9') {
            width = (displayWidth21_9 / diagonalInches21_9) * data_diagonalInches / 1000 * scale * displayNumber;
        }
        else if (deviceId === 'display21_9_2') {
            width = (displayWidth21_9_2 / diagonalInches21_9) * data_diagonalInches / 1000 * scale * displayNumber;
        } else if (/display.*_2$/.test(deviceId)) {
            width = (displayWidth_2 / diagonalInches) * data_diagonalInches / 1000 * scale * displayNumber;
        } else {
            width = (displayWidth / diagonalInches) * data_diagonalInches / 1000 * scale * displayNumber;
        }

        if (deviceId.startsWith('displayScreen')) {
            height = allDeviceTypes['displayScreen'].depth / 1000 * scale;
        }
        else if (!deviceId.startsWith('roomKitEqx')) {
            height = displayDepth / 1000 * scale;  /* height is displayDepth, which is constant regardless of diagnol inches. roomKitEqx width is set in the videoDevices object */
        }



        if (unit === 'feet') {
            width = width * 3.28084;
            if (!deviceId.startsWith('roomKitEqx')) height = height * 3.28084;
        }


    }

    /* convert to upper left pixel position before conversion */
    let cornerXY = findUpperLeftXY({ x: pixelX, y: pixelY, rotation: rotation, width: width, height: height });

    if (updateNode) {
        updateNodeAttributes(updateNode);
        return;
    }

    function updateNodeAttributes(node) {
        node.x(cornerXY.x);
        node.y(cornerXY.y);
        node.width(width);
        node.height(height);
        node.rotation(rotation);


        if ('scaleX' in attrs) {
            node.scaleX = attrs.scaleX;
        };

        if ('scaleY' in attrs) {
            node.scaleX = attrs.scaleX;
        };

        if ('data_diagonalInches' in attrs) {
            node.data_diagonalInches = data_diagonalInches;
        }

        if ('data_zPosition' in attrs && !(attrs.data_zPosition === '')) {
            node.data_zPosition = data_zPosition;
        }

        if ('data_vHeight' in attrs && attrs.data_vHeight != '') {
            node.data_vHeight = data_vHeight;
        }

        if ('data_tilt' in attrs && attrs.data_tilt != '') {
            node.data_tilt = data_tilt;
        }

        if ('data_slant' in attrs && attrs.data_slant != '') {
            node.data_slant = data_slant;
        }

        if ('data_labelField' in attrs && attrs.data_labelField.trim() !== '{}') {
            node.data_labelField = attrs.data_labelField;
        }

        if (attrs.data_fovHidden) {
            node.data_fovHidden = attrs.data_fovHidden;
        }

        if (attrs.data_audioHidden) {
            node.data_audioHidden = attrs.data_audioHidden;
        }

        if (attrs.data_dispDistHidden) {
            node.data_dispDistHidden = attrs.data_dispDistHidden;
        }

        if ('data_role' in attrs) {
            node.data_role = attrs.data_role; /* data_role.value & data_role.index */
        }

        if ('data_color' in attrs) {
            node.data_color = attrs.data_color; /* data_color.value & data_color.index */
        }


        if ('data_mount' in attrs) {
            node.data_mount = attrs.data_mount; /* data_mount.value & data_mount.index */
        }

        node.data_layerId = ('data_layerId' in attrs && attrs.data_layerId) ? attrs.data_layerId : '0';
        applyLayerStateToNode(node, node.data_layerId);

        /* Group / CustomItem membership */
        node.data_groupId = attrs.data_groupId || null;
        node.data_customItemId = attrs.data_customItemId || null;

        /* Configurable fill / opacity — defensive mirror. box / carpet /
         * stageFloor route through insertTable(), but the four-place rule
         * wants both writers in sync so any future Image-rendered device
         * with configurableColor: true picks up the values too. */
        node.data_fill = attrs.data_fill || null;
        node.data_opacity = (attrs.data_opacity == null) ? null : Number(attrs.data_opacity);

        if ('name' in insertDevice) {
            node.name(insertDevice.name);
        }

        if ('opacity' in insertDevice) {
            node.opacity(insertDevice.opacity);
        }

    }

    let imageObj = new Image();

    imageObj.onload = function imageObjOnLoad() {
        let imageItem = new Konva.Image({
            x: cornerXY.x,
            y: cornerXY.y,
            image: imageObj,
            width: width,
            height: height,
            id: uuid,
            draggable: true,
            rotation: rotation,
        });

        imageItem.hitStrokeWidth(hitStrokeWidth); /* don't need to be close to the image to be selected */

        imageItem.data_deviceid = deviceId;

        updateNodeAttributes(imageItem);

        imageItem.on('dragend', function imageItemOnDragEnd() {
            endGroupDragFollow();
            endCustomItemDragFollow();
            /* Drift diagnostic must run BEFORE the bundle early-return
             * below so bundle drags are still measured — the early-return
             * only skips the single-item guide-line cleanup +
             * canvasToJson, which the bundle path defers to
             * stage.on('mouseup') anyway (see "Deferred canvasToJson
             * sync model" note above beginGroupDragFollow). */
            endDriftCheck('imageItem.dragend');
            if (trNodesLength > 1) return;
            allGuideLines.forEach(guideLine => {
                guideLine.destroy();
            });

            allGuideLines = [];

            canvasToJson();
        });



        imageItem.on('dragstart', function imageItemOnDragStart(e) {
            /* Capture the pre-drag snapshot for group / customItem drag-
             * follow BEFORE Konva's drag system advances the target's
             * position. See the matching tblWallFlr.on('dragstart') for
             * the full reasoning. */
            if (e.target.data_groupId) {
                beginGroupDragFollow(e.target);
            }
            if (e.target.data_customItemId) {
                beginCustomItemDragFollow(e.target);
            }
            /* Opt-in drift diagnostic — see beginDriftCheck() docstring. */
            beginDriftCheck('imageItem.dragstart', e.target);
        });

        imageItem.on('dragmove', function imageItemOnDragMove(e) {

            if (isAllCoverageGroupHidden) return;

            snapCenterToIncrement(imageItem);

            snapToGuideLines(e);


            updateShading(imageItem);


            /* in case the dragged item is not the tr.node, make it the tr.node */

            if (!tr.nodes().includes(e.target)) {
                if (e.target.data_groupId || e.target.data_customItemId) {
                    /* Bundle member dragged solo — select the whole bundle
                     * (rect + every member) instead of just this one
                     * item. */
                    tr.nodes([e.target]);
                    expandSelectionForGroups();
                } else {
                    tr.nodes([e.target]);
                    /* tables and other objects maybe resizable. */
                    if (e.target.getParent() === groupTables || e.target.getParent() === groupStageFloors || e.target.getParent() === groupBoxes || e.target.getParent() === groupRooms) {
                        resizeTableOrWall();
                    } else {
                        tr.resizeEnabled(false);
                    }
                }
                enableCopyDelBtn();
            }

            if (e.target.attrs.id) {
                if (tr.nodes().length === 1) {
                    updateFormatDetails(e, true);
                }
            }

            /* If this item belongs to a Group / CustomItem, drag the rest
             * of the bundle along with it. The Group follower runs first;
             * the CustomItem follower handles items only in a customItem
             * (its internal guard avoids double-shifting siblings already
             * moved by the Group follower). */
            followGroupDragFromMember(imageItem);
            followCustomItemDragFromMember(imageItem);
        });

        imageItem.on('mousedown touchstart', function imageItemOnMouseDownTouchstart(e) {

            if (panScrollableOn || isSelectingTwoPointsOn || movingBackgroundImage || isWallBuilderOn || isWallWriterOn2 || isPolyBuilderOn) {
                e.evt.preventDefault();
                return;
            }


            updateShading(imageItem);
            clickedOnItemId = imageItem.id();
        });

        imageItem.on('mouseup touchend', function imageItemMouseUpTouchend(e) {


            clickedOnItemId = '';

            let overlapItemOutlines = layerTransform.find('#overlapItemOutline');


            overlapItemOutlines.forEach(overlapItemOutline => {

                overlapItemOutline.data_dragNode.data_zPosition = overlapItemOutline.data_dragItem_zPosition;

                overlapItemOutline.data_dragItem.data_zPosition = overlapItemOutline.data_dragItem_zPosition;

                overlapItemOutline.destroy();

            });
        });

        imageItem.on('transform', function imageItemOnTrasform() {

            if (isAllCoverageGroupHidden) return;

            updateShading(imageItem);
        });


        /* add the shape to the layer */
        group.add(imageItem);

        updateShading(imageItem);

        if (selectTrNode) {

            tr.nodes([imageItem]);
            enableCopyDelBtn();
            /* add delay before updateFormatDetails to give time for object to be inserted and roomObj JSON to be updated */
            setTimeout(() => {
                updateFormatDetails(uuid)
            }, 500);
        }

        /* on insert and refresh of the page, make sure person is over the chair. */
        if (imageItem.data_deviceid.startsWith('person')) {
            imageItem.moveToTop();
        }

        if (imageItem.data_deviceid.startsWith('chair') || imageItem.data_deviceid.startsWith('plant') || imageItem.data_deviceid.startsWith('door') || imageItem.data_deviceid.startsWith('pouf')) {
            imageItem.zIndex(0);
        }

        if (allDeviceTypes[imageItem.data_deviceid].parentGroup === 'videoDevices') {
            if (imageItem.data_deviceid.startsWith('ptz')) {
                imageItem.moveToTop();
            } else {
                imageItem.zIndex(0);
            }
        }

        /* only add labels to Video Devices and Microphones, or devices that have labels */
        if (groupName === 'videoDevices' || groupName === 'microphones' || 'data_labelField' in attrs) {

            if ((groupName === 'videoDevices' || groupName === 'microphones') && (deviceId != 'laptop')) {
                addLabel(imageItem, attrs, true);
            }
            else if (attrs.data_labelField) {
                addLabel(imageItem, attrs);
            }

        }

        canvasNodesMap.set(imageItem.id(), imageItem);


    };


    if (addHighlight) {
        createHighlightImage(deviceId, imageObj);
    } else {
        imageObj.src = './assets/images/' + insertDevice.topImage;
    }

    /* add coverage for cameras */
    if ('wideHorizontalFOV' in insertDevice) {

        let groupFov = new Konva.Group({
            id: 'fov~' + uuid,
            x: pixelX,
            y: pixelY,
            listening: false,
            rotation: 0,
            name: 'shading_group',
        })

        if (attrs.data_fovHidden) {
            groupFov.visible(false);
        } else {
            groupFov.visible(true);
        }

        let teleAngle;
        /* teleFullWidth is for multi-lense devices like the Quad Camera were the combined teleAngle equals the wide FOV. */
        if (insertDevice.teleFullWidth) {
            teleAngle = insertDevice.wideHorizontalFOV;
        } else {
            teleAngle = insertDevice.teleHorizontalFOV;
        }

        /* Show narrow field of FOV based on field view for the ptz 4k camera when  */
        if ('data_role' in attrs && attrs.data_role && (attrs.data_role.value.startsWith('extended_reach') || attrs.data_role.value.startsWith('presentertrack') || attrs.data_role.value === 'virtualLens')) {
            insertDevice = { ...insertDevice, ...insertDevice[attrs.data_role.value] };
            teleAngle = insertDevice[attrs.data_role.value].teleHorizontalFOV;
        }

        let onePersonCrop = defaultOnePersonCrop;
        let twoPersonCrop = defaultTwoPersonCrop;

        if (unit == 'feet') {
            /*  feet  */
            twoPersonCrop = twoPersonCrop * 3.28084;
            onePersonCrop = onePersonCrop * 3.28084;
        }


        let onePersonDistance = (insertDevice.onePersonDistance * (roomObj.unit === 'feet' ? 3.28084 : 1)) || getDistanceA(insertDevice.teleHorizontalFOV / 2, onePersonCrop / 2) * insertDevice.onePersonZoom;

        let twoPersonDistance = (insertDevice.twoPersonDistance * (roomObj.unit === 'feet' ? 3.28084 : 1)) || getDistanceA(insertDevice.teleHorizontalFOV / 2, twoPersonCrop / 2) * insertDevice.twoPersonZoom;

        let gradientRatio = onePersonDistance / twoPersonDistance;

        let gradientStop1 = gradientRatio * 0.9;

        let gradientStop2 = gradientRatio * 1.1;

        let onePersonCropColor = "#8FBC8B";
        let twoPersonCropColor = "#87aeed";

        let wideFOV = new Konva.Wedge({
            /* x and y should be tracked in the group only */
            radius: twoPersonDistance * scale * 1.3,
            angle: insertDevice.wideHorizontalFOV,
            fill: 'yellow',
            stroke: 'black',
            strokeWidth: 1,
            name: 'wFOV-' + deviceId + '-' + groupName,
            rotation: -insertDevice.wideHorizontalFOV / 2 + 90,
            opacity: 0.1,
            listening: false,
            perfectDrawEnabled: perfectDrawEnabled,
        });



        let teleTwoPersonFOV = new Konva.Wedge({
            /* x and y should be tracked in the group only */
            opacity: 0.55,
            radius: twoPersonDistance * scale,
            angle: teleAngle,
            stroke: '#0000004D',
            strokeWidth: 1,
            name: 'singleTeleFOV' + deviceId + '-' + groupName,
            rotation: 0 - teleAngle / 2 + 90,
            listening: false,
            perfectDrawEnabled: perfectDrawEnabled,

            fillRadialGradientStartPoint: { x: 0, y: 0 },
            fillRadialGradientStartRadius: 0,
            fillRadialGradientEndPoint: { x: 0, y: 0 },
            fillRadialGradientEndRadius: twoPersonDistance * scale,
            fillRadialGradientColorStops: [0, onePersonCropColor, gradientStop1, onePersonCropColor, gradientStop2, twoPersonCropColor, 1, twoPersonCropColor + '64'],

        });

        let txtTwoPersonFov = new Konva.Text({
            x: -1000,
            y: twoPersonDistance * scale - 15,
            width: 2000,
            text: '2 person zoom: ' + twoPersonDistance.toFixed(1) + ' ' + abbrUnit + ' to camera',
            fontSize: 12,
            fill: '#6495ED',
            padding: 3,
            align: 'center',
        });

        let teleOnePersonFOV = new Konva.Wedge({
            /* x and y should be tracked in the group only */
            opacity: 0.3,
            radius: onePersonDistance * scale,
            angle: teleAngle,
            stroke: '#0000004D',
            strokeWidth: 1,
            name: 'singleTeleFOV' + deviceId + '-' + groupName,
            rotation: -teleAngle / 2 + 90,
            listening: false,
            perfectDrawEnabled: perfectDrawEnabled,
        });

        let txtOnePersonFov = new Konva.Text({
            x: -1000,
            y: onePersonDistance * scale - 15,
            width: 2000,
            text: '1 person zoom: ' + onePersonDistance.toFixed(1) + ' ' + abbrUnit + ' to camera',
            fontSize: 12,
            fill: '#023020',
            padding: 3,
            align: 'center',
        });

        /* multiLens shows multiple lens ranges on the outside for Room Bar Pro and Board Pros*/
        if ('multiLensReach' in insertDevice) {

            insertDevice.multiLensReach.forEach((lensReach, index) => {

                let gradientRatio = lensReach.onePersonDistance / lensReach.twoPersonDistance;

                let gradientStop1 = gradientRatio * 0.9;

                let gradientStop2 = gradientRatio * 1.1;

                let twoPersonDistMultiLens = lensReach.twoPersonDistance * scale * (roomObj.unit === 'feet' ? 3.28084 : 1)

                let teleMultiTwoPersonFOV = new Konva.Wedge({
                    /* x and y should be tracked in the group only */
                    opacity: 0.55,
                    radius: twoPersonDistMultiLens,
                    angle: lensReach.teleAngle,
                    stroke: '#8989894D',
                    strokeWidth: 0.5,
                    name: 'singleMutliLensTeleFOV-' + index + '-' + deviceId + '-' + groupName,
                    rotation: lensReach.rotation,
                    listening: false,
                    perfectDrawEnabled: perfectDrawEnabled,
                    fillRadialGradientStartPoint: { x: 0, y: 0 },
                    fillRadialGradientStartRadius: 0,
                    fillRadialGradientEndPoint: { x: 0, y: 0 },
                    fillRadialGradientEndRadius: twoPersonDistMultiLens,
                    fillRadialGradientColorStops: [0, onePersonCropColor, gradientStop1, onePersonCropColor, gradientStop2, twoPersonCropColor, 1, twoPersonCropColor + '64'],
                });

                groupFov.add(teleMultiTwoPersonFOV.clone());

            })
        };


        /* make the ptz4k more closely match hte Workspace Designer limit, and only show green */
        if ((deviceId.startsWith('ptz')) && onePersonDistance === 0) {
            teleTwoPersonFOV.fillRadialGradientColorStops([0, onePersonCropColor, gradientStop2, onePersonCropColor, 1, onePersonCropColor + '64'])
            wideFOV.radius(twoPersonDistance * scale * 1.3 * 2);

        }


        if (!(deviceId.startsWith('ptz'))) {
            groupFov.add(txtOnePersonFov);
            groupFov.add(txtTwoPersonFov);
        }


        groupFov.add(teleOnePersonFOV);
        groupFov.add(wideFOV);
        groupFov.add(teleTwoPersonFOV);
        cameraCoverage.add(groupFov);

    }


    if ('micRadius' in insertDevice) {

        let groupAudioShading = new Konva.Group({
            id: 'audio~' + uuid,
            x: pixelX,
            y: pixelY,
            listening: false,
            rotation: 0,
            name: 'shading_group',
        })

        if (attrs.data_audioHidden) {
            groupAudioShading.visible(false);
        } else {
            groupAudioShading.visible(true);
        }

        let micRadius = insertDevice.micRadius / 1000 * scale;

        let lblMicRadius = insertDevice.micRadius / 1000;

        if (unit === 'feet') {
            micRadius = micRadius * 3.28084;
            lblMicRadius = lblMicRadius * 3.28084;
        }

        let audioShadingLine = new Konva.Wedge({
            /* x and y should be tracked in the group only */
            radius: micRadius,
            angle: insertDevice.micDeg,
            name: 'audio-' + deviceId + '-' + groupName,
            rotation: 90 - insertDevice.micDeg / 2,
            opacity: 0.3,
            listening: false,
            perfectDrawEnabled: perfectDrawEnabled,
            opacity: 0.3,
            stroke: '#00000080',
            strokeWidth: 1,
        });

        /* audioShadingLine & audioShadingShade combine to form the coverage */
        let audioShadingShade = new Konva.Wedge({
            /* x and y should be tracked in the group only */
            radius: micRadius * 1.2,
            angle: insertDevice.micDeg,
            stroke: '',
            strokeWidth: 3,
            name: 'audio-' + deviceId + '-' + groupName,
            rotation: 90 - insertDevice.micDeg / 2,
            opacity: 0.3,
            listening: false,
            perfectDrawEnabled: perfectDrawEnabled,
            opacity: 0.3,
            fillRadialGradientStartPoint: { x: 0, y: 0 },
            fillRadialGradientStartRadius: 0,
            fillRadialGradientEndPoint: { x: 0, y: 0 },
            fillRadialGradientEndRadius: micRadius * 1.2,
            fillRadialGradientColorStops: [0, 'purple', 0.6, '#800080EE', 0.8, '#80008088', 1, '#80008000'],
        });


        let txtAudio = new Konva.Text({
            x: -1000,
            y: micRadius - 10,
            width: 2000,
            text: lblMicRadius.toFixed(1) + ' ' + abbrUnit + ' from mic',
            fontSize: 12,
            fill: 'purple',
            padding: 3,
            align: 'center',
        });

        groupAudioShading.add(audioShadingLine);
        groupAudioShading.add(audioShadingShade);
        groupAudioShading.add(txtAudio);
        microphoneCoverage.add(groupAudioShading);
    }

    if ('speakerRadius' in insertDevice && 'speakerDeg' in insertDevice) {


        let groupSpeakerCoverage = new Konva.Group({
            id: 'speaker~' + uuid,
            x: pixelX,
            y: pixelY,
            listening: false,
            rotation: 0,
            name: 'shading_group',
        })

        if (attrs.data_speakerHidden) {
            groupSpeakerCoverage.visible(false);
        } else {
            groupSpeakerCoverage.visible(true);
        }

        let speakerRadius = insertDevice.speakerRadius / 1000 * scale;

        let lblSpeakerRadius = insertDevice.speakerRadius / 1000;


        let innerRadius = speakerRadius * 0.2;

        if ('innerSpeakerRadius' in insertDevice) {
            innerRadius = insertDevice.innerSpeakerRadius * scale;
        }

        if (unit === 'feet') {
            innerRadius = innerRadius * 3.28084;
            speakerRadius = speakerRadius * 3.28084;
            lblSpeakerRadius = lblSpeakerRadius * 3.28084;
        }

        let speakerShadingLine = new Konva.Arc({
            /* x and y should be tracked in the group only */
            innerRadius: innerRadius,
            outerRadius: speakerRadius,
            angle: insertDevice.speakerDeg,
            name: 'speaker-' + deviceId + '-' + groupName,
            rotation: 90 - insertDevice.speakerDeg / 2,
            opacity: 0.3,
            listening: false,
            perfectDrawEnabled: perfectDrawEnabled,
            opacity: 0.3,
            stroke: '#96969680',
            strokeWidth: 1,
        });

        /* audioShadingLine & audioShadingShade combine to form the coverage */
        let speakerShadingShade = new Konva.Arc({
            /* x and y should be tracked in the group only */
            innerRadius: innerRadius,
            outerRadius: speakerRadius * 1.2,
            angle: insertDevice.speakerDeg,
            strokeWidth: 3,
            name: 'speaker-' + deviceId + '-' + groupName,
            rotation: 90 - insertDevice.speakerDeg / 2,
            opacity: 0.3,
            listening: false,
            perfectDrawEnabled: perfectDrawEnabled,
            opacity: 0.3,
            fillRadialGradientStartPoint: { x: 0, y: 0 },
            fillRadialGradientStartRadius: 0,
            fillRadialGradientEndPoint: { x: 0, y: 0 },
            fillRadialGradientEndRadius: speakerRadius * 1.2,
            fillRadialGradientColorStops: [0, 'blue', 0.6, '#001c80ee', 0.8, '#02629da8', 1, 'rgba(36, 0, 128, 0)'],

        });


        let txtSpeaker = new Konva.Text({
            x: -1000,
            y: speakerRadius - 10,
            width: 2000,
            text: lblSpeakerRadius.toFixed(1) + ' ' + abbrUnit + ' from mic',
            fontSize: 12,
            fill: 'purple',
            padding: 3,
            align: 'center',
        });

        groupSpeakerCoverage.add(speakerShadingLine);
        groupSpeakerCoverage.add(speakerShadingShade);
        // groupSpeakerCoverage.add(txtSpeaker);
        speakerCoverage.add(groupSpeakerCoverage);
    }




    /* Add shading lines for a display */
    if (data_diagonalInches > 0) {

        let groupItemDisplayDistance = new Konva.Group({
            id: 'dispDist~' + uuid,
            x: pixelX,
            y: pixelY,
            listening: false,
            rotation: 0,
            name: 'shading_group',
        })



        if (attrs.data_dispDistHidden) {
            groupItemDisplayDistance.visible(false);
        } else {
            groupItemDisplayDistance.visible(true);
        }
        groupItemDisplayDistance.visible(true);

        let widthRatio = 1 * displayNumber;
        let diagonalUnit = data_diagonalInches / 12;

        if (unit === 'meters') {
            diagonalUnit = diagonalUnit / 3.28084;
        }

        let xc1 = -diagonalUnit * scale * widthRatio;
        let distance1 = diagonalUnit * scale;
        let distance1unit = diagonalUnit;
        let xc2 = diagonalUnit * scale * widthRatio;

        let angle = 145;
        if (deviceId === 'display21_9') {
            distance1 = distance1 * 0.8;
            distance1unit = distance1unit * 0.8;
        }


        let outerRadius = distance1 * 3.2;

        if (displayNumber > 1) {
            outerRadius = distance1 * 3.65;
            angle = 138;
        }

        if ('data_role' in attrs && !attrs.data_role.value.startsWith('single')) {
            outerRadius = distance1 * 3.65;
        }




        let displayDistanceWedge1 = new Konva.Arc({
            /* x and y should be tracked in the group only */
            innerRadius: distance1,
            outerRadius: outerRadius,
            angle: angle,
            rotation: (90 - angle / 2),
            listening: false,
            perfectDrawEnabled: perfectDrawEnabled,
            opacity: 0.5,
            stroke: '#96969680',
            strokeWidth: 2,
            name: 'shading_group',
            fill: '#0080004d',
            visibile: true,
        });

        /* audioShadingLine & audioShadingShade combine to form the coverage */
        let displayCoverage4x = new Konva.Arc({
            /* x and y should be tracked in the group only */
            innerRadius: outerRadius,
            outerRadius: distance1 * 4,
            angle: angle,
            rotation: (90 - angle / 2),
            opacity: 0.3,
            listening: false,
            perfectDrawEnabled: perfectDrawEnabled,
            opacity: 0.6,
            fillRadialGradientStartPoint: { x: 0, y: 0 },
            fillRadialGradientStartRadius: distance1 * 3.2,
            fillRadialGradientEndPoint: { x: 0, y: 0 },
            fillRadialGradientEndRadius: distance1 * 4,
            fillRadialGradientColorStops: [0, '#00805a4d', 1, 'rgba(0, 124, 128, 0.18)'],
            name: 'displayCoverage4x',

        });

        groupItemDisplayDistance.add(displayCoverage4x);
        groupItemDisplayDistance.add(displayDistanceWedge1);
        displayDistanceCoverage.add(groupItemDisplayDistance);

        if (document.getElementById('showDisplayCoverage4x').checked === true) {
            displayCoverage4x.show();
        } else {
            displayCoverage4x.hide();
        }


    }

    /* Coverage groups (fov~, audio~, speaker~, dispDist~) and label~ are created
     * after applyLayerStateToNode() runs at the top of this function. Re-apply the
     * layer state to those nodes now that they exist, so items in hidden layers
     * also have their coverage hidden. */
    const insertedNode = stage.findOne('#' + uuid);
    if (insertedNode) {
        const _layer = getLayerById(insertedNode.data_layerId || '0');
        applyLayerStateToCoverageNodes(insertedNode, _layer ? _layer.visible : true);
    }

}

function updateLabel(node, attrs) {
    let label = stage.findOne('#label~' + node.id())
    let text;
    let textCandidate = '';

    node.data_labelField = attrs.data_labelField;

    if ('data_labelField' in attrs) {
        textCandidate = attrs.data_labelField.replace(/{.*?}/g, '');
        if (textCandidate) {
            text = textCandidate;
        }
    }

    if (label && (textCandidate.trim() === '' || textCandidate.trim() === '{}')) {
        label.destroy();
    } else if (label && textCandidate) {

        let children = label.getChildren();


        children.forEach(child => {
            if (child instanceof Konva.Text) {
                child.text(text);
            }
        });


    } else if (textCandidate) {
        addLabel(node, attrs);
    }

}


function addLabel(node, attrs, alwaysLabel = false) {
    let text = node.name();
    let textCandidate = '';

    if ('data_labelField' in attrs) {
        textCandidate = attrs.data_labelField.replace(/{.*?}/g, '');
        if (textCandidate) {
            text = textCandidate;
        }
    }

    if (textCandidate === '' && !alwaysLabel) return

    let fontSize = 10;

    let boundingBox = node.getClientRect();
    let center = getNodeCenter(node);
    let bottomY = center.y + boundingBox.height / 2 * (100 / zoomValue);
    let centerX = center.x;

    const labelTip = new Konva.Label({
        x: centerX,
        y: bottomY,
        opacity: 0.85,
        id: 'label~' + node.id(),
        name: 'labelText',
        listening: false,
    });

    labelTip.add(
        new Konva.Tag({
            fill: 'black',
            stroke: 'darkgrey',
            strokeWidth: 0.5,
            pointerDirection: 'up',
            pointerWidth: 10,
            pointerHeight: 10,
            lineJoin: 'round',
            shadowColor: 'black',
            shadowBlur: 7,
            shadowOffsetX: 5,
            shadowOffsetY: 5,
            shadowOpacity: 0.5,
            cornerRadius: 2,
        })
    );

    labelTip.add(
        new Konva.Text({
            text: text,
            fontSize: fontSize,
            padding: 5,
            fill: 'white'
        })
    );

    overlayLabels.add(labelTip);

    /* If the parent item is in a hidden VRC layer, hide the label too. */
    if (isItemInHiddenLayer(node)) {
        labelTip.visible(false);
    }

}


/* snap the center of the node to the increment.
 *
 * Bundle (Group / CustomItem) drags use the bundle's RECT center as the
 * source — same "rect_only" rule as Snap to Objects. The grid lattice
 * is fixed (it doesn't depend on other objects) so we don't need to
 * exclude bundle members from any candidate list; we only need to pick
 * the right source point and propagate the delta correctly:
 *
 *   - Transformer drag (`tr.isDragging()` true): rect already moved with
 *     everyone. Compute delta from rect's current center → grid; apply
 *     delta to the rect + every member.
 *   - Member-direct drag: only `node` (e.target) has moved. Project the
 *     rect's would-be center using the dragstart snapshot, snap to
 *     grid, then apply the delta to `node` only — the existing
 *     followGroupDragFromMember / followCustomItemDragFromMember at the
 *     tail of the dragmove handler will propagate the delta to siblings
 *     and the rect.
 */
function snapCenterToIncrement(node) {
    let snapIncrement = Number(document.getElementById('snapToIncrement').value);
    let snapIncrementCheckBox = document.getElementById('snapIncrementCheckBox');

    if (snapIncrement < 0.02 || (snapIncrement > roomObj.room.roomWidth / 2)) {
        snapIncrement = 0.25;
        document.getElementById('snapToIncrement').value = snapIncrement;
    }

    if (!snapIncrementCheckBox.checked) return;

    const bundleSel = (typeof getActiveGroupSelection === 'function' ? getActiveGroupSelection() : null)
        || (typeof getActiveCustomItemSelection === 'function' ? getActiveCustomItemSelection() : null);

    if (!bundleSel) {
        if (tr.nodes().length !== 1) return;

        /* get the center of the node in pixels */
        let pixelXY = getNodeCenter(node);

        /* convert pixels to feet/meters */
        let x = (pixelXY.x - pxOffset) / scale;
        let y = (pixelXY.y - pyOffset) / scale;

        /* round to increment */
        let newX = Math.round(x / snapIncrement) * snapIncrement;
        let newY = Math.round(y / snapIncrement) * snapIncrement;

        /* get delta of new position - old position */
        let deltaX = newX - x;
        let deltaY = newY - y;

        /* convert the delta back to pixels */
        let deltaPixelX = ((deltaX) * scale);
        let deltaPixelY = ((deltaY) * scale);

        /* add the delta back to the original node */
        node.x(node.x() + deltaPixelX);
        node.y(node.y() + deltaPixelY);
        return;
    }

    /* Bundle path — source is the rect's center. */
    const rectNode = bundleSel.rectNode;
    if (!rectNode) return;

    /* Compute the rect's would-be center (member-direct) or current
     * center (Transformer drag). */
    let projectionDx = 0;
    let projectionDy = 0;
    if (!tr.isDragging() && node && node !== rectNode) {
        const snapshot = bundleSel.groupId ? _groupDragSnapshot : _customItemDragSnapshot;
        if (!snapshot || snapshot.target !== node) return;
        projectionDx = node.x() - snapshot.startPos.x;
        projectionDy = node.y() - snapshot.startPos.y;
    }

    const rectCenter = getNodeCenter(rectNode);
    const x = ((rectCenter.x + projectionDx) - pxOffset) / scale;
    const y = ((rectCenter.y + projectionDy) - pyOffset) / scale;

    const newX = Math.round(x / snapIncrement) * snapIncrement;
    const newY = Math.round(y / snapIncrement) * snapIncrement;

    const deltaPixelX = (newX - x) * scale;
    const deltaPixelY = (newY - y) * scale;
    if (deltaPixelX === 0 && deltaPixelY === 0) return;

    if (tr.isDragging()) {
        const memberNodes = bundleSel.groupId
            ? getGroupMemberNodes(bundleSel.groupId)
            : getCustomItemMemberNodes(bundleSel.customItemId);
        /* First-frame proxyDrag double-application guard — see the
         * extended comment in snapBundleToGuideLines for the full
         * rationale. Same drift mechanism applies here: if we shift
         * rect + every member on the first member-direct dragmove,
         * Konva.Transformer._proxyDrag (chained after this listener)
         * uses the dragged member's POST-snap absPos to compute the
         * delta it applies to siblings + rect, double-applying the
         * snap. Skip snap entirely on the first frame where any
         * non-target member is not yet dragging. */
        if (node && memberNodes.some(m => m !== node && !m.isDragging())) {
            return;
        }
        rectNode.x(rectNode.x() + deltaPixelX);
        rectNode.y(rectNode.y() + deltaPixelY);
        memberNodes.forEach(m => {
            m.x(m.x() + deltaPixelX);
            m.y(m.y() + deltaPixelY);
        });
    } else if (node) {
        node.x(node.x() + deltaPixelX);
        node.y(node.y() + deltaPixelY);
    }
}


/* snap to object start */

/* were can we snap our objects? If resize = true, ignore center.
 *
 * `excludeBundle` (optional): { groupId, customItemId } — when set, the
 * caller is snapping a Group / CustomItem bundle as a single unit. Drop
 * every node carrying that groupId / customItemId so the bundle never
 * snaps to itself. (Per the user's "exclude_all_bundles" choice we also
 * drop ALL other bundle MEMBERS — only bundle rects + non-bundled items
 * remain as snap targets, regardless of excludeBundle.) */
function getLineGuideStops(skipShape, resize = false, excludeBundle = null) {
    /* we can snap to stage borders and the center of the stage */

    let outerWall = stage.find("#cOuterWall")[0];
    let outerBox = outerWall.getClientRect();
    let outsideBox;
    let vertical = [outerBox.x, outerBox.x + outerBox.width / 2, outerBox.x + outerBox.width];
    let horizontal = [outerBox.y, outerBox.y + outerBox.height / 2, outerBox.y + outerBox.height];

    /* remove center items*/
    if (resize) {
        vertical.splice(1, 1);
        horizontal.splice(1, 1);
    }


    let outsideWall = stage.find("#outsideWall")[0];
    if (outsideWall) {
        outsideBox = outsideWall.getClientRect();
        if (resize) {
            vertical.push([outsideBox.x, outsideBox.x + outsideBox.width]);
            horizontal.push([outsideBox.y, outsideBox.y + outsideBox.height])
        } else {
            vertical.push([outsideBox.x, outsideBox.x + outsideBox.width / 2, outsideBox.x + outsideBox.width]);
            horizontal.push([outsideBox.y, outsideBox.y + outsideBox.height / 2, outsideBox.y + outsideBox.height]);
        }
    }



    /* Go through objects on the primary layer.  Only return draggable() items.  and we snap over edges and center of each object on the canvas */
    layerTransform.find(node => {
        let groupName = node.getParent().name();
        /* ignore the shading and the temporary groups */
        if (!(groupName === 'theTransformer' || groupName === 'microphoneCoverage' || groupName === 'cameraCoverage' || groupName === 'displayDistanceCoverage' || groupName === 'speakerCoverage')) {

            /* Drop bundle MEMBER items globally — only bundle rects
             * (data_deviceid 'group' / 'customItem') represent a bundle
             * as a snap target. Member items inside any Group or
             * CustomItem are not surfaced individually so the user
             * doesn't see noisy "snap to one chair inside a bundle"
             * guides; the bundle's rect serves the snap intent. */
            if (node.data_groupId && node.data_deviceid !== 'group') return false;
            if (node.data_customItemId && node.data_deviceid !== 'customItem') return false;

            /* Drop the dragged bundle's own rect (skipShape only matches
             * one specific node; member-direct drag passes a member as
             * skipShape, not the bundle's rect, so this is needed to
             * keep the bundle from snapping to itself). */
            if (excludeBundle) {
                if (excludeBundle.groupId
                    && node.data_deviceid === 'group'
                    && node.data_groupId === excludeBundle.groupId) return false;
                if (excludeBundle.customItemId
                    && node.data_deviceid === 'customItem'
                    && node.data_customItemId === excludeBundle.customItemId) return false;
            }

            if (node.draggable() && Konva.Util.haveIntersection(outerBox, node.getClientRect())) {
                return true;
            } else {
                return false;
            }



        }

    }
    ).forEach((guideItem) => {
        if (guideItem === skipShape) {
            return;
        }
        let box = guideItem.getClientRect();
        /* and we can snap to all edges of shapes. If resize equals true, don't grab center values */
        if (resize) {
            vertical.push([box.x, box.x + box.width]);
            horizontal.push([box.y, box.y + box.height]);
        } else {
            vertical.push([box.x, box.x + box.width / 2, box.x + box.width]);
            horizontal.push([box.y, box.y + box.height / 2, box.y + box.height]);
        }

    });


    return {
        vertical: vertical.flat(),
        horizontal: horizontal.flat(),
    };
}

/* were can we snap our objects? If resize = true, ignore center */
function getLineGuideStops2(skipShape, resize = false) {
    /* we can snap to stage borders and the center of the stage */

    let outerWall = stage.find("#cOuterWall")[0];
    let outerBox = outerWall.getClientRect();
    let outsideBox;
    let vertical = [outerBox.x, outerBox.x + outerBox.width / 2, outerBox.x + outerBox.width];
    let horizontal = [outerBox.y, outerBox.y + outerBox.height / 2, outerBox.y + outerBox.height];

    /* remove center items*/
    if (resize) {
        vertical.splice(1, 1);
        horizontal.splice(1, 1);
    }


    let outsideWall = stage.find("#outsideWall")[0];
    if (outsideWall) {
        outsideBox = outsideWall.getClientRect();
        if (resize) {
            vertical.push([outsideBox.x, outsideBox.x + outsideBox.width]);
            horizontal.push([outsideBox.y, outsideBox.y + outsideBox.height])
        } else {
            vertical.push([outsideBox.x, outsideBox.x + outsideBox.width / 2, outsideBox.x + outsideBox.width]);
            horizontal.push([outsideBox.y, outsideBox.y + outsideBox.height / 2, outsideBox.y + outsideBox.height]);
        }
    }



    /* Go through objects on the primary layer.  Only return draggable() items.  and we snap over edges and center of each object on the canvas */
    layerTransform.find(node => {
        let groupName = node.getParent().name();
        /* ignore the shading and the temporary groups */
        if (!(groupName === 'theTransformer' || groupName === 'microphoneCoverage' || groupName === 'cameraCoverage' || groupName === 'displayDistanceCoverage' || groupName === 'speakerCoverage')) {
            /* only snap to objects inside the current room part */
            if (node.draggable() && Konva.Util.haveIntersection(outerBox, node.getClientRect())) {
                return true;
            } else {
                return false;
            }



        }

    }
    ).forEach((guideItem) => {
        if (guideItem === skipShape) {
            return;
        }
        let box = guideItem.getClientRect();
        /* and we can snap to all edges of shapes. If resize equals true, don't grab center values */
        if (resize) {
            vertical.push([box.x, box.x + box.width]);
            horizontal.push([box.y, box.y + box.height]);
        } else {
            vertical.push([box.x, box.x + box.width / 2, box.x + box.width]);
            horizontal.push([box.y, box.y + box.height / 2, box.y + box.height]);
        }

    });


    return {
        vertical: vertical.flat(),
        horizontal: horizontal.flat(),
    };
}


/* what points of the object will trigger to snapping?
 If it is resize, igonore center of objects.  */
function getObjectSnappingEdges(node, resize = false) {
    let box = node.getClientRect();
    let absPos = node.absolutePosition();
    let objectSnap = {}


    objectSnap.vertical = [
        {
            guide: round(box.x),
            offset: round(absPos.x - box.x),
            snap: 'start',
        },
        {
            guide: round(box.x + box.width),
            offset: round(absPos.x - box.x - box.width),
            snap: 'end',
        },
    ];

    objectSnap.horizontal = [
        {
            guide: round(box.y),
            offset: round(absPos.y - box.y),
            snap: 'start',
        },
        {
            guide: round(box.y + box.height),
            offset: round(absPos.y - box.y - box.height),
            snap: 'end',
        },
    ];

    if (!resize) {

        objectSnap.vertical[2] = {

            guide: Math.round(box.x + box.width / 2),
            offset: Math.round(absPos.x - box.x - box.width / 2),
            snap: 'center',

        };

        objectSnap.horizontal[2] = {
            guide: Math.round(box.y + box.height / 2),
            offset: Math.round(absPos.y - box.y - box.height / 2),
            snap: 'center',
        };
    }

    return objectSnap;
}

/* find all snapping possibilities */
function getGuides(lineGuideStops, itemBounds) {
    // console.log('lineGuideStops', JSON.stringify(lineGuideStops, null, 5));
    // console.log('itemBounds', JSON.stringify(itemBounds, null, 5 ));
    let resultV = [];
    let resultH = [];

    lineGuideStops.vertical.forEach((lineGuide) => {
        itemBounds.vertical.forEach((itemBound) => {
            let diff = Math.abs(lineGuide - itemBound.guide);
            /* if the distance between guild line and object snap point is close we can consider this for snapping */
            if (diff < GUIDELINE_OFFSET && !itemBound.ignore) {
                resultV.push({
                    lineGuide: lineGuide,
                    diff: diff,
                    snap: itemBound.snap,
                    offset: itemBound.offset,
                });
            }
        });
    });

    lineGuideStops.horizontal.forEach((lineGuide) => {
        itemBounds.horizontal.forEach((itemBound) => {
            let diff = Math.abs(lineGuide - itemBound.guide);
            if (diff < GUIDELINE_OFFSET && !itemBound.ignore) {
                resultH.push({
                    lineGuide: lineGuide,
                    diff: diff,
                    snap: itemBound.snap,
                    offset: itemBound.offset,
                });
            }
        });
    });


    // let guides = [];
    // let minV = getObjectsWithLowestDiff(resultV);

    // let minH = getObjectsWithLowestDiff(resultH);

    // minV.forEach(guide => {
    //     guides.push({
    //         lineGuide: guide.lineGuide,
    //         offset: guide.offset,
    //         orientation: 'V',
    //         snap: guide.snap,
    //     });
    // })

    // minH.forEach(guide => {
    //     guides.push({
    //         lineGuide: guide.lineGuide,
    //         offset: guide.offset,
    //         orientation: 'H',
    //         snap: guide.snap,
    //     });
    // })



    /* find closest snap */

    let guides = [];
    let minV = resultV.sort((a, b) => a.diff - b.diff)[0];
    let minH = resultH.sort((a, b) => a.diff - b.diff)[0];
    if (minV) {
        guides.push({
            lineGuide: minV.lineGuide,
            offset: minV.offset,
            orientation: 'V',
            snap: minV.snap,
        });


    }
    if (minH) {
        guides.push({
            lineGuide: minH.lineGuide,
            offset: minH.offset,
            orientation: 'H',
            snap: minH.snap,
        });
    }
    return guides;
}

function getObjectsWithLowestDiff(resultV) {
    // Edge case: return empty array if input is empty
    if (!resultV || resultV.length === 0) {
        return [];
    }

    // 1. Find the minimum value among all items, rounding to the nearest integer
    const minRoundedDiff = Math.min(...resultV.map(item => Math.round(item.diff)));

    // 2. Filter the array to return only objects that match this minimum rounded value
    return resultV.filter(item => Math.round(item.diff) === minRoundedDiff);
}

function snapToGuideLinesResize(moved) {
    let original = lastSelectedNodePosition;
    if (snapGuidesDrawn && moved.rotation() === 0) {

        updateFormatDetails(e.target.id());
    }
}

/* Snap a Group / CustomItem bundle to other objects.
 *
 * Source: the bundle's RECT bounds (per the user's "rect_only" choice).
 * Members never contribute snap edges.
 *
 * Two drag styles to handle:
 *
 *   1. Transformer drag (`tr.isDragging() === true`): Konva already moved
 *      every node in tr.nodes() (rect + members) by the drag delta. The
 *      rect's getClientRect() reflects the current dragged position. We
 *      compute a snap delta against the rect and apply it to the rect +
 *      every member. We do NOT call `e.target.absolutePosition(...)`
 *      because the existing follower (followGroupDragFromMember /
 *      followCustomItemDragFromMember) no-ops while tr.isDragging — so
 *      shifting only e.target would split the bundle.
 *
 *   2. Member-direct drag (`tr.isDragging() === false`): only e.target
 *      has moved. The rect is still at its dragstart position. We project
 *      the rect's would-be position (rect.snapshotStartPos + member drag
 *      delta) and compute the snap against that projected position. We
 *      apply the snap delta to e.target only — the existing follower
 *      runs at the tail of the dragmove handler and propagates the new
 *      delta (which now includes the snap offset) to the rect + siblings.
 *
 * Idempotent across re-fires within a frame: after the first apply, the
 * rect (or its projection) sits exactly on the snap line, so the next
 * call computes delta = 0.
 */
function snapBundleToGuideLines(e, bundleSel) {
    /* Resize is meaningless on a bundle — Transformer has no anchors. */
    /* (Caller already filters resize, but be defensive.) */
    const rectNode = bundleSel.rectNode;
    if (!rectNode) return;

    /* Clear any prior magenta guide lines before drawing new ones. */
    allGuideLines.forEach(guideLine => { guideLine.destroy(); });
    allGuideLines = [];

    /* Identify the bundle so getLineGuideStops can drop both the rect AND
     * its sibling members from the candidate list (member-direct drag
     * passes a member as e.target, not the rect, so skipShape alone
     * isn't enough to exclude the dragged bundle). */
    const excludeBundle = bundleSel.groupId
        ? { groupId: bundleSel.groupId, customItemId: null }
        : { groupId: null, customItemId: bundleSel.customItemId };

    /* Pull snap targets — pass the rect as skipShape so the dragged
     * bundle's own rect is excluded; the new excludeBundle filter then
     * also drops every member of this bundle. */
    const lineGuideStops = getLineGuideStops(rectNode, false, excludeBundle);

    /* Compute snap source — for member-direct drag we project the rect to
     * its would-be position so the snap source matches what the user will
     * see after the follower propagates. For Transformer drag the rect has
     * already moved, so its current bounds are the source directly. */
    let projectedRect = null;     /* {dx, dy} projection delta, member-direct only */

    if (!tr.isDragging() && e && e.target && e.target !== rectNode) {
        /* Member-direct path: read the snapshot captured at dragstart. */
        const snapshot = bundleSel.groupId
            ? _groupDragSnapshot
            : _customItemDragSnapshot;
        if (!snapshot || snapshot.target !== e.target) return;
        projectedRect = {
            dx: e.target.x() - snapshot.startPos.x,
            dy: e.target.y() - snapshot.startPos.y,
        };
    }

    /* Build itemBounds against the rect's projected (or actual) bounds. */
    const itemBounds = getObjectSnappingEdges(rectNode, false);
    if (projectedRect) {
        /* Shift every guide/offset by the projection delta so getGuides
         * compares against the would-be rect position. */
        itemBounds.vertical.forEach(b => { b.guide += projectedRect.dx; });
        itemBounds.horizontal.forEach(b => { b.guide += projectedRect.dy; });
    }

    const guides = getGuides(lineGuideStops, itemBounds);
    if (!guides.length) return;

    drawSnapGuides(guides);

    /* Compute snap deltas (sdx, sdy) — how much to shift the bundle to
     * land on the matched line guides. Each guide entry's offset is
     * (rectAbsPos - rectBoxEdge), so the new rect absPos = lineGuide +
     * offset. The delta is therefore (newAbsPos - currentRectAbsPos). */
    const rectAbsPos = rectNode.absolutePosition();
    let sdx = 0;
    let sdy = 0;
    guides.forEach((lg) => {
        if (lg.orientation === 'V') {
            const newAbsX = lg.lineGuide + lg.offset;
            sdx = newAbsX - rectAbsPos.x;
            if (projectedRect) sdx -= projectedRect.dx; /* rect hasn't moved yet in member-direct drag */
        } else if (lg.orientation === 'H') {
            const newAbsY = lg.lineGuide + lg.offset;
            sdy = newAbsY - rectAbsPos.y;
            if (projectedRect) sdy -= projectedRect.dy;
        }
    });
    if (sdx === 0 && sdy === 0) return;

    if (tr.isDragging()) {
        const memberNodes = bundleSel.groupId
            ? getGroupMemberNodes(bundleSel.groupId)
            : getCustomItemMemberNodes(bundleSel.customItemId);
        /* CRITICAL: on the FIRST member-direct dragmove of a bundle,
         * Konva.Transformer._proxyDrag (chained AFTER VRC's listener
         * because tr.nodes() registers its proxyDrag listeners after the
         * per-item listeners are bound at item creation time) has NOT
         * yet shifted the siblings + rect into the "dragging" state.
         * proxyDrag's first-frame forEach reads
         *   dx = draggedMember.absPos - lastPos
         * where lastPos was captured at dragstart (BEFORE any snap),
         * and applies that dx to every other node in tr.nodes(). If we
         * ALSO shift siblings + rect here, proxyDrag will then add the
         * snap delta a second time on top, leaving siblings + rect at
         *   start + delta1 + 2*sdx
         * while the dragged member sits at
         *   start + delta1 + sdx
         * — a per-bundle drift of exactly sdx that persists for the
         * rest of the drag (proxyDrag bakes the extra shift into each
         * sibling's offset_member at _createDragElement time, so
         * subsequent _setDragPosition calls can't recover lockstep).
         * Detection: any non-target bundle member with isDragging()===
         * false signals "first frame, proxyDrag.forEach hasn't run".
         * Skipping snap entirely on that frame is correct — snap fires
         * again on every subsequent frame where all members ARE
         * dragging, and shifts everyone uniformly (lockstep). The
         * single-frame snap delay is imperceptible. */
        if (e && e.target && memberNodes.some(m => m !== e.target && !m.isDragging())) {
            return;
        }
        /* Transformer drag OR subsequent member-direct frame — shift
         * rect + every member by (sdx, sdy). */
        rectNode.x(rectNode.x() + sdx);
        rectNode.y(rectNode.y() + sdy);
        memberNodes.forEach(m => {
            m.x(m.x() + sdx);
            m.y(m.y() + sdy);
        });
    } else if (e && e.target) {
        /* Member-direct drag — shift only e.target. The follower at the
         * tail of the dragmove handler will recompute target.x() -
         * snapshot.startPos.x (now drag delta + snap delta) and propagate
         * to siblings + rect. */
        e.target.x(e.target.x() + sdx);
        e.target.y(e.target.y() + sdy);
    }
}

function snapToGuideLines(e, resize = false) {

    if (!document.getElementById('snapGuidelinesCheckBox').checked) return; /* bail out if snap to guidelines not turned on */

    /* Bundle (Group / CustomItem) selection has 2+ nodes in tr.nodes()
     * (rect + members). Route to the bundle-aware snapper which uses the
     * rect as the snap source. Resize-mode snap is meaningless on a
     * bundle (Transformer has no resize anchors) so we skip it. */
    const bundleSel = (typeof getActiveGroupSelection === 'function' ? getActiveGroupSelection() : null)
        || (typeof getActiveCustomItemSelection === 'function' ? getActiveCustomItemSelection() : null);
    if (bundleSel) {
        if (resize) return;
        snapBundleToGuideLines(e, bundleSel);
        return;
    }

    if (tr.nodes().length != 1) return;  /* only work if one node */

    allGuideLines.forEach(guideLine => {
        guideLine.destroy();
    });
    allGuideLines = [];

    /* find possible snapping lines */
    let lineGuideStops = getLineGuideStops(e.target, resize);



    let absPos = e.target.absolutePosition();
    if (resize === true) {

        let original = lastSelectedNodePosition;
        let moved = e.target;
        /* make sure it is a resize transformation and not a rotation, and is 0, 90, 180, 270 */
        if (Math.round(original.rotation() * 10) === Math.round(moved.rotation() * 10) && (moved.rotation() % 90) === 0) {

            /* find snapping points of current object .guide, .offset, .snap: start & end */
            let itemBounds = getObjectSnappingEdges(e.target, resize);

            let itemOriginalBounds = getObjectSnappingEdges(original, resize);


            if (!itemOriginalBounds) return;
            if (!itemBounds) return;




            if (Math.abs(itemBounds.vertical[1].guide - itemOriginalBounds.vertical[1].guide) > Math.abs(itemBounds.vertical[0].guide - itemOriginalBounds.vertical[0].guide)) {
                itemBounds.vertical[0].ignore = true;

            } else {
                itemBounds.vertical[1].ignore = true;
            }

            if (Math.abs(itemBounds.horizontal[1].guide - itemOriginalBounds.horizontal[1].guide) > Math.abs(itemBounds.horizontal[0].guide - itemOriginalBounds.horizontal[0].guide)) {
                itemBounds.horizontal[0].ignore = true;
            } else {
                itemBounds.horizontal[1].ignore = true;
            }


            /* now find where can we snap current object */
            let guides = getGuides(lineGuideStops, itemBounds);

            /* do nothing of no snapping */
            if (!guides.length) {
                return;
            }

            /* only show vertical guides */
            if (Math.round(original.width() * 1000) === Math.round(moved.width() * 1000) && ((moved.rotation() % 180) === 0)) {
                let snapGuidesDrawn = drawSnapGuides(guides, 'H');
                lastSelectionGuideLines.type = 'H';
                lastSelectionGuideLines.guides = guides;

                console.log('H');


            }
            else {
                drawSnapGuides(guides, 'V');

            }
        }

    } else {

        /* find snapping points of current object */
        let itemBounds = getObjectSnappingEdges(e.target, resize);

        /* now find where can we snap current object */
        let guides = getGuides(lineGuideStops, itemBounds);

        /* do nothing of no snapping */
        if (!guides.length) {
            return;
        }
        drawSnapGuides(guides);

        /* now force object position */
        guides.forEach((lg) => {
            switch (lg.orientation) {
                case 'V': {
                    absPos.x = lg.lineGuide + lg.offset;
                    break;
                }
                case 'H': {
                    absPos.y = lg.lineGuide + lg.offset;
                    break;
                }
            }
        });
        e.target.absolutePosition(absPos);
    }

}

function drawSnapGuides(guides, direction = 'both') {
    let snapGuidesDrawn = false;
    guides.forEach((lg) => {
        if (lg.orientation === 'H' && (direction === 'both' || direction === 'H')) {
            let line = new Konva.Line({
                points: [-6000, 0, 6000, 0],
                stroke: 'rgb(247, 0, 255)',
                strokeWidth: 1,
                name: 'guide-line',
                dash: [4, 6],
            });
            layerTransform.add(line);
            allGuideLines.push(line);
            line.absolutePosition({
                x: 0,
                y: lg.lineGuide,
            });
            snapGuidesDrawn = true;
        } else if (lg.orientation === 'V' && (direction === 'both' || direction === 'V')) {
            let line = new Konva.Line({
                points: [0, -6000, 0, 6000],
                stroke: 'rgb(247, 0, 255)',
                strokeWidth: 1,
                name: 'guide-line',
                dash: [4, 6],
            });
            layerTransform.add(line);
            allGuideLines.push(line);
            line.absolutePosition({
                x: lg.lineGuide,
                y: 0,
            });
            snapGuidesDrawn = true;
        }
    });

    return snapGuidesDrawn;
}

