/*
    Change stage.Width, stage.Height, stage.ScaleX and stage.ScaleY at the same time.
    Performance hits are taken with a larger canvas, so decide Zoom level allowed based on device.
    Safari supports limited canvas sizes, so limit zoom size.
    RoomOS can run into memory issues, so keep the canvas smaller.
    zoomChange is: + or - number, or 'in' or 'out' or 'reset'
 */
function zoomInOut(zoomChange) {
    let scrollContainer = document.getElementById('scroll-container');

    /* when there is a large number of nodes, tr nodes take too much screen rewrite time. Temporarily move tr.nodes */
    const nodesCopy = tr.nodes().slice();
    tr.nodes([]);
    let originalZoomValue = zoomValue;
    zoomValue = document.getElementById('zoomValue').textContent;
    zoomValue = zoomValue.replace(/%/, '');
    zoomValue = Number(zoomValue);

    if (zoomChange === 'in') {
        if (zoomValue >= 150) {
            zoomChange = -25;
        }
        else {
            zoomChange = -10;
        }
    }

    if (zoomChange === 'out') {
        if (zoomValue > 150) {
            zoomChange = 25;
        }
        else {
            zoomChange = 10;
        }
    }

    if (zoomChange === 'reset') {
        zoomChange = 0;
        zoomValue = 100;

    }
    else {
        zoomValue = zoomValue - zoomChange;
    }

    if (zoomValue < 100) {
        zoomValue = 100;
    }

    document.getElementById('btnZoomIn').disabled = false;

    if (zoomValue > 400) {
        zoomValue = 400;
        document.getElementById('btnZoomIn').disabled = true;
    }

    if (zoomValue > 250 && mobileDevice != 'false') {
        zoomValue = 250;
        document.getElementById('btnZoomIn').disabled = true;
    }

    if (zoomValue > 150 && mobileDevice === 'RoomOS') {
        zoomValue = 150;
        document.getElementById('btnZoomIn').disabled = true;
    }

    if (zoomValue > 100) {
        document.getElementById('btnSelectPan').disabled = false;
        document.getElementById('btnZoomOut').disabled = false;
        document.getElementById('btnZoomReset').disabled = false;
    } else {
        document.getElementById('btnSelectPan').disabled = true;
        document.getElementById('btnZoomOut').disabled = true;
        document.getElementById('btnZoomReset').disabled = true;
        document.getElementById('btnSelectPan').classList.remove('active');
        document.getElementById("canvasDiv").style.cursor = "auto";

        panScrollableOn = false;
        panRectangle.hide();

        listItemsOffStage();

    }

    /* resend message to Workspace Designer as orphaned objects can appear if you are zoomed in, so remove zoomed in */
    if (zoomValue < 102 && zoomValue !== originalZoomValue) {

        setTimeout(() => { postMessageToWorkspace(); }, 250);
    }

    zoomScaleX = zoomValue / 100;
    zoomScaleY = zoomValue / 100;

    stage.scaleX(zoomScaleX);
    stage.scaleY(zoomScaleY);
    stage.width(stageOriginalWidth * zoomScaleX);
    stage.height(stageOriginalLength * zoomScaleY);

    stage.draw();

    document.getElementById('zoomValue').textContent = String(zoomValue) + '%';
    layerGrid.draw();

    document.getElementById("large-container").style.width = stage.width() + 'px';
    document.getElementById("large-container").style.height = stage.height() + 'px';

    if (zoomValue <= 100) {
        scrollContainer.style.borderColor = 'white';
    } else {
        scrollContainer.style.borderColor = 'black';
    }

    if (zoomValue === 100) {
        scrollContainer.scrollLeft = 0;
        scrollContainer.scrollTop = 0;

    }

    tr.borderStrokeWidth(1);
    tr.nodes(nodesCopy);
    updateTrNodesShadingTimer();
}

function onScrollContainerScroll() {
    dx = scrollContainer.scrollLeft;
    dy = scrollContainer.scrollTop;
}

/* Set 'large-container' to stage width/height.  It will get larger when there is a scrollbar. */
document.getElementById("large-container").style.width = stage.width() + 'px';
document.getElementById("large-container").style.height = stage.height() + 'px';

function repositionStage() {
    dx = scrollContainer.scrollLeft;
    dy = scrollContainer.scrollTop;
    stage.container().style.transform = 'translate(' + dx + 'px, ' + dy + 'px)';
    stage.x(-dx);
    stage.y(-dy);
}

scrollContainer.addEventListener('scroll', repositionStage);

repositionStage();

/* ----------------------------------------------------------------- */
/* Scroll-hint button.                                                */
/*                                                                    */
/* For each .subtabcontent / .subtabcontent2 panel inside the sidebar */
/* we append one sticky "scroll down" chevron button.  The button is  */
/* shown via a `hasScrollHint` class on the panel only when the panel */
/* is currently overflowing AND the user is not already scrolled to   */
/* the bottom.  Click smoothly scrolls the panel by ~80% of its       */
/* visible height.  Resize / scroll / tab switches re-evaluate the    */
/* class via updateAllScrollHints().                                  */
/*                                                                    */
/* This replaces the old addScrollButton() / checkIfScrollable()      */
/* implementation that used hard-coded panel ids, an absolutely-      */
/* positioned overlay inside #Insert, and four kludgy spacer divs in  */
/* the HTML.                                                          */
/* ----------------------------------------------------------------- */

/* `#equipmentScrollArea` is the long-scroll wrapper that owns the
 * Equipment tab's overflow (the .subtabcontent children inside it are
 * `overflow: visible` and never scroll themselves — see the comment
 * block above `#equipmentScrollArea` in style.css). It therefore needs
 * its own sticky scroll-hint button instead of relying on the
 * per-.subtabcontent path used everywhere else. */
const SCROLL_HINT_PANEL_SELECTOR = '.subtabcontent, .subtabcontent2, .recentFloorPlansScroll, #equipmentScrollArea';
const SCROLL_HINT_OVERFLOW_SLOP_PX = 1;
const SCROLL_HINT_PAGE_FRACTION = 0.8;

function isPanelOverflowing(panel) {
    return panel.scrollHeight - panel.clientHeight > SCROLL_HINT_OVERFLOW_SLOP_PX;
}

function isPanelAtBottom(panel) {
    return panel.scrollTop + panel.clientHeight
        >= panel.scrollHeight - SCROLL_HINT_OVERFLOW_SLOP_PX;
}

function updateScrollHintForPanel(panel) {
    const show = isPanelOverflowing(panel) && !isPanelAtBottom(panel);
    panel.classList.toggle('hasScrollHint', show);
}

function updateAllScrollHints() {
    document
        .querySelectorAll(SCROLL_HINT_PANEL_SELECTOR)
        .forEach(updateScrollHintForPanel);
}

function initScrollHints() {
    document
        .querySelectorAll(SCROLL_HINT_PANEL_SELECTOR)
        .forEach((panel) => {
            if (panel.dataset.scrollHintInit === '1') return;
            panel.dataset.scrollHintInit = '1';

            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = 'scrollHintBtn';
            btn.title = 'Scroll down';
            btn.setAttribute('aria-label', 'Scroll down');
            btn.innerHTML = '<i class="icon icon-arrow-down-bold"></i>';
            btn.addEventListener('click', () => {
                panel.scrollBy({
                    top: Math.round(panel.clientHeight * SCROLL_HINT_PAGE_FRACTION),
                    behavior: 'smooth'
                });
            });
            panel.appendChild(btn);

            const update = () => updateScrollHintForPanel(panel);
            panel.addEventListener('scroll', update, { passive: true });
            if (typeof ResizeObserver !== 'undefined') {
                new ResizeObserver(update).observe(panel);
            }
        });

    updateAllScrollHints();
}

initScrollHints();
window.addEventListener('resize', updateAllScrollHints);

/* returns the type of object. Similar to typeof but more specific on objects */
function type(value) {
    if (value === null) {
        return "null";
    }
    const baseType = typeof value;
    /* Primitive types */
    if (!["object", "function"].includes(baseType)) {
        return baseType;
    }

    /* Symbol.toStringTag often specifies the "display name" of the
     object's class. It's used in Object.prototype.toString(). */
    const tag = value[Symbol.toStringTag];
    if (typeof tag === "string") {
        return tag;
    }

    /* If it's a function whose source code starts with the "class" keyword */
    if (
        baseType === "function" &&
        Function.prototype.toString.call(value).startsWith("class")
    ) {
        return "class";
    }

    /* The name of the constructor; for example `Array`, `GeneratorFunction`, `Number`, `String`, `Boolean` or `MyCustomClass` */
    const className = value.constructor.name;
    if (typeof className === "string" && className !== "") {
        return className;
    }

    /*  At this point there's no robust way to get the type of value, so we use the base implementation. */
    return baseType;
}

