setupDragAndDropImport()
// import a file by dragging and dropping it into the tab
function setupDragAndDropImport() {
    const onFileDrop = (e) => {
        e.preventDefault();
        const item = e.dataTransfer?.items?.[0];
        if (item && item.kind === 'file') {
            const file = item.getAsFile();
            const fileName = file.name;
            const reader = new FileReader();
            reader.readAsText(file, 'UTF-8');
            reader.onload = function (evt) {
                /* Delegate to the shared file-text router so drag-drop and the
                 * file picker behave identically — routeUploadedFileText()
                 * decides between VRC JSON, Workspace Designer JSON, and
                 * Cisco xConfiguration .txt dumps based on file content. */
                try {
                    routeUploadedFileText(evt.target.result, fileName);
                } catch (error) {
                    console.error(error);
                    alert(`Error loading file '${fileName}':\n\n${error.message}`);
                }
            }
        }
    }

    document.body.addEventListener('dragover', e => e.preventDefault())
    document.body.addEventListener('drop', onFileDrop)
}


function floatingWorkspaceResize(size) {

    document.getElementById('floatingWorkspaceBtnFullScreen').style.borderStyle = 'hidden';
    document.getElementById('floatingWorkspaceBtnPip').style.borderStyle = 'hidden';
    document.getElementById('floatingWorkspaceBtnSlideOver').style.borderStyle = 'hidden';

    if (size === 'fullScreen') {
        document.getElementById('floatingWorkspace').style.left = 0 + 'px';
        document.getElementById('floatingWorkspaceBtnFullScreen').style.borderStyle = '';
        document.getElementById('floatingWorkspace').style.top = 0 + 'px';
        document.getElementById('floatingWorkspace').style.width = '100%';
        document.getElementById('floatingWorkspace').style.height = '100%';
    }
    else if (size === 'slideOver') {
        document.getElementById('floatingWorkspaceBtnSlideOver').style.borderStyle = '';
        document.getElementById('floatingWorkspace').style.left = (window.innerWidth) * 0.595 + 'px';
        document.getElementById('floatingWorkspace').style.top = '1%';
        document.getElementById('floatingWorkspace').style.width = (window.innerWidth) * 0.4 + 'px';
        document.getElementById('floatingWorkspace').style.height = '98%';
    }
    else if (size === 'pip') {
        document.getElementById('floatingWorkspaceBtnPip').style.borderStyle = '';
        document.getElementById('floatingWorkspace').style.left = (window.innerWidth * 3 / 4 - 10) + 'px';
        document.getElementById('floatingWorkspace').style.top = (window.innerHeight * 1 / 2 + 70) + 'px';
        document.getElementById('floatingWorkspace').style.width = (window.innerWidth * .25) + 'px';
        document.getElementById('floatingWorkspace').style.height = (window.innerHeight * .25) + 'px';
    }

}

/* key commands */
function onKeyDown(e) {
    const { key, target } = e;
    const { tagName } = target;
    const DELTA = 1; /* change in key movement in Canvas pixel */
    let isShortCutKeyUsed = false;

    if ((key === ',' || key === '.') && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
    }

    if (blockKeyActions) return;

    if ((key === 'r') && e.shiftKey && (e.ctrlKey || e.metaKey)) return; /* allow for a hard refresh. */

    if ((key === 'r') && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
    }

    /* export to a Cisco xConfiguration .txt file (must be checked before the
     * Ctrl/Cmd+E branch below, otherwise Ctrl/Cmd+Shift+E would also trigger
     * the Workspace Designer download). */
    if (key === 'e' && e.shiftKey && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        exportXConfigFile();
        return;
    }

    /* export to the Workspace Designer */
    if (key === 'e' && !e.shiftKey && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        downloadFileWorkspace();
    }

    /* export to a CAD .dxf file. Must be checked before the plain Ctrl/Cmd+D
     * branch below (which calls duplicateItems()) — Ctrl/Cmd+Shift+D would
     * otherwise duplicate the selection. */
    if (key === 'd' && e.shiftKey && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        exportDxfFile();
        return;
    }

    if ((key === ',' || key === '.') && (e.ctrlKey || e.metaKey)) {
        if (key === ',') {

            rotateRoom(-90);
        } else if (key === '.') {

            rotateRoom(90);
        }
    }

    /* save / download VRC JSON file */
    if (key === 's' && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        downloadRoomObj();
    }

    if (key === 'm' && (e.ctrlKey)) {
        measuringToolOn(true);
    }


    if (((key === 'o') || (key === 'i')) && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        document.getElementById('fileUpload').click();
    }


    /* ctrl-3 and ctrl-w now open/toggle Split View for all users.                  */
    /* Note: ctrl-w is the browser close-tab shortcut; preventDefault() works in    */
    /* Chromium/WebKit but may not suppress it in all browsers.                     */

    if ((key === 'w' || key === '3') && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        splitViewToggle();
    }

    const inputElements = ['input', 'textarea']

    {
        if (key === ' ' && !inputElements.includes(target.tagName?.toLowerCase())) {
            quickAddMouse.x = mouseUnit.x;
            quickAddMouse.y = mouseUnit.y;
            toggleQuickAdd(true);
        }


        if (!inputElements.includes(target.tagName?.toLowerCase()) && (!(e.ctrlKey || e.metaKey))) {

            if (isWallBuilderOn) {
                if (key === 's') {
                    changeWallBuilderWall(key);
                } else if (key === 'g') {
                    changeWallBuilderWall(key);
                } else if (key === 'w') {
                    changeWallBuilderWall(key);
                } else if (key === 'c') {
                    changeWallBuilderWall(key);
                }
            }
            else if ((key === 'c')) { /* camera coverage toggle */
                cameraCoverageVisible();
                displayDistanceCoverageVisible(false);
                microphoneCoverageVisible(false);
            }
            else if ((key === 'd')) { /* display coverage toggle */
                cameraCoverageVisible(false);
                displayDistanceCoverageVisible();
                microphoneCoverageVisible(false);
            }
            else if ((key === 'm')) { /* display mic coverage toggle */
                cameraCoverageVisible(false);
                displayDistanceCoverageVisible(false);
                microphoneCoverageVisible();
            }
        }
    }



    if (['INPUT', 'TEXTAREA', 'BUTTON'].includes(tagName)) return;

    if (key === 'Shift') {
        isShiftKeyDown = true;
    }



    /* duplicate item takes time, so prevent default anytime the D key is pressed */
    if (key === 'd') {
        e.preventDefault();
    }

    if (key === 'Backspace' || key === 'Delete') {
        e.preventDefault();
        deleteTrNodes();
        isShortCutKeyUsed = true;
    }
    else if ((key === 'Escape' || key === 'Esc')) {
        if (isMeasuringToolOn) {
            hideMeasuringTool()

        } else if (isSelectingTwoPointsOn) {
            hideSelect2PointsShapes();
            document.getElementById('btnUpdateImageScale').disabled = true;
        }

        closeAllDialogModals();

        if (isWallBuilderOn && wallBuilderWritingState !== 'none') {

            wallBuilderRestart();
        } else if (isWallBuilderOn) {
            wallBuilderOn(false);
        }

        if (isWallWriterOn2 && wallWriterConnectorLine2.isVisible()) {
            wallBuilderRestart2();
        } else if (isWallWriterOn2) {
            wallBuilderOn2(false);
        }


        if (!(simplePathEditorId === '' || simplePathEditorId === 'none')) {
            polyBuilderOn(false);
            updateItem();
        } else if (isPolyBuilderOn) {
            polyBuilderOn(false);
        }


        e.preventDefault();
        toggleQuickAdd(false);
        tr.nodes([]);
        enableCopyDelBtn();
    }
    else if ((key === 'z') && e.shiftKey && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        btnRedoClicked();
        isShortCutKeyUsed = true;
    }
    else if (e.ctrlKey || e.metaKey) {

        if (key === 'y' || key === 'z' || key === 'r') {
            e.preventDefault();
        }

        if (key === 'y' & redoArray.length > 0) {
            isShortCutKeyUsed = true;
        }
        else if (key === 'z' && undoArray.length > 1) {
            btnUndoClicked();
            isShortCutKeyUsed = true;
        }
        else if (key === 'd' && tr.nodes().length > 0) {
            e.preventDefault();
            duplicateItems();
            isShortCutKeyUsed = true;
        } else if (key === 'c') {
            copyItems();
            isShortCutKeyUsed = true;
        } else if (key === 'v') {
            pasteItems(false);
            isShortCutKeyUsed = true;
        } else if (key === 'x') {
            cutItems();
            isShortCutKeyUsed = true;
        }         else if (key === 'r') {
            e.preventDefault();
            rotateTrNodeItems();
            isShortCutKeyUsed = true;
        } else if (key === 'g' && !e.shiftKey) {
            e.preventDefault();
            createGroup();
            isShortCutKeyUsed = true;
        } else if (key === 'g' && e.shiftKey) {
            e.preventDefault();
            ungroupSelectedItems();
            isShortCutKeyUsed = true;
        }
        // else if (key === 'f'){
        //     e.preventDefault();
        //     flipItems();
        //     isShortCutKeyUsed = true;
        // }
    }

    /* make a copy of the tr node for speed. After changes, restore tr.nodes([]) */
    const trNodesCopy = tr.nodes().slice();

    tr.nodes([]);
    hideAllCoverageGroups(true);

    trNodesCopy.forEach(shape => {

        if (e.ctrlKey || e.metaKey) {

            if (e.keyCode === 37) {
                // rotateNodeAroundCenter(shape, DELTA);
            } else if (e.keyCode === 38) {
                if (!shape.data_zPosition) {
                    shape.data_zPosition = 0;
                }
                shape.data_zPosition = round(shape.data_zPosition + DELTA * 0.01);

                isShortCutKeyUsed = true;
            } else if (e.keyCode === 39) {
                //
            } else if (e.keyCode === 40) {

                if (!shape.data_zPosition) {
                    shape.data_zPosition = 0;
                }
                shape.data_zPosition = round(shape.data_zPosition - DELTA * 0.01);

                isShortCutKeyUsed = true;
            }
        } else {

            if (e.keyCode === 37) {
                shape.x(shape.x() - DELTA);
                isShortCutKeyUsed = true;
            } else if (e.keyCode === 38) {
                shape.y(shape.y() - DELTA);
                isShortCutKeyUsed = true;
            } else if (e.keyCode === 39) {
                shape.x(shape.x() + DELTA);
                isShortCutKeyUsed = true;
            } else if (e.keyCode === 40) {
                shape.y(shape.y() + DELTA);
                isShortCutKeyUsed = true;
            }

        }


        if (isShortCutKeyUsed) {
            e.preventDefault();
            updateShading(shape);

            lastKeyDownMovement = true;
        }

        if (tr.nodes().length === 1 || trNodesCopy.length === 1) {
            updateFormatDetails(shape.id());
        }
    })

    hideAllCoverageGroups(false);
    tr.nodes(trNodesCopy);
}



function quickAddFromButton() {

    quickAddMouse.x = -1000;
    quickAddMouse.y = -1000;
    toggleQuickAdd(true);

}



function toggleQuickAdd(show) {
    const dialog = document.querySelector('.quick-dialog');

    tr.nodes([]);

    // already open
    if (show && dialog.style.display === 'flex') return

    if (show) {
        if (isWallBuilderOn) wallBuilderOn(false);
        if (isWallWriterOn2) wallBuilderOn2(false);
        if (isMeasuringToolOn) hideMeasuringTool();
    }

    dialog.style.display = show ? 'flex' : 'none';
    const input = dialog.querySelector('input');

    if (show) {
        /* Fetch the VRC Custom Item Library into the in-memory cache so
         * library tiles appear in search results. Fire-and-forget: the
         * fetch resolves async, then re-fires the change handler with
         * the current input value so library matches surface without
         * the user having to type again. If the user types before the
         * fetch completes, they'll see device-only results until the
         * library load resolves a few ms later — acceptable for a
         * one-shot startup cost. */
        loadCustomItemLibraryRecordsForQuickAdd().then(function (records) {
            if (!records || !records.length) return;
            if (dialog.style.display !== 'flex') return; /* dialog closed during fetch */
            if (input && input.value && input.value.length >= 2) {
                /* Synthesize an oninput event so onQuickAddChange re-runs
                 * with the freshly loaded library records included. */
                onQuickAddChange({ target: input });
            }
        });

        if (input) {
            setTimeout(() => {
                input.focus();
                input.select();
            }, 20)
        }
    }
    else {
        /* Drop the in-memory cache when the dialog closes. The records
         * carry base64 menuImages (~10-30KB each, up to 200 records)
         * which together can be several MB. Cheap to refetch on next
         * open; expensive to keep resident across a long session. */
        _customItemQuickAddRecordsCache = [];
        if (input) input.blur();
    }
}


/* Compute the include/exclude regex and the user-typed search string
 * stripped of any `**` prefix sigil, given the raw search input.
 *
 * Three-way rule mirrors the historical Quick Add behaviour:
 *   • Default          → exclude `_name` AND any `name*` (covers `*` and `**`).
 *   • WD-partial on    → exclude `_name` AND `name**` only — `name*` is allowed
 *                        in normal browsing because the WD-partial toggle is
 *                        the user's explicit opt-in to non-WD-supported items.
 *   • Query starts `**`→ exclude `_name` ONLY — both `name*` AND `name**`
 *                        come through. The `**` is stripped from the query
 *                        before name matching so `**phone` matches "Phone 9871".
 *
 * Shared by `searchQuickItem` (Quick Add modal) and `onEquipmentSearchChange`
 * (sidebar search). Optional chaining on getElementById guards against the
 * checkbox not being in the DOM yet during very early boot. */
function getEquipmentSearchRegex(rawQuery) {
    let regex = /(^_.*)|(.*\*$)/;
    let stripped = rawQuery;
    if (document.getElementById('useNonWorkspaceItemsCheckBox')?.checked) {
        regex = /(^_.*)|(.*\*\*$)/;
    }
    if (/^\*\*.*/.test(rawQuery)) {
        regex = /(^_.*)/;
        stripped = rawQuery.replace(/\*\*/, '');
    }
    return { regex, stripped };
}

function searchQuickItem(items, word = '') {
    if (word.length < 2) return []

    const { regex, stripped } = getEquipmentSearchRegex(word);

    const match = (search = '', fullWord = '') =>
        fullWord.toLowerCase().replaceAll(' ', '')
            .includes(search.toLowerCase().replaceAll(' ', ''))

    const all = items.filter(i => match(stripped, i.name))


    return all.filter(i => !regex.test(i.name));
}

function onQuickAddChange(e) {
    const deviceItems = [].concat(tables, videoDevices, microphones, chairs, displays, boxes, stageFloors, rooms);

    /* Transform library customItem records into the same search-entry
     * shape `searchQuickItem` and the tile renderer below expect:
     *   { id, name, _isCustomItem, _record }
     *
     * - id:           customItemBaseId — used for the button's DOM id.
     *                 Doesn't collide with device ids because
     *                 allDeviceTypes lookup returns undefined for it,
     *                 which the renderer branch handles.
     * - name:         customItemName (legacy: data_labelField) — what
     *                 the user types against (matches searchQuickItem's
     *                 match-on-name logic). Read via the helper so old
     *                 IDB rows surface until they're auto-migrated.
     * - _isCustomItem:render-time discriminator. The marker fields use
     *                 a `_` prefix to avoid colliding with any
     *                 device-record fields and to signal "internal".
     * - _record:      full library record — passed to
     *                 insertCustomItemAtPosition on click.
     *
     * Records with empty/whitespace name are filtered out defensively:
     * an unnamed template would never match a real search term
     * (`searchQuickItem` requires ≥ 2 chars) but the filter keeps the
     * array tidy if a record somehow leaked through with no name
     * (e.g. legacy IDB row from before the canvas-only invariant). */
    const libraryEntries = (_customItemQuickAddRecordsCache || [])
        .filter(rec => rec && getCustomItemRecordName(rec).trim())
        .map(rec => ({
            id: rec.customItemBaseId,
            name: getCustomItemRecordName(rec),
            _isCustomItem: true,
            _record: rec,
        }));

    /* Library entries go FIRST so user-curated templates surface above
     * device matches — the "what I built" view ranks above "what the
     * app ships with" when both match the same search term. */
    const allItems = libraryEntries.concat(deviceItems);

    const word = e.target.value;
    const matches = searchQuickItem(allItems, word);

    const gallery = document.querySelector('.quick-dialog .gallery');

    gallery.innerHTML = '';
    matches.forEach((m, n) => {

        if (m._isCustomItem) {
            /* Library customItem tile — built by the shared
             * buildCustomItemTile() helper so the Equipment-tab
             * sidebar pill and the Quick Add modal render identical
             * tiles. `insertCenter` opts triggers click-to-insert
             * (modal behaviour, drag disabled). See the helper for
             * the long-form comments about the ellipsis-span pattern
             * and click-handler routing. */
            gallery.appendChild(buildCustomItemTile(m._record, { onClick: 'insertCenter' }));
            return;
        }

        const btnItem = document.createElement('button');

        /* Standard device tile (unchanged from the original handler). */
        const parentGroup = allDeviceTypes[m.id]?.parentGroup;

        const img = m.frontImage || m.topImage;
        if (img) {
            const i = document.createElement('img');
            i.src = `./assets/images/${img}`;
            i.draggable = false;
            btnItem.appendChild(i);
            i.id = `${parentGroup}-${m.id}-img`;
        }
        const label = document.createElement('label');
        label.innerText = m.name?.slice(0, 30);
        btnItem.title = `${m.name} - Tap to add to room`;
        btnItem.appendChild(label);



        btnItem.classList.add('flexItems');
        btnItem.classList.add('equipmentItemOnMenu');
        btnItem.id = `${parentGroup}-${m.data_deviceid}-div`;
        btnItem.draggable = false;

        if (allDeviceTypes[m.id] && allDeviceTypes[m.id].newItem === true) {
            let newBadgeDiv = document.createElement("div");
            newBadgeDiv.classList.add('newBadge');
            newBadgeDiv.innerText = 'New';
            btnItem.appendChild(newBadgeDiv);
        }

        btnItem.onclick = () => {
            const { roomWidth, roomLength } = roomObj.room;

            const attrs = {};
            let b; /* boundary */
            b = roomObj.unit === 'feet' ? 0.6 : 0.2;

            if (quickAddMouse.x > -b && quickAddMouse.x < (roomWidth + b) && quickAddMouse.y > -b && quickAddMouse.y < (roomLength + b)) {
                attrs.x = quickAddMouse.x;
                attrs.y = quickAddMouse.y;
            } else {
                attrs.x = roomWidth / 2;
                attrs.y = roomLength / 2;
            }

            insertItemFromMenu(m.id, attrs);

            toggleQuickAdd(false);

        }


        gallery.appendChild(btnItem);
    })

    if (!matches.length) {
        const msg = word.length > 1 ? 'No matching object found.' : 'Type at least 2 characters.'
        gallery.innerHTML = `<i>${msg}</i>`;
    }
}

function onQuickInputKey(event) {
    if (event.key === 'Enter') {
        const first = document.querySelector('.quick-dialog button');
        if (first) {
            first.click();
        }
    }
    else if (event.key === 'Escape') {
        toggleQuickAdd(false);
    }
}

/* Take a wallChairs object and return an array of chairs */
function expandChairs(item, unit = roomObj.unit) {
    let singleChairWidth = 2.35;
    let chairArray = [];
    if (unit === 'meters') {
        singleChairWidth = singleChairWidth / 3.28084;
    }

    let numberOfChairs = Math.round(item.height / singleChairWidth)

    let rotation = normalizeDegree(item.rotation - 90);


    let tempChair =
    {
        "x": item.x,
        "y": item.y,
        "rotation": item.rotation,
        "height": 0.64,
        "width": 0.64,
        "name": "Chair",
        "data_deviceid": "chair",
        "id": item.id
    }



    let centerXY = getItemCenter(tempChair);

    let primaryChair = structuredClone(tempChair);

    primaryChair.x = centerXY.x;
    primaryChair.y = centerXY.y;
    primaryChair.id = 'primaryChair-1-of-' + numberOfChairs + '-' + item.id;
    primaryChair.rotation = rotation;

    if ('data_zPosition' in item) {
        primaryChair.data_zPosition = item.data_zPosition;
    }

    if ('data_tilt' in item) {
        primaryChair.data_tilt = item.data_tilt;
    }

    if ('data_slant' in item) {
        primaryChair.data_slant = item.data_slant;
    }

    chairArray.push(primaryChair);

    for (let i = 1; i < numberOfChairs; i++) {
        let newXY = findNewTransformationCoordinate(primaryChair, singleChairWidth * i, 0);
        let rowChair = structuredClone(primaryChair);
        rowChair.x = newXY.x;
        rowChair.y = newXY.y;
        rowChair.id = 'rowChair-' + (i + 1) + '-of-' + numberOfChairs + '-' + item.id;
        chairArray.push(rowChair);
    }


    return chairArray;


}

/* Don't let degrees be greater than 360 or less than -360 */
function normalizeDegree(degree) {
    degree = Number(degree);
    while (degree > 359) {
        degree = degree - 360;
    }

    while (degree < -359) {
        degree = degree + 360;
    }
    return degree;
}

/* Rotate a point x, y around origin x,y a certain amount of degrees */
function rotatePointAroundOrigin(pointX, pointY, originX, originY, angleInDegrees) {

    const angleInRadians = angleInDegrees * Math.PI / 180;
    const cosTheta = Math.cos(angleInRadians);
    const sinTheta = Math.sin(angleInRadians);

    const translatedX = pointX - originX;
    const translatedY = pointY - originY;

    const rotatedX = translatedX * cosTheta - translatedY * sinTheta;
    const rotatedY = translatedX * sinTheta + translatedY * cosTheta;

    const finalX = rotatedX + originX;
    const finalY = rotatedY + originY;

    return { x: finalX, y: finalY };
}

/*
comeback to flipItems
*/
function flipItems() {
    let rotationAmount = 90;

    let trCenter = getNodeCenter(tr); /* get the center of the tr Transformer node to perform the transform */

    tr.nodes().forEach(node => {

        let nodeCenter = getNodeCenter(node);

        let rotation = normalizeDegree(node.rotation())
        let rotationAmount;
        if (rotation > 0) {
            rotationAmount = -(rotation * 2);
        } else {
            rotationAmount = rotation * 2;
        }


        let newNodeXY = rotatePointAroundOrigin(nodeCenter.x, nodeCenter.y, node.x(), node.y(), rotationAmount);


        let nodeCornerXY = findUpperLeftXY({ x: newNodeXY.x, y: newNodeXY.y, rotation: rotationAmount, width: node.width(), height: node.height() })
        node.x(newNodeXY.x);
        node.y(newNodeXY.y);



        node.offsetX(node.width() / 2);
        node.offsetY(node.height() / 2);

        node.rotation(-node.rotation());

        node.offsetX(0); /* reset the offsetX and offsetY back to zero */
        node.offsetY(0);

    })
}


function selectAllTrNodes() {
    tr.nodes(selectAllNodes());
};

function selectAllNodes() {
    let shapes = groupVideoDevices.getChildren();

    shapes = shapes.concat(groupStageFloors.getChildren());

    shapes = shapes.concat(groupDisplays.getChildren());

    shapes = shapes.concat(groupMicrophones.getChildren());

    shapes = shapes.concat(groupBoxes.getChildren());

    shapes = shapes.concat(groupRooms.getChildren());

    shapes = shapes.concat(groupSpeakers.getChildren());

    shapes = shapes.concat(groupTables.getChildren());

    shapes = shapes.concat(groupTouchPanels.getChildren());

    shapes = shapes.concat(groupChairs.getChildren());

    /* Include Group rects so drag-select can capture them */
    if (groupGroupRects) {
        shapes = shapes.concat(groupGroupRects.getChildren());
    }

    /* Include CustomItem rects so drag-select can capture them */
    if (groupCustomItemRects) {
        shapes = shapes.concat(groupCustomItemRects.getChildren());
    }

    return shapes;
}

function rotateBackgroundImage(rotationAmount, rotationCenter) {
    let node = stage.findOne('#konvaBackgroundImageFloor');

    if (node) {
        let nodeCenter = getNodeCenter(node);
        let newNodeXY = rotatePointAroundOrigin(nodeCenter.x, nodeCenter.y, rotationCenter.x, rotationCenter.y, rotationAmount);

        let totalRotation = normalizeDegree(node.rotation() + rotationAmount);

        let nodeCornerXY = findUpperLeftXY({ x: newNodeXY.x, y: newNodeXY.y, rotation: totalRotation, width: node.width(), height: node.height() })
        node.x(nodeCornerXY.x);
        node.y(nodeCornerXY.y);

        node.offsetX(nodeCenter.x - node.x());
        node.offsetY(nodeCenter.y - node.y());

        node.rotation(totalRotation);

        node.offsetX(0); /* reset the offsetX and offsetY back to zero */
        node.offsetY(0);

    }
}


function blockAndMessage(message = 'Please Wait', time = 2000) {
    let dialog = document.getElementById('waitMessageDialog');

    dialog.textContent = message;

    dialog.showModal();
    blockKeyActions = true;

    setTimeout(() => {
        dialog.close();
        blockKeyActions = false;
    }, time)

}

function rotateRoom(rotationAmount) {


    if (isActiveRoomPart) {
        alertDialog('Rotate Room Not Available.', 'First go back to the floorplan overview, then rotate entire floorplan.')
        return;
    }

    if (!addressBarUpdate) {
        alertDialog('Room initializing. Please wait', 'Trying rotating the room again in 3 seconds.');
        return;
    }

    if (blockKeyActions) return;

    if (isRotatingRoom) return;

    document.getElementById('dialogRotateRoom').showModal();

    if (rotationAmount < 0) {
        document.getElementById('iconDialogRotateRoom').style.transform = 'scaleX(1)';

    } else {
        document.getElementById('iconDialogRotateRoom').style.transform = 'scaleX(-1)';
    }

    isRotatingRoom = true;
    blockKeyActions = true;

    hideAllCoverageGroups(true);


    /* use setTimeOut so that the .showModal() abobe renders before the page is shown */
    setTimeout(function startRotateRoom() {

        if (zoomValue !== 100) {
            zoomInOut('reset');
        }


        let allNodes = selectAllNodes();

        let allNodesLength = allNodes.length;
        let timeForEachStage = (allNodesLength / 20);


        setTimeout(() => {
            isRotatingRoom = false;
            canvasToJson();
        }, 1 * timeForEachStage + 100);

        setTimeout(() => {

            closeAllDialogModals();
            blockKeyActions = false;
            hideAllCoverageGroups(false);

        }, 1 * timeForEachStage + 600);

        let roomWidth = roomObj.room.roomWidth;
        let roomLength = roomObj.room.roomLength;
        let roomSurfaces = { ...roomObj.roomSurfaces };

        /* make the room the larger of roomWidth or roomLenght on both sides */

        let stageWidth = stage.width();
        let stageHeight = stage.height();


        let roomWidthLength;
        if (roomWidth > roomLength) {
            roomWidthLength = roomWidth;
            stage.height(stageWidth);
        } else {
            roomWidthLength = roomLength
            stage.width(stageHeight);
        }


        roomObj.room.roomLength = roomWidthLength;
        roomObj.room.roomWidth = roomWidthLength;


        let rotationCenter = {};

        rotationCenter.x = ((roomWidth) / 2) * scale + pxOffset;
        rotationCenter.y = ((roomLength)) * scale / 2 + pyOffset;

        // flip for counter clockwise
        if (rotationAmount === 90) {
            rotationCenter.x = rotationCenter.y;
        }
        else {
            rotationCenter.y = rotationCenter.x;
        }


        selectAllTrNodes();
        rotateTrNodeItems(rotationAmount, rotationCenter);
        rotateBackgroundImage(rotationAmount, rotationCenter);

        roomObj.room.roomLength = roomWidth;
        roomObj.room.roomWidth = roomLength;

        if (rotationAmount === 90) {

            roomObj.roomSurfaces.leftwall = roomSurfaces.backwall;
            roomObj.roomSurfaces.backwall = roomSurfaces.rightwall;
            roomObj.roomSurfaces.rightwall = roomSurfaces.videowall;
            roomObj.roomSurfaces.videowall = roomSurfaces.leftwall;

        }
        else {
            roomObj.roomSurfaces.leftwall = roomSurfaces.videowall;
            roomObj.roomSurfaces.backwall = roomSurfaces.leftwall;
            roomObj.roomSurfaces.rightwall = roomSurfaces.backwall;
            roomObj.roomSurfaces.videowall = roomSurfaces.rightwall;
        }



        canvasToJson();


    }, 1);


}

function rotateTrNodeItemsOriginal(rotationAmount = 90, rotationCenter) {



    if (!rotationCenter) {
        rotationCenter = getNodeCenter(tr); /* get the center of the tr Transformer node to perform the transform */
    }


    tr.nodes().forEach(node => {

        let nodeCenter = getNodeCenter(node);
        let newNodeXY = rotatePointAroundOrigin(nodeCenter.x, nodeCenter.y, rotationCenter.x, rotationCenter.y, rotationAmount);

        let totalRotation = normalizeDegree(node.rotation() + rotationAmount);

        let nodeCornerXY = findUpperLeftXY({ x: newNodeXY.x, y: newNodeXY.y, rotation: totalRotation, width: node.width(), height: node.height() })
        node.x(nodeCornerXY.x);
        node.y(nodeCornerXY.y);

        node.offsetX(nodeCenter.x - node.x());
        node.offsetY(nodeCenter.y - node.y());

        node.rotation(totalRotation);

        node.offsetX(0); /* reset the offsetX and offsetY back to zero */
        node.offsetY(0);

        updateShading(node);

    })

}



function rotateTrNodeItems(rotationAmount = 90, rotationCenter) {


    clearTimeout(rotateResetTrNodeTimer);


    if (tr.nodes().length === 0) {

        return;
    }

    if (tr.nodes().length > 50) {
        hideAllCoverageGroups(true);
    }


    /* Get rotation center from transformer if not provided */
    if (!rotationCenter) {
        rotationCenter = getNodeCenter(tr); /* get the center of the tr Transformer node to perform the transform */
    }

    /* Copy nodes array and DETACH from transformer (speed optimization) */
    const nodesCopy = tr.nodes().slice();
    tr.nodes([]);

    for (let i = 0; i < nodesCopy.length; i++) {
        const node = nodesCopy[i];

        let nodeCenter = getNodeCenter(node);

        let newNodeXY = rotatePointAroundOrigin(
            nodeCenter.x,
            nodeCenter.y,
            rotationCenter.x,
            rotationCenter.y,
            rotationAmount
        );

        let totalRotation = normalizeDegree(node.rotation() + rotationAmount);

        let nodeCornerXY = findUpperLeftXY({
            x: newNodeXY.x,
            y: newNodeXY.y,
            rotation: totalRotation,
            width: node.width(),
            height: node.height(),

        });

        node.x(nodeCornerXY.x);
        node.y(nodeCornerXY.y);

        node.offsetX(nodeCenter.x - node.x());
        node.offsetY(nodeCenter.y - node.y());



        node.rotation(totalRotation);

        node.offsetX(0);
        node.offsetY(0);



    }


    /* Reattach nodes to transformer */
    tr.nodes(nodesCopy);
    rotateResetTrNodeTimer = setTimeout(() => {




        hideAllCoverageGroups(false);

    }, 10);



}

const rotatePoint = ({ x, y }, rad) => {
    const rcos = Math.cos(rad);
    const rsin = Math.sin(rad);
    return { x: x * rcos - y * rsin, y: y * rcos + x * rsin };
};

function rotateAroundCenter2(node, rotation) {
    const topLeft = { x: -node.width() / 2, y: -node.height() / 2 };
    const current = rotatePoint(topLeft, Konva.getAngle(node.rotation()));
    const rotated = rotatePoint(topLeft, Konva.getAngle(rotation));
    const dx = rotated.x - current.x;
    const dy = rotated.y - current.y;
    node.rotation(rotation);
    node.x(node.x() + dx);
    node.y(node.y() + dy);
}

function rotateAroundCenter(node, deg) {

    const w = node.width();
    const h = node.height();

    node.offset({ x: w / 2, y: h / 2 });
    node.rotate(deg);


}

function rotateNodeAroundCenter(node, rotationAmount) {
    let nodeCenter = getNodeCenter(node);

    let nodeCornerXY = findUpperLeftXY({ x: nodeCenter.x, y: nodeCenter.y, rotation: rotation, width: node.width(), height: node.height() })
    node.x(nodeCornerXY.x);
    node.y(nodeCornerXY.y);

    node.offsetX(nodeCenter.x - node.x());
    node.offsetY(nodeCenter.y - node.y());

    node.rotation(rotationAmount);

    node.offsetX(0); /* reset the offsetX and offsetY back to zero */
    node.offsetY(0);

}

