/* addDefaultsToWorkspaceObj() - looks at workspaceKey and compares to videoDevices, chairs, displays and microphones and adds the first role, model or color to the workspaceKey - overwriting if it already exists */

addDefaultsToWorkspaceObj();

function returnStringOfDefaultRoleColor(keyValue) {
    let defaultRole;

    if (typeof (keyValue[0]) === 'string') {
        defaultRole = keyValue[0];

    } else {
        for (const [key, value] of Object.entries(keyValue[0])) {
            defaultRole = key;
        }
    }

    return defaultRole;
}



function addDefaultsToWorkspaceObj() {
    compareAdd(videoDevices);
    compareAdd(microphones);
    compareAdd(displays);
    compareAdd(chairs);

    function compareAdd(items) {
        let workspaceKeyArray = Object.keys(workspaceKey)
        workspaceKeyArray.forEach(key => {
            items.forEach((item) => {
                if (item.id === key) {
                    if ('roles' in item && item.roles) {
                        workspaceKey[key].role = returnStringOfDefaultRoleColor(item.roles);
                    }

                    if ('colors' in item && item.colors) {
                        workspaceKey[key].color = returnStringOfDefaultRoleColor(item.colors);
                    }

                    if ('mount' in item && item.mounts) {
                        workspaceKey[key].mount = returnStringOfDefaultRoleColor(item.mounts);
                    }
                }
            })
        })
    }

}



function exportRoomObjToWorkspace() {
  
    /* drawRoom() calls postMessageToWorkspace() at the end of the same turn, while createShareableLink() -> listItemsOffStage() is debounced (see canvasToJson). Without this, itemsOffStageId can lag behind a resize redraw; pathShapes use live getClientRect() in findFourCorners and are the first to misclassify. */
    listItemsOffStage();

    let swapXY = true;

    let roomObj2 = structuredClone(roomObj);  /* clone roomObj to make changes to units */

    roomObj2 = convertToMeters(roomObj2); /* convertToMeters() converts feet to meters and omits items whose ids are in itemsOffStageId (unless isActiveRoomPart). */

    /* Items in hidden VRC layers are omitted from the Workspace Designer export entirely. */
    removeHiddenLayerItemsForExport(roomObj2);

    /* For every exported item that belongs to a non-Default VRC layer, attach the
     * layer's name as a "layer" attribute on the workspaceItem. Importers (including
     * VRC's own importer) can then restore the layer assignment by name.
     * Default ('0') is the implicit layer and is intentionally NOT emitted to keep
     * the JSON minimal. convertToMeters() drops roomObj2.layers, so we look up the
     * layer name from the global roomObj.layers, which is the source of truth. */
    function setLayerOnWorkspaceItem(workspaceItem, item) {
        const layerId = item && item.data_layerId;
        if (!layerId || layerId === '0') return; /* Default layer is implicit */
        if (!roomObj.layers) return;
        const layer = roomObj.layers.find(l => l.layerid === layerId);
        if (layer && layer.name) workspaceItem.layer = layer.name;
    }

    /* For every exported item that belongs to a VRC Group / CustomItem,
     * attach the bundle's id as a "group" / "customItem" attribute on the
     * workspaceItem. Workspace Designer does not understand Group/CustomItem
     * items themselves, but it preserves arbitrary string attributes on
     * customObjects, so the references round-trip cleanly. The matching
     * geometry/metadata is emitted separately under workspaceObj.data.vrc.groups
     * and workspaceObj.data.vrc.customItems (see below). The Konva Group/
     * CustomItem rects themselves (data_deviceid === 'group' / 'customItem')
     * are never pushed to customObjects. */
    function setGroupOnWorkspaceItem(workspaceItem, item) {
        if (!item) return;
        if (item.data_groupId) workspaceItem.group = item.data_groupId;
        if (item.data_customItemId) workspaceItem.customItem = item.data_customItemId;
    }

    let activeRoomLength = roomObj2.activeRoomLength;
    let activeRoomWidth = roomObj2.activeRoomWidth;
    let activeRoomX = roomObj2.activeRoomX;
    let activeRoomY = roomObj2.activeRoomY;


    let workspaceObj = {};
    workspaceObj.title = '';
    workspaceObj.roomShape = {};
    workspaceObj.roomShape.manual = true;

    workspaceObj.roomShape.plant = false;

    if (swapXY) {
        workspaceObj.roomShape.width = roomObj2.room.roomWidth;
        workspaceObj.roomShape.length = roomObj2.room.roomLength;
    } else {
        workspaceObj.roomShape.width = roomObj2.room.roomLength;
        workspaceObj.roomShape.length = roomObj2.room.roomWidth;
    }

    ['leftwall', 'videowall', 'rightwall', 'backwall'].forEach(roomSurfaceId => {
        if (roomObj.roomSurfaces[roomSurfaceId].door === 'none') {
            delete roomObj.roomSurfaces[roomSurfaceId].door;
        }
    })

    workspaceObj.roomShape.roomSurfaces = [
        { ...{ objectId: 'leftwall' }, ...roomObj.roomSurfaces.leftwall },
        { ...{ objectId: 'videowall' }, ...roomObj.roomSurfaces.videowall },
        { ...{ objectId: 'rightwall' }, ...roomObj.roomSurfaces.rightwall },
        { ...{ objectId: 'backwall' }, ...roomObj.roomSurfaces.backwall },

    ]

    /* the default walls roomShape format above is inserting a tree. Adding walls one at time but onnly for designer.webex.com */
    let altDefaultWall = false;

    if (altDefaultWall === true && !roomObj.workspace.removeDefaultWalls) {
        let backwall = {};
        let leftwall = {};
        let rightwall = {};
        let videowall = {};

        backwall.id = 'backwall';
        backwall.x = -0.1 - activeRoomX;;
        backwall.y = roomObj2.room.roomLength + 0.1 - activeRoomY;
        backwall.data_zPosition = -0.10;
        backwall.data_vHeight = roomObj2.room.roomHeight + 0.10;
        backwall.rotation = -90;
        backwall.width = 0.10;
        backwall.height = roomObj2.room.roomWidth + 2 * 0.10;

        videowall.id = 'videowall';
        videowall.x = roomObj2.room.roomWidth + 0.10 - activeRoomX;
        videowall.y = -0.1 - activeRoomY;
        videowall.data_zPosition = -0.10;
        videowall.data_vHeight = roomObj2.room.roomHeight + 0.10;
        videowall.rotation = 90;
        videowall.width = 0.10;
        videowall.height = roomObj2.room.roomWidth + 2 * 0.10;

        leftwall.id = 'leftwall';
        leftwall.x = -0.1 - activeRoomX;
        leftwall.y = 0 - activeRoomY;
        leftwall.data_zPosition = 0;
        leftwall.data_vHeight = roomObj2.room.roomHeight;
        leftwall.rotation = 0;
        leftwall.width = 0.10;
        leftwall.height = roomObj2.room.roomLength;

        rightwall.id = 'rightwall';
        rightwall.x = roomObj2.room.roomWidth + 0.1 - activeRoomX;
        rightwall.y = roomObj2.room.roomLength - activeRoomY;
        rightwall.data_zPosition = 0;
        rightwall.data_vHeight = roomObj2.room.roomHeight;
        rightwall.rotation = 180;
        rightwall.width = 0.1;
        rightwall.height = roomObj2.room.roomLength;

        [backwall, leftwall, rightwall, videowall].forEach(wall => {
            let jsonLabel = {}

            if (roomObj.roomSurfaces[wall.id].type === 'regular') {
                wall.data_deviceid = 'wallStd';
            }
            else if (roomObj.roomSurfaces[wall.id].type === 'glass') {
                wall.data_deviceid = 'wallGlass';
            }
            else if (roomObj.roomSurfaces[wall.id].type === 'window') {
                wall.data_deviceid = 'wallWindow';
            }

            if ('acousticTreatment' in roomObj.roomSurfaces[wall.id]) {
                jsonLabel.acousticTreatment = roomObj.roomSurfaces[wall.id].acousticTreatment;
            }

            if ('door' in roomObj.roomSurfaces[wall.id]) {
                jsonLabel.door = roomObj.roomSurfaces[wall.id].door;
            }

            wall.data_labelField = JSON.stringify(jsonLabel);

            roomObj2.items.push(wall);

        });


    }

    if ('roomHeight' in roomObj2.room) {
        if ((roomObj2.room.roomHeight == 0 || roomObj2.room.roomHeight == '')) {
            workspaceObj.roomShape.height = 2.5;
        } else {
            workspaceObj.roomShape.height = roomObj2.room.roomHeight;
        }
    }


    if (roomObj.software) {
        workspaceObj.meetingPlatform = roomObj.software;
    }

    workspaceObj.roomId = roomObj.roomId;

    workspaceObj.customObjects = [];

    workspaceObj.source = {};
    workspaceObj.source.name = 'vrc';
    workspaceObj.source.url = fullShareLinkCollabExpBase;
    workspaceObj.source.version = version;

    workspaceObj.data = {};
    workspaceObj.data.vrc = {};
    workspaceObj.data.vrc.workspace = {};
    workspaceObj.data.vrc.workspace.theme = roomObj.workspace.theme || 'regular';

    if ('backgroundImageFile' in roomObj && 'backgroundImage' in roomObj2) {
        workspaceObj.data.vrc.backgroundImageFile = roomObj.backgroundImageFile;
        workspaceObj.data.vrc.backgroundImage = roomObj2.backgroundImage;
    }

    /* VRC Groups round-trip via data.vrc.groups. The Workspace Designer has
     * no concept of a Group item, so each member's data_groupId rides on the
     * member as a plain "group" string attribute (set by
     * setGroupOnWorkspaceItem above) and the Group rect's geometry +
     * metadata are stashed here in VRC's own JSON namespace — same approach
     * the background image uses. Stored in meters always (apply ratio if
     * the source roomObj is in feet); coordinates stay in VRC top-left
     * frame (no roomX/roomY shift) so they sit alongside the items the
     * importer reconstructs at VRC top-left coords. groupMembers is
     * intentionally NOT emitted: it's rebuilt on import by walking the
     * imported items and collecting every item whose data_groupId matches
     * the group's groupid. Empty groups are skipped — they're already
     * filtered out by the URL encoder and would just be dropped on
     * round-trip rebuild. The Konva Group rect (data_deviceid === 'group')
     * is never an item in roomObj.items, so customObjects don't include
     * it; only the H-block-style metadata here represents the rect. */
    if (Array.isArray(roomObj.groups) && roomObj.groups.length > 0) {
        const groupRatio = (roomObj.unit === 'feet') ? (1 / 3.28084) : 1;
        const exportedGroups = [];
        roomObj.groups.forEach(g => {
            if (!g || !g.groupid) return;
            if (Array.isArray(g.groupMembers) && g.groupMembers.length === 0) return;
            const exportedGroup = {
                groupid: g.groupid,
                name: g.name || '',
                x: round((g.x || 0) * groupRatio),
                y: round((g.y || 0) * groupRatio),
                width: round((g.width || 0) * groupRatio),
                height: round((g.height || 0) * groupRatio),
                rotation: g.rotation || 0,
                data_zPosition: round((g.data_zPosition || 0) * groupRatio),
            };
            /* Mirror the per-item layer convention: emit the layer NAME
             * (not the UUID) so that data.vrc.groups is human-readable and
             * stable across round-trips that may regenerate layer UUIDs.
             * Default ('0') is implicit. Lookups go through roomObj.layers
             * because convertToMeters() drops layers from roomObj2. */
            const groupLayerId = g.data_layerId;
            if (groupLayerId && groupLayerId !== '0' && roomObj.layers) {
                const groupLayer = roomObj.layers.find(l => l.layerid === groupLayerId);
                if (groupLayer && groupLayer.name) exportedGroup.layerName = groupLayer.name;
            }
            exportedGroups.push(exportedGroup);
        });
        if (exportedGroups.length > 0) {
            workspaceObj.data.vrc.groups = exportedGroups;
        }
    }

    /* VRC CustomItems round-trip via data.vrc.customItems. Mirror of the
     * Groups block above — see that block for the full rationale (always
     * meters, VRC top-left coords, customItemMembers omitted on export and
     * rebuilt on import, empty customItems skipped, layerName instead of
     * layerid for human-readability). The CustomItem rect Konva node has
     * data_deviceid === 'customItem' and is never pushed to customObjects;
     * only the metadata block here represents the rect. */
    if (Array.isArray(roomObj.customItems) && roomObj.customItems.length > 0) {
        const customItemRatio = (roomObj.unit === 'feet') ? (1 / 3.28084) : 1;
        const exportedCustomItems = [];
        roomObj.customItems.forEach(c => {
            if (!c || !c.customitemid) return;
            if (Array.isArray(c.customItemMembers) && c.customItemMembers.length === 0) return;
            const exportedCustomItem = {
                customitemid: c.customitemid,
                /* Family / template id — round-trips through WD JSON so
                 * "Save Workspace" then "Open Workspace" preserves the
                 * VRC Custom Item Library identity of every customItem.
                 * Omitted if missing on the source (e.g. ungrouped /
                 * malformed roomObj) — importer assigns a fresh baseId. */
                customItemBaseId: c.customItemBaseId || undefined,
                name: c.name || '',
                /* Optional descriptive metadata. Emitted only when
                 * present and non-empty so older importers don't see
                 * `"author": ""` noise on bundles that never carried
                 * the field. version defaults to '1' on the wire when
                 * the field exists at all (set by createCustomItem). */
                author: c.author || undefined,
                description: c.description || undefined,
                version: c.version || undefined,
                x: round((c.x || 0) * customItemRatio),
                y: round((c.y || 0) * customItemRatio),
                width: round((c.width || 0) * customItemRatio),
                height: round((c.height || 0) * customItemRatio),
                rotation: c.rotation || 0,
                data_zPosition: round((c.data_zPosition || 0) * customItemRatio),
            };
            if (!exportedCustomItem.customItemBaseId) delete exportedCustomItem.customItemBaseId;
            if (!exportedCustomItem.author) delete exportedCustomItem.author;
            if (!exportedCustomItem.description) delete exportedCustomItem.description;
            if (!exportedCustomItem.version) delete exportedCustomItem.version;
            const customItemLayerId = c.data_layerId;
            if (customItemLayerId && customItemLayerId !== '0' && roomObj.layers) {
                const customItemLayer = roomObj.layers.find(l => l.layerid === customItemLayerId);
                if (customItemLayer && customItemLayer.name) exportedCustomItem.layerName = customItemLayer.name;
            }
            exportedCustomItems.push(exportedCustomItem);
        });
        if (exportedCustomItems.length > 0) {
            workspaceObj.data.vrc.customItems = exportedCustomItems;
        }
    }


    if (altDefaultWall && document.getElementById('removeDefaultWallsCheckBox').checked === false) {
        delete workspaceObj.roomShape;
        let floor = {
            x: roomObj2.room.roomWidth + 0.1 - activeRoomX,
            y: 0 - activeRoomY,
            rotation: 90,
            data_deviceid: "floor",
            id: "primaryFloor",
            data_zPosition: -0.1,
            data_vHeight: 0.1,
            width: roomObj2.room.roomLength,
            height: roomObj2.room.roomWidth + 0.2,
        };


        workspaceObjWallPush(floor);
    }

    if (document.getElementById('removeDefaultWallsCheckBox').checked === true) {
        delete workspaceObj.roomShape;

        let wallWidth = 0.10; /* Add in the floor width to include the outer wall */

        let floor = {
            x: roomObj2.room.roomWidth - activeRoomX,
            y: 0 - activeRoomY,
            rotation: 90,
            data_deviceid: "floor",
            id: "primaryFloor",
            data_zPosition: -0.1,
            data_vHeight: 0.1,
            width: roomObj2.room.roomLength,
            height: roomObj2.room.roomWidth
        };


        workspaceObjWallPush(floor);


        let outerFloor = {
            x: roomObj2.room.roomWidth + wallWidth - activeRoomX,
            y: 0 - wallWidth - activeRoomY,
            rotation: 90,
            data_deviceid: "wall",
            id: "secondary-outerFloor",
            data_zPosition: -0.105,
            data_vHeight: 0.1,
            data_labelField: `{"color":"#CCC", "opacity": 0.97}`,
            width: roomObj2.room.roomLength + wallWidth * 2,
            height: roomObj2.room.roomWidth + wallWidth * 2
        };

        workspaceObjWallPush(outerFloor);

    }

    if ((roomObj.workspace.addCeiling === true && roomObj.workspace.removeDefaultWalls)) {
        let wallWidth = 0;
        let ceiling = {
            "x": 0 - wallWidth - activeRoomX,
            "y": 0 - wallWidth - activeRoomY,
            "rotation": 0,
            "data_deviceid": "ceiling",
            "id": "ceiling",
            "data_zPosition": roomObj2.room.roomHeight || defaultWallHeight,
            "data_vHeight": 0.01,
            "width": roomObj2.room.roomWidth + (wallWidth * 2),
            "height": roomObj2.room.roomLength + (wallWidth * 2)
        };

        if (!swapXY) {
            ceiling.width = roomObj2.room.roomLength;
            ceiling.height = roomObj2.room.roomWidth;
        }

        workspaceObjWallPush(ceiling);
    }


    if (roomObj2.name == null || roomObj2.name == '') {
        workspaceObj.title = 'Custom Room';
    } else {
        workspaceObj.title = roomObj2.name;
    }

    /* PERF RULE: bucket roomObj2.items once by parentGroup so the
     * per-category iterations below are O(n) total instead of N filter
     * passes (N=7). See plan flatten-roomobj-items-array. */
    const wdBuckets = bucketItemsByParentGroup(roomObj2);

    (wdBuckets.chairs || []).forEach((item) => {

        if (item.data_deviceid === 'wheelchairTurnCycle') {
            let newItem = structuredClone(item);
            newItem.width = 1.5;
            newItem.height = 1.5;
            let xy = findUpperLeftXY(newItem);
            let fakeTable = { data_deviceid: 'tblEllip', id: 'secondary-wheelChairRound-' + item.id, rotation: item.rotation, data_zPosition: -0.07, data_vHeight: 0.1, width: 1.5, height: 1.5, x: xy.x, y: xy.y };

            workspaceObjTablePush(fakeTable);

        }


        if (item.data_deviceid.startsWith('doorDouble')) {
            let leftDoor = structuredClone(item);
            let rightDoor = structuredClone(item);
            let deltaX = 0.51;

            let deltaY = -1 * ((allDeviceTypes[item.data_deviceid].depth / 2 / 1000) - 0.05);

            leftDoor.id = 'primary1-doorDouble-L-' + item.id;
            leftDoor.data_deviceid = rightDoor.data_deviceid + 'Left';

            rightDoor.id = 'primary2-dooorDouble-R-' + item.id;
            rightDoor.data_deviceid = rightDoor.data_deviceid + 'Right';

            let leftDoorXY = findNewTransformationCoordinate(item, deltaX, deltaY);
            let rightDoorXY = findNewTransformationCoordinate(item, -deltaX, deltaY);

            leftDoor.x = leftDoorXY.x;
            leftDoor.y = leftDoorXY.y;

            rightDoor.x = rightDoorXY.x;
            rightDoor.y = rightDoorXY.y;

            workspaceObjItemPush(rightDoor);
            item = structuredClone(leftDoor); /* let Left door become the main item */
        }

        workspaceObjItemPush(item);


    });

    (wdBuckets.microphones || []).forEach((item) => {

        if ((item.data_mount && item.data_mount.value.startsWith('ceilingMount')) || ((item.data_deviceid === 'ceilingMicPro') && !item.data_mount)) {
            let ceilingMount = structuredClone(item);
            let poleHeight = (roomObj2.room.roomHeight || defaultWallHeight) - (item.data_zPosition || 0);
            ceilingMount.data_vHeight = poleHeight;
            ceilingMount.data_deviceid = "ceilingMount";
            ceilingMount.data_zPosition = item.data_zPosition + (poleHeight / 35); /* the ceilingMount is a little off in zPosition, so adjust slightly */
            ceilingMount.id = "secondary-ceilingMount-" + item.id;
            delete ceilingMount.data_mount;

            workspaceObjItemPush(ceilingMount);

            delete item.data_mount;

        }


        if (item.data_deviceid === 'ceilingMic') {
            item.data_ceilingHeight = roomObj2.room.roomHeight;
        }

        workspaceObjItemPush(item);
    });

    (wdBuckets.tables || []).forEach((item) => {

        if (item.data_deviceid) {
            if (item.data_deviceid.startsWith('tbl') || item.data_deviceid.startsWith('couch') || item.data_deviceid.startsWith('credenza')) {
                workspaceObjTablePush(item);
            }
            else if (item.data_deviceid.startsWith('wallChairs')) {

                let chairs = expandChairs(item, 'meters');
                chairs.forEach(chair => {
                    if ('data_isItemOnStage' in item) {
                        chair.data_isItemOnStage = item.data_isItemOnStage;
                    }
                    workspaceObjItemPush(chair);
                });
            }
            else if (item.data_deviceid === 'sphere' || item.data_deviceid === 'cylinder') {

                workspaceObjWallPush(item);
            }
            else if (item.data_deviceid === 'pathShape') {
                workspaceObjItemPush(item);
            }
            else if (item.data_deviceid.startsWith('wall') || item.data_deviceid.startsWith('column') || item.data_deviceid.startsWith('floor') || item.data_deviceid.startsWith('box')) {
                workspaceObjWallPush(item);
            }
        }
    });

    (wdBuckets.stageFloors || []).forEach((item) => {
        if (item.data_deviceid) {

            if (item.data_deviceid.startsWith('stageFloor')) {
                if (item.id.startsWith('stage') || item.id.startsWith('step')) {
                    // do nothing for stage or step objects
                } else {
                    item.id = 'stageFloor~' + item.id;
                }

                workspaceObjWallPush(item);
            }
            else if (item.data_deviceid.startsWith('carpet')) {
                workspaceObjWallPush(item);
            }
        }
    });

    (wdBuckets.boxes || []).forEach((item) => {
        workspaceObjWallPush(item);
    });


    (wdBuckets.rooms || []).forEach((item) => {
        workspaceObjWallPush(item);
    });

    (wdBuckets.videoDevices || []).forEach((item) => {
        /* Adjust the height and create a pole for a flipped camera */
        if (item.data_mount && item.data_mount.value.startsWith('flippedPole')) {

            /* only adjust height on ptz4KMount2 and ptzVision2. The original ptz4kMount and ptzVision stay the same. */
            if (item.data_deviceid === 'ptz4kMount2' || item.data_deviceid === 'ptzVision2') {
                item.data_zPosition = item.data_zPosition + allDeviceTypes[item.data_deviceid].height / 1000;
            }

            let pole = {};
            let poleHeight = (roomObj2.room.roomHeight || defaultWallHeight) - (item.data_zPosition || 0);
            pole.width = 0.04;
            pole.height = 0.04;
            let poleXY = findNewTransformationCoordinate(item, pole.width / 2, pole.width / 2);
            pole.x = poleXY.x;
            pole.y = poleXY.y;
            pole.data_zPosition = (item.data_zPosition || 0);
            pole.data_vHeight = poleHeight;
            pole.width = 0.04;
            pole.height = 0.04;
            pole.rotation = item.rotation;
            pole.data_deviceid = "box";
            pole.data_labelField = '{"color":"#999999"}';
            pole.id = "secondary-flippedPoleMount-" + item.id;
            workspaceObjWallPush(pole);
        }

        if (item.data_mount && item.data_mount.value === 'flipped') {
            if (item.data_deviceid === 'ptz4kMount2' || item.data_deviceid === 'ptzVision2') {
                item.data_zPosition = item.data_zPosition + allDeviceTypes[item.data_deviceid].height / 1000;
            }
        }


        workspaceObjItemPush(item);
    });

    (wdBuckets.displays || []).forEach((item) => {

        let displayRatio = 0.995;

        if (item.data_deviceid.startsWith('displayDbl') || item.data_deviceid.startsWith('displayTrpl')) {

            if (!(/display.*_2$/.test(item.data_deviceid))) {

                item.data_diagonalInches = item.data_diagonalInches / 0.98; /* workspace designer changed screen size by 0.989 */
            };
            let leftDisplay = structuredClone(item);
            let rightDisplay = structuredClone(item);
            let centerDisplay = structuredClone(item);
            let data_diagonalInches = item.data_diagonalInches;

            let deltaX = (data_diagonalInches / 12 / 3.804 * displayRatio) / 2; /* convert inches to meters, multiply by ratio and take half */
            if (item.data_deviceid.startsWith('displayTrpl')) {
                deltaX = deltaX * 1.98;
                centerDisplay.data_deviceid = 'displaySngl';
                centerDisplay.id = 'centerScreen~' + centerDisplay.id;
                centerDisplay.role = 'firstScreen';
                workspaceObjDisplayPush(centerDisplay);

            }
            let deltaY = 0;

            let leftDisplayXY = findNewTransformationCoordinate(item, -deltaX, deltaY);
            let rightDisplayXY = findNewTransformationCoordinate(item, deltaX, deltaY);

            leftDisplay.data_deviceid = 'displaySngl';
            leftDisplay.id = 'screen-L~' + leftDisplay.id;
            leftDisplay.x = leftDisplayXY.x;
            leftDisplay.y = leftDisplayXY.y;
            leftDisplay.role = 'secondScreen';
            workspaceObjDisplayPush(leftDisplay);

            rightDisplay.data_deviceid = 'displaySngl';
            rightDisplay.id = 'screen-R~' + rightDisplay.id;

            rightDisplay.x = rightDisplayXY.x;
            rightDisplay.y = rightDisplayXY.y;
            rightDisplay.role = 'firstScreen';

            workspaceObjDisplayPush(rightDisplay);

        } else {
            item.role = 'firstScreen';
            workspaceObjDisplayPush(item);
        }
    })


    function workspaceObjItemPush(newItem) {

        let x, y, attr;
        let z = 0;
        let item = structuredClone(newItem);

        /* plants will be converted to christmas trees. Note: scale is different */
        /*
        if (item.data_deviceid === 'plant' && roomObj.workspace.theme === 'christmas') {
            item.data_deviceid = 'tree';
        }
         */

        if ((item.data_deviceid in workspaceKey)) {
            attr = workspaceKey[item.data_deviceid];
        } else {
            /* need to write to log and on screen for end user */
            console.info('Item not in workSpaceKey', item.data_deviceid);
            attr = workspaceKey.customVRC;
            attr.model = item.data_deviceid;
        }

        if (item.data_deviceid.startsWith('roomKitEqx')) {

            let newData_zPosition, deltaY;
            let leftDisplay = structuredClone(item);
            let rightDisplay = structuredClone(item);
            let displayRatio = 0.98;

            /* if the data_zPosition (height) is blank or null, set to 0 */
            if (!item.data_zPosition) {
                item.data_zPosition = 0;
            }

            let deltaX = (item.data_diagonalInches / 12 / 3.804 * displayRatio) / 2; /* convert inches to meters, multiply by ratio and take half */

            let newDisplayHeight = item.data_diagonalInches / diagonalInches * displayHeight_2 / 1000;

            if (item.data_deviceid === 'roomKitEqxFS') {
                newData_zPosition = 1.76 + Number(item.data_zPosition) - newDisplayHeight;
                deltaY = -0.07;
            }
            else if (item.data_deviceid === 'roomKitEqxWS') {
                newData_zPosition = 1.76 + Number(item.data_zPosition) - newDisplayHeight;
                deltaY = -0.12;
            }
            else {
                newData_zPosition = 1.081 + Number(item.data_zPosition) - newDisplayHeight;
                deltaY = -0.12;
            }

            let leftDisplayXY = findNewTransformationCoordinate(item, -deltaX, deltaY);
            let rightDisplayXY = findNewTransformationCoordinate(item, deltaX, deltaY);

            leftDisplay.data_deviceid = 'displaySngl';
            leftDisplay.id = 'display-KitEQX-L~' + item.data_deviceid + '-' + leftDisplay.id;
            leftDisplay.x = leftDisplayXY.x;
            leftDisplay.y = leftDisplayXY.y;
            leftDisplay.data_zPosition = newData_zPosition;
            leftDisplay.role = 'secondScreen';
            workspaceObjDisplayPush(leftDisplay);

            rightDisplay.data_deviceid = 'displaySngl';
            rightDisplay.id = 'display-KitEQX-R~' + item.data_deviceid + '-' + rightDisplay.id;

            rightDisplay.x = rightDisplayXY.x;
            rightDisplay.y = rightDisplayXY.y;
            rightDisplay.data_zPosition = newData_zPosition;
            rightDisplay.role = 'firstScreen';

            workspaceObjDisplayPush(rightDisplay);

        }


        if ('data_zPosition' in item) {
            if (item.data_zPosition != "") z = item.data_zPosition;
        }


        if ('yOffset' in attr || 'xOffset' in attr || 'data_labelField' in item) {
            let yOffset = 0;
            let xOffset = 0;


            if ('yOffset' in attr) yOffset = attr.yOffset;
            if ('xOffset' in attr) xOffset = attr.xOffset;

            if ('data_labelField' in item) {
                let labelParsed = parseDataLabelFieldJson(item);
                if (labelParsed) {
                    xOffset = labelParsed.xOffset || xOffset;
                    yOffset = labelParsed.yOffset || yOffset;
                }
            }

            let newXY = findNewTransformationCoordinate(item, xOffset, yOffset);

            item.y = newXY.y;
            item.x = newXY.x;
        }

        x = (item.x - (roomObj2.room.roomWidth) / 2);
        y = (item.y - (roomObj2.room.roomLength) / 2);

        if ('vertOffset' in attr) {
            z = z + attr.vertOffset;
        }

        if (item.data_deviceid === 'cylinder' || item.data_deviceid === 'sphere') {
            x = x + item.width / 2;
            y = y + item.width / 2;
        }

        let workspaceItem = {
            id: item.id,
            "position": [
                (swapXY ? x : y),
                z,
                (swapXY ? y : x)
            ],
            "rotation": [
                ((item.data_tilt) * (Math.PI / 180)) || 0,
                ((item.rotation) * -(Math.PI / 180)),
                ((item.data_slant) * (Math.PI / 180)) || 0,
            ]
        }

        workspaceItem = { ...workspaceItem, ...attr };

        delete workspaceItem.idRegex;

        if (item.data_deviceid === 'sphere') {
            workspaceItem.radius = item.width / 2;
        }

        if (item.data_deviceid === 'cylinder') {
            let zPosition = item.data_zPosition || 0;
            z = zPosition - (item.width / 2);
        }

        if ('data_role' in item && item.data_role) {
            workspaceItem.role = item.data_role.value;
            if (workspaceItem.role === 'presentertrack2') {
                workspaceItem.role = 'presentertrack';
            } else if (workspaceItem.role === 'crossviewPresenterTrack') {
                workspaceItem.role = 'crossview+presentertrack'
            }
        }

        if ('data_ceilingHeight' in item && item.data_ceilingHeight) {
            workspaceItem.ceilingHeight = item.data_ceilingHeight;
        }

        if ('data_isItemOnStage' in item) {
            workspaceItem.ignore = !item.data_isItemOnStage;
        }

        if ('data_color' in item && item.data_color) {
            workspaceItem.color = item.data_color.value;
        }

        if ('data_mount' in item && item.data_mount) {
            /* items like the PTZ 4K camera may be flipped */
            if (item.data_mount.value.startsWith('flipped')) {
                workspaceItem.scale = [1, -1, 1];
            }
            else if (item.data_mount.value.startsWith('stdMount')) {
                workspaceItem.scale = [1, 1, 1];
            }
            else {
                workspaceItem.mount = item.data_mount.value;
            }
        }

        if (item.data_deviceid.startsWith('ceilingMount')) {
            workspaceItem.scale = [1, item.data_vHeight, 1];
        };

        /* coverage of analog Ceiling Mic shows 180 from above */
        if (item.data_deviceid === 'ceilingMic') {
            workspaceItem.sphere = 'quarter';
        }

        if (item.data_hiddenInDesigner) {
            workspaceItem.hidden = true;
        }

        if ('data_vHeight' in item && item.data_vHeight && item.data_deviceid === 'pathShape') {
            workspaceItem.thickness = item.data_vHeight;
        }

        if ('data_labelField' in item) {
            workspaceItem = parseDataLabelFieldJson(item, workspaceItem);
        }

        /* Configurable fill / opacity round-trip into WD JSON for
         * furniture-path devices (currently only pathShape on this code
         * path). MUST run AFTER parseDataLabelFieldJson() so per-item
         * data_fill / data_opacity (from the Details inputs) win over
         * legacy label-JSON "color" / "opacity" keys — mirrors the
         * in-canvas render precedence in insertTable()'s pathShape
         * branch. Gated on device-def flags so dropdown-style data_color
         * (roomBar etc.) is unaffected. opacity is emitted as a STRING
         * to match the wallGlass / circulationSpace convention the WD
         * parser already accepts. */
        const __deviceDefFurnRT = allDeviceTypes[item.data_deviceid];
        if (__deviceDefFurnRT && __deviceDefFurnRT.configurableColor && item.data_fill) {
            workspaceItem.color = item.data_fill;
        }
        if (__deviceDefFurnRT && __deviceDefFurnRT.wdOpacity && item.data_opacity != null) {
            workspaceItem.opacity = String(item.data_opacity);
        }

        /* WD quirk (pathShape and similar furniture-path items with
         * configurableColor): if `color` is sent without an `opacity`,
         * the Workspace Designer drops the color tint silently. The
         * workaround the user identified is: whenever `color` is set,
         * always also send `opacity`. Default to "1" when no picker
         * override has run. This block runs LAST so it sees the final
         * color/opacity state after both parseDataLabelFieldJson and
         * the data_fill / data_opacity pushes above. */
        if (__deviceDefFurnRT && __deviceDefFurnRT.configurableColor
            && workspaceItem.color && !('opacity' in workspaceItem)) {
            workspaceItem.opacity = "1";
        }

        /* Second pathShape-specific WD quirk: an emitted opacity of
         * EXACTLY 1 prevents the WD from applying `color` at all. Clamp
         * to "0.999" (visually indistinguishable) whenever the final
         * opacity equals 1 / "1" for a pathShape. Covers all sources
         * of opacity on the workspaceItem:
         *   - the "1" auto-default above
         *   - parseDataLabelFieldJson() injecting a label-JSON
         *     {"opacity": 1} as the number 1
         *   - (defensive) any future code path that emits 1 directly
         * The "0.999" sentinel is mirrored by the WD-import path
         * (deviceType.wdOpacity branch in the WD importer), which snaps
         * pathShape opacity >= 0.999 back to the implicit default so a
         * VRC → WD JSON → VRC round-trip preserves the "no override"
         * state. Other configurableColor devices on this push (none
         * today, but future-proof) still get the literal "1". */
        if (item.data_deviceid === 'pathShape'
            && 'opacity' in workspaceItem
            && Number(workspaceItem.opacity) === 1) {
            workspaceItem.opacity = "0.999";
        }

        if ('vertOffset' in workspaceItem) {
            delete workspaceItem.vertOffset;
        }

        if ('yOffset' in workspaceItem) {
            delete workspaceItem.yOffset;
        }

        if ('xOffset' in workspaceItem) {
            delete workspaceItem.xOffset;
        }

        setLayerOnWorkspaceItem(workspaceItem, item);
        setGroupOnWorkspaceItem(workspaceItem, item);
        workspaceObj.customObjects.push(workspaceItem);
    }

    function workspaceObjDisplayPush(item) {

        let x, y;
        let z = displayHeight / 1000;
        let displayScale = item.data_diagonalInches / diagonalInches;
        let attr = workspaceKey[item.data_deviceid];


        if (item.data_deviceid === 'display21_9') {
            z = displayHeight21_9 / 1000;
            displayScale = item.data_diagonalInches / diagonalInches21_9;
            item.role = 'ultrawide';

        }

        z = z * displayScale / 2; /* center of display */

        if ('data_zPosition' in item) {
            if (item.data_zPosition != "") {
                z = item.data_zPosition + z;
            };
        }

        if ('yOffset' in attr || 'xOffset' in attr || 'data_labelField' in item) {
            let yOffset = 0;
            let xOffset = 0;


            if ('yOffset' in attr) yOffset = attr.yOffset;
            if ('xOffset' in attr) xOffset = attr.xOffset;

            if ('data_labelField' in item) {
                let labelParsed = parseDataLabelFieldJson(item);
                if (labelParsed) {
                    xOffset = labelParsed.xOffset || xOffset;
                    yOffset = labelParsed.yOffset || yOffset;
                }
            }

            let newXY = findNewTransformationCoordinate(item, xOffset, yOffset);

            item.y = newXY.y;
            item.x = newXY.x;
        }

        x = (item.x - (roomObj2.room.roomWidth) / 2);
        y = (item.y - (roomObj2.room.roomLength) / 2);

        let workspaceItem = {
            id: item.id,
            "position": [
                (swapXY ? x : y),
                z,
                (swapXY ? y : x)
            ],
            "rotation": [
                ((item.data_tilt) * (Math.PI / 180)) || 0,
                ((item.rotation) * -(Math.PI / 180)),
                ((item.data_slant) * (Math.PI / 180)) || 0,
            ],
            size: item.data_diagonalInches,
            "role": item.role
        }

        workspaceItem = { ...attr, ...workspaceItem };
        delete workspaceItem.idRegex;

        if ('data_role' in item && item.data_role) {
            workspaceItem.role = item.data_role.value;
        }

        if ('data_color' in item && item.data_color) {
            workspaceItem.color = item.data_color.value;
        }

        if ('data_mount' in item && item.data_mount) {
            workspaceItem.mount = item.data_mount.value;
        }

        if (item.data_hiddenInDesigner) {
            workspaceItem.hidden = true;
        }


        if ('data_labelField' in item) {
            workspaceItem = parseDataLabelFieldJson(item, workspaceItem);
        }

        if ('model' in workspaceItem && 'size' in workspaceItem) {

            if (!validateDisplaySizeAndModel(workspaceItem.model, workspaceItem.size)) {
                console.info('Model and size inches mismatch:', workspaceItem.model, workspaceItem.size, 'Removing model from display.');
                delete workspaceItem.model;
            }
        }



        if ('data_isItemOnStage' in item) {
            workspaceItem.ignore = !item.data_isItemOnStage;
        }

        if ('yOffset' in workspaceItem) {
            delete workspaceItem.yOffset;
        }

        if ('xOffset' in workspaceItem) {
            delete workspaceItem.xOffset;
        }

        setLayerOnWorkspaceItem(workspaceItem, item);
        setGroupOnWorkspaceItem(workspaceItem, item);
        workspaceObj.customObjects.push(workspaceItem);
    }

    function workspaceObjTablePush(item) {

        let x, y, z, verticalHeight, workspaceItem;
        z = 0;
        verticalHeight = 0;

        let xy = getItemCenter(item);

        let attr = workspaceKey[item.data_deviceid];

        x = (xy.x - roomObj2.room.roomWidth / 2);
        y = (xy.y - roomObj2.room.roomLength / 2);

        if ('yOffset' in attr || 'xOffset' in attr || 'data_labelField' in item) {
            let yOffset = 0;
            let xOffset = 0;

            if ('yOffset' in attr) yOffset = attr.yOffset;
            if ('xOffset' in attr) xOffset = attr.xOffset;

            if ('data_labelField' in item) {
                let labelParsed = parseDataLabelFieldJson(item);
                if (labelParsed) {
                    xOffset = labelParsed.xOffset || xOffset;
                    yOffset = labelParsed.yOffset || yOffset;
                }
            }

            let newXY = findNewTransformationCoordinate({ x: x, y: y, rotation: item.rotation }, xOffset, yOffset);

            y = newXY.y;
            x = newXY.x;
        }

        if ('data_zPosition' in item) {
            if (item.data_zPosition != "") z = item.data_zPosition;
        } else {
            z = 0;
        }

        if ('data_vHeight' in item) {
            if (item.data_vHeight != "") {
                verticalHeight = item.data_vHeight + verticalHeight;
            } else {
                verticalHeight = null;
            }
        }

        workspaceItem = {
            id: item.id,
            "position": [
                (swapXY ? x : y),
                z,
                (swapXY ? y : x)
            ],
            "rotation": [
                ((item.data_tilt) * (Math.PI / 180)) || 0,
                ((item.rotation) * -(Math.PI / 180)),
                ((item.data_slant) * (Math.PI / 180)) || 0,
            ],
            "width": item.width,
            "length": item.height
        }

        // TODO: come back to this once the WD json api is set
        // if(item.data_deviceid === 'tblBullet' && 'data_role' in item && item.data_role.index === 1){
        //
        //     workspaceItem.radius = 0;
        // }


        if (verticalHeight) {
            workspaceItem.height = verticalHeight;
        }

        /* tblSchoolDesk does not support radius or radiusRight in the Workspace Designer, remove if present */
        if ('tblRectRadius' in item && item.data_deviceid != 'tblSchoolDesk') {
            workspaceItem.radius = item.tblRectRadius;
        }

        if ('tblRectRadiusRight' in item && item.data_deviceid != 'tblSchoolDesk') {
            workspaceItem.radiusRight = item.tblRectRadiusRight;
        }

        /* flip school desks around when converting from the VRC to the Designer.  This way the desk is facing forward when rendered */
        if (item.data_deviceid === 'tblSchoolDesk') {
            workspaceItem.rotation[1] = ((item.rotation - 180) * -(Math.PI / 180));
        }

        /* turn the couch 90 deg when converting from VRC to Designer */
        if (item.data_deviceid === 'couch') {
            workspaceItem.scale = [item.height, 1, 1]
            workspaceItem.rotation[1] = (item.rotation - 90) * -(Math.PI / 180);
        }

        /* The Workspace handles trapezoid/tappered tables differently than the VRC.  Make the conversion */
        if (item.data_deviceid === 'tblTrap') {
            if (item.data_trapNarrowWidth < item.width) {
                workspaceItem.width = Number(item.data_trapNarrowWidth);
                workspaceItem.taper = item.width - item.data_trapNarrowWidth;
            }
            else {
                workspaceItem.width = Number(item.width); /* if data_trapNarrowWidth > table.width, just use the table.width */
                workspaceItem.taper = 0;
            }
        }

        workspaceItem = { ...workspaceItem, ...attr };
        delete workspaceItem.idRegex;

        if ('data_role' in item && item.data_role) {
            workspaceItem.role = item.data_role.value;
        }

        if ('data_color' in item && item.data_color) {
            workspaceItem.color = item.data_color.value;
        }

        if ('data_mount' in item && item.data_mount) {
            workspaceItem.mount = item.data_mount.value;
        }

        if (item.data_hiddenInDesigner) {
            workspaceItem.hidden = true;
        }

        if ('yOffset' in workspaceItem) {
            delete workspaceItem.yOffset;
        }

        if ('xOffset' in workspaceItem) {
            delete workspaceItem.xOffset;
        }

        if ('data_labelField' in item) {
            workspaceItem = parseDataLabelFieldJson(item, workspaceItem);
        }

        setLayerOnWorkspaceItem(workspaceItem, item);
        setGroupOnWorkspaceItem(workspaceItem, item);
        workspaceObj.customObjects.push(workspaceItem);
    }

    function workspaceObjWallPush(item) {

        let swapXY = true;

        let x, y, z, verticalHeight, workspaceItem;

        let xy = getItemCenter(item);

        let attr = workspaceKey[item.data_deviceid];

        x = (xy.x - roomObj2.room.roomWidth / 2);
        y = (xy.y - roomObj2.room.roomLength / 2);

        verticalHeight = defaultWallHeight;

        if ('data_vHeight' in item && item.data_vHeight) {
            verticalHeight = item.data_vHeight;
        } else {
            verticalHeight = roomObj2.room.roomHeight || defaultWallHeight;
        }

        if (isNaN(verticalHeight)) {
            verticalHeight = Number(defaultWallHeight);
        }

        if ('data_zPosition' in item) {
            if (item.data_zPosition != "") {
                z = item.data_zPosition + (verticalHeight / 2);
            } else {
                z = (verticalHeight / 2);
            }

        } else {
            z = (verticalHeight / 2);
        }

        if (item.data_deviceid === 'sphere') {
            if (item.data_zPosition) {
                z = item.data_zPosition + (item.width / 2);
            }
            else {
                z = (item.width / 2);
            }

        }




        /* Fix hundreths place rounding error messing with placement of carpet to keep it from overlapping with table base */
        if (item.data_deviceid === 'carpet') {
            z = Math.round((z - 0.005) * 100) / 100;
        }

        workspaceItem = {
            "objectType": "wall",
            id: item.id,
            "position": [
                (swapXY ? x : y),
                z,
                (swapXY ? y : x)
            ],
            "rotation": [
                ((item.data_slant) * -(Math.PI / 180)) || 0,
                ((item.rotation - 90) * -(Math.PI / 180)),
                ((item.data_tilt) * (Math.PI / 180)) || 0,
            ],
            "height": verticalHeight,
            "length": item.width,
            "width": item.height,
        }

        if (item.data_deviceid === 'boxRoomPart' || item.data_deviceid === 'polyRoom') {
            workspaceItem.hidden = true;
            workspaceItem.opacity = 0.01;
        }

        if (item.data_deviceid === 'sphere') {
            workspaceItem.radius = item.width / 2;
            delete workspaceItem.width;
            delete workspaceItem.height;
            delete workspaceItem.rotation;
        }

        if (item.data_deviceid === 'cylinder') {
            workspaceItem.radius = item.width / 2;

            if ('data_vHeight' in item && item.data_vHeight) {
                workspaceItem.length = item.data_vHeight;
            } else {
                workspaceItem.length = roomObj2.room.roomHeight || defaultWallHeight;
            }

            workspaceItem.rotation[0] = ((item.data_tilt) * (Math.PI / 180)) || 0;
            workspaceItem.rotation[1] = ((item.rotation) * -(Math.PI / 180)) || 0;
            workspaceItem.rotation[2] = ((item.data_slant) * (Math.PI / 180)) || 0;

            delete workspaceItem.width;
            delete workspaceItem.height;
        }



        if (item.id === 'primaryCeiling') {
            workspaceItem.scale = [item.height, verticalHeight, item.width];
            workspaceItem.objectType = 'ceiling';
            delete workspaceItem.height;
            delete workspaceItem.length;
            delete workspaceItem.width;
        }


        workspaceItem = { ...workspaceItem, ...attr };
        delete workspaceItem.idRegex;

        if ('data_role' in item && item.data_role) {
            workspaceItem.role = item.data_role.value;
        }

        if ('data_color' in item && item.data_color) {
            workspaceItem.color = item.data_color.value;
        }

        if ('data_mount' in item && item.data_mount) {
            workspaceItem.mount = item.data_mount.value;
        }

        /* Configurable fill / opacity round-trip into WD JSON.
         * Gated on the device-def flags so the existing roomBar-style
         * dropdown `data_color` system (which writes a named-color
         * string via its own data_color.value) is unaffected. The two
         * systems never coexist on a single device — see CLAUDE.md
         * "Configurable Fill & Opacity" section. workspaceItem.opacity
         * is emitted as a STRING to match the existing wallGlass /
         * circulationSpace convention so the WD parser accepts it. */
        const __deviceDefWdRT = allDeviceTypes[item.data_deviceid];
        if (__deviceDefWdRT && __deviceDefWdRT.configurableColor && item.data_fill) {
            workspaceItem.color = item.data_fill;
        }
        if (__deviceDefWdRT && __deviceDefWdRT.wdOpacity && item.data_opacity != null) {
            workspaceItem.opacity = String(item.data_opacity);
        }

        if (item.data_hiddenInDesigner) {
            workspaceItem.hidden = true;
        }


        if ('data_labelField' in item) {
            workspaceItem = parseDataLabelFieldJson(item, workspaceItem);
        }

        setLayerOnWorkspaceItem(workspaceItem, item);
        setGroupOnWorkspaceItem(workspaceItem, item);
        workspaceObj.customObjects.push(workspaceItem);
    }

    return workspaceObj;

}

/* for a display with a model attribute, if the size attribute doesn't match the end of the of the model number, return False */
function validateDisplaySizeAndModel(model, size) {
    if (model === null || model === undefined) {
        return false;
    }

    const regex = /-(\d+)$/;
    const match = model.match(regex);

    if (!match) {
        return false;
    }

    const modelNumber = parseInt(match[1], 10);

    const inchesNumber = Number(size);

    if (isNaN(inchesNumber)) {
        return false;
    }

    return modelNumber === inchesNumber;
}

function parseDataLabelFieldJson(item, workspaceItem) {

    let commentPart;

    let jsonPart = /{.*}/.exec(item.data_labelField);

    if ('data_labelField' in item && item.data_labelField) {
        commentPart = item.data_labelField.replace(/{.*?}/g, '');
    }

    if (jsonPart) {
        try {
            let newKeyValues = JSON.parse(jsonPart[0]);
            workspaceItem = { ...workspaceItem, ...newKeyValues }
        } catch {
            console.info('Error parsing JSON ', jsonPart);
        }
    }

    if (commentPart && workspaceItem) {
        workspaceItem.comment = commentPart.trim();
    }

    return workspaceItem;
}

/* parse out {"path:": "values"} from the data_labelField.  */
function parsePathShapeLabelFieldJson(item) {

    let newLabel = '';
    let lblObj = {};
    lblObj.label = "";
    lblObj.path = "";

    let jsonPart = /{.*}/.exec(item.data_labelField);

    if ('data_labelField' in item && item.data_labelField) {
        newLabel = item.data_labelField.replace(/{.*?}/g, ''); /* remove regex portion between {} */
    }

    if (jsonPart) {
        try {
            let jsonValue = JSON.parse(jsonPart[0]);
            if ('path' in jsonValue) {
                lblObj.path = jsonValue.path;
                delete jsonValue.path;
            }

            if (!isObjectEmpty(jsonValue)) {
                newLabel = (newLabel + " " + JSON.stringify(jsonValue)).trim();
            }


        } catch {
            newLabel = item.data_labelField;
            document.getElementById("labelPath").placeholder = "Error parsing JSON. Edit here or *Item Label*."
            console.info('Error parsing JSON on parsePathShapeLabelFieldJson()', jsonPart);
        }

    }

    if (newLabel) {
        lblObj.label = newLabel;
    }

    return lblObj;

}

function combinePathShapeLabel(label, path) {
    let newLabel = '';

    let commentPart = label.replace(/{.*?}/g, '').trim();

    let jsonPart = /{.*}/.exec(label);

    label = label.trim();

    path = path.trim();

    if (jsonPart) {
        try {
            let jsonValue = JSON.parse(jsonPart[0]);

            if (path) {
                jsonValue.path = path;
            }

            if (label && !isObjectEmpty(jsonValue)) {
                newLabel = commentPart + JSON.stringify(jsonValue);
            }
            else if (label) {
                newLabel = label;

            }
            else if (!isObjectEmpty(jsonValue)) {
                newLabel = JSON.stringify(jsonValue);
            }

        } catch {
            if (path && path.trim() != '') {
                newLabel = (label + '{"path":"' + path + '"}').trim();
            } else {
                newLabel = label;
            }


            console.info('Error parsing JSON on combine:', jsonPart);
        }
    } else {
        if (path && path != '') {
            newLabel = (label + '{"path":"' + path + '"}').trim();
        } else {
            newLabel = label;
        }
    }

    return newLabel;

}



function downloadJsonWorkpaceFile(workspaceObj) {

    let downloadRoomName;
    const link = document.createElement("a");
    const content = JSON.stringify(workspaceObj, null, 5);
    const file = new Blob([content], { type: 'text/plain' });
    link.href = URL.createObjectURL(file);
    downloadRoomName = workspaceObj.title.replace(/[/\\?%*:|"<>]/g, '-');
    downloadRoomName = downloadRoomName.trim() + '.json';
    link.download = downloadRoomName;
    link.click();
    URL.revokeObjectURL(link.href);
}

/* download native VRC file format */
function downloadRoomObj() {
    /* create a time stamp */
    let tzoffset = (new Date()).getTimezoneOffset() * 60000; //offset in milliseconds
    let localISOTime = (new Date(Date.now() - tzoffset)).toISOString().slice(0, -1);
    localISOTime = localISOTime.replaceAll(/:/g, '');
    let downloadRoomName = 'VideoRoomCalc_' + localISOTime;

    const link = document.createElement("a");

    /* use the roomObj clone, but remove unneeded objects and arrange the order so the name is at the top of the file */
    let roomObj2 = structuredClone(roomObj);
    delete roomObj2.room;
    delete roomObj2.trNodes;
    let roomItems = {};
    roomItems.room = {};
    roomItems.name = roomObj.name;
    roomItems.date = new Date();
    roomItems.room.roomWidth = roomObj.room.roomWidth;
    roomItems.room.roomLength = roomObj.room.roomLength;
    roomItems.room.roomHeight = roomObj.room.roomHeight;

    /* because undo might mess up roomObj.backgroundImageFile, just add the current background image to roomObj2 or get rid of all references to the backgroundImage */
    let konvaBackgroundImageFloor = getKonvaBackgroundImageFloor();
    if (konvaBackgroundImageFloor && 'backgroundImage' in roomObj2) {
        roomObj2.backgroundImageFile = backgroundImageFloor.src;
    } else {
        delete roomObj2.backgroundImageFile;
        delete roomObj2.backgroundImage;
    }


    let newRoomObj = { ...roomItems, ...roomObj2 };

    const content = JSON.stringify(newRoomObj, null, 5);
    const file = new Blob([content], { type: 'text/plain' });
    link.href = URL.createObjectURL(file);
    if (roomObj2.name.length > 1) {
        downloadRoomName = roomObj2.name.replace(/[/\\?%*:|"<>]/g, '-');
    }
    downloadRoomName = downloadRoomName.trim() + '.vrc.json';
    link.download = downloadRoomName;
    link.click();
    URL.revokeObjectURL(link.href);
}


tooltipTitleHover();

function tooltipTitleHover() {

    if (mobileDevice != 'false') return; /* do not use on mobile devices */

    const tooltipTitles = document.querySelectorAll('.tooltipTitle');

    tooltipTitles.forEach(tooltipTitle => {
        tooltipTitle.addEventListener('mouseenter', function mouseover() {
            const boundingRect = tooltipTitle.getBoundingClientRect();

            const x = boundingRect.left;
            const y = boundingRect.top;

            let tip = tooltipTitle.querySelector('.tooltiptextTitle');
            let tipLeft = x - 40;
            let tipTop = y - 40;

            if (tipLeft < 0) tipLeft = 0;
            if (tipTop < 0) tipTop = 0;

            tip.style.left = tipLeft + 'px';
            tip.style.top = tipTop + 'px';

            toolTipTextTimeout = setTimeout(() => {
                tip.style.position = 'fixed';
                tip.style.display = 'inline';
            }
                , 1000);
        });
    });

    tooltipTitles.forEach(tooltipTitle => {
        tooltipTitle.addEventListener('mouseleave', function mouseover() {
            closeTooltipTitleText();
        });
    });
}

function closeTooltipTitleText() {
    const tooltipTextTitles = document.querySelectorAll('.tooltiptextTitle');
    clearTimeout(toolTipTextTimeout);

    tooltipTextTitles.forEach(tip => {
        tip.style.display = 'none';
    })
}

tooltip2Hover();

function tooltip2Hover() {


    const tooltipTitles = document.querySelectorAll('.tooltip, .tooltipIcon, .tooltipBottom');

    tooltipTitles.forEach(tooltipTitle => {
        tooltipTitle.addEventListener('pointerenter', function mouseover() {

            let tips = tooltipTitle.querySelectorAll('.tooltiptext, .tooltiptextIcon, .tooltiptextBottom');
            toolTipTextTimeout2 = setTimeout(() => {
                tips.forEach(tip => {
                    tip.style.visibility = 'visible';
                    tip.style.opacity = 1;
                });
            }
                , 1000);


        });

        let tips2 = tooltipTitle.querySelectorAll('.tooltiptext, .tooltiptextIcon, .tooltiptextBottom');

        tips2.forEach(tip => {
            tip.addEventListener('pointerenter', function pointenter() {
                closeTooltipTitleText2();
            });
        });
    });

    tooltipTitles.forEach(tooltipTitle => {
        tooltipTitle.addEventListener('pointerleave', function mouseover() {
            closeTooltipTitleText2();
        });
    });
}


function closeTooltipTitleText2() {
    const tooltipTextTitles2 = document.querySelectorAll('.tooltiptext, .tooltiptextIcon, .tooltiptextBottom');
    clearTimeout(toolTipTextTimeout2);
    tooltipTextTitles2.forEach(tip => {
        tip.style.visibility = 'hidden';
        tip.style.opacity = 0;
    })
}


let rightClickMenuDialogId = 'rightClickMenuId';
let mouseOverRightClickMenu = false; /* is the mouse over the rightclick menu */


function closeRightClickMenu() {
    let element = document.getElementById(rightClickMenuDialogId);
    if (element) {
        element.remove();
    } /* if the menu already exists, remove and recreate */
}


/* Per-item Group / CustomItem ellipse menu. Anchored to the clicked
 * .itemEllipseBtn (fixed-position popover). Menu contents derive from
 * `tr.nodes()`, not from which button was clicked. CustomItem actions
 * live ONLY here (not on the right-click menu); only Group/Ungroup are
 * shared between the two surfaces. See CLAUDE.md → ellipse menu. */
const ITEM_ACTIONS_MENU_ID = 'itemActionsMenu';

function closeItemActionsMenu() {
    const el = document.getElementById(ITEM_ACTIONS_MENU_ID);
    if (el) el.remove();
    document.removeEventListener('mousedown', _itemActionsMenuOutsideClick, true);
    document.removeEventListener('keydown',   _itemActionsMenuKeydown,      true);
}

function _itemActionsMenuOutsideClick(e) {
    const el = document.getElementById(ITEM_ACTIONS_MENU_ID);
    if (!el) return;
    /* Don't close when the user clicks the menu itself or one of the
     * ellipse buttons (the button's own onclick handles toggle). */
    if (el.contains(e.target)) return;
    if (e.target.closest && e.target.closest('.itemEllipseBtn')) return;
    closeItemActionsMenu();
}

function _itemActionsMenuKeydown(e) {
    if (e.key === 'Escape') closeItemActionsMenu();
}

function toggleItemActionsMenu(event, mode) {
    if (event) {
        event.preventDefault();
        event.stopPropagation();
    }

    /* Toggle off if already open */
    if (document.getElementById(ITEM_ACTIONS_MENU_ID)) {
        closeItemActionsMenu();
        return;
    }

    const anchorBtn = (event && event.currentTarget) ||
        (mode === 'multi'
            ? document.getElementById('btnMultiUpdateItemEllipse')
            : document.getElementById('btnUpdateItemEllipse'));
    if (!anchorBtn) return;

    /* ---- Selection introspection ----
     * Build the same canGroup / canUngroup booleans used by the
     * right-click menu (see createRightClickMenu lines ~27515-27521)
     * so the two surfaces stay in lock-step. CustomItem booleans are
     * computed here only — they don't appear on the right-click menu. */
    const trNodes = (typeof tr !== 'undefined' && tr && tr.nodes) ? tr.nodes() : [];

    const itemsOnly = trNodes.filter(n =>
        n.data_deviceid !== 'group' && n.data_deviceid !== 'customItem');

    const distinctGroupIds = new Set(itemsOnly.map(n => n.data_groupId || null));
    const allSameExistingGroup = (distinctGroupIds.size === 1 && !distinctGroupIds.has(null));

    const distinctCustomItemIds = new Set(itemsOnly.map(n => n.data_customItemId || null));
    const allSameExistingCustomItem = (distinctCustomItemIds.size === 1 && !distinctCustomItemIds.has(null));

    /* Compute the single-CustomItem-bundle predicate up front — it
     * gates both "Unjoin Custom Item" (enabled only when it's true)
     * and "Create Group" (disabled when it's true; see below). Hoisted
     * above canGroup so the boolean is in scope for both decisions. */
    const activeCustomItemSel = getActiveCustomItemSelection(trNodes);
    const singleCustomItemBundleSelected = !!activeCustomItemSel;

    /* Group creation is disabled when:
     *   - fewer than 2 real items are selected, OR
     *   - all items already share the same Group (no-op — would just
     *     dissolve and recreate the existing Group), OR
     *   - the selection is *exactly* one CustomItem bundle and nothing
     *     else. The bundle is already a logical grouping; wrapping it
     *     in a Group around just itself would produce a redundant
     *     1-CustomItem Group with no other members. Mixed selections
     *     (CustomItem bundle + an outside item) still allow Group
     *     creation, per the architectural rule "a Group can have
     *     CustomItems, but a CustomItem cannot have Groups". The
     *     CustomItem rect tags along on Group drags via
     *     `getCustomItemRectsAllInGroup()`. */
    const canGroup = itemsOnly.length >= 2 && !allSameExistingGroup && !singleCustomItemBundleSelected;
    const canUngroup = trNodes.some(n => n.data_deviceid === 'group' || n.data_groupId);

    /* CustomItem creation rules: 2+ items selected, not already all in
     * the same single CustomItem (would just dissolve and recreate the
     * existing CustomItem). Existing `data_groupId` on the members does
     * NOT block creation — `createCustomItem()` enforces "a CustomItem
     * cannot have Groups" by dissolving every touched Group as part of
     * the create, so any nested Group state is stripped from the new
     * bundle.
     *
     * Single-item exception: a single `pathShape` is also allowed to
     * become a CustomItem on its own. Custom Path Shapes are
     * user-authored geometry that the user often wants to bundle (and
     * save to the library) as a standalone reusable template — the
     * "2+ items" rule that prevents redundant 1-item bundles for normal
     * devices doesn't make sense for these. The same
     * `!allSameExistingCustomItem` check still gates re-bundling an
     * already-bundled pathShape. */
    const isSinglePathShape =
        itemsOnly.length === 1 && itemsOnly[0].data_deviceid === 'pathShape';
    const canCustomItem =
        (itemsOnly.length >= 2 || isSinglePathShape) && !allSameExistingCustomItem;

    /* "Unjoin Custom Item" is offered only when the selection is *exactly*
     * one CustomItem bundle and nothing else — i.e. the same condition
     * that drives the "Custom Item Name:" Details panel via
     * `getActiveCustomItemSelection()`. That helper already enforces:
     *   - no Group rect in the selection (Group bundle wins),
     *   - exactly one CustomItem rect,
     *   - every other selected node is a member of that CustomItem.
     * Tying the menu state to the same predicate keeps the surface
     * coherent: if you can see "Custom Item Name:" you can remove it,
     * and vice versa. Multi-CustomItem selections, mixed selections,
     * and bare CustomItem-member selections (no rect) all fail this
     * test — by design, the user is expected to first click into the
     * specific bundle they want to dissolve. */
    const canUncustomItem = singleCustomItemBundleSelected;

    /* ---- Build menu DOM ---- */
    const menu = document.createElement('div');
    menu.id = ITEM_ACTIONS_MENU_ID;

    const addItem = (label, disabled, onClick) => {
        const div = document.createElement('div');
        div.className = disabled ? 'itemActionsMenuItemDisable' : 'itemActionsMenuItem';
        div.textContent = label;
        if (!disabled) {
            div.addEventListener('click', () => {
                closeItemActionsMenu();
                try { onClick(); } catch (err) { console.error(err); }
            });
        }
        menu.appendChild(div);
    };

    const addDivider = () => {
        const hr = document.createElement('hr');
        hr.className = 'itemActionsMenuDivider';
        menu.appendChild(hr);
    };

    addItem('Create Group',       !canGroup,        () => createGroup());
    addItem('Ungroup',            !canUngroup,      () => ungroupSelectedItems());
    addDivider();
    addItem('Create Custom Item', !canCustomItem,   () => openCreateCustomItemDialog());
    addItem('Unjoin Custom Item', !canUncustomItem, () => ungroupSelectedCustomItems());

    /* ---- Single-CustomItem-bundle actions ----
     * The Export / library actions ONLY appear when the selection is
     * exactly one CustomItem bundle (rect + all its members). We
     * reuse getActiveCustomItemSelection's strict predicate — same
     * one that gates the Details panel's "Custom Item Name:" field —
     * so the three surfaces (right-click menu, Details panel, this
     * popover) stay in lock-step about what counts as "the currently
     * focused Custom Item".
     *
     * Library membership is read synchronously from the in-memory
     * customItemLibraryIds Set (hydrated from IDB on page load).
     * Showing "Add to Custom Library" or "Remove from Library" is
     * mutually exclusive based on isCustomItemInLibrary; the third
     * action (Export) is always shown when a single CustomItem is
     * selected — its own pre-check (must have a name) is enforced
     * inside exportCustomItem() with an alertDialog if missing.
     *
     * Re-uses `activeCustomItemSel` hoisted above the canGroup
     * computation (single source of truth for "is the selection
     * exactly one CustomItem bundle?"). */
    if (activeCustomItemSel && activeCustomItemSel.customItem) {
        const sel = activeCustomItemSel.customItem;
        const baseId = sel.customItemBaseId;
        const inLibrary = isCustomItemInLibrary(baseId);
        addDivider();
        addItem('Export Custom Item', false, () => exportCustomItem(sel));
        if (inLibrary) {
            addItem('Remove from Library', false, () => removeCustomItemFromLibrary(sel));
        } else {
            addItem('Add to Custom Library', false, () => addCustomItemToLibrary(sel));
        }
    }

    /* ---- Position & mount ----
     * Fixed-position popover anchored just below the ellipse button.
     * Pinned to the button's right edge so the menu hugs the panel's
     * right side, then nudged left if it would clip the viewport.
     * Mount first so we can measure the rendered width. */
    document.body.appendChild(menu);

    const btnRect = anchorBtn.getBoundingClientRect();
    const menuRect = menu.getBoundingClientRect();

    let left = btnRect.right - menuRect.width;
    if (left + menuRect.width > window.innerWidth - 4) {
        left = Math.max(4, window.innerWidth - menuRect.width - 4);
    }
    if (left < 4) left = 4;

    let top = btnRect.bottom + 4;
    if (top + menuRect.height > window.innerHeight - 4) {
        /* Flip above the button when there isn't room below */
        top = Math.max(4, btnRect.top - menuRect.height - 4);
    }

    menu.style.left = left + 'px';
    menu.style.top  = top  + 'px';

    /* Close on outside click or Escape — capture phase so we beat any
     * click handlers inside the panel itself. */
    document.addEventListener('mousedown', _itemActionsMenuOutsideClick, true);
    document.addEventListener('keydown',   _itemActionsMenuKeydown,      true);
}


/* createas a right click menu */
function createRightClickMenu(usePreviousPosition = false) {

    if (isMeasuringToolOn) return;

    let previousXY = {};
    quickAddMouse.x = mouseUnit.x;
    quickAddMouse.y = mouseUnit.y;



    let element = document.getElementById(rightClickMenuDialogId);

    if (element && element.open) {

        element.close();
        return;
    }

    if (element) {

        element.remove();
    } /* if the menu already exists, remove and recreate */


    mouseOverRightClickMenu = false;

    let bottomBuffer = 256;
    let rightBuffer = 277;

    if (mobileDevice === 'RoomOS') {
        bottomBuffer = 380;
    }

    selecting = false; /* selecting rectangle should not be used */

    let rightClickMenuDialog = document.createElement('div');
    rightClickMenuDialog.id = rightClickMenuDialogId;
    rightClickMenuDialog.className = 'rightClickMenu';


    let rightClickMenuDiv = document.createElement('div');
    rightClickMenuDiv.id = 'rightClickMenuDiv';
    rightClickMenuDiv.className = 'rightClickMenuDiv';


    document.body.appendChild(rightClickMenuDialog); /* Adds to the end of the body, but shows up as a dialog modal where the arrow is located */

    rightClickMenuDialog.appendChild(rightClickMenuDiv);
    /* if dialog and showModal() use the following */

    let mouseX = mouse.x;
    let mouseY = mouse.y;

    if (window.innerHeight - bottomBuffer < mouseY) {
        mouseY = window.innerHeight - bottomBuffer;
    }

    if (window.innerWidth - rightBuffer < mouseX) {
        mouseX = window.innerWidth - rightBuffer;
    }

    let newX = mouseX;
    let newY = mouseY;

    if (usePreviousPosition) {
        newX = rightClickMenuDialogLastPosition.x;
        newY = rightClickMenuDialogLastPosition.y;
    }

    const pos = stage.getPointerPosition();
    const shape = layerTransform.getIntersection(pos);

    let hr = document.createElement('hr');
    hr.className = 'rightClickHorizontalLine';


    rightClickMenuDiv.textContent = '';

    if (!isMeasuringToolOn) {
        createMenuItem('copyMenuDiv', 'Copy', 'ctrl+c', tr.nodes().length < 1);
        createMenuItem('pasteMenuDiv', 'Paste', 'ctrl+p', !Object.keys(canvasClipBoard).length || false);
        createMenuItem('deleteMenuDiv', 'Delete', 'delete', tr.nodes().length < 1);
        createMenuItem('duplicateMenuDiv', 'Duplicate', 'ctrl+d', tr.nodes().length < 1);
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        createMenuItem('quickAddMenu', 'Quick Add', 'space', false);
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        /* Group / CustomItem enable-state.
         *
         * `itemsOnly` excludes both Group rects AND CustomItem rects —
         * neither becomes a Group/CustomItem member (`createGroup()` /
         * `createCustomItem()` filter them both out of `finalNodes`);
         * counting them here would mis-enable the menu when only one
         * real item is selected alongside a CustomItem rect.
         *
         * Group: enabled when 2+ real items selected AND they are not
         * already all members of the same single Group. CustomItem
         * state intentionally does NOT block Group creation: a Group
         * can wrap one or more CustomItems (the items keep their
         * `data_customItemId` and additionally get the new
         * `data_groupId`).
         *
         * CustomItem: enabled when (2+ real items selected, OR a
         * single `pathShape` selected) AND not already all in the same
         * single CustomItem AND the selection is NOT exactly one
         * CustomItem bundle. Matches the ellipse-menu equivalent in
         * `toggleItemActionsMenu()` — single source of truth for the
         * predicate so the two surfaces stay in lock-step.
         *
         * The right-click `Create Custom Item` entry replaces the old
         * `Zoom 100%` entry (zoom reset is still reachable via the
         * toolbar zoom controls and the existing zoom keyboard
         * shortcuts). */
        const trNodesRC = tr.nodes();
        const itemsOnly = trNodesRC.filter(n =>
            n.data_deviceid !== 'group' && n.data_deviceid !== 'customItem');
        const distinctGroupIds = new Set(itemsOnly.map(n => n.data_groupId || null));
        const allSameExistingGroup = (distinctGroupIds.size === 1 && !distinctGroupIds.has(null));
        const distinctCustomItemIds = new Set(itemsOnly.map(n => n.data_customItemId || null));
        const allSameExistingCustomItem = (distinctCustomItemIds.size === 1 && !distinctCustomItemIds.has(null));
        const activeCustomItemSelRC = getActiveCustomItemSelection(trNodesRC);
        const singleCustomItemBundleSelectedRC = !!activeCustomItemSelRC;
        const canGroup = itemsOnly.length >= 2 && !allSameExistingGroup && !singleCustomItemBundleSelectedRC;
        const canUngroup = trNodesRC.some(n => n.data_deviceid === 'group' || n.data_groupId);
        const isSinglePathShape =
            itemsOnly.length === 1 && itemsOnly[0].data_deviceid === 'pathShape';
        const canCustomItem =
            (itemsOnly.length >= 2 || isSinglePathShape) && !allSameExistingCustomItem;
        createMenuItem('customItemMenuDiv', 'Create Custom Item', '', !canCustomItem);
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        createMenuItem('rotateDiv', 'Rotate 90°', 'ctrl+r', trNodesRC.length < 1)
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        createMenuItem('groupMenuDiv',   'Group',   'ctrl+g',       !canGroup);
        createMenuItem('ungroupMenuDiv', 'Ungroup', 'ctrl+shift+g', !canUngroup);
        rightClickMenuDiv.appendChild(hr.cloneNode(true));
        createMenuItem('undoDiv', 'Undo', 'ctrl+z', !(undoArray.length > 1));
        createMenuItem('redoDiv', 'Redo', 'ctrl+y', !(redoArray.length > 0));
    }




    rightClickMenuDialog.style.top = newY + 'px'; /* Distance from the top of the viewport, moved to center */
    rightClickMenuDialog.style.left = newX + 'px';

    rightClickMenuDialogLastPosition.x = newX;
    rightClickMenuDialogLastPosition.y = newY;

    rightClickMenuDialog.style.position = 'fixed';


    rightClickMenuDiv.addEventListener('mouseenter', function (event) {
        mouseOverRightClickMenu = true;

    });

    rightClickMenuDiv.addEventListener('mouseleave', function (event) {
        mouseOverRightClickMenu = false;

    });

    /* recreate menu on second right click */
    rightClickMenuDialog.addEventListener('contextmenu', function (event) {
        event.preventDefault();

        if (mouseUnit.x < 0 || mouseUnit.y < 0) {
            rightClickMenuDialog.close();
            return;
        }

        createRightClickMenu();

    });


    function createMenuItem(menuId, menuText, shortCut, disableDiv = false) {
        let mainDivClass = 'rightClickMenuItem';

        if (disableDiv) {
            mainDivClass = 'rightClickMenuItemDisable';
            menuId = menuId + 'Disable';
        }

        let menuItem = document.createElement('div');
        menuItem.id = menuId;
        menuItem.className = mainDivClass;
        menuItem.textContent = menuText;
        rightClickMenuDiv.appendChild(menuItem);

        let shortCutSpan = document.createElement('span');
        shortCutSpan.id = menuId + 'shortCut';
        shortCutSpan.className = 'rightClickMenuShortCutText';
        shortCutSpan.textContent = shortCut;
        menuItem.appendChild(shortCutSpan);

        menuItem.addEventListener('click', function menuItemClick(e) {

            closeRightClickMenu();
            if (e.target.id === 'copyMenuDiv') {
                copyItems();
            }
            else if (e.target.id === 'deleteMenuDiv') {
                deleteTrNodes();
            }
            else if (e.target.id === 'pasteMenuDiv') {
                pasteItems(false);
            }
            else if (e.target.id === 'duplicateMenuDiv') {
                duplicateItems();
            }
            else if (e.target.id === 'customItemMenuDiv') {
                openCreateCustomItemDialog();
            }
            else if (e.target.id === 'undoDiv') {
                btnUndoClicked();
            }
            else if (e.target.id === 'redoDiv') {
                btnRedoClicked();
            }
            else if (e.target.id === 'quickAddMenu') {
                toggleQuickAdd(true);
            }
            else if (e.target.id === 'rotateDiv') {
                rotateTrNodeItems();

                tr.nodes().forEach(node => {
                    updateShading(node);
                });

                if (tr.nodes().length === 1) {
                    updateFormatDetails(shape.id());
                }
            }
            else if (e.target.id === 'groupMenuDiv') {
                createGroup();
            }
            else if (e.target.id === 'ungroupMenuDiv') {
                ungroupSelectedItems();
            }
        });


    }

}

